window.__QUIZ_SUBJECT__=[{"id": "objective>IRK>2010>1", "subject": "IRK", "year": "2010", "type": "Objective", "topic": "THE JAHILIYYAH: ARABIA BEFORE ISLAM : DESCRIPTION OF ARABIA – LOCATION", "question": "Kazraj is to 'Aws as Kharaj is to", "images": [], "options": {"A": "Kaffaah", "B": "Jizyah", "C": "'Iddah", "D": "Amanah"}, "answer": "B", "explanation": "kazraj is to ' Aws as kharaj is to jizya.   It  should be noted that Khazraj and Jizya are forms of taxes  while Aws and Khazraj are descendants of Azd tribe and were known as Banū Qayla in pre-Islamic era.", "marks": "1", "difficulty": "3"}, {"id": "objective>IRK>2010>2", "subject": "IRK", "year": "2010", "type": "Objective", "topic": "SHARI ‘AH : SOURCES (THE QUR’AN, THE SUNNAH, THE IJMA‘ AND THE QIYAS.)", "question": "The following are sources of Shari'ah except?", "images": [], "options": {"A": "ijma'", "B": "Qiran", "C": "Qur'an", "D": "Qiyas"}, "answer": "B", "explanation": "Qiran is not source of shari'ah. The qiran or beam of light belonging to Allah is to make us better Muslims and in that attempt He chooses to throw that qiran to all those who have faith.  The primary sources of Islamic law are the Holy Book (The Quran), The Sunnah (the traditions or known practices of the Prophet Muhammad ), Ijma' (Consensus), and Qiyas (Analogy)", "marks": "1", "difficulty": "1"}, {"id": "objective>IRK>2010>3", "subject": "IRK", "year": "2010", "type": "Objective", "topic": "HADITH : READING (IN EITHER THE ARABIC TEXT OR TRANSLITERATION). MEMORIZATION, MEANING OF THE FOLLOWING AHADITH AND LESSONS LEARNT FROM THEM (IDENTIFICATION, EXPLANATION, INTERPRETATION AND APPLICATION): AN-NAWAWI’S COLLECTION. 1, 5, 7, 9, 13, 15,16,18,34 AND 41.", "question": "An-Nawawi's Hadith No.9 teaches", "images": [], "options": {"A": "moderation in questioning", "B": "the pillars of islam", "C": "he importance of irtention", "D": "lawful and prohibit things"}, "answer": "A", "explanation": "An_Nawawi's Hadith No 9 teaches moderation in questioning", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2010>4", "subject": "IRK", "year": "2010", "type": "Objective", "topic": "HADITH : THE SIX SOUND COLLECTIONS OF HADITH (SIHAUS-SITTAH) AND THEIR COMPILERS.", "question": "One of the practices of imam bukhari is that", "images": [], "options": {"A": "Perform ablution and prayer before regarding any tradition", "B": "Carefully check all  his tradition with that of muslim", "C": "reflect all his his tradition after his visit with that of the prophet", "D": "recite a part of the Qur'an before the Hadit"}, "answer": "A", "explanation": "One of the practices of imam Bukhari is that he performed ablution and prayer before recording any traditions.", "marks": "1", "difficulty": "3"}, {"id": "objective>IRK>2010>5", "subject": "IRK", "year": "2010", "type": "Objective", "topic": "HADITH : CLASSIFICATION OF HADITH: SAHIH, HASAN AND DA‘IF.", "question": "The following personalities excelled in Hadith memorization except", "images": [], "options": {"A": "Abu Hurayrah", "B": "Aishah", "C": "Fatimah", "D": "Zaydb. Thabit"}, "answer": "C", "explanation": "Fatimah, the daughter of Prophet Muhammad (S.A.W), is not known for her memorization of Hadith. While she was a significant figure in Islamic history, she did not excel in Hadith memorization like Abu Hurayrah, Aishah, and Zayd b. Thabit did. Abu Hurayrah is known to have narrated more Hadith than any other companion of the Prophet. Aishah, the Prophet's wife, is also known for her extensive knowledge of Hadith. Zayd b. Thabit was a prominent scholar among the companions of the Prophet and is known for his knowledge of Hadith.", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2010>6", "subject": "IRK", "year": "2010", "type": "Objective", "topic": "HADITH : THE IMPORTANCE OF HADITH AND SUNNAH", "question": "Which of the following wives of the prophet (S.A.W) did not [participate in the transmission of hadith?", "images": [], "options": {"A": "Liamm Habibah", "B": "maymunah", "C": "khadijah", "D": "Aishat"}, "answer": "C", "explanation": "Khadijah, the first wife of Prophet Muhammad (S.A.W), died before the Prophet began to openly preach Islam. Therefore, she did not participate in the transmission of Hadith. The Hadith are the sayings, actions, and approvals of the Prophet Muhammad (S.A.W) regarding the daily life of a Muslim. The other wives of the Prophet mentioned in the options, Umm Habibah, Maymunah, and Aishah, are known to have narrated Hadith.", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2010>7", "subject": "IRK", "year": "2010", "type": "Objective", "topic": "QUR’AN : REVELATION OF THE QUR’AN: VISITS OF THE PROPHET (S.A.W.) TO CAVE HIRA ; FIRST REVELATION AND HIS REACTION TO IT, DIFFERENT MODES OF REVELATION, PIECEMEAL- REVELATION OF THE QUR’AN.", "question": "The type of revelation experienced in the farm of vision is", "images": [], "options": {"A": "Ru'ya", "B": "Wahy", "C": "Liham", "D": "Kasht"}, "answer": "A", "explanation": "The type of revelation experienced in the form of vision is Ru'ya. (The letter) Ra', (The letter) Hemzah, (The letter) Ya', make a root that indicates sight and vision with the eye or mind", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2010>8", "subject": "IRK", "year": "2010", "type": "Objective", "topic": "SALAT : KINDS OF SALAT AND HOW THEY ARE OBSERVED", "question": "The first friday  congregation salat was held in the year", "images": [], "options": {"A": "622 C.E", "B": "624 C.E", "C": "630 C.E", "D": "631 C.E"}, "answer": "B", "explanation": "The first Friday congregational salat was held in the year 624CE.", "marks": "1", "difficulty": "3"}, {"id": "objective>IRK>2010>9", "subject": "IRK", "year": "2010", "type": "Objective", "topic": "ZAKAT (CHARITY) : DEFINITIONS OF ZAKAT AND SADAQAH", "question": "The tax payable on the produce of landed properties of a muslim is known as a", "images": [], "options": {"A": "Lisha", "B": "Jizyah", "C": "Kharaj", "D": "Zakat"}, "answer": "C", "explanation": "The tax payable on the produce of landed property of a muslim is known as kharaj.This form of tax was levied by the Muslim government on certain categories of agricultural produce and was collected in cash and/or in kind.", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2010>10", "subject": "IRK", "year": "2010", "type": "Objective", "topic": "SALAT : MEANING AND IMPORTANCE", "question": "The Adhan became the medium of inviting muslim devotes to worship", "images": [], "options": {"A": "announcement", "B": "speaking", "C": "running", "D": "laughing"}, "answer": "A", "explanation": "The Adhan became the medium of inviting Muslims devotees to worship  ..... Adhān, (Arabic: \" announcement\"), the Muslim call to Friday public worship (jumʿah) and to the five daily hours of prayers", "marks": "1", "difficulty": "1"}, {"id": "objective>IRK>2010>11", "subject": "IRK", "year": "2010", "type": "Objective", "topic": "HAJJ (PILGRIMAGE) : RITES OF HAJJ", "question": "In bidding farewell to Ka'bah the pilgrims perform Tawal", "images": [], "options": {"A": "al-Quduen", "B": "al-ifsdah", "C": "al-wada", "D": "az-ziynrah"}, "answer": "C", "explanation": "In bidding farewell to the ka'bah, the pilgrims perform Tawal al_wada. . When they are ready to head home, pilgrims circle the Kaaba seven times in a farewell known as \"Tawaf Al-Wada", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2010>12", "subject": "IRK", "year": "2010", "type": "Objective", "topic": "HADITH : DEFINITION OF HADITH AND SUNNAH", "question": "Recommended and desirable actions in islam are referred to as", "images": [], "options": {"A": "Makruh", "B": "sunuah", "C": "wajib", "D": "mandah"}, "answer": "D", "explanation": "Recommended and desirable actions in islam are referred to as wandah", "marks": "1", "difficulty": "1"}, {"id": "objective>IRK>2010>13", "subject": "IRK", "year": "2010", "type": "Objective", "topic": "NIKAH (MARRIAGE) : CONCEPT", "question": "The wedding feast in islamic marriage is known as", "images": [], "options": {"A": "Khul", "B": "Qubul", "C": "waliyy", "D": "walimah"}, "answer": "D", "explanation": "The wedding feast in Islamic marriage is known as walimah .The word walima is derived from awlama, meaning to gather or assemble. It designates a feast in Arabic.", "marks": "1", "difficulty": "1"}, {"id": "objective>IRK>2010>14", "subject": "IRK", "year": "2010", "type": "Objective", "topic": "TALAQ ( DIVORCE) : KINDS", "question": "Divorce at the instance of the husband is", "images": [], "options": {"A": "Talaq", "B": "faslt", "C": "Li'an", "D": "Murbara'ah"}, "answer": "A", "explanation": "Divorce as the instance of the husband is Talaq. The term talaq is commonly translated as \"repudiation\" or simply \"divorce\". In classical Islamic law it refers to the husband's right to dissolve the marriage by simply announcing to his wife that he repudiates her.", "marks": "1", "difficulty": "1"}, {"id": "objective>IRK>2010>15", "subject": "IRK", "year": "2010", "type": "Objective", "topic": "TALAQ ( DIVORCE) : KINDS", "question": "Ziahris is a special way of terminating marriage because it involves the", "images": [], "options": {"A": "beating of one's partner with justification", "B": "comparison of one's wife in the back of one's mother", "C": "mutual cursing of one another in marriage", "D": "Absence of conjugal relations"}, "answer": "D", "explanation": "Ziharis a special way of terminating marriage because it involves the .......Zihar means a man tells his wife that she is to him like a relative of his whom he cannot marry", "marks": "1", "difficulty": "3"}, {"id": "objective>IRK>2010>16", "subject": "IRK", "year": "2010", "type": "Objective", "topic": "TALAQ ( DIVORCE) : ISLAM’S ATTITUDE (Q.4: 35)", "question": "The term Quru' is used in relation to", "images": [], "options": {"A": "Idrat", "B": "jihad", "C": "mursal", "D": "iddah"}, "answer": "D", "explanation": "The term 'Quru is used in relation to 'Iddah.iddah or iddat is the period a woman must observe after the death of her husband or after a divorce", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2010>17", "subject": "IRK", "year": "2010", "type": "Objective", "topic": "ZAKAT (CHARITY) : BENEFITS OF ZAKAT – SPIRITUAL, SOCIO-ECONOMIC AND MORAL.", "question": "One of the economic effect of zina is that it", "images": [], "options": {"A": "incures the displeasure of Allah", "B": "may resut in misapplication", "C": "leads to the birth of illegitimate children", "D": "facilitate the spread of viral disease"}, "answer": "B", "explanation": "The economic effect of zina is that it may result in misapplication of.....Zina is an Islamic legal term, meaning illicit sexual relations, that can be found in the Koran and the hadith (the collected words and acts of the Prophet Muhammad)", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2010>18", "subject": "IRK", "year": "2010", "type": "Objective", "topic": "THE KHULAFᾹ’UR-RᾹSHIDĪN (THE RIGHTLY – GUIDED CALIPHS) : THEIR CONTRIBUTIONS TO ISLAM", "question": "One of the contribution of Ibn sina was in the field of", "images": [], "options": {"A": "History", "B": "medicine", "C": "Geography", "D": "Theology"}, "answer": "B", "explanation": "Ibn Sina, also known as Avicenna, was a Persian polymath who made significant contributions to various fields. However, he is most renowned for his work in the field of medicine. His book, The Canon of Medicine, was used as a standard medical text in many universities up until the 17th century. Therefore, the correct answer is medicine.", "marks": "1", "difficulty": "3"}, {"id": "objective>IRK>2010>19", "subject": "IRK", "year": "2010", "type": "Objective", "topic": "ISLAM IN WEST AFRICA : THE ADVENT AND ROLES OF TRADERS, TEACHERS, MURᾹBITUN, SUFI ORDERS, MUJADDIDUN (REFORMERS) AND HAJJ IN THE PREAD OF ISLAM.", "question": "The person who brought the leader of al-murabbitun to west africa was", "images": [], "options": {"A": "Yahya b. Ibrahim", "B": "Abdullah b. yasin", "C": "Umar al-futi", "D": "Idris Alooma"}, "answer": "B", "explanation": "The person which broughht the leader (ofal. Murabbitun to west Afica was 'Abdullah b. Yasin", "marks": "1", "difficulty": "3"}, {"id": "objective>IRK>2010>20", "subject": "IRK", "year": "2010", "type": "Objective", "topic": "ISLAM IN WEST AFRICA : THE IMPACT OF ISLAM ON THE SOCIO-POLITICAL, ECONOMIC AND LINGUISTIC LIVES OF THE PEOPLES OF ANCIENT WEST AFRICAN EMPIRES (I.E. GHANA, MALI, SHONGHAI AND KANEM- BORNO", "question": "Mutual consultation is to shura as accountability is", "images": [], "options": {"A": "Hatal", "B": "Tatfif", "C": "Ma'uliyyah", "D": "Riba"}, "answer": "C", "explanation": "Mutual consultation is to shura as accountability is to Ma'uliyyah.   al-amanah and al-mas'uliyyah refer to something that is granted to a person to be performed or preserved and that person will be held responsible or accountable for errors or treacherous.", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2010>21", "subject": "IRK", "year": "2010", "type": "Objective", "topic": "TALAQ ( DIVORCE) : KINDS", "question": "The agreement of a couple to dissolve their marriage is", "images": [], "options": {"A": "Mubara'ah", "B": "Khul'", "C": "Faskh", "D": "Li'an"}, "answer": "A", "explanation": "The agreement by a couple to dissolve their marriage is Mubara'ah.  Divorce through mutual consent is usually called Mubara′ah.", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2010>22", "subject": "IRK", "year": "2010", "type": "Objective", "topic": "QUR’AN : PRESERVATION OF THE QUR’AN: COMPLETE ARRANGEMENT INCLUDING DISTINCTION BETWEEN MAKKI AND MADANI SUWAR; RECORDING; COMPILATION; STANDARDIZATION: ROLES PLAYED BY THE COMPANIONS OF THE PROPHET (S.A.W.) IN THE PRESERVATION OF THE QUR’AN.", "question": "The following were members of standardization committee of al Qur'an except", "images": [], "options": {"A": "Zayd b. Harith", "B": "Abdallah b. Zubayr", "C": "Sa'id b. al' As", "D": "Abddur Rahman b. Harith b. Hisham"}, "answer": "D", "explanation": "The standardization committee of al Qur'an was formed during the reign of Caliph Uthman ibn Affan. The members of this committee were Zayd b. Harith, Abdallah b. Zubayr, Sa'id b. al' As, and Abdur Rahman b. Harith b. Hisham was not a member of this committee.", "marks": "1", "difficulty": "3"}, {"id": "objective>IRK>2010>23", "subject": "IRK", "year": "2010", "type": "Objective", "topic": "ZAKAT (CHARITY) : ARTICLES ON WHICH ZAKAT IS PAID", "question": "One of the sources of fund to Baytul mal is", "images": [], "options": {"A": "Amanah", "B": "Kharaj", "C": "Rba", "D": "Tatfif"}, "answer": "B", "explanation": "One of the sources of funds to Baytul Mal is kharaj.Kharāj  is a type of individual Islamic tax on agricultural land and its produce developed under Islamic law.", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2010>24", "subject": "IRK", "year": "2010", "type": "Objective", "topic": "HAJJ (PILGRIMAGE) : RITES OF HAJJ", "question": "The rite of Ramy in Hajj is important because it", "images": [], "options": {"A": "Shows one's resolve to eschew evil tendencies", "B": "Demonstrates one's regard for Allah's injunctions", "C": "leads one into paradise without questioning", "D": "show a person's patience in the times of adversity"}, "answer": "B", "explanation": "1.\tThe rite of Ramy in Hajj is important because it demonstrates one's regard for Allah's injunctions . . It is one of a series of ritual acts that must be performed in the Hajj", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2010>25", "subject": "IRK", "year": "2010", "type": "Objective", "topic": "THE LIFE OF PROPHET MUHAMMAD (S.A.W.) : HIJRAH", "question": "The mekkans presented gifts to the Negus of Abyssinia in order to", "images": [], "options": {"A": "establish friendly relation with him", "B": "secure extradition of early muslims", "C": "re-establish relations after the event of the elephant", "D": "show their preference for christianity to islam faith"}, "answer": "B", "explanation": "The makkans presented gifts to the Negus  of Abyssinian in order to secure extraditions of the early Muslims", "marks": "1", "difficulty": "3"}, {"id": "objective>IRK>2010>26", "subject": "IRK", "year": "2010", "type": "Objective", "topic": "THE JAHILIYYAH: ARABIA BEFORE ISLAM : POLITICAL LIFE – SYSTEM OF GOVERNMENT", "question": "The alliance of sudul was important because it distributed it", "images": [], "options": {"A": "Distributed Zakat among he needy", "B": "Defended the ka'bah against the invaders", "C": "Drew membersip from outside Mukkuh", "D": "Protected the interest of the opposed"}, "answer": "D", "explanation": "The alliance of Fudul was important because it protected the interests of the oppressed. It was an alliance formed in pre-Islamic Arabia with the aim of ensuring justice and protecting the rights of the weak and oppressed. It drew its membership from various clans in Mecca, not necessarily from outside Mecca.", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2010>27", "subject": "IRK", "year": "2010", "type": "Objective", "topic": "THE LIFE OF PROPHET MUHAMMAD (S.A.W.) : HIJRAH", "question": "The yathribite who accepted islam at the first treaty of Asalah", "images": [], "options": {"A": "Alhara b, manur", "B": "Abbas b. Abdul multabib", "C": "Mus'ab b. umayr", "D": "Abu Qaya b. al-Aslar"}, "answer": "D", "explanation": "A practice associated with jahillyyah era was gender discrimination. Male youth recognized more gender- discriminatory practices within their females, even as these same practices were associated with fewer mental health problems among male youth.", "marks": "1", "difficulty": "3"}, {"id": "objective>IRK>2010>28", "subject": "IRK", "year": "2010", "type": "Objective", "topic": "THE JAHILIYYAH: ARABIA BEFORE ISLAM : SOCIAL LIFE – MARRIAGE, DIVORCE AND INHERITANCE.", "question": "The pratice unassociated with jahliyyah was", "images": [], "options": {"A": "gender discrimination", "B": "Hadith narration", "C": "angelic revelation", "D": "Qur'an memoriation"}, "answer": "D", "explanation": "Jahiliyyah refers to the period of ignorance before the revelation of the Qur'an in Arabian society. Therefore, Qur'an memorization could not have been a practice during Jahiliyyah as the Qur'an had not yet been revealed.", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2010>29", "subject": "IRK", "year": "2010", "type": "Objective", "topic": "THE LIFE OF PROPHET MUHAMMAD (S.A.W.) : HIJRAH", "question": "The year 621 C.E is important to muslims because", "images": [], "options": {"A": "Zakat was instituted to erase poverty", "B": "The early muslims emigrant returned from abyssina", "C": "Ah.b.abi accepted the religion of islam", "D": "salat became a mode of worshipping Allah"}, "answer": "A", "explanation": "The year 621 C.E is important to Muslim because  salat became the mode of worshipping Allah", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2010>30", "subject": "IRK", "year": "2010", "type": "Objective", "topic": "ISLAM IN WEST AFRICA : THE ADVENT AND ROLES OF TRADERS, TEACHERS, MURᾹBITUN, SUFI ORDERS, MUJADDIDUN (REFORMERS) AND HAJJ IN THE PREAD OF ISLAM.", "question": "The following were items of trade brought into west Africa except", "images": [], "options": {"A": "Shea butter", "B": "salt", "C": "silk cloth", "D": "cowries"}, "answer": "A", "explanation": "Shea butter is a product that is native to West Africa and was not brought into the region as a trade item. The other options - salt, silk cloth, and cowries - were all items that were brought into West Africa through trade.", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2010>31", "subject": "IRK", "year": "2010", "type": "Objective", "topic": "ISLAM IN WEST AFRICA : THE ADVENT AND ROLES OF TRADERS, TEACHERS, MURᾹBITUN, SUFI ORDERS, MUJADDIDUN (REFORMERS) AND HAJJ IN THE PREAD OF ISLAM.", "question": "The consolidation of influence of Tijanuyyah in west Africa is credited  to", "images": [], "options": {"A": "shaykh Ahamed Tijans", "B": "Shaykh Ahamed Labbo", "C": "Shaykh Mukhat al-kuntu", "D": "Al-Hajj Umar Tal"}, "answer": "C", "explanation": "The consolidation of the influence of Tijaniyyah in west Africa is credited to shaykh Mukhtar al_kuntu. Tijaniyya Tariqah is one of the contemporary forms of the Sufi movement which came from the teachings Sidi Ahmad al Tijani in North Africa but now increasingly prevalent in West Africa", "marks": "1", "difficulty": "3"}, {"id": "objective>IRK>2010>32", "subject": "IRK", "year": "2010", "type": "Objective", "topic": "HADITH : CRITERIA FOR AUTHENTICITY OF HADITH", "question": "Hadith was not put into writing during the prophet' (S.A.W) did  not permit him", "images": [], "options": {"A": "The prophet (S.A.W) did not permit the exercise", "B": "The prophet (S.A.W) ordered that it should be done after him", "C": "the collector of hadith were still learning the art of writing", "D": "Of fear that it might be mixed up with the Qu'ran"}, "answer": "D", "explanation": "Hadith was not put into writing during the prophet's (S.A.W) lifetime because of fear that is might be mixed up with the Qur'an", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2010>33", "subject": "IRK", "year": "2010", "type": "Objective", "topic": "HADITH : CRITERIA FOR AUTHENTICITY OF HADITH", "question": "The man factor which necessitated the collection of Hadith was the", "images": [], "options": {"A": "growing tendency of forgery", "B": "death of the prophet (S.A.W)", "C": "rise of different islamic centers of learning", "D": "Gradual decrease of the prophet companion"}, "answer": "D", "explanation": "The main factor which necessitate the collection of Hadith was the gradual decrease of the prophet's companions", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2010>34", "subject": "IRK", "year": "2010", "type": "Objective", "topic": "HADITH : THE SIX SOUND COLLECTIONS OF HADITH (SIHAUS-SITTAH) AND THEIR COMPILERS.", "question": "The lady who corrected caliphat umar when he erred in citing a tradition was", "images": [], "options": {"A": "Fatimah", "B": "Umar danda", "C": "Hafeah", "D": "Aishah"}, "answer": "D", "explanation": "The lady who corrected Caliph Umar when he erred in citing a tradition was Aishah. Aishah was one of the wives of Prophet Muhammad (S.A.W) and she was known for her knowledge and understanding of Islam. She often corrected the companions of the Prophet when they made mistakes in citing Hadiths or understanding Islamic laws.", "marks": "1", "difficulty": "3"}, {"id": "objective>IRK>2010>35", "subject": "IRK", "year": "2010", "type": "Objective", "topic": "THE LIFE OF PROPHET MUHAMMAD (S.A.W.) : CALL TO PROPHETHOOD", "question": "The year 610 C.E will remain memorable in islam because Mohammad (S.A.W)", "images": [], "options": {"A": "Received the first revelation", "B": "lost Khadijah and abu talib", "C": "migrated to the city of talif", "D": "boycotted by the Qurayah"}, "answer": "A", "explanation": "The year 610 C.E  will remain memorable in islam because Muhammed (S.A.W) received the first revelation,Muhammad's first revelation was an event described in Islamic tradition as taking place in 610 AD.", "marks": "1", "difficulty": "1"}, {"id": "objective>IRK>2010>36", "subject": "IRK", "year": "2010", "type": "Objective", "topic": "QUR’AN : THE QUR’AN AS A SOURCE OF GUIDANCE IN SOCIAL, POLITICAL, SPIRITUAL AND MORAL MATTERS", "question": "The name of the Qu'ran which describes it as the criterion is", "images": [], "options": {"A": "al-Hakim", "B": "al-Farqan", "C": "al-kitab", "D": "al- huda"}, "answer": "B", "explanation": "The name of the Qur'an which describes it as the criterion is al_Furqan, The name Al-Furqan, or \"The Criterion\" refers to the Qur'an itself as the decisive factor between good and evil", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2010>37", "subject": "IRK", "year": "2010", "type": "Objective", "topic": "QUR’AN : READING (IN EITHER ARABIC TEXT OR TRANSLITERATION), MEMORIZATION, MEANING OF THE FOLLOWING SUWAR AND THE LESSONS LEARNT FROM THEM (IDENTIFICATION, EXPLANATION, INTERPRETATION AND APPLICATION)", "question": "Sujudut - tilawah is unique because it is connected ith Qu'ran", "images": [], "options": {"A": "memorization", "B": "preservation", "C": "recitation", "D": "revelation"}, "answer": "C", "explanation": "Sujudut-tilawah is a prostration that is performed after the recitation of certain verses of the Quran. Therefore, it is connected with the recitation of the Quran, not its memorization, preservation, or revelation.", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2010>38", "subject": "IRK", "year": "2010", "type": "Objective", "topic": "QUR’AN : READING (IN EITHER ARABIC TEXT OR TRANSLITERATION), MEMORIZATION, MEANING OF THE FOLLOWING SUWAR AND THE LESSONS LEARNT FROM THEM (IDENTIFICATION, EXPLANATION, INTERPRETATION AND APPLICATION)", "question": "The recitation in surat-Duha(Q93-2) is", "images": [], "options": {"A": "thunderstorm", "B": "sunshine", "C": "daybreak", "D": "nightfall"}, "answer": "C", "explanation": "Surat Ad-Duha (Q93-2) is translated as 'The Morning Hours' or 'The Morning Bright'. The recitation in this Surah is related to the daybreak, not thunderstorm, sunshine, or nightfall.", "marks": "1", "difficulty": "1"}, {"id": "objective>IRK>2010>39", "subject": "IRK", "year": "2010", "type": "Objective", "topic": "IMAN (FAITH) : ARTICLES OF FAITH: BELIEF IN ALLAH WITH EMPHASIS ON KALIMATUSH-SHAHADAH(Q2: 163 AND 255; 3:18;17:42-43;21: 22 ; 23: 91 Q. 112, ISLAM AND THE CONCEPT OF TRINITY (Q.4:171; 5:75 – 76; 19:92-3; 112).", "question": "Monotheism is emphasized in surah", "images": [], "options": {"A": "al-kafirin", "B": "al-ikhlas", "C": "al-Naar", "D": "al-Qadr"}, "answer": "B", "explanation": "Monotheism is emphasized in surah al_ikhlas, Monotheism is the belief in Allah which rejects despotic tyrants", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2010>40", "subject": "IRK", "year": "2010", "type": "Objective", "topic": "ZAKAT (CHARITY) : DEFINITIONS OF ZAKAT AND SADAQAH", "question": "Suratul furqarl (Q25:63) declares that the servant of Allah are those who", "images": [], "options": {"A": "are steadfast at prayer", "B": "pay zakat to the poor", "C": "observe fast constantly", "D": "are peaceful"}, "answer": "D", "explanation": "Suratul Furqan (Q25:63) describes the servants of Allah as those who walk on the earth in humility and when the ignorant address them, they say, 'Peace.' This implies that they are peaceful. The other options, although they are also characteristics of the servants of Allah, are not specifically mentioned in this verse.", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2010>41", "subject": "IRK", "year": "2010", "type": "Objective", "topic": "ZAKAT (CHARITY) : ARTICLES ON WHICH ZAKAT IS PAID", "question": "The zakat payable on farm produce worth $25000.00 is", "images": [], "options": {"A": "$2,500`", "B": "$2,000", "C": "$1,500", "D": "$1,000"}, "answer": "A", "explanation": "The zakat payable on farm produce by rain, worth $25,000,000 is $2,500,000 . Your Zakat donation should amount to 2.5% of your total wealth accumulated over the year.", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2010>42", "subject": "IRK", "year": "2010", "type": "Objective", "topic": "THE LIFE OF PROPHET MUHAMMAD (S.A.W.) : HIJRAH", "question": "The cave of thawr is associated with the", "images": [], "options": {"A": "revelation of surat al Alaq", "B": "imigration from makkah to madinah", "C": "farewell sermon of the Prophet (S.A.W)", "D": "Hardship of isma'il and Hajarah"}, "answer": "B", "explanation": "The cave of Thawr is associated with the migration from makkah to marinas,  Muhammad and Abu Bakr left the city and took shelter in a cave", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2010>43", "subject": "IRK", "year": "2010", "type": "Objective", "topic": "HADITH : THE IMPORTANCE OF HADITH AND SUNNAH", "question": "Property taken from enemy force without fighting in battle is", "images": [], "options": {"A": "Glannlmah", "B": "Fay", "C": "Dara'ils", "D": "warf"}, "answer": "B", "explanation": "In Islamic jurisprudence, Fay refers to the property taken from the enemy without fighting in a battle. It is a term used to describe the goods, land, or property taken from the enemy without any actual fighting or warfare. This is different from 'Ghanimah' which refers to the spoils of war obtained after a battle.", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2010>44", "subject": "IRK", "year": "2010", "type": "Objective", "topic": "QUR’AN : THE QUR’AN AS A SOURCE OF GUIDANCE IN SOCIAL, POLITICAL, SPIRITUAL AND MORAL MATTERS", "question": "For a clear understanding the Qur'an, one must resort to", "images": [], "options": {"A": "Tartil", "B": "tafsir", "C": "Tilawah", "D": "Tabligls"}, "answer": "B", "explanation": "Tafsir is the Arabic term for the interpretation or explanation of the Qur'an. For a clear understanding of the Qur'an, one must resort to Tafsir. It involves understanding the context of the verses, the reasons for their revelation (Asbab al-nuzul), and the various interpretations provided by scholars. Tartil refers to the slow, measured rhythmic tone used in recitation of the Qur'an. Tilawah refers to the act of reciting the Qur'an, and Tabligh refers to conveying the message of Islam.", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2010>45", "subject": "IRK", "year": "2010", "type": "Objective", "topic": "QUR’AN : PRESERVATION OF THE QUR’AN: COMPLETE ARRANGEMENT INCLUDING DISTINCTION BETWEEN MAKKI AND MADANI SUWAR; RECORDING; COMPILATION; STANDARDIZATION: ROLES PLAYED BY THE COMPANIONS OF THE PROPHET (S.A.W.) IN THE PRESERVATION OF THE QUR’AN.", "question": "The fear of the Qur'an might be lost during the caliphate of Abu bakr led to its", "images": [], "options": {"A": "Memorization", "B": "standardization", "C": "translation", "D": "compilation"}, "answer": "D", "explanation": "The fear that the Qur'an might be lost during the caliphate of Abu bakr led to its compilation .The Quran was collected under the auspices of committee of four senior ranking Companions headed by Zayd ibn Thabit.", "marks": "1", "difficulty": "3"}, {"id": "objective>IRK>2010>46", "subject": "IRK", "year": "2010", "type": "Objective", "topic": "IMAN (FAITH) : HIS PROPHETS WITH SPECIAL EMPHASIS ON THE ULU1-‘AZM: IBRAHIM, NUH, MUSA, ‘ISA.(A.S.) MUHAMMAD (S.A.W.) Q. 6: 83-87: 4: 164; 10;47;21:107;46:35 AND AHADITH RELEVANT TO THE FOREGOING.", "question": "Mount al-judi is important because", "images": [], "options": {"A": "God spoke to prophet (A.S) there", "B": "Prophet Nuh'(A.S) ark", "C": "Adam and Hawa' parted company there", "D": "prophet isa(A.S)Ascended to heaven on it"}, "answer": "C", "explanation": "Mount al_judi is important because Adam and Ilawa parted company there", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2010>47", "subject": "IRK", "year": "2010", "type": "Objective", "topic": "THE KHULAFᾹ’UR-RᾹSHIDĪN (THE RIGHTLY – GUIDED CALIPHS) : THEIR BIOGRAPHIES", "question": "The battle of yammah was fought during the caliphate of", "images": [], "options": {"A": "Ali", "B": "abu bak", "C": "umar", "D": "usman"}, "answer": "A", "explanation": "Mount al_judi is important because Adam and Ilawa parted company there", "marks": "1", "difficulty": "3"}, {"id": "objective>IRK>2010>48", "subject": "IRK", "year": "2010", "type": "Objective", "topic": "QUR’AN : THE QUR’AN AS A SOURCE OF GUIDANCE IN SOCIAL, POLITICAL, SPIRITUAL AND MORAL MATTERS", "question": "Chapter on of the Qur'an is al fatihah because it", "images": [], "options": {"A": "contains seven verses", "B": "is repeated at salat", "C": "is an introductory message", "D": "was early makkah revelation"}, "answer": "C", "explanation": "Chapter one of the Qur'an is al Fatihah because it is an introductory message", "marks": "1", "difficulty": "1"}, {"id": "objective>IRK>2010>49", "subject": "IRK", "year": "2010", "type": "Objective", "topic": "QUR’AN : THE QUR’AN AS A SOURCE OF GUIDANCE IN SOCIAL, POLITICAL, SPIRITUAL AND MORAL MATTERS", "question": "The Qur'an  Adah-Dhikr", "images": [], "options": {"A": "Distinguishes between truth and falsehood", "B": "is a source of cure for all aliments", "C": "reminds on to be righteous at all times", "D": "is a revelation from allah to mankind"}, "answer": "C", "explanation": "The Qur'an as Adh_Dhikr reminds one to be righteous at all times.Allah refers to the Quran as 'Adh-dhikr' i.e. ' The Remembrance' or 'The Reminder", "marks": "1", "difficulty": "1"}, {"id": "objective>IRK>2010>50", "subject": "IRK", "year": "2010", "type": "Objective", "topic": "THE LIFE OF PROPHET MUHAMMAD (S.A.W.) : FORMATION OF THE UMMAH AND THE MADINAN CONSTITUTION", "question": "The first first person to begin the foundation of the prophet mosque in madinnah was", "images": [], "options": {"A": "Ammar b. yasir", "B": "Abdullah b . Ubayy", "C": "Abu Ayyub al-ansari", "D": "Anas b . malik"}, "answer": "A", "explanation": "The first person to begin the foundation of the Prophet's mosque in Madinah was Ammar b. Yasir. He was one of the earliest converts to Islam and played a significant role in the early Islamic community. Therefore, the correct answer is 'Ammar b. Yasir'.", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2010>51", "subject": "IRK", "year": "2010", "type": "Objective", "topic": "THE LIFE OF PROPHET MUHAMMAD (S.A.W.) : HIJRAH", "question": "Ahas an uncle of the prophet (S.A.W) is remembered at the second pledge of Aqabah because he", "images": [], "options": {"A": "was a principal witness to it", "B": "provided water to the yathribites", "C": "objected to the signing of the pact", "D": "followed the yathribites to the city"}, "answer": "A", "explanation": "'Abu, an uncle of the prophet (S.A.W),is remembered at the second pledge of 'Aqabah because he was a principal witness to it", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2010>52", "subject": "IRK", "year": "2010", "type": "Objective", "topic": "ISLAM IN WEST AFRICA : THE ADVENT AND ROLES OF TRADERS, TEACHERS, MURᾹBITUN, SUFI ORDERS, MUJADDIDUN (REFORMERS) AND HAJJ IN THE PREAD OF ISLAM.", "question": "Maratta in Gohir is remembered because uthman Dan fodio", "images": [], "options": {"A": "was born there", "B": "started his jihad there", "C": "migrated there with his followers", "D": "deposed his ruler"}, "answer": "A", "explanation": "Maratta in Gohir is remembered because \"Uthman Dan Fodio was born there", "marks": "1", "difficulty": "3"}, {"id": "objective>IRK>2010>53", "subject": "IRK", "year": "2010", "type": "Objective", "topic": "QUR’AN : REVELATION OF THE QUR’AN: VISITS OF THE PROPHET (S.A.W.) TO CAVE HIRA ; FIRST REVELATION AND HIS REACTION TO IT, DIFFERENT MODES OF REVELATION, PIECEMEAL- REVELATION OF THE QUR’AN.", "question": "Anytime the prophet (S.A.W) received a revelation , he first", "images": [], "options": {"A": "dictated it", "B": "wrote it down", "C": "memorized it", "D": "preached it"}, "answer": "C", "explanation": "Anytime the prophet (S.A.W) received a revelation , he first memorized it.Muhammad spent a lot of his time in prayer and meditation . On one of these occasions, he received the first revelation of the Qur'an from Allah. Muslims know this as the Night of Power. Muhammad was meditating in a cave on Mount Hira when he saw the Angel Jibril .", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2010>54", "subject": "IRK", "year": "2010", "type": "Objective", "topic": "ISLAM IN WEST AFRICA : THE ADVENT AND ROLES OF TRADERS, TEACHERS, MURᾹBITUN, SUFI ORDERS, MUJADDIDUN (REFORMERS) AND HAJJ IN THE PREAD OF ISLAM.", "question": "The place of retreat for sufi initiates is", "images": [], "options": {"A": "Masjid", "B": "Zawiyah", "C": "Madrash", "D": "Mimbar"}, "answer": "B", "explanation": "The place of retreat for Sufi initiates is known as a Zawiyah. Sufism is a mystical Islamic belief system where followers seek to find the truth of divine love and knowledge through direct personal experience of God. A Zawiyah is a place where Sufis gather to remember Allah, perform spiritual practices, and learn from their sheikh or guide. It serves as a spiritual retreat and a place of learning. Therefore, the correct answer is 'Zawiyah'.", "marks": "1", "difficulty": "3"}, {"id": "objective>IRK>2010>55", "subject": "IRK", "year": "2010", "type": "Objective", "topic": "QUR’AN : READING (IN EITHER ARABIC TEXT OR TRANSLITERATION), MEMORIZATION, MEANING OF THE FOLLOWING SUWAR AND THE LESSONS LEARNT FROM THEM (IDENTIFICATION, EXPLANATION, INTERPRETATION AND APPLICATION)", "question": "According to suratul ' Alaq (Q96:2) this as created from", "images": [], "options": {"A": "dry sand", "B": "congulated blood", "C": "Adam's ribs", "D": "divine substance"}, "answer": "B", "explanation": "The verse Q96:2 in the Quran says 'Created man from a clinging substance'. The term 'clinging substance' is often interpreted as 'congealed blood'.", "marks": "1", "difficulty": "1"}, {"id": "objective>IRK>2010>56", "subject": "IRK", "year": "2010", "type": "Objective", "topic": "ISLAM IN WEST AFRICA : THE ADVENT AND ROLES OF TRADERS, TEACHERS, MURᾹBITUN, SUFI ORDERS, MUJADDIDUN (REFORMERS) AND HAJJ IN THE PREAD OF ISLAM.", "question": "Jubril b. Umar is important in the life of Uthman Dan Fodio because he", "images": [], "options": {"A": "Saved him from drowning", "B": "gave him books on Tijaniyyah", "C": "took him along on Pilgrimage to makkah", "D": "Initiated him to a sufi order"}, "answer": "D", "explanation": "Jibril b.Umar is important in the life of ' Uthman Dan Fodio because he initiated him into a sufi order", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2010>57", "subject": "IRK", "year": "2010", "type": "Objective", "topic": "NIKAH (MARRIAGE) : CONCEPT", "question": "The minimum number of witnesses in an Islamic marriage is", "images": [], "options": {"A": "four males", "B": "three males", "C": "two males", "D": "one male"}, "answer": "C", "explanation": "For marriage a minimum of two witnesses is required. These witnesses are not for the bride or for the groom, but they are the witnesses for the marriage of the couple for whom they accept to be the witnesses.Nikah(marriage ceremony) is both a legal ceremony and a public ceremony. According to the Shari`ah, there should be two witnesses for all important legal contracts.Nikahas a public ceremony should also be done in the presence of many people (or at least two as the minimum), so that more people know that this man and this woman have come together as a legally married couple.", "marks": "1", "difficulty": "1"}, {"id": "objective>IRK>2010>58", "subject": "IRK", "year": "2010", "type": "Objective", "topic": "HAJJ (PILGRIMAGE) : RITES OF HAJJ", "question": "At-tashriq are the days of", "images": [], "options": {"A": "buying and selling", "B": "visits and caring", "C": "singing and dancing", "D": "eating and drinking."}, "answer": "D", "explanation": "When it is recommended to fast  The Prophet (peace and blessings be upon him) recommended that we fast the three \"white days\" of every lunar month, the day of 'Arafa, 'Ashura (10th of Muharram) and either the day preceding or following it, and the six days from the month of Shawwal, promising a great reward for the person who fasts on any of these days.  When it is unlawful to fast  It is unlawful to fast on the following:  - 'Eid ul-Fitr.  - 'Eid ul-Adha.  - Ayam al-Tashreeq (the three days following 'Eid ul-Adha).  Ayam al-Tashreeq  The Prophet (peace and blessings be upon him) called these the days of food and drink.", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2010>59", "subject": "IRK", "year": "2010", "type": "Objective", "topic": "SHIRK : WORSHIP OF IDOLS (Q.4:48:22:31:31:13:41:37)", "question": "The following are types of shirk except", "images": [], "options": {"A": "humanism", "B": "plytheism", "C": "dualism", "D": "monotheism"}, "answer": "D", "explanation": "Monotheism is not type of shirk, The term shirk in Islam is used to refer to idolatry or polytheism, which means deification, or worship of deity, gods, or anything other than Allāh", "marks": "1", "difficulty": "1"}, {"id": "objective>IRK>2010>60", "subject": "IRK", "year": "2010", "type": "Objective", "topic": "ZAKAT (CHARITY) : ARTICLES ON WHICH ZAKAT IS PAID", "question": "The zakat payable on property worth twenty million dollars is", "images": [], "options": {"A": "$500,000", "B": "$1,000,000", "C": "$ 2,000,000", "D": "$5,000,000"}, "answer": "A", "explanation": "Zakat is a form of alms-giving treated in Islam as a religious obligation or tax, which, by Quranic ranking, is next after prayer in importance. The amount of Zakat to be paid by an individual depends on the amount of money and the type of assets the individual possesses. The Quran does not provide specific guidelines on which types of wealth are taxable under the Zakat, nor does it specify percentages to be given. However, the customary practice is that the amount of Zakat paid on capital assets (e.g. money) is 2.5%. Therefore, the Zakat payable on property worth twenty million dollars would be 2.5% of 20,000,000, which is $500,000.", "marks": "1", "difficulty": "3"}, {"id": "objective>IRK>2012>1", "subject": "IRK", "year": "2012", "type": "Objective", "topic": "IMAN (FAITH) : HIS PROPHETS WITH SPECIAL EMPHASIS ON THE ULU1-‘AZM: IBRAHIM, NUH, MUSA, ‘ISA.(A.S.) MUHAMMAD (S.A.W.) Q. 6: 83-87: 4: 164; 10;47;21:107;46:35 AND AHADITH RELEVANT TO THE FOREGOING.", "question": "The number of prophet and messengers mentioned in the Qur'an  is", "images": [], "options": {"A": "55", "B": "45", "C": "35", "D": "25"}, "answer": "D", "explanation": "The  number of prophets and messengers mentioned in the Qur'an is 25.  25 prophets are mentioned in the Qur'an, although some believe there have been 124 000. Some prophets were given holy books to pass on to humankind", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2012>2", "subject": "IRK", "year": "2012", "type": "Objective", "topic": "SAWM (FASTING) : HOW FASTING IS OBSERVED IN ISLAM", "question": "The appropiate time to perform F'tikaf is during the", "images": [], "options": {"A": "first ten days of Ramadan", "B": "first ten days o Dhul-Hijjah", "C": "last ten days of Ramadan", "D": "last ten days of Dhul-Hijjah"}, "answer": "C", "explanation": "The appropriate time to perform l'tikaf is during the last ten days of Ramadan.  TheI'tikâf which is performed in the last ten days of Ramadân Mubarak", "marks": "1", "difficulty": "3"}, {"id": "objective>IRK>2012>3", "subject": "IRK", "year": "2012", "type": "Objective", "topic": "IMAN (FAITH) : HIS ANGELS – Q 2: 285; 8:50; 16: 2; 66: 6 ; 82: 10 – 12.", "question": "Angel Mika'il is responsible for", "images": [], "options": {"A": "rain fall", "B": "death", "C": "Guarding the fate of hell", "D": "Guarding he gate of paradise"}, "answer": "A", "explanation": "Angels Mika'il is responsible for rainfall. The Angel Mika'il (known as Michael in Christianity) is a friend to humanity. He is known as the giver of rain, which waters the land and helps to provide food for people.", "marks": "1", "difficulty": "1"}, {"id": "objective>IRK>2012>4", "subject": "IRK", "year": "2012", "type": "Objective", "topic": "SHIRK : ANCESTOR AND HERO- WORSHIP Q 3:64; 4:116;112:4; Q.2:13,40&41", "question": "Which of the following is not an aspect of Taudid", "images": [], "options": {"A": "Rububiyyah", "B": "Shirk", "C": "Uluhiyyah", "D": "Asma' wasiffat"}, "answer": "B", "explanation": "Shirk is not an aspect of Tawhid.  Shirk is anything which denies Tawhid. It is considered a terrible sin in Islam.", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2012>5", "subject": "IRK", "year": "2012", "type": "Objective", "topic": "HADITH : CLASSIFICATION OF HADITH: SAHIH, HASAN AND DA‘IF.", "question": "The impurities in isla are Hadith Akbar and", "images": [], "options": {"A": "Azam", "B": "Asghar", "C": "Aswad", "D": "Asfal"}, "answer": "B", "explanation": "The two impurities in islam are Hadath Akbar and Asghar.  Hadath is divided into two types; Hadath Asghar (minor impurity) and Hadath Akbar (major impurity).", "marks": "1", "difficulty": "3"}, {"id": "objective>IRK>2012>6", "subject": "IRK", "year": "2012", "type": "Objective", "topic": "ZAKAT (CHARITY) : THE BENEFICIARIES OF ZAKAT (Q.9:60)", "question": "Two of the eight categories of Zakat recipient are the", "images": [], "options": {"A": "Widow and the needy", "B": "Collector and the poor", "C": "children and the parent", "D": "Pilgrims and the tavellers"}, "answer": "B", "explanation": "Two of the eight categories of zakat recipient are the collector and the poor, These have  The recipients of Zakat ..2) Al-Masakin: The Needy", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2012>7", "subject": "IRK", "year": "2012", "type": "Objective", "topic": "NIKAH (MARRIAGE) : CONCEPT", "question": "One of the condition for a legal marriage is the presence of", "images": [], "options": {"A": "a marriage certificate", "B": "officiating Imams and Alfas", "C": "Two Adult male witnesses", "D": "two rings for the couples"}, "answer": "C", "explanation": "In Islamic law, one of the conditions for a legal marriage is the presence of two adult male witnesses. This is to ensure that the marriage is not conducted in secret and that there are people who can testify to the marriage. A marriage certificate, officiating Imams and Alfas, and two rings for the couples are not necessary conditions for a legal marriage in Islamic law.", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2012>8", "subject": "IRK", "year": "2012", "type": "Objective", "topic": "IMAN (FAITH) : ARTICLES OF FAITH: BELIEF IN ALLAH WITH EMPHASIS ON KALIMATUSH-SHAHADAH(Q2: 163 AND 255; 3:18;17:42-43;21: 22 ; 23: 91 Q. 112, ISLAM AND THE CONCEPT OF TRINITY (Q.4:171; 5:75 – 76; 19:92-3; 112).", "question": "Tawhid- ar Rubbabiyyah means", "images": [], "options": {"A": "holding the rope of Allah", "B": "maintaining the lordship of Allah", "C": "co-operating in the worship of the lord", "D": "saying in the house of worship"}, "answer": "B", "explanation": "Tawhid at_Rubbabiyyah means maintaining the lordship of Allah. Tawhid-ul-Rububiyyah (Oneness of Allah's Lordship) is the ascription of all Acts of Allah (Glorified and Exalted be He) to none but Him Alone t", "marks": "1", "difficulty": "3"}, {"id": "objective>IRK>2012>9", "subject": "IRK", "year": "2012", "type": "Objective", "topic": "ZAKAT (CHARITY) : ZAKATUL-FITR.", "question": "In Idhul-fitr Adha there is", "images": [], "options": {"A": "neither Adha nor Iqmah", "B": "one Adhan and one Iqamah", "C": "one Adhan and no Iqamah", "D": "neither iqamah nor tukbir"}, "answer": "A", "explanation": "In Idhul_fitr Adha there is neither Adha nor Iqinah", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2012>10", "subject": "IRK", "year": "2012", "type": "Objective", "topic": "IMAN (FAITH) : ARTICLES OF FAITH: BELIEF IN ALLAH WITH EMPHASIS ON KALIMATUSH-SHAHADAH(Q2: 163 AND 255; 3:18;17:42-43;21: 22 ; 23: 91 Q. 112, ISLAM AND THE CONCEPT OF TRINITY (Q.4:171; 5:75 – 76; 19:92-3; 112).", "question": "Tawid is divided into", "images": [], "options": {"A": "3 components", "B": "4 components", "C": "5 components", "D": "6 components"}, "answer": "A", "explanation": "Tawhid is divided into 3 components.Tawheed can be divided into three categories. (i) Tawheed ar-Ruboobeeyah (maintaining the unity of Lordship). (ii) Tawheed al-Asmaa-was-sifaat (maintaining the unity of Allah's name and attributes). (iii) Tawheed al-Ibaadah (maintaining the unity of worship).", "marks": "1", "difficulty": "3"}, {"id": "objective>IRK>2012>11", "subject": "IRK", "year": "2012", "type": "Objective", "topic": "QUR’AN : MORAL LESSONS FROM THE QUR’AN ATTITUDES TO PARENTS (Q.17 :23 – 24: 31 : 13 – 15 HONESTY IN WORDS AND DEEDS Q2: 42; 61: 2-3, 17: 35. PROHIBITION OF GAMBLING Q. 2:219:5 90-91.", "question": "Suratul Baqarah (Q2:195) admonishes human kind against", "images": [], "options": {"A": "corruption", "B": "Drug addiction", "C": "fornication", "D": "Extravagance"}, "answer": "A", "explanation": "Suratul Baqarah (Q2:195) admonishes human kind against corruption", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2012>12", "subject": "IRK", "year": "2012", "type": "Objective", "topic": "SALAT : MEANING AND IMPORTANCE", "question": "The supplication in the Ruku posture is", "images": [], "options": {"A": "Subhana Rabiyal-A'la", "B": "Subhana liah Walhmd lilah", "C": "Subhana Rabbika Rabbil'izzah", "D": "Subhana Rabbiyal Azim"}, "answer": "D", "explanation": "The supplication in the Ruku posture is subhana Rabbiyak Azim.To recite Subhana Rabbiyal 'Azim at least three times in Ruku' position", "marks": "1", "difficulty": "1"}, {"id": "objective>IRK>2012>13", "subject": "IRK", "year": "2012", "type": "Objective", "topic": "HAJJ (PILGRIMAGE) : PERFORMANCE OF ‘UMRAH AND HAJJ", "question": "Visiting the prophet (S.A.W) mosque in Madinah before after the performance of Hajj is", "images": [], "options": {"A": "Makrub", "B": "mandub", "C": "Mubah", "D": "mubatilat"}, "answer": "D", "explanation": "Visiting the prophet's (S.A.W) mosque in madinah before or  after the performance of Hajj is Mubtilat", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2012>14", "subject": "IRK", "year": "2012", "type": "Objective", "topic": "ISLAM IN WEST AFRICA : THE ADVENT AND ROLES OF TRADERS, TEACHERS, MURᾹBITUN, SUFI ORDERS, MUJADDIDUN (REFORMERS) AND HAJJ IN THE PREAD OF ISLAM.", "question": "Islam first came in west Africa through", "images": [], "options": {"A": "Scholar", "B": "pilgrim", "C": "traders", "D": "jihadist"}, "answer": "C", "explanation": "Islam first came to west Africa through traders.  Islam first came to West Africa as a slow and peaceful process, spread by Muslim traders and scholars .", "marks": "1", "difficulty": "1"}, {"id": "objective>IRK>2012>15", "subject": "IRK", "year": "2012", "type": "Objective", "topic": "THE LIFE OF PROPHET MUHAMMAD (S.A.W.) : MARRIAGE", "question": "the names of prophet muhammad's (S.A.W) daughters are", "images": [], "options": {"A": "Maryam, Zaynab , Rashidah and fatimah", "B": "Khadijah, Nafisah, Ruqayyah and Basirah", "C": "maymumah, jumilah, silimah and aminah", "D": "Zaynab, Raqayyah , ummal kulthum and fatimah"}, "answer": "D", "explanation": "The names of prophet Muhammad's (S.A.W) daughters are Zaynab,Ruqayyah, ummal kulthum and Fatimah . The Name of Allah, The Beneficent, The Merciful. ... Prophet( S.A.W) had four daughters, not just one. ... Zaynab, Ruqayyah, Umm Kulthum and Fatimah.", "marks": "1", "difficulty": "1"}, {"id": "objective>IRK>2012>16", "subject": "IRK", "year": "2012", "type": "Objective", "topic": "THE LIFE OF PROPHET MUHAMMAD (S.A.W.) : LEADERSHIP QUALITIES OF THE PROPHET", "question": "Prophet muhammed was called Al-amin because he was", "images": [], "options": {"A": "Posthumous child", "B": "Memorizer of the Qur'an", "C": "Messenger of Allah", "D": "trustworthy person"}, "answer": "D", "explanation": "Prophet Muhammad was called  al_Amin because he was a trustworthy person, They gave him this title, so it is claimed, because they considered him to be the best man among them, one who was never known to have told a lie.", "marks": "1", "difficulty": "1"}, {"id": "objective>IRK>2012>17", "subject": "IRK", "year": "2012", "type": "Objective", "topic": "THE LIFE OF PROPHET MUHAMMAD (S.A.W.) : MARRIAGE", "question": "The only child who survived the prophet (S.A.W)", "images": [], "options": {"A": "Ummul Kulhum", "B": "Zaynab", "C": "Fatimah", "D": "Ruquayyah"}, "answer": "C", "explanation": "The only child of Prophet Muhammad (S.A.W) who survived him was Fatimah. She lived for about six months after the death of her father.", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2012>18", "subject": "IRK", "year": "2012", "type": "Objective", "topic": "THE LIFE OF PROPHET MUHAMMAD (S.A.W.) : HIJRAH", "question": "An unfortunate event in the life of the prophet (S.A.W) after the end of the boycott was death of his", "images": [], "options": {"A": "Father and mother", "B": "Wife and uncle", "C": "Daughter and wife", "D": "Friends and companion"}, "answer": "B", "explanation": "An unfortunate event in the life of the prophet (S.A.W) after the end of the boycott was the death of his wife and uncle", "marks": "1", "difficulty": "3"}, {"id": "objective>IRK>2012>19", "subject": "IRK", "year": "2012", "type": "Objective", "topic": "HAJJ (PILGRIMAGE) : RITES OF HAJJ", "question": "Pilgrims are required to pass the 10th night of Dhul-hijjah at", "images": [], "options": {"A": "Arafah", "B": "makah", "C": "mina", "D": "Muzadalifah"}, "answer": "C", "explanation": "Pilgrims are required to pass the 10th night of Dhul_hijjah at mina,On the 10th of Dhul Hijjah, pilgrims return to Mina where they throw seven ... After the pelting has been completed.", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2012>20", "subject": "IRK", "year": "2012", "type": "Objective", "topic": "HADITH : THE SIX SOUND COLLECTIONS OF HADITH (SIHAUS-SITTAH) AND THEIR COMPILERS.", "question": "The six books of sound AHadiths are known as", "images": [], "options": {"A": "Asmaur-kijal", "B": "sahilayn", "C": "Sihahus-sittah", "D": "suhf"}, "answer": "C", "explanation": "The six books of sound AHadith are known as sihahus_sittah.  The Kutub al-Sittah are the six (originally five) books containing collections of hadith (sayings or acts of the prophet.", "marks": "1", "difficulty": "3"}, {"id": "objective>IRK>2012>21", "subject": "IRK", "year": "2012", "type": "Objective", "topic": "SALAT : MEANING AND IMPORTANCE", "question": "The essence of prayer in islam is to", "images": [], "options": {"A": "Keep one away from lewdness", "B": "Help one to have more friends", "C": "Empower one to become a teacher", "D": "encourage one become a leader"}, "answer": "A", "explanation": "The essence of prayer in islam is to keep one away from lewdness.  a Muslim must consider Salah as an effective weapon when it comes to fighting lewdness and evils of all sorts", "marks": "1", "difficulty": "1"}, {"id": "objective>IRK>2012>22", "subject": "IRK", "year": "2012", "type": "Objective", "topic": "IMAN (FAITH) : ARTICLES OF FAITH: BELIEF IN ALLAH WITH EMPHASIS ON KALIMATUSH-SHAHADAH(Q2: 163 AND 255; 3:18;17:42-43;21: 22 ; 23: 91 Q. 112, ISLAM AND THE CONCEPT OF TRINITY (Q.4:171; 5:75 – 76; 19:92-3; 112).", "question": "The second pillar of islam is the", "images": [], "options": {"A": "Imam", "B": "Zakat", "C": "Salat", "D": "Hajj"}, "answer": "C", "explanation": "The second pillar of islam is the salat. The second Pillar of Islam is to worship God five times a day - at dawn, noon, mid-afternoon, sunset, and nightfall. To do so, the believer washes according to a particular ritual and prostrates himself or herself on the ground in the direction of Mecca, while reciting certain phrases", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2012>23", "subject": "IRK", "year": "2012", "type": "Objective", "topic": "IMAN (FAITH) : ARTICLES OF FAITH: BELIEF IN ALLAH WITH EMPHASIS ON KALIMATUSH-SHAHADAH(Q2: 163 AND 255; 3:18;17:42-43;21: 22 ; 23: 91 Q. 112, ISLAM AND THE CONCEPT OF TRINITY (Q.4:171; 5:75 – 76; 19:92-3; 112).", "question": "Prophet Ibrahim(A.S) attempt to sacrifice his son was demonstration of his", "images": [], "options": {"A": "faith and allah", "B": "love for allah", "C": "patience with Allah", "D": "Obedience of Allah"}, "answer": "D", "explanation": "Prophet Ibrahim (A.S) attempt to sacrifice his own son was demonstration of his obedience of Allah. An important Islamic religious holiday, Eid al-Adha, commemorates Abraham's willingness to sacrifice his son Ishmael as an act of obedience to God, before God intervened to provide him with a sheep to sacrifice instead.", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2012>24", "subject": "IRK", "year": "2012", "type": "Objective", "topic": "IMAN (FAITH) : ARTICLES OF FAITH: BELIEF IN ALLAH WITH EMPHASIS ON KALIMATUSH-SHAHADAH(Q2: 163 AND 255; 3:18;17:42-43;21: 22 ; 23: 91 Q. 112, ISLAM AND THE CONCEPT OF TRINITY (Q.4:171; 5:75 – 76; 19:92-3; 112).", "question": "The central theme of suratul ikhlas is", "images": [], "options": {"A": "unity of God", "B": "freedom of worship", "C": "sincerity of faith", "D": "Abundance of wealth"}, "answer": "A", "explanation": "The central theme of suratul ikhlas is unity of God.Surah Ikhlash focuses on the oneness and unity of God and that everything and everyone needs Him for their existence and their needs.", "marks": "1", "difficulty": "1"}, {"id": "objective>IRK>2012>25", "subject": "IRK", "year": "2012", "type": "Objective", "topic": "THE LIFE OF PROPHET MUHAMMAD (S.A.W.) : THEIR BIOGRAPHIES", "question": "Ali was nicknamed alHafiz because he", "images": [], "options": {"A": "Deputized for the prophet", "B": "Wrote down many Hadith", "C": "memorized the Qur'an", "D": "Fought the battle of Khandaq"}, "answer": "A", "explanation": "Ali was nicknamed al_Hafiz because he deputized for the prophet. The Shiite claim was that 'Ali was the most suitable candidate for he was the closest relative of the Prophet", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2012>26", "subject": "IRK", "year": "2012", "type": "Objective", "topic": "THE LIFE OF PROPHET MUHAMMAD (S.A.W.) : THE BATTLES: BADR, UHUD AND KHANDAQ. (CAUSES, COURSES AND EFFECTS.)", "question": "Muslims were victorious at Badr because of", "images": [], "options": {"A": "superior weaponry", "B": "support from Allah", "C": "experience warfare", "D": "proximity to madinnah"}, "answer": "B", "explanation": "Muslims were victorious at Badr because of support from Allah. This is based on Islamic belief that divine intervention played a significant role in the victory at the Battle of Badr.", "marks": "1", "difficulty": "3"}, {"id": "objective>IRK>2012>27", "subject": "IRK", "year": "2012", "type": "Objective", "topic": "THE LIFE OF PROPHET MUHAMMAD (S.A.W.) : HIJRAH", "question": "The leader of the muslim emigrants Abyssinia was", "images": [], "options": {"A": "Ali b. Abi Talib", "B": "Amr b. Al-As", "C": "Ja'far b.Abi Talib", "D": "Uthman b . Affan"}, "answer": "C", "explanation": "The leader of the muslim emigrants Abyssinia was ja'far b. Abi Talib. Muhammad Mustafa appointed his first cousin, Jaafer ibn Abi Talib, an elder brother of Ali, as the leader of this group", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2012>28", "subject": "IRK", "year": "2012", "type": "Objective", "topic": "SALAT : KINDS OF SALAT AND HOW THEY ARE OBSERVED", "question": "An example of fardul kifayah payer is salatu", "images": [], "options": {"A": "d-Duha", "B": "a-Zuha", "C": "j-janazah", "D": "t-Tawawih"}, "answer": "C", "explanation": "An example of fard_ kifayah prayer is salatu j. Janazah . When a Muslim dies, funeral prayer (Salat al- Janazah) is offered in Funeral prayer is collective obligation (Fard al-. Kifayah) on all the Muslims of the locality of the dead person", "marks": "1", "difficulty": "1"}, {"id": "objective>IRK>2012>29", "subject": "IRK", "year": "2012", "type": "Objective", "topic": "TAHARAH (PURIFICATION) : AL-WUDU’", "question": "One of the things that nulify al-wudu is", "images": [], "options": {"A": "sneezing", "B": "singing", "C": "drinking", "D": "urinating"}, "answer": "D", "explanation": "One of the thing that nullify al_Wudu is urinating, and apparently included in the ruling of urinating is the similar moisture that comes out after urinating and before performing istibrāʾ", "marks": "1", "difficulty": "1"}, {"id": "objective>IRK>2012>30", "subject": "IRK", "year": "2012", "type": "Objective", "topic": "QUR’AN : MORAL LESSONS FROM THE QUR’AN ATTITUDES TO PARENTS (Q.17 :23 – 24: 31 : 13 – 15 HONESTY IN WORDS AND DEEDS Q2: 42; 61: 2-3, 17: 35. PROHIBITION OF GAMBLING Q. 2:219:5 90-91.", "question": "Suratul isra' (Q 17:23-24) teaches", "images": [], "options": {"A": "Kindness to parents", "B": "obedience  to authority", "C": "sincerity in worship", "D": "decency in appearance"}, "answer": "A", "explanation": "Suratul isra'(Q.17:23:24) teaches the kindness to parents . child should respect and appreciate his or her parents every day throughout the year. Allah has asked human beings to recognize their parents after recognition of Allah Himself.", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2012>31", "subject": "IRK", "year": "2012", "type": "Objective", "topic": "QUR’AN : MORAL LESSONS FROM THE QUR’AN ATTITUDES TO PARENTS (Q.17 :23 – 24: 31 : 13 – 15 HONESTY IN WORDS AND DEEDS Q2: 42; 61: 2-3, 17: 35. PROHIBITION OF GAMBLING Q. 2:219:5 90-91.", "question": "A lesson From suratul Humazah is that", "images": [], "options": {"A": "Mankind should mercy to others", "B": "arrogance generally leads to destruction", "C": "one wealth is irrelevant at death", "D": "Righteousness is not based on one's origin"}, "answer": "C", "explanation": "Lesson from suratul Humazzah is that ones wealth is irrelevant  at death. Surah [Humazah] is the Consequences of man in loss. It condemns those who slander others, whether by speech or action, and imagine that their own wealth will keep them immune from death", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2012>32", "subject": "IRK", "year": "2012", "type": "Objective", "topic": "QUR’AN : READING (IN EITHER ARABIC TEXT OR TRANSLITERATION), MEMORIZATION, MEANING OF THE FOLLOWING SUWAR AND THE LESSONS LEARNT FROM THEM (IDENTIFICATION, EXPLANATION, INTERPRETATION AND APPLICATION)", "question": "Tajwid important because it", "images": [], "options": {"A": "explains the verse of the Qur'an", "B": "Ensures correct recitation of the Qur'an", "C": "Faciliate the memorization of the Qur'an", "D": "makes translation"}, "answer": "B", "explanation": "Tajwid is important because It ensures correct recitation  of the Qur'an. . The purpose of the science of Tajweed, in essence, is to make the reciter proficient in reciting the Qur'an, observing the correct pronunciation of every letter with the rulings and characteristics which apply to it", "marks": "1", "difficulty": "1"}, {"id": "objective>IRK>2012>33", "subject": "IRK", "year": "2012", "type": "Objective", "topic": "QUR’AN : READING (IN EITHER ARABIC TEXT OR TRANSLITERATION), MEMORIZATION, MEANING OF THE FOLLOWING SUWAR AND THE LESSONS LEARNT FROM THEM (IDENTIFICATION, EXPLANATION, INTERPRETATION AND APPLICATION)", "question": "Sub'ul mathani in the Quran refers to surah", "images": [], "options": {"A": "Al fatihah", "B": "at takathar", "C": "al - kawthar", "D": "an-Nas"}, "answer": "A", "explanation": "Sab,ul mathani in the Qur'an refers to surah al_fatihah. Al-Fātiḥah is the first chapter (sūrah) of the Quran. Its seven verses (āyāt) are a prayer for the guidance, lordship, and mercy of God", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2012>34", "subject": "IRK", "year": "2012", "type": "Objective", "topic": "IMAN (FAITH) : HIS PROPHETS WITH SPECIAL EMPHASIS ON THE ULU1-‘AZM: IBRAHIM, NUH, MUSA, ‘ISA.(A.S.) MUHAMMAD (S.A.W.) Q. 6: 83-87: 4: 164; 10;47;21:107;46:35 AND AHADITH RELEVANT TO THE FOREGOING.", "question": "According to the Qur'an prophet issa (A.S) was", "images": [], "options": {"A": "Crucified on the cross", "B": "raised to heaven", "C": "Given the tawrah", "D": "forgiven of his sins"}, "answer": "B", "explanation": "According to Qur'an prophet 'Issa (A.S)  was raised to heaven given. Muslims believe that Isa  did not die on the cross but Allah  raised him to heaven and he will return one day", "marks": "1", "difficulty": "3"}, {"id": "objective>IRK>2012>35", "subject": "IRK", "year": "2012", "type": "Objective", "topic": "HADITH : READING (IN EITHER THE ARABIC TEXT OR TRANSLITERATION). MEMORIZATION, MEANING OF THE FOLLOWING AHADITH AND LESSONS LEARNT FROM THEM (IDENTIFICATION, EXPLANATION, INTERPRETATION AND APPLICATION): AN-NAWAWI’S COLLECTION. 1, 5, 7, 9, 13, 15,16,18,34 AND 41.", "question": "Hadith 10 of an-Nawawi collection teaches that", "images": [], "options": {"A": "Actions a judge by intentions", "B": "Doubtful matters should be avoided", "C": "Allah accepts only that which is good", "D": "we should love our neighbour and guest is discussed in Hadith"}, "answer": "C", "explanation": "Hadith 10 of an_Nawawi's collection teaches that Allah accepts only that which is good.He does not accept but that which is pure\", the hadith refers to all good deeds. Allah does not accept any deeds that are spoilt.", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2012>36", "subject": "IRK", "year": "2012", "type": "Objective", "topic": "HADITH : READING (IN EITHER THE ARABIC TEXT OR TRANSLITERATION). MEMORIZATION, MEANING OF THE FOLLOWING AHADITH AND LESSONS LEARNT FROM THEM (IDENTIFICATION, EXPLANATION, INTERPRETATION AND APPLICATION): AN-NAWAWI’S COLLECTION. 1, 5, 7, 9, 13, 15,16,18,34 AND 41.", "question": "Good treatment of neighbours and guest is discussed in Hadith", "images": [], "options": {"A": "14th of an-Nawawi", "B": "15th of an-Nawawi", "C": "16th of an-Nawawi", "D": "17th of an-Nawawi"}, "answer": "B", "explanation": "Good treatment of neighbors and guest is discuss in hadith 15th of an_Nawawi. The meaning of the 15th hadith of Nawawi taught by Gomaa: good manners and living virtuously. ... And you should be generous to your neighbour and guest as well.", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2012>37", "subject": "IRK", "year": "2012", "type": "Objective", "topic": "SALAT : KINDS OF SALAT AND HOW THEY ARE OBSERVED", "question": "Salatul istiqa is performed when there is", "images": [], "options": {"A": "Eclipse", "B": "rainstorm", "C": "Drought", "D": "earthquake"}, "answer": "C", "explanation": "Salatul istiiqa is performed when there js drought. Prophet Muhammad, peace be upon him, traditionally offered the special Islamic prayer during times of drought.", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2012>38", "subject": "IRK", "year": "2012", "type": "Objective", "topic": "HADITH : PARTS OF THE HADITH: ‘ISNAD, MATN AND RAWI", "question": "The content of Hadith is called", "images": [], "options": {"A": "isnad", "B": "matn", "C": "musnad", "D": "sahid"}, "answer": "B", "explanation": "The content of Hadith is called matn. Matn. Content or text of a hadith report. Along with its chain of transmitters (isnad), one of the two main parts of a hadith report", "marks": "1", "difficulty": "1"}, {"id": "objective>IRK>2012>39", "subject": "IRK", "year": "2012", "type": "Objective", "topic": "NIKAH (MARRIAGE) : CONCEPT", "question": "Which of these is not right of a woman in islam", "images": [], "options": {"A": "spiritual attainment", "B": "intellectual development", "C": "Economic independence", "D": "matrimonial leadership"}, "answer": "D", "explanation": "In Islam, women have the right to spiritual attainment, intellectual development, and economic independence. However, matrimonial leadership is typically reserved for men. This is based on the Islamic principle of 'Qawwam', where men are considered the protectors and maintainers of women. This does not mean women are inferior, but it's about the distribution of roles and responsibilities within a family.", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2012>40", "subject": "IRK", "year": "2012", "type": "Objective", "topic": "SALAT : MEANING AND IMPORTANCE", "question": "The esseence of l'tikaff is to", "images": [], "options": {"A": "Redress the sin of the muslims", "B": "facilitate the memorization of the Qur'an", "C": "Derive benefit from the night of power", "D": "Assist in concentration at prayer"}, "answer": "C", "explanation": "The essence of l'tikaff is to derive benefit from the night of power. Muslims stay up every night eager to attempt the Night of Power. The Night of Decree and I' tikaf in Ramadan", "marks": "1", "difficulty": "3"}, {"id": "objective>IRK>2012>41", "subject": "IRK", "year": "2012", "type": "Objective", "topic": "IMAN (FAITH) : HIS PROPHETS WITH SPECIAL EMPHASIS ON THE ULU1-‘AZM: IBRAHIM, NUH, MUSA, ‘ISA.(A.S.) MUHAMMAD (S.A.W.) Q. 6: 83-87: 4: 164; 10;47;21:107;46:35 AND AHADITH RELEVANT TO THE FOREGOING.", "question": "Prophet Ibrahim was referred to as Khalilllulah because he is the", "images": [], "options": {"A": "Word of God", "B": "Friend of God", "C": "Spirit of God", "D": "sword of God"}, "answer": "B", "explanation": "Prophet ibrahim (A.S) is reffered to as khalliluiah because he is the friend of God. Because of the description given to Abraham in Surah 4.125, that God took him for a khalil, a friend, he is thus called Khalilullah in Islam.", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2012>42", "subject": "IRK", "year": "2012", "type": "Objective", "topic": "ZAKAT (CHARITY) : THE BENEFICIARIES OF ZAKAT (Q.9:60)", "question": "Who among the following is not entitled to zakat", "images": [], "options": {"A": "the poor", "B": "the needy", "C": "the sick", "D": "the slave"}, "answer": "C", "explanation": "The sick are not entitled to zakat.  To be eligible to receive zakat, the recipient must be poor and/or needy.", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2012>43", "subject": "IRK", "year": "2012", "type": "Objective", "topic": "IMAN (FAITH) : MEANING AND SIGNIFICANCE OF IMAN (FAITH)", "question": "Jihad as an islamic concept is to", "images": [], "options": {"A": "kill the unbeliever", "B": "Capture slaves", "C": "share the booties", "D": "Strive the Allah's way"}, "answer": "D", "explanation": "Jihad as an Islamic concept is to strive in Allah's way.  The word \"jihad\" means \"struggle\" or \"striving\" (in the way of God) or to work for a noble cause with determination.", "marks": "1", "difficulty": "3"}, {"id": "objective>IRK>2012>44", "subject": "IRK", "year": "2012", "type": "Objective", "topic": "SHARI ‘AH : SOURCES (THE QUR’AN, THE SUNNAH, THE IJMA‘ AND THE QIYAS.)", "question": "The source of shari'ah are", "images": [], "options": {"A": "Qur'an, tarikh and Hadith", "B": "Hadith , ijina and Qur'an", "C": "Hadith, Qur'an ad muwatta", "D": "Qiyas, ijina , Hidayah"}, "answer": "B", "explanation": "The source of shari'ah  are Hadith,ijina and Qur'an. Various sources of Sharia are used by Islamic jurisprudence to elaborate the body of Islamic law.", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2012>45", "subject": "IRK", "year": "2012", "type": "Objective", "topic": "THE JAHILIYYAH: ARABIA BEFORE ISLAM : RELIGIOUS LIFE – IDOL WORSHIP AND NAMES OF MAJOR GODS/IDOLS.", "question": "The following religious existed in Arabia before islam except", "images": [], "options": {"A": "Buhddisim", "B": "christianity", "C": "judaism", "D": "paganism"}, "answer": "A", "explanation": "Buddhism does not exist in Arabia before islam. Buddhism did not seem to have viewed Islam as a rival religion.", "marks": "1", "difficulty": "1"}, {"id": "objective>IRK>2012>46", "subject": "IRK", "year": "2012", "type": "Objective", "topic": "ZAKAT (CHARITY) : BENEFITS OF ZAKAT – SPIRITUAL, SOCIO-ECONOMIC AND MORAL.", "question": "Which of the following is a major function of Zakat?", "images": [], "options": {"A": "Reduction of poverty", "B": "circuation of wealth", "C": "making people happy", "D": "Display of generosity"}, "answer": "A", "explanation": "Reduction of poverty is the major function of zakat. Zakat plays an important role in reducing poverty and promotes equitable sharing of wealth.", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2012>47", "subject": "IRK", "year": "2012", "type": "Objective", "topic": "IMAN (FAITH) : MEANING AND SIGNIFICANCE OF IMAN (FAITH)", "question": "Which of the following is not a concept of islamic brotherhood?", "images": [], "options": {"A": "Promotion of self-centeredness", "B": "teaching equality among muslims", "C": "discouragement of tribalism", "D": "Spread of islamic virtues and ideals"}, "answer": "A", "explanation": "Promotion of self_centeredness is not a concept of islam brotherhood.  the brotherhood of believers with each other; which says: \"the believers are but brothers, so make settlement between your brothers. And fear Allah that you may receive mercyt", "marks": "1", "difficulty": "1"}, {"id": "objective>IRK>2012>48", "subject": "IRK", "year": "2012", "type": "Objective", "topic": "HADITH : THE SIX SOUND COLLECTIONS OF HADITH (SIHAUS-SITTAH) AND THEIR COMPILERS.", "question": "Muhammad ibn isma'il is the full name of imam", "images": [], "options": {"A": "Bukhari", "B": "Hambal", "C": "muslims", "D": "Timidhi"}, "answer": "D", "explanation": "Muhammed ibn isma'il  is the full name of imam bukhari", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2012>49", "subject": "IRK", "year": "2012", "type": "Objective", "topic": "THE LIFE OF PROPHET MUHAMMAD (S.A.W.) : THE BATTLES: BADR, UHUD AND KHANDAQ. (CAUSES, COURSES AND EFFECTS.)", "question": "The battle of ditch took place in", "images": [], "options": {"A": "610 C.E", "B": "625 C.E", "C": "627  C.E", "D": "630 C.E"}, "answer": "C", "explanation": "The battle of ditch took place in 627C.E . Battle of the Ditch, (ad 627), Arabic Al-Khandaq (The Ditch), an early Muslim victory that ultimately forced the Meccans to recognize the political and religious strength of the Muslim community in Medina.", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2012>50", "subject": "IRK", "year": "2012", "type": "Objective", "topic": "QUR’AN : REVELATION OF THE QUR’AN: VISITS OF THE PROPHET (S.A.W.) TO CAVE HIRA ; FIRST REVELATION AND HIS REACTION TO IT, DIFFERENT MODES OF REVELATION, PIECEMEAL- REVELATION OF THE QUR’AN.", "question": "Angel jibril brought revelation to the prophet (SAW) for period of", "images": [], "options": {"A": "20 years", "B": "21 years", "C": "22 years", "D": "23 years"}, "answer": "D", "explanation": "Angel jibril brought revelation to the Prophet (S.A.W) for a period of 23 years. Muhammad was meditating in a cave on Mount Hira when he saw the Angel Jibril . The angel commanded him to recite the words before him.", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2012>51", "subject": "IRK", "year": "2012", "type": "Objective", "topic": "THE KHULAFᾹ’UR-RᾹSHIDĪN (THE RIGHTLY – GUIDED CALIPHS) : THEIR CONTRIBUTIONS TO ISLAM", "question": "Amur bin ai- As. the leader of the muslims conquered Egypt during the caliphat of", "images": [], "options": {"A": "Abu-Bakr", "B": "Uthman", "C": "Umar", "D": "Ali"}, "answer": "C", "explanation": "Amr bin al_As the leader of the muslims, conquered Egypt during the caliphate of  umar.ʿAmr ibn al-ʿĀṣ al-Sahmī; c. 573 - 664) was the Arab commander who led the Muslim conquest of Egypt and served as its governor", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2012>52", "subject": "IRK", "year": "2012", "type": "Objective", "topic": "THE LIFE OF PROPHET MUHAMMAD (S.A.W.) : THE BATTLES: BADR, UHUD AND KHANDAQ. (CAUSES, COURSES AND EFFECTS.)", "question": "The last muslims expendition that was dispatched to Syria by the prophet (SAW) before his death was led by", "images": [], "options": {"A": "Ali b. Abi Talib", "B": "Khalid b.al-walid", "C": "Usmah b. Zayd", "D": "Amr b. al-As"}, "answer": "A", "explanation": "The last musilms expedition  that was dispatched to Syria by the prophet (S.A.W) before the death was led by Alu b. Abi Talibq", "marks": "1", "difficulty": "3"}, {"id": "objective>IRK>2012>53", "subject": "IRK", "year": "2012", "type": "Objective", "topic": "THE JAHILIYYAH: ARABIA BEFORE ISLAM : THE REFORMS INTRODUCED BY ISLAM ON THE JAHILIYYAH PRACTICES.", "question": "The following practices of jahilyyah were condemned by islam except", "images": [], "options": {"A": "Hospitality", "B": "Bribery and usury", "C": "tribal feud", "D": "Infanticide"}, "answer": "A", "explanation": "The  practices of jahiliyyah was condemned by islam except hospitalitystupidly.   The term jahiliyyah is derived from the verbal root jahala \"to be ignorant or stupid, to act stupidly", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2012>54", "subject": "IRK", "year": "2012", "type": "Objective", "topic": "THE JAHILIYYAH: ARABIA BEFORE ISLAM : SOCIAL LIFE – MARRIAGE, DIVORCE AND INHERITANCE.", "question": "Who among the following personalities was called the father of sociology", "images": [], "options": {"A": "A-Ghazdi", "B": "ibn sina", "C": "Ar-Razi", "D": "ibn  khaldun"}, "answer": "B", "explanation": "Ibn sina was called the father of sociology .  He is generally considered the greatest Arab historian as well as the father of sociology and the science of history.", "marks": "1", "difficulty": "3"}, {"id": "objective>IRK>2012>55", "subject": "IRK", "year": "2012", "type": "Objective", "topic": "THE KHULAFᾹ’UR-RᾹSHIDĪN (THE RIGHTLY – GUIDED CALIPHS) : THEIR BIOGRAPHIES", "question": "Uthman b. affan was referred to as Dhu Nurayan because he", "images": [], "options": {"A": "was distingusihed adminstrator", "B": "died while reading the Quran", "C": "married two daughters of the prophet", "D": "Standardized te recitation of the Qur'an"}, "answer": "C", "explanation": "Uthman b. Affan was referred to as Dhu Nurayn, which means 'the possessor of two lights', because he had the unique honor of marrying two daughters of the Prophet Muhammad, not in the same time, but after the first wife had died he married the other. None of the other options correctly explain why he was referred to as Dhu Nurayn.", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2012>56", "subject": "IRK", "year": "2012", "type": "Objective", "topic": "THE LIFE OF PROPHET MUHAMMAD (S.A.W.) : MARRIAGE", "question": "Khadijah married Muhammad (SAW) because of his", "images": [], "options": {"A": "status", "B": "Honesty", "C": "lineage", "D": "wealth"}, "answer": "B", "explanation": "Khadijah married Muhammad (SAW) because of his honesty. Muhammad (SAW) was known as Al-Amin, which means 'the trustworthy', even before his prophethood. His honesty and integrity were well recognized in Mecca, which attracted Khadijah to him. The other options do not accurately represent the main reason for Khadijah's decision to marry Muhammad (SAW).", "marks": "1", "difficulty": "1"}, {"id": "objective>IRK>2012>57", "subject": "IRK", "year": "2012", "type": "Objective", "topic": "THE LIFE OF PROPHET MUHAMMAD (S.A.W.) : THE BATTLES: BADR, UHUD AND KHANDAQ. (CAUSES, COURSES AND EFFECTS.)", "question": "The battle of Uhud was fought because the", "images": [], "options": {"A": "muslim wanted security", "B": "muslim wanted to capture makkah", "C": "Quraysh wanted to capture their territories", "D": "Quraysh wanted to take revenge"}, "answer": "D", "explanation": "The Battle of Uhud was fought because the Quraysh wanted to take revenge for their defeat in the Battle of Badr. The Quraysh, who were the dominant tribe in Mecca, were defeated by the Muslims in the Battle of Badr, which was the first major battle between the two groups. The Quraysh wanted to avenge their loss, so they attacked the Muslims at Uhud a year later.", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2012>58", "subject": "IRK", "year": "2012", "type": "Objective", "topic": "HAJJ (PILGRIMAGE) : RITES OF HAJJ", "question": "Pilgrims are required to spend the 9th day of Dhul-Hijjah at", "images": [], "options": {"A": "Makkah", "B": "muzdalifa", "C": "Arafah", "D": "madinah"}, "answer": "C", "explanation": "Pilgrims are required to spend the 9th day of Dhul_Hijjah at Arafah.On 9th Dhul Hijjah, pilgrims travel to the plains of 'Arafat, where they will combine their Dhuhr and Asr prayers", "marks": "1", "difficulty": "1"}, {"id": "objective>IRK>2012>59", "subject": "IRK", "year": "2012", "type": "Objective", "topic": "THE LIFE OF PROPHET MUHAMMAD (S.A.W.) : MARRIAGE", "question": "The prophet (SAW) married the daughter of", "images": [], "options": {"A": "Abu Bakr and Umar", "B": "Ali and Umar", "C": "Uthman and Abu-Bakr", "D": "Ali and Uthman"}, "answer": "A", "explanation": "The prophet (S A.W) married the daughters of Abu Bakr and Umar", "marks": "1", "difficulty": "1"}, {"id": "objective>IRK>2012>60", "subject": "IRK", "year": "2012", "type": "Objective", "topic": "THE JAHILIYYAH: ARABIA BEFORE ISLAM : RELIGIOUS LIFE – IDOL WORSHIP AND NAMES OF MAJOR GODS/IDOLS.", "question": "Abraha Ashram failed to accomplish his mission is Makkah because", "images": [], "options": {"A": "He rode on an elephant", "B": "of Makkah resistance", "C": "he was overpowered by swarms and fying creatures", "D": "He was friven away by th jinns and wild animals"}, "answer": "C", "explanation": "Abraha Ashram failed to accomplish his mission in Makkah because he was overpowered by the swarms and flying creatures", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2013>1", "subject": "IRK", "year": "2013", "type": "Objective", "topic": "QUR’AN : REVELATION OF THE QUR’AN: VISITS OF THE PROPHET (S.A.W.) TO CAVE HIRA ; FIRST REVELATION AND HIS REACTION TO IT, DIFFERENT MODES OF REVELATION, PIECEMEAL- REVELATION OF THE QUR’AN.", "question": "The prophet (SAW) recieved the first revelation in the month of", "images": [], "options": {"A": "Muharram", "B": "Rijab", "C": "Sha'ban", "D": "Ramadan"}, "answer": "D", "explanation": "The prophet ( S.A.W) recieved the first revelation in the month of Ramadan. It came on a night late in the sacred month of Ramadan, the night known to Muslims as Laylat-ul-Qadr, the 'Night of Decree.", "marks": "1", "difficulty": "1"}, {"id": "objective>IRK>2013>2", "subject": "IRK", "year": "2013", "type": "Objective", "topic": "IMAN (FAITH) : HIS BOOKS – Q.2: 2; 2:285; 87: 19 – 19; 5:46", "question": "Laylatul-Qadri is important because", "images": [], "options": {"A": "he fails in the month of Ramdan", "B": "prophet muhammed ascended to heaven", "C": "it was the night of Umar b. al khattab accepted islam", "D": "it was the night the revelation of the Qur'an commenced"}, "answer": "D", "explanation": "Laylatul-Qadri, also known as the Night of Power, is significant because it is believed to be the night when the first verses of the Quran were revealed to the Prophet Muhammad (SAW). This event marks the beginning of the revelation of the Quran.", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2013>3", "subject": "IRK", "year": "2013", "type": "Objective", "topic": "THE LIFE OF PROPHET MUHAMMAD (S.A.W.) : HIJRAH", "question": "An advantage of the Hijrab  to the yathrib was that", "images": [], "options": {"A": "The Qur'an was memorised  and recieved", "B": "the mekkans took into marriage some muslim women", "C": "it produced the document for governance in Makkah", "D": "it gave the prophet the needed peace to practice islam"}, "answer": "D", "explanation": "An advantage of Hijrah to Yathrib is that it gave the prophet the needed peace to practice Islam. Medina was formerly known as Yathrib.", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2013>4", "subject": "IRK", "year": "2013", "type": "Objective", "topic": "THE LIFE OF PROPHET MUHAMMAD (S.A.W.) : HIJRAH", "question": "The persecution of muslims in the 5th year of Muhammed's(SAW) mission led to their migration to", "images": [], "options": {"A": "Abyssinia", "B": "Ta'if", "C": "Syria", "D": "Madinah"}, "answer": "D", "explanation": "The prosecution of Muslims in the 5th year of Muhammad's (S.A.W) mission led to their migration to Madinah.", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2013>5", "subject": "IRK", "year": "2013", "type": "Objective", "topic": "THE LIFE OF PROPHET MUHAMMAD (S.A.W.) : BIRTH", "question": "Abdul-muttalib as prophet muhammed's(SAW)", "images": [], "options": {"A": "Uncle", "B": "nephew", "C": "cosusin", "D": "grandfather"}, "answer": "D", "explanation": "Abdul-Muttalib was the grandfather of Prophet Muhammad (SAW). He was the leader of the Quraysh tribe of Mecca and is known for his discovery of the Zamzam Well. He was the father of Abdullah, who was the father of Prophet Muhammad (SAW).", "marks": "1", "difficulty": "1"}, {"id": "objective>IRK>2013>6", "subject": "IRK", "year": "2013", "type": "Objective", "topic": "SHARI ‘AH : SOURCES (THE QUR’AN, THE SUNNAH, THE IJMA‘ AND THE QIYAS.)", "question": "The first secondary source of shari'ah is", "images": [], "options": {"A": "Ijma", "B": "sunnah", "C": "Qiyas", "D": "ijtihid"}, "answer": "A", "explanation": "The first secondary school source of Shari'ah is ijma. Ijmāʿ  is an Arabic term referring to the consensus or agreement of Islamic scholars on a point of Islamic law.", "marks": "1", "difficulty": "1"}, {"id": "objective>IRK>2013>7", "subject": "IRK", "year": "2013", "type": "Objective", "topic": "QUR’AN : READING (IN EITHER ARABIC TEXT OR TRANSLITERATION), MEMORIZATION, MEANING OF THE FOLLOWING SUWAR AND THE LESSONS LEARNT FROM THEM (IDENTIFICATION, EXPLANATION, INTERPRETATION AND APPLICATION)", "question": "The first verse Suratun-Nasr(Q.110) deals with", "images": [], "options": {"A": "judgement", "B": "death", "C": "victory", "D": "properity"}, "answer": "C", "explanation": "The first verse of suratul Nasr (Q.119) deals with victory. It states that \"When there comes the help of Allah and victory\".", "marks": "1", "difficulty": "1"}, {"id": "objective>IRK>2013>8", "subject": "IRK", "year": "2013", "type": "Objective", "topic": "SHARI ‘AH : DEFINITION", "question": "Rights of non muslims in an islamic state include the following except", "images": [], "options": {"A": "Freedom of worship", "B": "freedom of economic activities", "C": "Protection against attack", "D": "Exemption from payment of Jizya"}, "answer": "D", "explanation": "Exemption from payment of Jizya is one the rights of non- Muslim in an islamic state. Jizyah, also spelled jizya, historically, a tax (the term is often incorrectly translated as a \"head tax\" or \"poll tax\") paid by non-Muslim populations to their Muslim rulers", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2013>9", "subject": "IRK", "year": "2013", "type": "Objective", "topic": "SALAT : JOINING A CONGREGATIONAL SALAT.", "question": "A later-corner to a congregational prayer should", "images": [], "options": {"A": "join the congregation immediately", "B": "wait till congregation finishes", "C": "observe his own prayer seperately", "D": "joins in the next rak'ah"}, "answer": "A", "explanation": "In Islamic congregational prayer, if someone comes late, they should join the congregation immediately. This is because the congregational prayer is considered more virtuous than praying alone. The latecomer should then make up for the missed Rak'ahs (units of prayer) after the Imam (leader of the prayer) concludes the prayer.", "marks": "1", "difficulty": "1"}, {"id": "objective>IRK>2013>10", "subject": "IRK", "year": "2013", "type": "Objective", "topic": "QUR’AN : THE QUR’AN AS A SOURCE OF GUIDANCE IN SOCIAL, POLITICAL, SPIRITUAL AND MORAL MATTERS", "question": "Ihdnas - Siratal - mustaqim (Q 1:5) is a reference to the", "images": [], "options": {"A": "Prophethood of Muhammed", "B": "religion of islam", "C": "Holy scripture of islam", "D": "Hadith of the prophet"}, "answer": "B", "explanation": "Ihdinas- siratal - Mustaqim (Q.1: 5) is a reference to religion of Islam.  \"Ihdina's-sirata'l-mustaqim\" {Guide us on the straight path}.", "marks": "1", "difficulty": "1"}, {"id": "objective>IRK>2013>11", "subject": "IRK", "year": "2013", "type": "Objective", "topic": "HADITH : CLASSIFICATION OF HADITH: SAHIH, HASAN AND DA‘IF.", "question": "The most authentic Hadith collection is that is", "images": [], "options": {"A": "Malik b. Anas", "B": "ibn majah", "C": "an-Nasa'i", "D": "al-Bukhari"}, "answer": "D", "explanation": "The most authentic Hadith collection is Sahih al-Bukhari. It is one of the six major Hadith collections of Sunni Islam and is highly respected for the rigorous verification checks that its author, Imam Bukhari, put into place to ensure the authenticity of the Hadiths included in it.", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2013>12", "subject": "IRK", "year": "2013", "type": "Objective", "topic": "QUR’AN : REVELATION OF THE QUR’AN: VISITS OF THE PROPHET (S.A.W.) TO CAVE HIRA ; FIRST REVELATION AND HIS REACTION TO IT, DIFFERENT MODES OF REVELATION, PIECEMEAL- REVELATION OF THE QUR’AN.", "question": "The highest form of revelation to prophet is", "images": [], "options": {"A": "Wahy", "B": "Ru'ya", "C": "Risalah", "D": "kashf"}, "answer": "A", "explanation": "wahy is the highest form of revelation to prophet. Wahy is the Arabic word for revelation. In Islamic context, it refers to the revelations of God (Arabic: Allah) to his prophets, for all humankind. In Islam, the Qur'an is considered a wahy given to Muhammad.", "marks": "1", "difficulty": "3"}, {"id": "objective>IRK>2013>13", "subject": "IRK", "year": "2013", "type": "Objective", "topic": "THE LIFE OF PROPHET MUHAMMAD (S.A.W.) : HIJRAH", "question": "Prophet Muhammed (SAW) left Taif because", "images": [], "options": {"A": "Jews outnumbered the muslims", "B": "People were not interested in his message", "C": "Yahribithes had recalled him to their city", "D": "early muslims had returned to Makkah"}, "answer": "B", "explanation": "Prophet Muhammed (SAW) left Taif because the people were not interested in his message. He had gone to Taif to seek refuge and to spread the message of Islam, but the people of Taif rejected him and his message, and he was forced to leave.", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2013>14", "subject": "IRK", "year": "2013", "type": "Objective", "topic": "QUR’AN : THE QUR’AN AS A SOURCE OF GUIDANCE IN SOCIAL, POLITICAL, SPIRITUAL AND MORAL MATTERS", "question": "A feature of the Mukkah suwar is that they", "images": [], "options": {"A": "contain civil ad criminal laws", "B": "give an account battles with the Quraysh", "C": "Outline direction of rituals", "D": "Condemn the bad practices of the Jahiliyyah"}, "answer": "D", "explanation": "The Makkan suwar (chapters of the Quran revealed in Makkah) are known for their condemnation of the bad practices of the Jahiliyyah (the period of ignorance before the advent of Islam). These suwar often focused on the principles of monotheism, the afterlife, and moral and ethical issues, rather than legal matters or historical events.", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2013>15", "subject": "IRK", "year": "2013", "type": "Objective", "topic": "QUR’AN : READING (IN EITHER ARABIC TEXT OR TRANSLITERATION), MEMORIZATION, MEANING OF THE FOLLOWING SUWAR AND THE LESSONS LEARNT FROM THEM (IDENTIFICATION, EXPLANATION, INTERPRETATION AND APPLICATION)", "question": "Wala'akhiratu khayrun laka minal ida (Q, 93:3) means", "images": [], "options": {"A": "Your lord has neither forsaken you nor is he displeased with you", "B": "and the hereafter will be better for you than the present", "C": "and your lord will soon give you and you will be pleased", "D": "did he not find you an orphan and give you shelter"}, "answer": "B", "explanation": "Walal' akhiratu khayrun laka minal ula (Q 93:3) means and the Hereafter will be better for you than the present.", "marks": "1", "difficulty": "1"}, {"id": "objective>IRK>2013>16", "subject": "IRK", "year": "2013", "type": "Objective", "topic": "THE LIFE OF PROPHET MUHAMMAD (S.A.W.) : MARRIAGE", "question": "The age difference between Khadijah and Muhamed is", "images": [], "options": {"A": "6", "B": "8", "C": "15", "D": "25"}, "answer": "C", "explanation": "The age difference between khadijah and prophet  was 15 years. At the time of the marriage Muhammad was 25 years old and Khadijah was 40 years old.", "marks": "1", "difficulty": "1"}, {"id": "objective>IRK>2013>17", "subject": "IRK", "year": "2013", "type": "Objective", "topic": "THE LIFE OF PROPHET MUHAMMAD (S.A.W.) : THE FAREWELL PILGRIMAGE: DESCRIPTION, SERMON, AND ITS LESSONS.", "question": "The pilgrimage of the tenth year of Hijrah was called Haijul, Wada because it", "images": [], "options": {"A": "attrated an excpetionally large congregation", "B": "was led by the first of the orthodox caliphs", "C": "was the last one performed by the prophet (SAW)", "D": "Bought about the final revelation of the Qur'an"}, "answer": "C", "explanation": "The Farewell Pilgrimage refers to the one Hajj pilgrimage that Muhammad performed in the Islamic year 10 AH, following the Conquest of Mecca.", "marks": "1", "difficulty": "3"}, {"id": "objective>IRK>2013>18", "subject": "IRK", "year": "2013", "type": "Objective", "topic": "THE KHULAFᾹ’UR-RᾹSHIDĪN (THE RIGHTLY – GUIDED CALIPHS) : THEIR BIOGRAPHIES", "question": "Fatimah is to Muhammed as Hafsah is to", "images": [], "options": {"A": "Umar", "B": "Abu-Bakr", "C": "Uthman", "D": "Ali"}, "answer": "A", "explanation": "Fatimah is to Muhammed as Hafsah is to Umar. This is because Fatimah is the daughter of Prophet Muhammed (SAW) and Hafsah is the daughter of Umar ibn al-Khattab, the second caliph of Islam.", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2013>19", "subject": "IRK", "year": "2013", "type": "Objective", "topic": "THE LIFE OF PROPHET MUHAMMAD (S.A.W.) : LEADERSHIP QUALITIES OF THE PROPHET", "question": "Muhammed (SAW) was given the title of Amin because of his", "images": [], "options": {"A": "Patience", "B": "Humility", "C": "trustworthy", "D": "uprightness"}, "answer": "C", "explanation": "Allah made Muhammad grow in a good manner, and Allah took care of him, so he was the the best of his people in physical wellbeing and in attitude, he was the most generous, the most patient, the most truthful, the most sincere and the most honest, so his people called him al-Ameen (the trustworthy).", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2013>20", "subject": "IRK", "year": "2013", "type": "Objective", "topic": "IMAN (FAITH) : ARTICLES OF FAITH: BELIEF IN ALLAH WITH EMPHASIS ON KALIMATUSH-SHAHADAH(Q2: 163 AND 255; 3:18;17:42-43;21: 22 ; 23: 91 Q. 112, ISLAM AND THE CONCEPT OF TRINITY (Q.4:171; 5:75 – 76; 19:92-3; 112).", "question": "Kalimathah-shilasidah is important because it is", "images": [], "options": {"A": "a prayer of glorification", "B": "the means of ending a prayer", "C": "a way of greeting", "D": "the gate way of islam"}, "answer": "D", "explanation": "Kalimathah-shilasidah, also known as the Shahada, is the declaration of faith in Islam. It is the first pillar of Islam and is considered the gateway to the religion. It states 'There is no god but Allah, and Muhammad is the messenger of Allah'. This declaration is a fundamental aspect of being a Muslim and is recited by all Muslims.", "marks": "1", "difficulty": "1"}, {"id": "objective>IRK>2013>21", "subject": "IRK", "year": "2013", "type": "Objective", "topic": "THE LIFE OF PROPHET MUHAMMAD (S.A.W.) : LEADERSHIP QUALITIES OF THE PROPHET", "question": "The greatest enemy of prophet muhammed (SAW) was", "images": [], "options": {"A": "Abu-sham", "B": "Abu-lahab", "C": "ibn-Abbas", "D": "Abu-sufyae"}, "answer": "B", "explanation": "Abū Lahab  (c. 549 - 624) was Muhammad's half paternal uncle. He was one of the Meccan Quraysh leaders who opposed Muhammad and his followers and was condemned in the surah Lahab (Surah al-Massad) of the Quran for antagonizing Islam.", "marks": "1", "difficulty": "1"}, {"id": "objective>IRK>2013>22", "subject": "IRK", "year": "2013", "type": "Objective", "topic": "TAHARAH (PURIFICATION) : IMPORTANCE OF TAHARAH", "question": "The term taharah means", "images": [], "options": {"A": "Salutation", "B": "supplication", "C": "submission", "D": "purification"}, "answer": "D", "explanation": "Tahara in accordance to Islamic law is an act of purifying oneself from ritual impurity or even najis or filth until one is eligible to perform a particular ibadah for worshipping Allah i.e performing daily prayers etc. Besides purifying the body, one must also purify his/her clothes and place(s).", "marks": "1", "difficulty": "1"}, {"id": "objective>IRK>2013>23", "subject": "IRK", "year": "2013", "type": "Objective", "topic": "HADITH : DEFINITION OF HADITH AND SUNNAH", "question": "In Islamic jurispudence , Ghashd Haydah is", "images": [], "options": {"A": "Sunnah", "B": "Fard", "C": "Musatahahb", "D": "Haram"}, "answer": "B", "explanation": "- Ghusul haydah is fard in Islamic jurisprudence. Ghusl Hayd follows menstruation.", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2013>24", "subject": "IRK", "year": "2013", "type": "Objective", "topic": "QUR’AN : PRESERVATION OF THE QUR’AN: COMPLETE ARRANGEMENT INCLUDING DISTINCTION BETWEEN MAKKI AND MADANI SUWAR; RECORDING; COMPILATION; STANDARDIZATION: ROLES PLAYED BY THE COMPANIONS OF THE PROPHET (S.A.W.) IN THE PRESERVATION OF THE QUR’AN.", "question": "Compilation of the Qur'an became necessary because", "images": [], "options": {"A": "Some companionslos their copies of it", "B": "ther were dialectial difference in it reading", "C": "many memorizers of the Qur'an did in RIddah wars", "D": "different materials were used in its compilation"}, "answer": "C", "explanation": "It became necessary to compile the Quran because many of the memorizers of the Quran died in Riddah wars.", "marks": "1", "difficulty": "3"}, {"id": "objective>IRK>2013>25", "subject": "IRK", "year": "2013", "type": "Objective", "topic": "TAHARAH (PURIFICATION) : AL-GHUSL", "question": "The occasion that necessitates Ghasl al-jannah is", "images": [], "options": {"A": "Sexual intercourse", "B": "conversion to islam", "C": "child birth", "D": "menstruation"}, "answer": "A", "explanation": "Ghusul  Jannabah is performed after sexual intercourse.", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2013>26", "subject": "IRK", "year": "2013", "type": "Objective", "topic": "HADITH : PARTS OF THE HADITH: ‘ISNAD, MATN AND RAWI", "question": "The Hadith collection which is arranged according to ismad and matn is", "images": [], "options": {"A": "musannof", "B": "muwatta", "C": "musmad", "D": "mutawatr"}, "answer": "C", "explanation": "Musnad is the hadith collection which is arranged according to Isnad and Matn.", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2013>27", "subject": "IRK", "year": "2013", "type": "Objective", "topic": "QUR’AN : READING (IN EITHER ARABIC TEXT OR TRANSLITERATION), MEMORIZATION, MEANING OF THE FOLLOWING SUWAR AND THE LESSONS LEARNT FROM THEM (IDENTIFICATION, EXPLANATION, INTERPRETATION AND APPLICATION)", "question": "Allamal insana ma lam ya'lam is contained in suratul", "images": [], "options": {"A": "Hamazah", "B": "Alaq", "C": "Qari'ah", "D": "Kafiran"}, "answer": "B", "explanation": "The phrase 'Allamal insana ma lam ya'lam' is contained in Suratul Alaq. This phrase translates to 'Taught man that which he knew not' and it is from the Quran 96:5.", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2013>28", "subject": "IRK", "year": "2013", "type": "Objective", "topic": "THE LIFE OF PROPHET MUHAMMAD (S.A.W.) : FORMATION OF THE UMMAH AND THE MADINAN CONSTITUTION", "question": "The ukhuwayah initiated by the prophet (SAW) in Madinnah was significant because it", "images": [], "options": {"A": "Defined the relationship betwee the jews and the muslims", "B": "Formalize the brotherhood of Assar and the muhahijin", "C": "Made prophet muhammed (SAW) the leader of the Ummah", "D": "Sought to unite the disputing faction of the city"}, "answer": "D", "explanation": "The importance of ukhuwah initiated by the prophet ( SAW) in Madinah is that it sought to unite the dispute factions of the city.\" Ukhuwah\" Lit: Brotherhood, fraternity. Tech: The inter-relationship of Muslims in the society are regulated by a sense of 'ukhuwah. It is the basis of mutual benevolence in the society. Some of the economic relations are also governed by 'ukhuwah.", "marks": "1", "difficulty": "3"}, {"id": "objective>IRK>2013>29", "subject": "IRK", "year": "2013", "type": "Objective", "topic": "QUR’AN : READING (IN EITHER ARABIC TEXT OR TRANSLITERATION), MEMORIZATION, MEANING OF THE FOLLOWING SUWAR AND THE LESSONS LEARNT FROM THEM (IDENTIFICATION, EXPLANATION, INTERPRETATION AND APPLICATION)", "question": "The first verse of suratul-Tin(Q.95)  is transliterated  as", "images": [], "options": {"A": "watt-Tin waz Zayun", "B": "Wad-Duha wal-Layl", "C": "Watiri xinin", "D": "wawajadaka'a'ilan fa aghna"}, "answer": "A", "explanation": "The first verse of Surat At-Tin (Q.95) is 'Wat-teeni waz-zaytoon' which is translated as 'By the fig and the olive'. This is the correct transliteration of the verse from Arabic to English.", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2013>30", "subject": "IRK", "year": "2013", "type": "Objective", "topic": "THE LIFE OF PROPHET MUHAMMAD (S.A.W.) : CALL TO PROPHETHOOD", "question": "The first revelation came to the prophet (SAW) in the year", "images": [], "options": {"A": "608 C.E", "B": "609 C.E", "C": "610 C.E", "D": "611 C.E"}, "answer": "C", "explanation": "Muhammad's first revelation was an event described in Islamic tradition as taking place in 610 AD, during which the Islamic prophet, Muhammad was visited by the angel Jibrīl, known as Gabriel in English, who revealed to him the beginnings of what would later become the Qur'an.", "marks": "1", "difficulty": "1"}, {"id": "objective>IRK>2013>31", "subject": "IRK", "year": "2013", "type": "Objective", "topic": "THE LIFE OF PROPHET MUHAMMAD (S.A.W.) : THE FAREWELL PILGRIMAGE: DESCRIPTION, SERMON, AND ITS LESSONS.", "question": "'All men are from ' Adam and Hawa' and an arab is not superior ro a non- Arab ' was a declaration made", "images": [], "options": {"A": "Whe saalman al faris embraced Islam", "B": "at the palace of King Negus of Abyssinia", "C": "at the Battle of Confederates by the prophet", "D": "during the farewell sermon of the prophet"}, "answer": "A", "explanation": "Salman al-Farsi  born Roozbeh , was a companion of the Islamic prophet Muhammad and the first Persian who converted to Islam. He made the declaration that all men are from Adam and Hawa and that no Arab  is superior to a non Arab.", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2013>32", "subject": "IRK", "year": "2013", "type": "Objective", "topic": "THE JAHILIYYAH: ARABIA BEFORE ISLAM : DESCRIPTION OF ARABIA – LOCATION", "question": "The Jahiliyyah era is referred to as the days of", "images": [], "options": {"A": "light", "B": "knowledge", "C": "war", "D": "ignorance"}, "answer": "D", "explanation": "The Jahiliyyah era, also known as the Age of Ignorance, is a term used by Islamic scholars to refer to the time period in Arabia before the advent of Islam. During this time, the people of Arabia were largely polytheistic and lived in a state of ignorance about monotheism and the teachings that would later form the basis of Islam.", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2013>33", "subject": "IRK", "year": "2013", "type": "Objective", "topic": "THE KHULAFᾹ’UR-RᾹSHIDĪN (THE RIGHTLY – GUIDED CALIPHS) : THEIR CONTRIBUTIONS TO ISLAM", "question": "An advantage of Mas' aliyyah in islamic governance is that it", "images": [], "options": {"A": "ensures abstinence from alcoholic intake", "B": "checks misapplication of state funds", "C": "facilitate leadership on democratic principles", "D": "makes everyone equal before the law"}, "answer": "D", "explanation": "Al-Amanah (trusts) and al-mas'uliyyah (responsibilities) refer to the ethical character of the human character that must be practiced in daily life, especially by every Muslim. Both of these noble. It makes one equal before the law", "marks": "1", "difficulty": "3"}, {"id": "objective>IRK>2013>34", "subject": "IRK", "year": "2013", "type": "Objective", "topic": "HADITH : THE IMPORTANCE OF HADITH AND SUNNAH", "question": "Sunnh is important because it", "images": [], "options": {"A": "forms part of the revelation", "B": "is the statement of companions", "C": "is the secondary source of Shari'ah", "D": "provides guidance where the Qur'an is silent"}, "answer": "D", "explanation": "Sunnah, in Islam, refers to the practices, customs, and traditions of Prophet Muhammad. It is important because it provides guidance where the Qur'an is silent. It is considered a source of legislation and is used to interpret the Qur'an. It does form part of the revelation, but it is not the statement of companions or the secondary source of Shari'ah.", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2013>35", "subject": "IRK", "year": "2013", "type": "Objective", "topic": "THE JAHILIYYAH: ARABIA BEFORE ISLAM : RELIGIOUS LIFE – IDOL WORSHIP AND NAMES OF MAJOR GODS/IDOLS.", "question": "Which of the following was not a Jahiliyah idol?", "images": [], "options": {"A": "al-Hanif", "B": "al-lat", "C": "al-Uzzah", "D": "al-Munat"}, "answer": "A", "explanation": "Al-Hanif was not a Jahiliyah idol. Jahiliyah refers to the period of ignorance before the advent of Islam. During this time, many idols were worshipped, including al-Lat, al-Uzzah, and al-Manat. However, al-Hanif refers to an individual or group that rejected idolatry and sought monotheism. It does not refer to an idol.", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2013>36", "subject": "IRK", "year": "2013", "type": "Objective", "topic": "SALAT : MEANING AND IMPORTANCE", "question": "One of the spiritual advantages of salat is", "images": [], "options": {"A": "Closeness to Allah", "B": "unity of Muslim", "C": "promotion of good health", "D": "symathy with the poor"}, "answer": "A", "explanation": "When a person prays five times a day, he becomes accustomed to feeling the presence of God and develops the sense that Allah is watching Him at all times. He is never hidden from Allah, even when alone.", "marks": "1", "difficulty": "1"}, {"id": "objective>IRK>2013>37", "subject": "IRK", "year": "2013", "type": "Objective", "topic": "QUR’AN : READING (IN EITHER ARABIC TEXT OR TRANSLITERATION), MEMORIZATION, MEANING OF THE FOLLOWING SUWAR AND THE LESSONS LEARNT FROM THEM (IDENTIFICATION, EXPLANATION, INTERPRETATION AND APPLICATION)", "question": "The central theme of suratul- Baqarah (Q.2:2-19)", "images": [], "options": {"A": "Bribery ad corruption", "B": "adultery and forncation", "C": "alcoholism and gambling", "D": "arrongance and extravagance"}, "answer": "A", "explanation": "The discouragement of  bibery and corruption is the main theme of Suratul Baqarah ( Q 2: 219).", "marks": "1", "difficulty": "3"}, {"id": "objective>IRK>2013>38", "subject": "IRK", "year": "2013", "type": "Objective", "topic": "IMAN (FAITH) : HIS PROPHETS WITH SPECIAL EMPHASIS ON THE ULU1-‘AZM: IBRAHIM, NUH, MUSA, ‘ISA.(A.S.) MUHAMMAD (S.A.W.) Q. 6: 83-87: 4: 164; 10;47;21:107;46:35 AND AHADITH RELEVANT TO THE FOREGOING.", "question": "ibn Sina  Kitabush-shifa is a classical work on", "images": [], "options": {"A": "politics", "B": "mysticism", "C": "medicine", "D": "astronomy"}, "answer": "C", "explanation": "This work is Ibn Sina's major work on science and philosophy, and is intended to \"cure\" or \"heal\" ignorance of the soul.", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2013>39", "subject": "IRK", "year": "2013", "type": "Objective", "topic": "HADITH : THE SIX SOUND COLLECTIONS OF HADITH (SIHAUS-SITTAH) AND THEIR COMPILERS.", "question": "Hudhayfah b. yamani is noted in Islam for", "images": [], "options": {"A": "Being a delegate at Hudaybiyyah", "B": "compiling the Qur'an into a single volume", "C": "leading the muslims at the battle of Hunayn", "D": "detecting dialectical difference in Qur'an recitation"}, "answer": "C", "explanation": "Hudayfah b Yamani led the Muslims to the  battle of  Hunayn .", "marks": "1", "difficulty": "3"}, {"id": "objective>IRK>2013>40", "subject": "IRK", "year": "2013", "type": "Objective", "topic": "SHARI ‘AH : DEFINITION", "question": "The term Ghanimah is commonly used in islamic", "images": [], "options": {"A": "politics", "B": "Economy", "C": "jurisprudence", "D": "Philosophy"}, "answer": "B", "explanation": "Ghanīmah, in the early Islāmic community (7th century ad), booty taken in battle in the form of weapons, horses, prisoners, and movable goods. It is commonly used in ISLAMIC jurisprudence.", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2013>41", "subject": "IRK", "year": "2013", "type": "Objective", "topic": "SAWM (FASTING) : DEFINITION AND TYPES", "question": "Dhul-Hijjah is to Hajj as Ramadan is to", "images": [], "options": {"A": "Sa'y", "B": "I'tikaf", "C": "Iddah", "D": "Da'wah"}, "answer": "B", "explanation": "Dhul-Hijjah is the month in which the Hajj (pilgrimage) takes place in the Islamic calendar. Similarly, Ramadan is the month in which I'tikaf (seclusion in the mosque for worship) is often observed. Therefore, the analogy is that just as Dhul-Hijjah is associated with Hajj, Ramadan is associated with I'tikaf.", "marks": "1", "difficulty": "1"}, {"id": "objective>IRK>2013>42", "subject": "IRK", "year": "2013", "type": "Objective", "topic": "IMAN (FAITH) : THE DAY OF RESURRECTION, JUDGEMENT: ETERNAL LIFE Q 20: 15:32:10-20: 36: 78-70; 75: 3-13.", "question": "The day of Resurrection is called yamul-Husab because of its", "images": [], "options": {"A": "duration and numbers of angel", "B": "alternating brigthness and darkness", "C": "association with accountability", "D": "effects on those who have gone astray"}, "answer": "D", "explanation": "Yawmul Hisab -  the Day of Judgement, when Allah will decide how people will spend their afterlife. Most Muslims believe they have free will to make their own choices. They also believe that they will be judged by God for those choices. They recognise that humans are still responsible for their actions.", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2013>43", "subject": "IRK", "year": "2013", "type": "Objective", "topic": "HADITH : THE SIX SOUND COLLECTIONS OF HADITH (SIHAUS-SITTAH) AND THEIR COMPILERS.", "question": "The number of hadith examined by Imam Muslim is about", "images": [], "options": {"A": "300,000", "B": "400,000", "C": "500,000", "D": "600,000"}, "answer": "A", "explanation": "Imam Muslim ibn al-Hajjaj, the renowned Islamic scholar, is best known for his compilation of hadith called Sahih Muslim. He examined a large number of hadiths in order to select the authentic ones for his collection.    The total number of hadith examined by Imam Muslim is reported to be around 300,000 hadiths.    Imam Muslim lived in the 9th century CE (approximately 821-875 CE) and was a contemporary of Imam Bukhari. Both scholars are renowned for their meticulous approach to the collection and authentication of hadith.", "marks": "1", "difficulty": "3"}, {"id": "objective>IRK>2013>44", "subject": "IRK", "year": "2013", "type": "Objective", "topic": "THE LIFE OF PROPHET MUHAMMAD (S.A.W.) : THE FAREWELL PILGRIMAGE: DESCRIPTION, SERMON, AND ITS LESSONS.", "question": "The utternace Alayhs-salam is an an indication that the name of", "images": [], "options": {"A": "maryam , mother of jesus has been mentioned", "B": "prophet ya'qub has been mentioned", "C": "prophet muhammed has been mentioned", "D": "an orthodox caliph has been mentioned"}, "answer": "C", "explanation": "peace be upon him - The Arabic phrase ʿalayhi s-salām , which translates as \"peace be upon him\" is a conventionally complimentary phrase or durood attached to the names of the prophets in Islam. The English phrase is also given the abbreviation PBUH in English-language writing. It's an indication that a prophet name has been mentioned.", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2013>45", "subject": "IRK", "year": "2013", "type": "Objective", "topic": "HADITH : READING (IN EITHER THE ARABIC TEXT OR TRANSLITERATION). MEMORIZATION, MEANING OF THE FOLLOWING AHADITH AND LESSONS LEARNT FROM THEM (IDENTIFICATION, EXPLANATION, INTERPRETATION AND APPLICATION): AN-NAWAWI’S COLLECTION. 1, 5, 7, 9, 13, 15,16,18,34 AND 41.", "question": "Hadith  of an-Nawawi's collection centers on avoidance", "images": [], "options": {"A": "worldly things", "B": "cheating", "C": "injustice", "D": "doubtful matters"}, "answer": "D", "explanation": "In Hadith 6 of an-Nawawi's collection, the Prophet(SAW) said the lawful and unlawful are all clear, but between them are ambiguous matters.", "marks": "1", "difficulty": "3"}, {"id": "objective>IRK>2013>46", "subject": "IRK", "year": "2013", "type": "Objective", "topic": "QUR’AN : MORAL LESSONS FROM THE QUR’AN ATTITUDES TO PARENTS (Q.17 :23 – 24: 31 : 13 – 15 HONESTY IN WORDS AND DEEDS Q2: 42; 61: 2-3, 17: 35. PROHIBITION OF GAMBLING Q. 2:219:5 90-91.", "question": "A lesson that can be derived from suratul-Takatathar is that muslim shold avoid", "images": [], "options": {"A": "Unecessary argument", "B": "consumption of alchol", "C": "piling of wealth", "D": "acts of insurbordination"}, "answer": "C", "explanation": "Suratul-Takathur (Chapter of Competition in Increase) in the Quran warns against the human tendency to accumulate wealth and worldly possessions, neglecting the hereafter. The Surah teaches that Muslims should avoid the piling of wealth and instead focus on their spiritual growth and preparation for the hereafter.", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2013>47", "subject": "IRK", "year": "2013", "type": "Objective", "topic": "THE JAHILIYYAH: ARABIA BEFORE ISLAM : THE REFORMS INTRODUCED BY ISLAM ON THE JAHILIYYAH PRACTICES.", "question": "The following are correct except that", "images": [], "options": {"A": "The farewell sermon took place in 633 C.E", "B": "Ja'far participated in Hijrah to Abyssinia", "C": "Revenge for murders was prescribed in jahiliyyah", "D": "Tafsir is the commentary of the Qur'an"}, "answer": "C", "explanation": "Revenge for murder was not prescribed in the Jahiliyyah.", "marks": "1", "difficulty": "3"}, {"id": "objective>IRK>2013>48", "subject": "IRK", "year": "2013", "type": "Objective", "topic": "HADITH : READING (IN EITHER THE ARABIC TEXT OR TRANSLITERATION). MEMORIZATION, MEANING OF THE FOLLOWING AHADITH AND LESSONS LEARNT FROM THEM (IDENTIFICATION, EXPLANATION, INTERPRETATION AND APPLICATION): AN-NAWAWI’S COLLECTION. 1, 5, 7, 9, 13, 15,16,18,34 AND 41.", "question": "Hadith one of an-Nawawa's collection says thatt every man will be rewarded according to his", "images": [], "options": {"A": "Works", "B": "efforts", "C": "labour", "D": "intentions"}, "answer": "D", "explanation": "Hadith 1 : It is narrated on the authority of Amir al-Mu'minin (Leader of the Believers), Abu Hafs 'Umar bin al-Khattab MALE radi-allahu-anhu, who said: I heard the Messenger of Allah saw say: \"Surely, all actions are but driven by intentions, and verily every man shall have but that which he intended.", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2013>49", "subject": "IRK", "year": "2013", "type": "Objective", "topic": "THE LIFE OF PROPHET MUHAMMED (S.A.W.) : LEADERSHIP QUALITIES OF THE PROPHET", "question": "al-Amin is to Muhammed (SAW) as al-faruq is to", "images": [], "options": {"A": "Umar", "B": "Uthman", "C": "ABu-Bakr", "D": "Ali"}, "answer": "A", "explanation": "Al-Faruq is a title given to Umar ibn Al-Khattab, the second Caliph of the Rashidun Caliphate, following his conversion to Islam. The title 'Al-Faruq' signifies someone who distinguishes truth from falsehood.", "marks": "1", "difficulty": "1"}, {"id": "objective>IRK>2013>50", "subject": "IRK", "year": "2013", "type": "Objective", "topic": "HAJJ (PILGRIMAGE) : SIGNIFICANCE OF HAJJ (SPIRITUAL, SOCIO-ECONOMIC AND MORAL OBJECTIVES OF HAJJ.", "question": "One of the lessons of Idul-Adha is that muslims", "images": [], "options": {"A": "should dance and eat publicly", "B": "Are cautioned not to engage in human sacrifice", "C": "should know the relationship betweeb isma'il and ishaq", "D": "must embark on Pilgrimage in any of th sacred months"}, "answer": "B", "explanation": "Idul-Adha, also known as the 'Festival of Sacrifice', is one of the two official holidays in Islam. It honors the willingness of Ibrahim (Abraham) to sacrifice his son Isma'il as an act of obedience to God. However, before Abraham could sacrifice his son, God provided a lamb to sacrifice instead. In remembrance of this intervention, an animal, usually a sheep, is sacrificed ritually. One third of its meat is consumed by the family offering the sacrifice, while the rest is distributed to the poor and needy. Thus, the festival, among other things, makes a point about abhorring human sacrifice and instead giving up something of one's own to help those in need.", "marks": "1", "difficulty": "1"}, {"id": "objective>IRK>2013>51", "subject": "IRK", "year": "2013", "type": "Objective", "topic": "SALAT : KINDS OF SALAT AND HOW THEY ARE OBSERVED", "question": "Zuhr is a salat as Li'an is to", "images": [], "options": {"A": "Zakar", "B": "nikah", "C": "Talaq", "D": "Janazah"}, "answer": "C", "explanation": "In Islam Talaq means Divorce. Li'an as a mode of divorce is seldom used among the Muslim society. It involves taking an oath to avoid hudud punishment for the charge of adultery (zina).", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2013>52", "subject": "IRK", "year": "2013", "type": "Objective", "topic": "ISLAM IN WEST AFRICA : THE ADVENT AND ROLES OF TRADERS, TEACHERS, MURᾹBITUN, SUFI ORDERS, MUJADDIDUN (REFORMERS) AND HAJJ IN THE PREAD OF ISLAM.", "question": "A common activity associated with sufi practice is", "images": [], "options": {"A": "Zuwiyah", "B": "talbiyah", "C": "khutbah", "D": "Dhikr"}, "answer": "A", "explanation": "Sufi practice focuses on the renunciation of worldly things, purification of the soul and the mystical contemplation of God's nature. Followers try to get closer to God by seeking spiritual learning known as tariqa  Zuwliyah is  a common Sufi practice.", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2013>53", "subject": "IRK", "year": "2013", "type": "Objective", "topic": "ISLAM IN WEST AFRICA : THE IMPACT OF ISLAM ON THE SOCIO-POLITICAL, ECONOMIC AND LINGUISTIC LIVES OF THE PEOPLES OF ANCIENT WEST AFRICAN EMPIRES (I.E. GHANA, MALI, SHONGHAI AND KANEM- BORNO", "question": "One of the achievement of shaykh al maghili was his", "images": [], "options": {"A": "book on traditional medicine", "B": "establishment of the theology seminary", "C": "jihad against the fulbe rulers", "D": "work on good governance"}, "answer": "C", "explanation": "Jihād against Fulbe rulers is one of the achievements of Shaykh Maghili", "marks": "1", "difficulty": "3"}, {"id": "objective>IRK>2013>54", "subject": "IRK", "year": "2013", "type": "Objective", "topic": "HAJJ (PILGRIMAGE) : RITES OF HAJJ", "question": "Ramy is to Hajj as I'tidal is to", "images": [], "options": {"A": "Sodaqah", "B": "Talaq", "C": "salat", "D": "sawm"}, "answer": "C", "explanation": "I'tidal is to Salat . I'TIDAL after bowing.  I'tidal way of bowing After bowing to perfection and finished the prayer, then the rise of bowing (i'tidal). Rise time is read (SAMI'ALLAAHU Liman Hamida) is accompanied by raising both hands as time takbiratul ihrom.", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2013>55", "subject": "IRK", "year": "2013", "type": "Objective", "topic": "ISLAM IN WEST AFRICA : THE ADVENT AND ROLES OF TRADERS, TEACHERS, MURᾹBITUN, SUFI ORDERS, MUJADDIDUN (REFORMERS) AND HAJJ IN THE PREAD OF ISLAM.", "question": "The first contact of islam with Africa was in", "images": [], "options": {"A": "610 C.E", "B": "615 C.E", "C": "622 C.E", "D": "624 C.E"}, "answer": "B", "explanation": "The first contact of Islam with Africa occurred in 615 CE when a group of early Muslims fled from persecution in Makkah and migrated to Abyssinia (modern-day Ethiopia). This migration was led by Ja'far ibn Abi Talib, the cousin of the Prophet Muhammad (peace be upon him), and included approximately 80 Muslims seeking refuge under the rule of the Christian king, Negus (also known as Ashama ibn Abjar), who provided them protection.", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2013>56", "subject": "IRK", "year": "2013", "type": "Objective", "topic": "ZAKAT (CHARITY) : ARTICLES ON WHICH ZAKAT IS PAID", "question": "The tax is calculated at the rate 10% is", "images": [], "options": {"A": "ushr", "B": "khums", "C": "kharaj", "D": "Jizyr"}, "answer": "C", "explanation": "The kharaj was a land tax that was originally paid only by non-Muslims, whereas Muslims had to pay the 'ushr -- a religious tithe. Eventually however, the term kharaj comes to describe any tax paid to the Muslim authorities. It is calculated at the rate of 10 %.", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2013>57", "subject": "IRK", "year": "2013", "type": "Objective", "topic": "ZAKAT (CHARITY) : BENEFITS OF ZAKAT – SPIRITUAL, SOCIO-ECONOMIC AND MORAL.", "question": "The essence of Baytul mal is to", "images": [], "options": {"A": "Surpervise the lodgment and application", "B": "distributed alms at the ends of Ramadam", "C": "pay Imams allowance for their leadership", "D": "construct school, mosques and other public places"}, "answer": "A", "explanation": "payment of allowance to Imam for their leadership is the essence of Baytul mal. Bayt al-mal is an Arabic term that is translated as \"House of money\" or \"House of   Wealth.\"Historically, it was a financial institution responsible for the administration of taxes in Islamic states, particularly in the early Islamic Caliphate.", "marks": "1", "difficulty": "1"}, {"id": "objective>IRK>2013>58", "subject": "IRK", "year": "2013", "type": "Objective", "topic": "HADITH : THE SIX SOUND COLLECTIONS OF HADITH (SIHAUS-SITTAH) AND THEIR COMPILERS.", "question": "The Hadith collection of imam at-Itmidhi is known as", "images": [], "options": {"A": "sahih", "B": "suman", "C": "jamil", "D": "musnad"}, "answer": "C", "explanation": "The Hadith collection of Imam at-Tirmidhi is known as Jami` at-Tirmidhi. It is one of the six major Hadith collections, and was collected by Abu `Isa Muhammad ibn `Isa at-Tirmidhi. It contains roughly 4400 hadith (with repetitions) in 46 books.", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2013>59", "subject": "IRK", "year": "2013", "type": "Objective", "topic": "THE KHULAFᾹ’UR-RᾹSHIDĪN (THE RIGHTLY – GUIDED CALIPHS) : THEIR CONTRIBUTIONS TO ISLAM", "question": "A unique feature of the islamic political system under the orthodox caliphs was", "images": [], "options": {"A": "Justice and fair play", "B": "flogging of adulturers", "C": "payment of tax by all", "D": "punishment of unbelievers"}, "answer": "A", "explanation": "The unique feature of the Islamic political system under the orthodox caliphs was justice and fair play. The caliphs were known for their fair and just rule, treating everyone equally regardless of their status. This is a fundamental principle in Islamic governance, where everyone is equal in the eyes of the law and justice is served without bias.", "marks": "1", "difficulty": "3"}, {"id": "objective>IRK>2013>60", "subject": "IRK", "year": "2013", "type": "Objective", "topic": "ZAKAT (CHARITY) : THE BENEFICIARIES OF ZAKAT (Q.9:60)", "question": "The number of beneficiaries of Zakat listed in the Qur'an is", "images": [], "options": {"A": "six", "B": "eight", "C": "ten", "D": "twelve"}, "answer": "B", "explanation": "Beneficiaries of Zakat. Zakat can only be distributed to any of the eight eligible beneficiaries (asnaf) that are mentioned in the Quran in Surah Taubah:60.", "marks": "1", "difficulty": "1"}, {"id": "objective>IRK>2015>1", "subject": "IRK", "year": "2015", "type": "Objective", "topic": "THE LIFE OF PROPHET MUHAMMAD (S.A.W.) : THEIR BIOGRAPHIES", "question": "Ja'far b. Abi Talib is remembered for", "images": [], "options": {"A": "Killing hamzah the prophet uncle", "B": "being the first Mu'adhdhin of islam", "C": "accompanying the prophet of Ta'if", "D": "being the spokeman of the Muslim in Abyssinia"}, "answer": "D", "explanation": "Ja'far b. Abi Talib is remembered for being the spokesman of the Muslims in Abyssinia. When a group of Muslims migrated to Abyssinia (modern day Ethiopia) to escape persecution in Mecca, Ja'far was chosen to speak on their behalf to the Negus (king) of Abyssinia. He eloquently explained the teachings of Islam and the reasons for their migration, which led to the Negus granting them protection.", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2015>2", "subject": "IRK", "year": "2015", "type": "Objective", "topic": "THE LIFE OF PROPHET MUHAMMAD (S.A.W.) : THEIR BIOGRAPHIES", "question": "Abdallah, a scribe of the prophet was expelled from Madinnah for", "images": [], "options": {"A": "Associating with the Quraysh", "B": "Aiding the news", "C": "refusing the partake in the battle", "D": "tampering with the Qur'an"}, "answer": "A", "explanation": "Abdullah a scribe of the prophet was expelled from Medina for associating with the Quraysh. Muhammad had scribes write his revelations down for him. One scribe was `Abdullah Ibn Sa'd Ibn Abi Sarh. As Sarh wrote these revelations down, he frequently made suggestions on improving their wording. Muhammad often agreed and allowed the changes to be made. Eventually, Sarh left Islam, knowing it could not be from God if a mere scribe were allowed to change God's word. Later, after the conquest of Mecca, Muhammad ordered Sarh's death.", "marks": "1", "difficulty": "3"}, {"id": "objective>IRK>2015>3", "subject": "IRK", "year": "2015", "type": "Objective", "topic": "SAWM (FASTING) : HOW FASTING IS OBSERVED IN ISLAM", "question": "Fasting begins with sahur and ends with", "images": [], "options": {"A": "Iftar", "B": "T'tikaf", "C": "kaffarah", "D": "Zakat al-Filtr"}, "answer": "A", "explanation": "Fasting in Islam begins with Sahur (pre-dawn meal) and ends with Iftar (meal at sunset). This is a basic principle in Islamic fasting during the month of Ramadan.", "marks": "1", "difficulty": "1"}, {"id": "objective>IRK>2015>4", "subject": "IRK", "year": "2015", "type": "Objective", "topic": "SALAT : KINDS OF SALAT AND HOW THEY ARE OBSERVED", "question": "A muslim gravelling beyond fifty miles must", "images": [], "options": {"A": "shorten his prayer", "B": "provide enough for his family", "C": "Say all his salat before the journey", "D": "recite the Ma'udhatayn"}, "answer": "A", "explanation": "According to Islamic jurisprudence, a Muslim who is traveling a distance of approximately 50 miles or more has the concession to shorten his/her prayer. This is known as Qasr prayer, a part of the flexibility in Islamic law for travelers.", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2015>5", "subject": "IRK", "year": "2015", "type": "Objective", "topic": "SALAT : KINDS OF SALAT AND HOW THEY ARE OBSERVED", "question": "The magbrib prayer is observed", "images": [], "options": {"A": "Exactly by 7p.m", "B": "shortly after night fall", "C": "before the sun set", "D": "immediately after sunset"}, "answer": "D", "explanation": "The Maghrib prayer is one of the five mandatory salah (Islamic prayer). As per Islamic beliefs and practice, the Maghrib prayer is observed immediately after sunset. It is the fourth of the five daily prayers performed by practicing Muslims. The term Maghrib refers to the period just after sunset. It is not tied to a specific time, and its timing is given in relation to the sun's movement.", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2015>6", "subject": "IRK", "year": "2015", "type": "Objective", "topic": "QUR’AN : REVELATION OF THE QUR’AN: VISITS OF THE PROPHET (S.A.W.) TO CAVE HIRA ; FIRST REVELATION AND HIS REACTION TO IT, DIFFERENT MODES OF REVELATION, PIECEMEAL- REVELATION OF THE QUR’AN.", "question": "Suratul Qadr(Q.97) is associated with", "images": [], "options": {"A": "Revelation of the Qur'an", "B": "Free-will and predestination", "C": "commencement of I'tikaf", "D": "id al-fitr festivities"}, "answer": "D", "explanation": "Suratul Qadr (Q.96) is associated with Id al fitri festival.", "marks": "1", "difficulty": "3"}, {"id": "objective>IRK>2015>7", "subject": "IRK", "year": "2015", "type": "Objective", "topic": "QUR’AN : READING (IN EITHER ARABIC TEXT OR TRANSLITERATION), MEMORIZATION, MEANING OF THE FOLLOWING SUWAR AND THE LESSONS LEARNT FROM THEM (IDENTIFICATION, EXPLANATION, INTERPRETATION AND APPLICATION)", "question": "The last verse of suratul-Tin (Q.95) is transliterated as", "images": [], "options": {"A": "Alaysalallahu bi Alikamilhakmin", "B": "Fama yukadhdhibuka ba du bidin", "C": "Thumma radadna hu asfala safilin", "D": "Laqad Khlawnal insane fi ashani taqwim"}, "answer": "A", "explanation": "The last verse of Suratul-Tin (Q.95) is 'Alaysalallahu bi Alikamilhakmin'. This verse translates to 'Is not Allah the most just of judges?' in English. The other options are verses from different Surahs in the Quran.", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2015>8", "subject": "IRK", "year": "2015", "type": "Objective", "topic": "QUR’AN : READING (IN EITHER ARABIC TEXT OR TRANSLITERATION), MEMORIZATION, MEANING OF THE FOLLOWING SUWAR AND THE LESSONS LEARNT FROM THEM (IDENTIFICATION, EXPLANATION, INTERPRETATION AND APPLICATION)", "question": "Alam yajidhka yatiman fa'wa in suratul-Duha (Q.93) refers to the prophet as", "images": [], "options": {"A": "a needy", "B": "a wanderer", "C": "An orphan", "D": "a beggar"}, "answer": "C", "explanation": "The phrase 'Alam yajidhka yatiman fa'wa' in Suratul-Duha (Q.93) refers to the Prophet Muhammad as an orphan. The phrase translates to 'Did He not find you an orphan and give you refuge?' in English. The other options do not correctly interpret the meaning of this verse.", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2015>9", "subject": "IRK", "year": "2015", "type": "Objective", "topic": "ZAKAT (CHARITY) : ZAKATUL-FITR.", "question": "Kaffarah may take any of the following forms except", "images": [], "options": {"A": "Feeding of sixty people", "B": "fasting for two consecutive months", "C": "Setting a muslim slave free", "D": "reciting the Qur'an"}, "answer": "D", "explanation": "Kaffara (also romanized as Kaffarah), is a religious donation of money or food made to help those in need. Kaffara is made when someone deliberately misses a fast or breaks their fast purposefully, such as by having intercourse, or eating.It takes different forms such as feeding 60 people, fasting for two consecutive months,setting a Muslim slave free.It does not include reciting the Quran.", "marks": "1", "difficulty": "3"}, {"id": "objective>IRK>2015>10", "subject": "IRK", "year": "2015", "type": "Objective", "topic": "THE LIFE OF PROPHET MUHAMMAD (S.A.W.) : THE FAREWELL PILGRIMAGE: DESCRIPTION, SERMON, AND ITS LESSONS.", "question": "In his farewell sermon, the prophet admonished muslims to hold fast to the", "images": [], "options": {"A": "A daily parayers and the alms giving", "B": "Six articles of his faith in islam", "C": "practice of his companions", "D": "Book of Allah and his sunnah"}, "answer": "D", "explanation": "In his farewell sermon, the prophet admonished Muslims to hold fast to the Book of Allah and his ssunnah.", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2015>11", "subject": "IRK", "year": "2015", "type": "Objective", "topic": "HADITH : CLASSIFICATION OF HADITH: SAHIH, HASAN AND DA‘IF.", "question": "Bukahri is to sahih as Tirmidhi is to", "images": [], "options": {"A": "Jami", "B": "Hasan", "C": "Musnad", "D": "sunan"}, "answer": "A", "explanation": "Bukhari is to Sahih as Tirmidhi is to Jami. Sahih Bukhari and Jami` at-Tirmidhi are both collections of hadiths, sayings and actions of Prophet Muhammad. Sahih Bukhari is a collection by Imam Bukhari and is considered the most authentic book after the Quran. Jami` at-Tirmidhi is a collection by Imam Tirmidhi. The term 'Jami' refers to a comprehensive, all-encompassing collection.", "marks": "1", "difficulty": "3"}, {"id": "objective>IRK>2015>12", "subject": "IRK", "year": "2015", "type": "Objective", "topic": "HADITH : READING (IN EITHER THE ARABIC TEXT OR TRANSLITERATION). MEMORIZATION, MEANING OF THE FOLLOWING AHADITH AND LESSONS LEARNT FROM THEM (IDENTIFICATION, EXPLANATION, INTERPRETATION AND APPLICATION): AN-NAWAWI’S COLLECTION. 1, 5, 7, 9, 13, 15,16,18,34 AND 41.", "question": "Hadith 7 of an-Nawawi's collection teaches", "images": [], "options": {"A": "The pillar of Islam", "B": "the anger controlled", "C": "the religion is a source", "D": "peaceful coexistence aong people"}, "answer": "C", "explanation": "Hadith 7 of An Nawawi's collection teaches that religion is a source of good admonition", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2015>13", "subject": "IRK", "year": "2015", "type": "Objective", "topic": "THE LIFE OF PROPHET MUHAMMAD (S.A.W.) : THE BATTLES: BADR, UHUD AND KHANDAQ. (CAUSES, COURSES AND EFFECTS.)", "question": "The prophet's emissary to the jewish tribe of banu Nadir was", "images": [], "options": {"A": "Khalid b. walid", "B": "Ali b. abi-Talib", "C": "Umar b. al-khattab", "D": "Muhammad b. musaylamah"}, "answer": "D", "explanation": "Prophet's emissary to the jewish tribe of Banu Nadir was Ummar b al Kitab.", "marks": "1", "difficulty": "3"}, {"id": "objective>IRK>2015>14", "subject": "IRK", "year": "2015", "type": "Objective", "topic": "HADITH : THE SIX SOUND COLLECTIONS OF HADITH (SIHAUS-SITTAH) AND THEIR COMPILERS.", "question": "Imam muslim was born in 817 C.E at", "images": [], "options": {"A": "Nisabur", "B": "Bukhara", "C": "Khurusan", "D": "Madinah"}, "answer": "A", "explanation": "Imam Muslim was born in 817 C.E at Nisabur. Imam Muslim, also known as Muslim ibn al-Hajjaj, was a prominent Islamic scholar from the 9th century who is best known for his compilation of hadiths (sayings and actions of the Prophet Muhammad) known as Sahih Muslim, one of the six major hadith collections in Sunni Islam. He was born in the city of Nisabur in the region of Khorasan, which is in present-day Iran.", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2015>15", "subject": "IRK", "year": "2015", "type": "Objective", "topic": "THE JAHILIYYAH: ARABIA BEFORE ISLAM : RELIGIOUS LIFE – IDOL WORSHIP AND NAMES OF MAJOR GODS/IDOLS.", "question": "Which of the following is not pre-islamic deity ?", "images": [], "options": {"A": "Awf", "B": "Nasr", "C": "Husbal", "D": "Kiswah"}, "answer": "A", "explanation": "Nasr, Hubal and Kiswal are pre Islamic deity. Awf is not inclusive.", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2015>16", "subject": "IRK", "year": "2015", "type": "Objective", "topic": "THE LIFE OF PROPHET MUHAMMAD (S.A.W.) : BIRTH", "question": "Abu Iahab was so nicked named because of his", "images": [], "options": {"A": "wickedness", "B": "greatness", "C": "jealousy", "D": "Arrogance"}, "answer": "D", "explanation": "Abu lahab was so nicknamed because of his arrogance. His original name was 'Abd al-'Uzzā, but his father called him Abū Lahab (\"Father of Flame\") \"because of his beauty and charm\" due to his red (inflamed) cheeks.", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2015>17", "subject": "IRK", "year": "2015", "type": "Objective", "topic": "TALAQ ( DIVORCE) : KINDS", "question": "The following are types of divorce except", "images": [], "options": {"A": "Li'an", "B": "Faskh", "C": "Khul", "D": "Idrar"}, "answer": "D", "explanation": "The four types of divorce in Islam are Talaq (repudiation), Khul (mutual divorce), Faskh (judicial divorce) and Ila (oath not to have sexual relations). Li'an is a procedure in Islamic law for cases of denial of paternity, not a type of divorce. Idrar is not recognized as a type of divorce in Islamic law.", "marks": "1", "difficulty": "3"}, {"id": "objective>IRK>2015>18", "subject": "IRK", "year": "2015", "type": "Objective", "topic": "SALAT : KINDS OF SALAT AND HOW THEY ARE OBSERVED", "question": "A worshipper recites the Tashahhud in the posture of", "images": [], "options": {"A": "Qiyam", "B": "Ruku", "C": "Julus", "D": "sujud"}, "answer": "C", "explanation": "A worshipper recites the Tashaahud at the Julus position. The Tashahhud , also known as at-Tahiyyat , is the portion of the Muslim prayer where the person kneels or sits on the ground facing the qibla, glorifies God, and greets the messenger and the righteous people of God followed by the two testimonials. The recitation is followed by an invocation of the blessings and peace upon the prophet known as Salawat.", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2015>19", "subject": "IRK", "year": "2015", "type": "Objective", "topic": "HADITH : DEFINITION OF HADITH AND SUNNAH", "question": "The prinicple of Adalah is unique in that in guarantee", "images": [], "options": {"A": "Mutual  consultation", "B": "equality before the law", "C": "Accountability before Allah", "D": "Good human relations"}, "answer": "B", "explanation": "The principle of Adalah is unique in that it guarantees equality before the law. Adalah (\"Justice\" in Arabic) is an independent human rights organization and legal center.", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2015>20", "subject": "IRK", "year": "2015", "type": "Objective", "topic": "QUR’AN : REVELATION OF THE QUR’AN: VISITS OF THE PROPHET (S.A.W.) TO CAVE HIRA ; FIRST REVELATION AND HIS REACTION TO IT, DIFFERENT MODES OF REVELATION, PIECEMEAL- REVELATION OF THE QUR’AN.", "question": "According to suratul Alaq (Q.96:2) man was created", "images": [], "options": {"A": "From a clot", "B": "in the best of forms", "C": "from clay", "D": "as Allah's vicegerent"}, "answer": "A", "explanation": "Suratul Alaq (Q.96:2) states 'Created man, out of a (mere) clot of congealed blood'. Therefore, according to this verse, man was created from a clot.", "marks": "1", "difficulty": "1"}, {"id": "objective>IRK>2015>21", "subject": "IRK", "year": "2015", "type": "Objective", "topic": "HADITH : THE IMPORTANCE OF HADITH AND SUNNAH", "question": "The revelation of al- Qur'an started in the month", "images": [], "options": {"A": "Muharram", "B": "Rabi-Awwal", "C": "Ramadan", "D": "Dhul-Hijjah"}, "answer": "C", "explanation": "The revelation of the Qur'an started in the month of Ramadan. This is a well-known fact in Islamic history. The first revelation was sent down during Laylat al-Qadr (The Night of Power) which falls in the last ten days of Ramadan.", "marks": "1", "difficulty": "1"}, {"id": "objective>IRK>2015>22", "subject": "IRK", "year": "2015", "type": "Objective", "topic": "QUR’AN : THE QUR’AN AS A SOURCE OF GUIDANCE IN SOCIAL, POLITICAL, SPIRITUAL AND MORAL MATTERS", "question": "Surah Al-Imran (Q3:104) is an admonition on", "images": [], "options": {"A": "Piety", "B": "worship", "C": "preaching", "D": "humility"}, "answer": "C", "explanation": "Surah Al-Imran (Q3:104) is an admonition on preaching. The verse says 'Let there arise out of you a group of people inviting to all that is good (Islam), enjoining Al-Ma'ruf (i.e. Islamic Monotheism and all that Islam orders one to do) and forbidding Al-Munkar (polytheism and disbelief and all that Islam has forbidden). And it is they who are the successful.' This verse clearly talks about the importance of preaching in Islam.", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2015>23", "subject": "IRK", "year": "2015", "type": "Objective", "topic": "SALAT : KINDS OF SALAT AND HOW THEY ARE OBSERVED", "question": "Muslims perform salatul-Kusuf", "images": [], "options": {"A": "in times of drought", "B": "during an eclipse", "C": "Before burying their corpse", "D": "when a journey"}, "answer": "B", "explanation": "Salatul-Kusuf (the prayer for a solar eclipse) is performed by Muslims during a solar eclipse. It consists of two rak'ahs (units of prayer) and is usually performed in congregation. The prayer is accompanied by a special khutbah (sermon) delivered by the imam after the prayer.", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2015>24", "subject": "IRK", "year": "2015", "type": "Objective", "topic": "HADITH : READING (IN EITHER THE ARABIC TEXT OR TRANSLITERATION). MEMORIZATION, MEANING OF THE FOLLOWING AHADITH AND LESSONS LEARNT FROM THEM (IDENTIFICATION, EXPLANATION, INTERPRETATION AND APPLICATION): AN-NAWAWI’S COLLECTION. 1, 5, 7, 9, 13, 15,16,18,34 AND 41.", "question": "Falyaqul Khayram awliyasmul in Hadith 15 of an-Nawawi encourages Muslims to be", "images": [], "options": {"A": "Hardworking and prayerful", "B": "very active and resolute", "C": "simple and modest", "D": "decent utterance"}, "answer": "D", "explanation": "\"Falyaqul khayram awliyasmul\" in hadith 15 of An Nawawi encourages Muslims to make decent utterances or keep silent.", "marks": "1", "difficulty": "3"}, {"id": "objective>IRK>2015>25", "subject": "IRK", "year": "2015", "type": "Objective", "topic": "HADITH : CLASSIFICATION OF HADITH: SAHIH, HASAN AND DA‘IF.", "question": "An hadith becomes mawdu when it", "images": [], "options": {"A": "is fabicated and untrue", "B": "has relief isnad", "C": "is inferior in term of authourity", "D": "has defeats in both isnad and matn"}, "answer": "A", "explanation": "A Hadith becomes mawdu, or fabricated, when it is made up and not true. This means that the Hadith was not actually said by the Prophet Muhammad, but was falsely attributed to him. This is considered a serious offense in Islam, as it involves lying about the words of the Prophet.", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2015>26", "subject": "IRK", "year": "2015", "type": "Objective", "topic": "QUR’AN : REVELATION OF THE QUR’AN: VISITS OF THE PROPHET (S.A.W.) TO CAVE HIRA ; FIRST REVELATION AND HIS REACTION TO IT, DIFFERENT MODES OF REVELATION, PIECEMEAL- REVELATION OF THE QUR’AN.", "question": "The cave of hira is associated with the", "images": [], "options": {"A": "first revelation of the Qur'an", "B": "last verse of the Qur'an", "C": "Hijrah to madinah", "D": "battle of Khandiq"}, "answer": "C", "explanation": "The cave of hira is associated with the flight of the prophet (SAW) and his followers from Makkah to Medina.It is termed Hijrah .", "marks": "1", "difficulty": "1"}, {"id": "objective>IRK>2015>27", "subject": "IRK", "year": "2015", "type": "Objective", "topic": "THE KHULAFᾹ’UR-RᾹSHIDĪN (THE RIGHTLY – GUIDED CALIPHS) : THEIR BIOGRAPHIES", "question": "Caliph uthman b. Affan began his reign in", "images": [], "options": {"A": "632 A.D", "B": "634 A.D", "C": "644 A.D", "D": "656 A.D"}, "answer": "C", "explanation": "Caliph Uthman b. Affan began his reign in 644 A.D. He was the third Caliph of the Rashidun Caliphate, and he took over after the assassination of Umar ibn al-Khattab.", "marks": "1", "difficulty": "3"}, {"id": "objective>IRK>2015>28", "subject": "IRK", "year": "2015", "type": "Objective", "topic": "THE LIFE OF PROPHET MUHAMMAD (S.A.W.) : THE BATTLES: BADR, UHUD AND KHANDAQ. (CAUSES, COURSES AND EFFECTS.)", "question": "The battle of uhud is so named because", "images": [], "options": {"A": "uhad was a very brave soldier", "B": "it was fought on a mountain called uhud", "C": "A plague called Uhud", "D": "Muslims were victorious"}, "answer": "B", "explanation": "The Battle of Uhud is named so because it was fought on the slopes and plains of Mount Uhud, near Medina, in present-day Saudi Arabia. Therefore, the correct answer is 'it was fought on a mountain called Uhud'.", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2015>29", "subject": "IRK", "year": "2015", "type": "Objective", "topic": "IMAN (FAITH) : ARTICLES OF FAITH: BELIEF IN ALLAH WITH EMPHASIS ON KALIMATUSH-SHAHADAH(Q2: 163 AND 255; 3:18;17:42-43;21: 22 ; 23: 91 Q. 112, ISLAM AND THE CONCEPT OF TRINITY (Q.4:171; 5:75 – 76; 19:92-3; 112).", "question": "Allah is al-Alim because he is", "images": [], "options": {"A": "All knowing", "B": "The wise", "C": "The creator", "D": "All powerful"}, "answer": "A", "explanation": "In Islamic theology, Allah is referred to as 'Al-Alim' which translates to 'The All-Knowing'. This is one of the 99 names of Allah in Islam, and it signifies that Allah has complete knowledge of everything. Therefore, the correct answer is 'All knowing'.", "marks": "1", "difficulty": "1"}, {"id": "objective>IRK>2015>30", "subject": "IRK", "year": "2015", "type": "Objective", "topic": "IMAN (FAITH) : ARTICLES OF FAITH: BELIEF IN ALLAH WITH EMPHASIS ON KALIMATUSH-SHAHADAH(Q2: 163 AND 255; 3:18;17:42-43;21: 22 ; 23: 91 Q. 112, ISLAM AND THE CONCEPT OF TRINITY (Q.4:171; 5:75 – 76; 19:92-3; 112).", "question": "The First part of kalimantush-shahadah emphasizers", "images": [], "options": {"A": "Monotheism", "B": "Righteousness", "C": "Commitment", "D": "Tolerance"}, "answer": "A", "explanation": "The first part of Kalimatush -shahadah emphasizes on monotheism. Kalimatush-shahadah means testifying that there is no deity god expect Allah and that prophet Muhammad (SAW) is the messenger of Allah.", "marks": "1", "difficulty": "1"}, {"id": "objective>IRK>2015>31", "subject": "IRK", "year": "2015", "type": "Objective", "topic": "QUR’AN : READING (IN EITHER ARABIC TEXT OR TRANSLITERATION), MEMORIZATION, MEANING OF THE FOLLOWING SUWAR AND THE LESSONS LEARNT FROM THEM (IDENTIFICATION, EXPLANATION, INTERPRETATION AND APPLICATION)", "question": "Tat fif is condemned is islamic economic system because it", "images": [], "options": {"A": "is a form of gambling", "B": "can lead to financial hardship", "C": "can cause inflation", "D": "involves tricks to make money"}, "answer": "D", "explanation": "Tat fif is condemned in islamic economic system because it involves trick to make money. Tat fif is an Arabic term which means deceit and cheating in this context it means cheating and deceiving people in business transactions.", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2015>32", "subject": "IRK", "year": "2015", "type": "Objective", "topic": "THE LIFE OF PROPHET MUHAMMAD (S.A.W.) : CONQUEST OF MAKKAH", "question": "In suratul-Nasr one is reminded of the", "images": [], "options": {"A": "conquet of Makkah", "B": "Victory of Badr", "C": "Hijrah to madinah", "D": "Explusion of the jews"}, "answer": "A", "explanation": "Suratul-Nasr is the 110th chapter of the Quran. It is a Madani Surah, meaning it was revealed in Madinah. The Surah discusses the conquest of Makkah, which was a significant event in Islamic history. Therefore, the correct answer is 'conquest of Makkah'.", "marks": "1", "difficulty": "1"}, {"id": "objective>IRK>2015>33", "subject": "IRK", "year": "2015", "type": "Objective", "topic": "QUR’AN : READING (IN EITHER ARABIC TEXT OR TRANSLITERATION), MEMORIZATION, MEANING OF THE FOLLOWING SUWAR AND THE LESSONS LEARNT FROM THEM (IDENTIFICATION, EXPLANATION, INTERPRETATION AND APPLICATION)", "question": "The verse which follows Hatta zutumul maqabr in saratul-Takathur (Q:102) is", "images": [], "options": {"A": "Al-hakumut - takathur", "B": "Thustima Kalla sawfa ta lamin", "C": "Kalla sawfa ta lamim", "D": "Thuma latus almina yawna idhin anin-Na im"}, "answer": "C", "explanation": "The verse that follows hatta zurtumul maqabr in suratul Takathur is kalla sawfa ta'lamun.", "marks": "1", "difficulty": "3"}, {"id": "objective>IRK>2015>34", "subject": "IRK", "year": "2015", "type": "Objective", "topic": "QUR’AN : THE QUR’AN AS A SOURCE OF GUIDANCE IN SOCIAL, POLITICAL, SPIRITUAL AND MORAL MATTERS", "question": "The Qur'an is al-Huda because it is a", "images": [], "options": {"A": "Book", "B": "Guide", "C": "Revelation", "D": "reminder"}, "answer": "B", "explanation": "The Quran is al huda because it is a guide. Huda name meaning is right guidance, correct guidance, guidance towards good that is a muslim girl name and lucky number for Huda is one. Huda name is Arabic originated with multiple meanings.Iddah,Faskh and Mahr are relevant to divorce and marriage. Ramy is not included.", "marks": "1", "difficulty": "1"}, {"id": "objective>IRK>2015>35", "subject": "IRK", "year": "2015", "type": "Objective", "topic": "NIKAH (MARRIAGE) : CONCEPT", "question": "The following terms are relevant to marriage and divorce except", "images": [], "options": {"A": "Ramy", "B": "faskh", "C": "Iddah", "D": "Mahr"}, "answer": "A", "explanation": "In the context of marriage and divorce in Islamic law, 'Ramy' is not a relevant term. 'Ramy' refers to the ritual of throwing stones at the three pillars during the Hajj pilgrimage in Mecca. On the other hand, 'faskh' refers to judicial annulment of marriage, 'Iddah' is the waiting period a woman must observe after a divorce or the death of her husband before she can remarry, and 'Mahr' is a mandatory gift given by the groom to the bride at the time of marriage.", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2015>36", "subject": "IRK", "year": "2015", "type": "Objective", "topic": "HADITH : READING (IN EITHER THE ARABIC TEXT OR TRANSLITERATION). MEMORIZATION, MEANING OF THE FOLLOWING AHADITH AND LESSONS LEARNT FROM THEM (IDENTIFICATION, EXPLANATION, INTERPRETATION AND APPLICATION): AN-NAWAWI’S COLLECTION. 1, 5, 7, 9, 13, 15,16,18,34 AND 41.", "question": "Do not be angry is an admonition in Nawawi Hadith", "images": [], "options": {"A": "14", "B": "15", "C": "16", "D": "17"}, "answer": "C", "explanation": "\"Do not be angry\" is an admonition in hadith 16 of An Nawawi.", "marks": "1", "difficulty": "3"}, {"id": "objective>IRK>2015>37", "subject": "IRK", "year": "2015", "type": "Objective", "topic": "HADITH : THE SIX SOUND COLLECTIONS OF HADITH (SIHAUS-SITTAH) AND THEIR COMPILERS.", "question": "Who among the following is associated with sihuhus -sittah?", "images": [], "options": {"A": "Malik bu Anas", "B": "Ahmad b. Hambal", "C": "An-Nasa's", "D": "An-Nawawi"}, "answer": "C", "explanation": "Al-Ṣiḥāḥ al-Sitta  refers to 6 huge Sunni collections of hadiths. They are very reliable for Sunni Muslims and are considered as their most important religious sources after the Qur'an. They include: Sahih al-Bukhari, Sahih Muslim, Sunan Abi Dawud, Sunan Ibn Maja, Sunan al-Tirmidhi, and Sunan al-Nasa'i.", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2015>38", "subject": "IRK", "year": "2015", "type": "Objective", "topic": "THE LIFE OF PROPHET MUHAMMAD (S.A.W.) : HIJRAH", "question": "Muhammed (SAW) went to Ta'if in 620 A.D to", "images": [], "options": {"A": "Seek the support of the tribe of thaqif", "B": "contract another marriage", "C": "provide leadership for the new muslims", "D": "Meditate and pray in their vineyards"}, "answer": "A", "explanation": "Prophet Muhammad (SAW) went to Ta'if in 620 AD to reach out and seek support and shelter for amateur Muslims beyond the city of Makkah.", "marks": "1", "difficulty": "3"}, {"id": "objective>IRK>2015>39", "subject": "IRK", "year": "2015", "type": "Objective", "topic": "ISLAM IN WEST AFRICA : THE ADVENT AND ROLES OF TRADERS, TEACHERS, MURᾹBITUN, SUFI ORDERS, MUJADDIDUN (REFORMERS) AND HAJJ IN THE PREAD OF ISLAM.", "question": "The juhad of uthman Dan fodio was aimed at", "images": [], "options": {"A": "Introduction islamic reforms", "B": "protecting the fulani interest", "C": "overcoming the Habe rulers", "D": "Liberating muslims captives."}, "answer": "A", "explanation": "The jihad of Uthman Dan Fodio was primarily aimed at introducing Islamic reforms. He was a religious teacher who was dissatisfied with the syncretic practices that had crept into the Hausa states. He therefore launched a jihad to purify Islam and remove these practices. While the jihad did result in the overthrow of the Habe rulers and the establishment of the Sokoto Caliphate, this was a consequence of the jihad, not its primary aim.", "marks": "1", "difficulty": "3"}, {"id": "objective>IRK>2015>40", "subject": "IRK", "year": "2015", "type": "Objective", "topic": "IMAN (FAITH) : HIS PROPHETS WITH SPECIAL EMPHASIS ON THE ULU1-‘AZM: IBRAHIM, NUH, MUSA, ‘ISA.(A.S.) MUHAMMAD (S.A.W.) Q. 6: 83-87: 4: 164; 10;47;21:107;46:35 AND AHADITH RELEVANT TO THE FOREGOING.", "question": "The son of prophet Nuh (A.S) who perished in the flood was", "images": [], "options": {"A": "yam", "B": "salih", "C": "Sam", "D": "kan'an"}, "answer": "D", "explanation": "The Son of prophet Nuh better known as Kan'an did not believe in his father and was drowned in the Flood of Noah together with other unbelievers.", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2015>41", "subject": "IRK", "year": "2015", "type": "Objective", "topic": "HAJJ (PILGRIMAGE) : PERFORMANCE OF ‘UMRAH AND HAJJ", "question": "The sa'y  is performed", "images": [], "options": {"A": "As a kind execise for pilgrims", "B": "in memory of search for water by Hajar", "C": "to complete the work of Hajj", "D": "So that one may distance oneself from satan"}, "answer": "D", "explanation": "The sa'y is performed as a form of exercise pilgrims. Sa'y is a search. It is a movement with an aim. It is depicted by running and hurrying.", "marks": "1", "difficulty": "3"}, {"id": "objective>IRK>2015>42", "subject": "IRK", "year": "2015", "type": "Objective", "topic": "SALAT : MEANING AND IMPORTANCE", "question": "Rak'ah  is to slat as Ghanimah is to", "images": [], "options": {"A": "Baytul mal", "B": "lawhul mahfuz", "C": "Baytul izzah", "D": "sadaqatul filtr"}, "answer": "A", "explanation": "Rak'ah is to salat as Ghanimah is for Baytul mal. Bayt al-mal in Arabic term can be translated as \"House of Money\" or \"House of Wealth.\"", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2015>43", "subject": "IRK", "year": "2015", "type": "Objective", "topic": "SALAT : MEANING AND IMPORTANCE", "question": "Wha differentiates adhan from iqamah is the statement", "images": [], "options": {"A": "Allahu Akbar", "B": "Ash-hadu an Liahlaha illa Allah", "C": "Qadqamtis-salat", "D": "la ilaha Allah"}, "answer": "C", "explanation": "Adhan is the call to prayer that is recited before the prayer starts, while Iqamah is the second call to prayer that is recited just before the prayer starts. The statement that differentiates Adhan from Iqamah is 'Qadqamtis-salat', which means 'prayer has certainly been established'. This statement is only recited in Iqamah and not in Adhan.", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2015>44", "subject": "IRK", "year": "2015", "type": "Objective", "topic": "QUR’AN : REVELATION OF THE QUR’AN: VISITS OF THE PROPHET (S.A.W.) TO CAVE HIRA ; FIRST REVELATION AND HIS REACTION TO IT, DIFFERENT MODES OF REVELATION, PIECEMEAL- REVELATION OF THE QUR’AN.", "question": "Whenever the prophet recieved a revelation, he first", "images": [], "options": {"A": "reduced it to writing", "B": "instructed the scribes to memorize it", "C": "taught it to muslims", "D": "dictate it to his scribes"}, "answer": "C", "explanation": "Whenever the Prophet received a revelation, he would first memorize it himself and later declare the revelation and instruct his Companions (R.A).", "marks": "1", "difficulty": "3"}, {"id": "objective>IRK>2015>45", "subject": "IRK", "year": "2015", "type": "Objective", "topic": "QUR’AN : THE QUR’AN AS A SOURCE OF GUIDANCE IN SOCIAL, POLITICAL, SPIRITUAL AND MORAL MATTERS", "question": "Sarutul kafirun tals about freedom of", "images": [], "options": {"A": "Association", "B": "movement", "C": "Worship", "D": "Expression"}, "answer": "C", "explanation": "Suratul Kafirun, also known as Chapter of the Disbelievers, talks about freedom of worship. It emphasizes the Islamic principle of 'no compulsion in religion', allowing everyone the freedom to choose and practice their own faith.", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2015>46", "subject": "IRK", "year": "2015", "type": "Objective", "topic": "QUR’AN : PRESERVATION OF THE QUR’AN: COMPLETE ARRANGEMENT INCLUDING DISTINCTION BETWEEN MAKKI AND MADANI SUWAR; RECORDING; COMPILATION; STANDARDIZATION: ROLES PLAYED BY THE COMPANIONS OF THE PROPHET (S.A.W.) IN THE PRESERVATION OF THE QUR’AN.", "question": "When the Qur'an is divided into sixty parts, each is called", "images": [], "options": {"A": "Ayah", "B": "Surah", "C": "Juz", "D": "Hizb"}, "answer": "C", "explanation": "The Qur'an is divided into 60 parts, each of which is called a Juz. This division is used to make it easier for Muslims to read the Qur'an during the month of Ramadan, with one Juz read each night.", "marks": "1", "difficulty": "1"}, {"id": "objective>IRK>2015>47", "subject": "IRK", "year": "2015", "type": "Objective", "topic": "IMAN (FAITH) : ARTICLES OF FAITH: BELIEF IN ALLAH WITH EMPHASIS ON KALIMATUSH-SHAHADAH(Q2: 163 AND 255; 3:18;17:42-43;21: 22 ; 23: 91 Q. 112, ISLAM AND THE CONCEPT OF TRINITY (Q.4:171; 5:75 – 76; 19:92-3; 112).", "question": "The pronouncement of Kalimatush -shahadah makes a person", "images": [], "options": {"A": "mushin", "B": "Alim", "C": "muslim", "D": "Abid"}, "answer": "C", "explanation": "The pronouncement of Kalimatush-shahadah, which is the declaration of faith in Islam, makes a person a Muslim. It is one of the Five Pillars of Islam and states 'There is no god but Allah, and Muhammad is the messenger of Allah'.", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2015>48", "subject": "IRK", "year": "2015", "type": "Objective", "topic": "HADITH : THE SIX SOUND COLLECTIONS OF HADITH (SIHAUS-SITTAH) AND THEIR COMPILERS.", "question": "The full name of Imam al- Tirmidhi is", "images": [], "options": {"A": "Abdul-hasayn al-hajj al Qushayri", "B": "Muhammad b. Isna ilAbu Abdullah al-jufi", "C": "Abu isa Muhammad b. isa b. sarwa", "D": "Abu Zakaryya b. isa"}, "answer": "C", "explanation": "Imam al-Tirmidhi's full name is Abu Isa Muhammad b. Isa b. Sarwa. He was a Persian Islamic scholar and collector of Hadith who wrote al-Jami` as-Sahih, one of the six canonical hadith compilations in Sunni Islam.", "marks": "1", "difficulty": "3"}, {"id": "objective>IRK>2015>49", "subject": "IRK", "year": "2015", "type": "Objective", "topic": "HADITH : READING (IN EITHER THE ARABIC TEXT OR TRANSLITERATION). MEMORIZATION, MEANING OF THE FOLLOWING AHADITH AND LESSONS LEARNT FROM THEM (IDENTIFICATION, EXPLANATION, INTERPRETATION AND APPLICATION): AN-NAWAWI’S COLLECTION. 1, 5, 7, 9, 13, 15,16,18,34 AND 41.", "question": "An-Nawawis Hadith 15 states that we", "images": [], "options": {"A": "shall be accountable to Allah on the last day", "B": "Should do unto other as we expect from them", "C": "should steadfast at prayer", "D": "should declare an intention before any action"}, "answer": "A", "explanation": "An Nawawi hadith 15 states  that we shall be accountable to Allah on the day of judgement.", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2015>50", "subject": "IRK", "year": "2015", "type": "Objective", "topic": "THE KHULAFᾹ’UR-RᾹSHIDĪN (THE RIGHTLY – GUIDED CALIPHS) : THEIR CONTRIBUTIONS TO ISLAM", "question": "The greatest contribution of ar-Razi to learning is in", "images": [], "options": {"A": "History", "B": "geography", "C": "medicine", "D": "Linguistics"}, "answer": "C", "explanation": "The greatest contribution of ar razi to learning is in medicine. al-Razi (ca. 865-925), also known as Rhazes, prepared compilations that were influential in Western medicine for centuries.", "marks": "1", "difficulty": "3"}, {"id": "objective>IRK>2016>1", "subject": "IRK", "year": "2016", "type": "Objective", "topic": "QUR’AN : PRESERVATION OF THE QUR’AN: COMPLETE ARRANGEMENT INCLUDING DISTINCTION BETWEEN MAKKI AND MADANI SUWAR; RECORDING; COMPILATION; STANDARDIZATION: ROLES PLAYED BY THE COMPANIONS OF THE PROPHET (S.A.W.) IN THE PRESERVATION OF THE QUR’AN.", "question": "The Mufassir is different from the Hafiz because the former", "images": [], "options": {"A": "records the Qur'an", "B": "Interprets the Qur'an", "C": "Memorizes th Qur'an", "D": "teaches the Qur'an"}, "answer": "B", "explanation": "The Mufassir is different from the Hafiz because it interpret the Qur'an. The Mufassir basically interprets the Quran and the duty of the Hafiz is to memorize the Quran, he helps to preserve the Quran.", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2016>2", "subject": "IRK", "year": "2016", "type": "Objective", "topic": "QUR’AN : THE QUR’AN AS A SOURCE OF GUIDANCE IN SOCIAL, POLITICAL, SPIRITUAL AND MORAL MATTERS", "question": "According to Qur'an 43:3 th revelation of the Qur'an in Arabic is to", "images": [], "options": {"A": "Enable the prophet understand it", "B": "Distinguish it from other revealed books", "C": "make popular the language of the prophet", "D": "restrict it in-depth understanding to the Arabs"}, "answer": "A", "explanation": "According to Qur'an 43:3 the revelation of the Qur'an in Arabic is to enable the prophet understand  it. The Quran was revealed in Arabic in order for the prophet to be able to understand it, as that was his native language.", "marks": "1", "difficulty": "3"}, {"id": "objective>IRK>2016>3", "subject": "IRK", "year": "2016", "type": "Objective", "topic": "THE KHULAFᾹ’UR-RᾹSHIDĪN (THE RIGHTLY – GUIDED CALIPHS) : THEIR BIOGRAPHIES", "question": "Anbiya is to musa (AS) as khulafaur-Rashidun is to", "images": [], "options": {"A": "Umar b. AbdulAzeez", "B": "Uthman b. Affan", "C": "Harun ar-Rashid", "D": "Abdullahi b. Umar"}, "answer": "B", "explanation": "Anabiya is to Musa (AS) as khulafaur_Rashidun is to Uthman b. Affan .  The Rashidun Caliphate was once headed by Uthman b. Affan.", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2016>4", "subject": "IRK", "year": "2016", "type": "Objective", "topic": "HAJJ (PILGRIMAGE) : RITES OF HAJJ", "question": "The hastening between safa and marwah reminds pilgrims of", "images": [], "options": {"A": "Khadijah", "B": "Aminah", "C": "Hajar", "D": "Aishah"}, "answer": "C", "explanation": "The hastening between safa and marwah reminds pilgrims of Hajar.  Muslims walk between the two mountains (called Sa'ee), which they believe was made a ritual as a tribute to Hajar's search for water in the area when she ran out of provisions after Ibrahim left her in the valley upon Allah's command. The space between the two mountains in which the pilgrims walk is called al-Mas'aa.", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2016>5", "subject": "IRK", "year": "2016", "type": "Objective", "topic": "THE LIFE OF PROPHET MUHAMMAD (S.A.W.) : BIRTH", "question": "Abu-Tablib died when the prophet (SAW) attained the age of", "images": [], "options": {"A": "25", "B": "40", "C": "45", "D": "49"}, "answer": "D", "explanation": "Abu Talib, the uncle and protector of Prophet Muhammad (SAW), died when the Prophet was 49 years old. This year is known in Islamic history as the 'Year of Sorrow' as the Prophet's wife Khadijah also died in the same year.", "marks": "1", "difficulty": "1"}, {"id": "objective>IRK>2016>6", "subject": "IRK", "year": "2016", "type": "Objective", "topic": "SALAT : KINDS OF SALAT AND HOW THEY ARE OBSERVED", "question": "The phrase ''Sami'a Allahu Iiman Hamidah is recited in", "images": [], "options": {"A": "Sujud", "B": "Roku", "C": "I'tidal", "D": "Jalsah"}, "answer": "C", "explanation": "The phrase 'Sami'a Allahu Iiman Hamidah' is recited in I'tidal. I'tidal is the standing position in the prayer (Salah) after the bowing position (Ruku). This phrase is said when moving from the bowing position to the standing position, and it means 'Allah hears whoever praises Him'.", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2016>7", "subject": "IRK", "year": "2016", "type": "Objective", "topic": "IMAN (FAITH) : HIS PROPHETS WITH SPECIAL EMPHASIS ON THE ULU1-‘AZM: IBRAHIM, NUH, MUSA, ‘ISA.(A.S.) MUHAMMAD (S.A.W.) Q. 6: 83-87: 4: 164; 10;47;21:107;46:35 AND AHADITH RELEVANT TO THE FOREGOING.", "question": "Muslims should believe in Allah's prophets because by implication, they", "images": [], "options": {"A": "Were raised from different communities", "B": "are mentioned in the Qur'an", "C": "are to be imitated as role models", "D": "Recieved revelation as a sign of honour"}, "answer": "C", "explanation": "Muslims should believe in Allah's prophets because by implication, they are to be role models.", "marks": "1", "difficulty": "3"}, {"id": "objective>IRK>2016>8", "subject": "IRK", "year": "2016", "type": "Objective", "topic": "QUR’AN : REVELATION OF THE QUR’AN: VISITS OF THE PROPHET (S.A.W.) TO CAVE HIRA ; FIRST REVELATION AND HIS REACTION TO IT, DIFFERENT MODES OF REVELATION, PIECEMEAL- REVELATION OF THE QUR’AN.", "question": "The first revelation to prophet can be found in saratul", "images": [], "options": {"A": "Ikhlas", "B": "Alaq", "C": "inshirah", "D": "Fatihah"}, "answer": "B", "explanation": "The first revelation to the prophet can be found in suratul Alaq . This was the first Surah which was revealed by Allah and signified the beginning of his Prophethood. At the time it was revealed the Angel Jibreel commanded him to read this Surah but Prophet Muhammad (ﷺ) was illiterate and could neither read or write.Bukhari and Muslim compiled the sahihayn traditions", "marks": "1", "difficulty": "1"}, {"id": "objective>IRK>2016>9", "subject": "IRK", "year": "2016", "type": "Objective", "topic": "HADITH : THE SIX SOUND COLLECTIONS OF HADITH (SIHAUS-SITTAH) AND THEIR COMPILERS.", "question": "Which of the following traditional complied the sahihayn", "images": [], "options": {"A": "Abu Daud and Ibn Majah", "B": "Tirmidhi and an-Nasa'i", "C": "Bukhari and muslim", "D": "Malik and ibn Hanbal"}, "answer": "C", "explanation": "Bukari and Muslim compiled the Sahihayn. It is commonly described as \"Sahihayn of the Bukhari and Muslim\".", "marks": "1", "difficulty": "3"}, {"id": "objective>IRK>2016>10", "subject": "IRK", "year": "2016", "type": "Objective", "topic": "THE KHULAFᾹ’UR-RᾹSHIDĪN (THE RIGHTLY – GUIDED CALIPHS) : THEIR BIOGRAPHIES", "question": "The title as-sidiq is associated with", "images": [], "options": {"A": "Ali b. Talib", "B": "Abdall,ah b.Umar", "C": "Abu Bakr b. Abi Quhhafah", "D": "Uthman b.Affan"}, "answer": "C", "explanation": "The title as-sidiq was given to Abu Bakr due to his unwavering faith and truthfulness. He was the first adult male to accept Islam and was a close companion of the Prophet Muhammad.", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2016>11", "subject": "IRK", "year": "2016", "type": "Objective", "topic": "QUR’AN : MORAL LESSONS FROM THE QUR’AN ATTITUDES TO PARENTS (Q.17 :23 – 24: 31 : 13 – 15 HONESTY IN WORDS AND DEEDS Q2: 42; 61: 2-3, 17: 35. PROHIBITION OF GAMBLING Q. 2:219:5 90-91.", "question": "The following can be deducted from al-fathah except that is", "images": [], "options": {"A": "Summaries the Qur'an as a whole", "B": "Magnifies Allah by Indicating his Oneness", "C": "Unfolds the Fundamentals principles", "D": "extols the attributes of the divine being"}, "answer": "D", "explanation": "Al-Fatiha entails the following:  -\tIt summarizes the Quran  -\tIt magnifies Allah by indicating His oneness  -It unfolds the fundamental principles of Faith", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2016>12", "subject": "IRK", "year": "2016", "type": "Objective", "topic": "THE LIFE OF PROPHET MUHAMMAD (S.A.W.) : THE BATTLES: BADR, UHUD AND KHANDAQ. (CAUSES, COURSES AND EFFECTS.)", "question": "Which of the following lessons can be derived from the battle of Badr?", "images": [], "options": {"A": "Ethnic solidarity", "B": "Strength is derived", "C": "Retreat when necessary", "D": "Love and wealth"}, "answer": "B", "explanation": "Battle of Badr, (624 CE), in Islamic history, major military victory led by the Prophet Muhammad that marked a turning point for the early Muslim community (ummah) from a defensive stance toward one of stability and expansion. The battle damaged Meccan trade and boosted the morale of the ummah as a viable force in its pursuit of control of the holy city. The prestige of the battle in the Islamic consciousness is marked by the fact that it is the only battle mentioned by name in the Qurʾān. Strength is a key denominator derived from this battle", "marks": "1", "difficulty": "3"}, {"id": "objective>IRK>2016>13", "subject": "IRK", "year": "2016", "type": "Objective", "topic": "ZAKAT (CHARITY) : ARTICLES ON WHICH ZAKAT IS PAID", "question": "The Zakat payable on 10 million dollars is", "images": [], "options": {"A": "$250,000", "B": "$200,000", "C": "$150,000", "D": "$50,000"}, "answer": "A", "explanation": "The zakat payable on 10 million dollars is $250,000.  The amount of zakat paid on capital assets (e.g. money) and stock-in-trade and jewelry is customarily 2.5% (1/40)", "marks": "1", "difficulty": "3"}, {"id": "objective>IRK>2016>14", "subject": "IRK", "year": "2016", "type": "Objective", "topic": "THE KHULAFᾹ’UR-RᾹSHIDĪN (THE RIGHTLY – GUIDED CALIPHS) : THEIR BIOGRAPHIES", "question": "The following participate in the battle of camel except", "images": [], "options": {"A": "Talha", "B": "Zubayr", "C": "Aishah", "D": "Abu Bakr"}, "answer": "D", "explanation": "Abu Bakr didn't  participate in the battle of camel.   Abu Bakr Siddiq (R.A.), popularly known as Abu Bakr, is the ﬁrst Caliph after the Prophet Mohammad (S.A.W.). His full name is Abdullah bin Abu Quhafah Uthman bin Aamer Al Qurashi Al Taymi.", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2016>15", "subject": "IRK", "year": "2016", "type": "Objective", "topic": "HADITH : READING (IN EITHER THE ARABIC TEXT OR TRANSLITERATION). MEMORIZATION, MEANING OF THE FOLLOWING AHADITH AND LESSONS LEARNT FROM THEM (IDENTIFICATION, EXPLANATION, INTERPRETATION AND APPLICATION): AN-NAWAWI’S COLLECTION. 1, 5, 7, 9, 13, 15,16,18,34 AND 41.", "question": "Religion is sincerity is part of an-Nawawi's Hadith", "images": [], "options": {"A": "5", "B": "7", "C": "9", "D": "10"}, "answer": "B", "explanation": "The Hadith 'Religion is sincerity' is part of an-Nawawi's collection of 40 Hadiths. However, it is the 7th Hadith in this collection. An-Nawawi's collection is a compilation of forty-two hadiths by Imam al-Nawawi, most of which are from Sahih Muslim and Sahih al-Bukhari. This collection is the most popular anthology and the best introduction to the study of the Prophet's sayings which, together with the Qur'an, contain the essential teachings of Islam.", "marks": "1", "difficulty": "1"}, {"id": "objective>IRK>2016>16", "subject": "IRK", "year": "2016", "type": "Objective", "topic": "TALAQ ( DIVORCE) : IDDATUT-TALAQ (WAITING PERIOD FOR A DIVORCED WOMAN): MEANING, DURATION AND IMPLICATION.", "question": "The confinement period of a muslim woman", "images": [], "options": {"A": "Khul", "B": "Iddah", "C": "Faskh", "D": "Ila"}, "answer": "B", "explanation": "The confinement period of a Muslim woman is Iddah . The literal meaning of Iddah is to keep count. In Islamic legal terminology, it is the period after her husband's demise, in which the woman has been instructed to refrain from getting married again. During this period, she is to avoid going out or making adornment on her body amongst other restrictions.", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2016>17", "subject": "IRK", "year": "2016", "type": "Objective", "topic": "TALAQ ( DIVORCE) : ISLAM’S ATTITUDE (Q.4: 35)", "question": "Which of the following is discouraged by islam", "images": [], "options": {"A": "Polygamy", "B": "monogamy", "C": "Divorce", "D": "Bigamy"}, "answer": "D", "explanation": "Bigamy is discouraged by islam. However, it is clearly stated that the man should be capable of taking responsibilities of the wives", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2016>18", "subject": "IRK", "year": "2016", "type": "Objective", "topic": "QUR’AN : PRESERVATION OF THE QUR’AN: COMPLETE ARRANGEMENT INCLUDING DISTINCTION BETWEEN MAKKI AND MADANI SUWAR; RECORDING; COMPILATION; STANDARDIZATION: ROLES PLAYED BY THE COMPANIONS OF THE PROPHET (S.A.W.) IN THE PRESERVATION OF THE QUR’AN.", "question": "Of the 114 chapter in the Qur'an maakan suwar are", "images": [], "options": {"A": "21", "B": "90", "C": "91", "D": "93"}, "answer": "D", "explanation": "Of the 114 chapters in the Qur'an , makkah surah are 21. There are 21 surahs in the second Meccan period.", "marks": "1", "difficulty": "3"}, {"id": "objective>IRK>2016>19", "subject": "IRK", "year": "2016", "type": "Objective", "topic": "HAJJ (PILGRIMAGE) : SIGNIFICANCE OF HAJJ (SPIRITUAL, SOCIO-ECONOMIC AND MORAL OBJECTIVES OF HAJJ.", "question": "The ZamZam is beneficial to pilgrims because it", "images": [], "options": {"A": "is very close to the ka'bah", "B": "shelter them from sunshine", "C": "has curative properties", "D": "squenches their thirst"}, "answer": "C", "explanation": "The ramzam is beneficial to pilgrims because it has curative properties.    Aside from being one of the most important rites of passage in Islam, Hajj and Umrah are wonderful pilgrimage experiences that enable visitors to discover the hidden secrets and beautiful locations of the holy city of Makkah in Saudi Arabia. One of the most astonishing features of the city is the Zamzam Well located within the Masjid Al Haram, a mere 20 metres east of the holy Kaaba.            It should be noted that Zamzam Water enhances energy levels in our cells", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2016>20", "subject": "IRK", "year": "2016", "type": "Objective", "topic": "QUR’AN : THE QUR’AN AS A SOURCE OF GUIDANCE IN SOCIAL, POLITICAL, SPIRITUAL AND MORAL MATTERS", "question": "At-Tamzil is another is another name of the Qur'an which means the", "images": [], "options": {"A": "Revelation", "B": "Guide", "C": "light", "D": "book"}, "answer": "C", "explanation": "Al_Tamzil is another name of the Qur'an which means the light.", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2016>21", "subject": "IRK", "year": "2016", "type": "Objective", "topic": "SHIRK : WORSHIP OF IDOLS (Q.4:48:22:31:31:13:41:37)", "question": "Allah forgive not that partners should be set up with him (Q4:48)centre on", "images": [], "options": {"A": "al-Taqwah", "B": "al-Tijarah", "C": "al-tawhid", "D": "al-ihsan"}, "answer": "A", "explanation": "Allah forgives not that partners should be set up with him (Q 4:48) centre on al_Taqwah   \"Indeed, Allah does not forgive associating others with Him ˹in worship\" - is the first part of this portion of the Quran.", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2016>22", "subject": "IRK", "year": "2016", "type": "Objective", "topic": "SHARI ‘AH : SOURCES (THE QUR’AN, THE SUNNAH, THE IJMA‘ AND THE QIYAS.)", "question": "The fourth source of shari'ah is", "images": [], "options": {"A": "Qiyas", "B": "sinnah", "C": "Ijihad", "D": "ijma"}, "answer": "A", "explanation": "The fourth source of Shari'ah is Qiyas. Shari'ah, the Islamic law, is derived from four main sources: the Quran, the Hadith (sayings and actions of Prophet Muhammad), Ijma (consensus of scholars), and Qiyas (analogical reasoning). Qiyas is used when an issue cannot be resolved through the first three sources. It involves applying the ruling of a known case to a new case because the latter has the same effective cause as the former.", "marks": "1", "difficulty": "1"}, {"id": "objective>IRK>2016>23", "subject": "IRK", "year": "2016", "type": "Objective", "topic": "THE KHULAFᾹ’UR-RᾹSHIDĪN (THE RIGHTLY – GUIDED CALIPHS) : THEIR BIOGRAPHIES", "question": "The caliphate of Ali b. Abi Talib began in june", "images": [], "options": {"A": "656 C.E", "B": "644 C.E", "C": "634 C.E", "D": "632 C.E"}, "answer": "A", "explanation": "The caliphate of \"Ali b. Abi Talib began  in june 656 C.E   Ali ibn Abi Talib ( 13 September 601 - 29 January 661) was a cousin and son-in-law of the Islamic prophet Muhammad, who ruled as the fourth caliph from 656 to 661.", "marks": "1", "difficulty": "3"}, {"id": "objective>IRK>2016>24", "subject": "IRK", "year": "2016", "type": "Objective", "topic": "IMAN (FAITH) : HIS ANGELS – Q 2: 285; 8:50; 16: 2; 66: 6 ; 82: 10 – 12.", "question": "Angels of Allah were created from", "images": [], "options": {"A": "water", "B": "fire", "C": "clay", "D": "light"}, "answer": "D", "explanation": "Angels of Allah were created from light.  The Angels were created from light, as is reported in a Hadith that Allah created the angels from light and He created the devils from fire and He created the humans from dirt.", "marks": "1", "difficulty": "1"}, {"id": "objective>IRK>2016>25", "subject": "IRK", "year": "2016", "type": "Objective", "topic": "QUR’AN : READING (IN EITHER ARABIC TEXT OR TRANSLITERATION), MEMORIZATION, MEANING OF THE FOLLOWING SUWAR AND THE LESSONS LEARNT FROM THEM (IDENTIFICATION, EXPLANATION, INTERPRETATION AND APPLICATION)", "question": "The word that differentiates verse 4 of suratul inshirah (Q.94) from verse 5 is", "images": [], "options": {"A": "Thuma", "B": "Wa", "C": "inna", "D": "fa"}, "answer": "D", "explanation": "The word that differentiate verse 4 of suratul  inshirah (Q.94) from verse 5 is fa.", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2016>26", "subject": "IRK", "year": "2016", "type": "Objective", "topic": "QUR’AN : READING (IN EITHER ARABIC TEXT OR TRANSLITERATION), MEMORIZATION, MEANING OF THE FOLLOWING SUWAR AND THE LESSONS LEARNT FROM THEM (IDENTIFICATION, EXPLANATION, INTERPRETATION AND APPLICATION)", "question": "The Qur'anic equivalent of prophet solomon is", "images": [], "options": {"A": "Ayyab", "B": "Ibrahim", "C": "Yusuf", "D": "Sulayman"}, "answer": "D", "explanation": "The Qur'anic equivalent of Prophet Solomon is Sulayman. In the Qur'an, Prophet Solomon is referred to as Sulayman. He is a significant figure in the Qur'an, being a prophet and a king with a kingdom which included jinn (genies), humans, and birds.", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2016>27", "subject": "IRK", "year": "2016", "type": "Objective", "topic": "HADITH : READING (IN EITHER THE ARABIC TEXT OR TRANSLITERATION). MEMORIZATION, MEANING OF THE FOLLOWING AHADITH AND LESSONS LEARNT FROM THEM (IDENTIFICATION, EXPLANATION, INTERPRETATION AND APPLICATION): AN-NAWAWI’S COLLECTION. 1, 5, 7, 9, 13, 15,16,18,34 AND 41.", "question": "Hadith 34 of an-Nawawi corroborates Qur'an", "images": [], "options": {"A": "3:104", "B": "2:177", "C": "3:102", "D": "2:255"}, "answer": "B", "explanation": "Hadith 34 of an-Nawawi corroborates Qur'an 2:177. This Hadith and the mentioned Qur'anic verse both emphasize the importance of righteousness, stating that it is not just about ritualistic worship but also includes giving out of one's wealth in spite of love for it, to kinsfolk, orphans, the poor, the wayfarer, to those who ask and to set slaves free.", "marks": "1", "difficulty": "3"}, {"id": "objective>IRK>2016>28", "subject": "IRK", "year": "2016", "type": "Objective", "topic": "HAJJ (PILGRIMAGE) : RITES OF HAJJ", "question": "Ramy as a part of Hajj involves", "images": [], "options": {"A": "Going round the ka'bah", "B": "Slaughtering of animals", "C": "Observance of Nawafil", "D": "throwing of pebbles"}, "answer": "D", "explanation": "Before dawn, pilgrims begin heading back to Mina, where they converge at the Jamarat bridge to perform the Ramy - a symbolic rite in which pebbles are thrown at pillars that represent the temptations of Satan", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2016>29", "subject": "IRK", "year": "2016", "type": "Objective", "topic": "ISLAM IN WEST AFRICA : THE ADVENT AND ROLES OF TRADERS, TEACHERS, MURᾹBITUN, SUFI ORDERS, MUJADDIDUN (REFORMERS) AND HAJJ IN THE PREAD OF ISLAM.", "question": "The first African country to have contacts with Islam was", "images": [], "options": {"A": "Eqypt", "B": "Libya", "C": "Abyssinia", "D": "Morocco"}, "answer": "D", "explanation": "The first African country to have contact with islam was Morocco", "marks": "1", "difficulty": "3"}, {"id": "objective>IRK>2016>30", "subject": "IRK", "year": "2016", "type": "Objective", "topic": "QUR’AN : READING (IN EITHER ARABIC TEXT OR TRANSLITERATION), MEMORIZATION, MEANING OF THE FOLLOWING SUWAR AND THE LESSONS LEARNT FROM THEM (IDENTIFICATION, EXPLANATION, INTERPRETATION AND APPLICATION)", "question": "The \"Qurayah\" in chapter 106 of the Qur'an refers to the prophet's", "images": [], "options": {"A": "Clan", "B": "family", "C": "Tribe", "D": "community"}, "answer": "A", "explanation": "The \"Qurayah\" in chapter 106 of the Qur'an refers to the prophet's clan.", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2016>31", "subject": "IRK", "year": "2016", "type": "Objective", "topic": "HADITH : READING (IN EITHER THE ARABIC TEXT OR TRANSLITERATION). MEMORIZATION, MEANING OF THE FOLLOWING AHADITH AND LESSONS LEARNT FROM THEM (IDENTIFICATION, EXPLANATION, INTERPRETATION AND APPLICATION): AN-NAWAWI’S COLLECTION. 1, 5, 7, 9, 13, 15,16,18,34 AND 41.", "question": "Hadith 34 of an-Nawawi centres on", "images": [], "options": {"A": "unity and brotherhood", "B": "fear of allah", "C": "Leadership and justice", "D": "correction of evil"}, "answer": "C", "explanation": "Hadith 34 of an_Nawawi centres on leadership and justice", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2016>32", "subject": "IRK", "year": "2016", "type": "Objective", "topic": "IMAN (FAITH) : ARTICLES OF FAITH: BELIEF IN ALLAH WITH EMPHASIS ON KALIMATUSH-SHAHADAH(Q2: 163 AND 255; 3:18;17:42-43;21: 22 ; 23: 91 Q. 112, ISLAM AND THE CONCEPT OF TRINITY (Q.4:171; 5:75 – 76; 19:92-3; 112).", "question": "La ilaha illa Allah is the declaration of", "images": [], "options": {"A": "Allah's Majesty", "B": "Allah's Ominiscience", "C": "brotherhood", "D": "monotheism"}, "answer": "D", "explanation": "La ilaha illa Allah is a declaration of monotheism.   The term \"La ilaha illallah\" means \"there's no God but God. Monotheism is the doctrine or belief that there is only one God.", "marks": "1", "difficulty": "1"}, {"id": "objective>IRK>2016>33", "subject": "IRK", "year": "2016", "type": "Objective", "topic": "TALAQ ( DIVORCE) : IDDATUT-TALAQ (WAITING PERIOD FOR A DIVORCED WOMAN): MEANING, DURATION AND IMPLICATION.", "question": "The waiting period prescribed in Q2:226 for taking an oath abstention before divorce is", "images": [], "options": {"A": "5 months", "B": "4 months", "C": "3 months", "D": "2 months"}, "answer": "D", "explanation": "The waiting period prescribed in Q2:226 for taking an oath of abstention before divorce is 2 months", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2016>34", "subject": "IRK", "year": "2016", "type": "Objective", "topic": "THE LIFE OF PROPHET MUHAMMAD (S.A.W.) : THE BATTLES: BADR, UHUD AND KHANDAQ. (CAUSES, COURSES AND EFFECTS.)", "question": "The batte of Khandaq is so called because", "images": [], "options": {"A": "it occured at a place known as khandaq", "B": "The prophet (SAW) decided to name it so", "C": "the muslim dug a ditch to defend madinah", "D": "The jews of Yathrib collaborated with other to attack the muslims"}, "answer": "C", "explanation": "The battle of khandaq is so called because the Muslims dug a ditch to protect and defend the city.  The word khandaq (ÎäÏÞ) is the Arabised form of the Middle Persian word kandag (˜äÏ; meaning \"that which has been dug\"). Salman the Persian advised Muhammad to dig a trench around the city. The battle is also referred to as the Battle of Confederates.", "marks": "1", "difficulty": "3"}, {"id": "objective>IRK>2016>35", "subject": "IRK", "year": "2016", "type": "Objective", "topic": "SHIRK : WORSHIP OF IDOLS (Q.4:48:22:31:31:13:41:37)", "question": "The type of shirk involving disbelief in the existence of Allah", "images": [], "options": {"A": "polytheism", "B": "Humanism", "C": "atheism", "D": "trinity"}, "answer": "C", "explanation": "Atheism is the disbelief in the existence of God or gods. In the context of Islamic theology, this would be considered a form of shirk (associating partners with Allah), as it denies the fundamental Islamic belief in the oneness of Allah. The other options, polytheism, humanism, and trinity, all involve some form of belief in a divine being or beings, and thus do not involve disbelief in the existence of Allah.", "marks": "1", "difficulty": "3"}, {"id": "objective>IRK>2016>36", "subject": "IRK", "year": "2016", "type": "Objective", "topic": "HADITH : READING (IN EITHER THE ARABIC TEXT OR TRANSLITERATION). MEMORIZATION, MEANING OF THE FOLLOWING AHADITH AND LESSONS LEARNT FROM THEM (IDENTIFICATION, EXPLANATION, INTERPRETATION AND APPLICATION): AN-NAWAWI’S COLLECTION. 1, 5, 7, 9, 13, 15,16,18,34 AND 41.", "question": "Hadith 9 of an-Nawawi is an admonition against", "images": [], "options": {"A": "Disagreement with each other", "B": "Following good things with bad ones", "C": "excessive questioning", "D": "Wishful thinking"}, "answer": "C", "explanation": "Hadith 9 of an-Nawawi is an admonition against excessive questioning. This Hadith is about the Prophet's warning against asking too many questions about things that have not been clearly defined in Islam, which could lead to unnecessary complications and confusion.", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2016>37", "subject": "IRK", "year": "2016", "type": "Objective", "topic": "SALAT : SUJUDUS-SAHWI (PROSTRATION OF FORGETFULNESS.)", "question": "Sujudus-sahwi is perfomed to", "images": [], "options": {"A": "increase the number of rak'ah in an Obligatory", "B": "decrease the number of rak'ah of a supererogatory salat", "C": "correct a error in the course of salat", "D": "add quality to an on-going salat"}, "answer": "C", "explanation": "Sujudus_sahwi is performed to correct an error in the source of salat .  Sujud Sahwi or Sajdah of forgetfulness occurs during the ritual salat prayer. Out of forgetfulness a person can either omit obligatory parts of salat (Qabli) or add to the salat (Ba'adi). In either cases the person corrects his/her salat by doing the Sujud Sahwi.", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2016>38", "subject": "IRK", "year": "2016", "type": "Objective", "topic": "QUR’AN : READING (IN EITHER ARABIC TEXT OR TRANSLITERATION), MEMORIZATION, MEANING OF THE FOLLOWING SUWAR AND THE LESSONS LEARNT FROM THEM (IDENTIFICATION, EXPLANATION, INTERPRETATION AND APPLICATION)", "question": "Mankind is directed in Saratul-Falaq (Q.113:4) to seek refuges from the", "images": [], "options": {"A": "Evil of Maligant witchcraft", "B": "Lord of the early morning hours", "C": "Evil of the envier when he envies", "D": "Lord of evenings"}, "answer": "C", "explanation": "Mankind is directed in suratul_Falaq (Q113:4) to seek refuge from the  Evil of the envient when he envies", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2016>39", "subject": "IRK", "year": "2016", "type": "Objective", "topic": "HADITH : READING (IN EITHER THE ARABIC TEXT OR TRANSLITERATION). MEMORIZATION, MEANING OF THE FOLLOWING AHADITH AND LESSONS LEARNT FROM THEM (IDENTIFICATION, EXPLANATION, INTERPRETATION AND APPLICATION): AN-NAWAWI’S COLLECTION. 1, 5, 7, 9, 13, 15,16,18,34 AND 41.", "question": "Hadith 3 of an-Nawawi dwells on the", "images": [], "options": {"A": "Effect of anger", "B": "Pillars of islam", "C": "reward of good deeds", "D": "importance of intentions"}, "answer": "B", "explanation": "Hadith 3 of an-Nawaawi emphasizes that Islam has been built on five pillars.", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2016>40", "subject": "IRK", "year": "2016", "type": "Objective", "topic": "SALAT : MEANING AND IMPORTANCE", "question": "Tamid is significant because it", "images": [], "options": {"A": "Expresses one's gratitude to Allah", "B": "shows humility and obedience to Allah", "C": "indicates the greatness and power of Allah", "D": "Potrays one's reliance on Allah"}, "answer": "B", "explanation": "Tamid is a form of prayer in Islam that shows humility and obedience to Allah. It is a daily prayer that is performed in the morning and evening. The act of performing Tamid is a way of showing obedience to Allah's commands and acknowledging His authority over all things.", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2016>41", "subject": "IRK", "year": "2016", "type": "Objective", "topic": "NIKAH (MARRIAGE) : CONCEPT", "question": "Lon absence of a husband from home without justification could be termed as", "images": [], "options": {"A": "hubb", "B": "it-Tihad", "C": "infaq", "D": "Idrar"}, "answer": "A", "explanation": "Long absence of a husband form home without justification could be termed as Hubb.", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2016>42", "subject": "IRK", "year": "2016", "type": "Objective", "topic": "HADITH : THE SIX SOUND COLLECTIONS OF HADITH (SIHAUS-SITTAH) AND THEIR COMPILERS.", "question": "Umar b Abdul Aziz is remembered in the development of Hadith because he", "images": [], "options": {"A": "gave orders for the collection of Hadith", "B": "studied under the Aishah, the Widow of the Prophet", "C": "instituted Tafsir of Hadith in the Islamic empire", "D": "Was the first to memorise the sahigayn"}, "answer": "D", "explanation": "Umar b. Abdul Aziz is remember in the development of Hadith because he was the first to memorize the sahihayn", "marks": "1", "difficulty": "3"}, {"id": "objective>IRK>2016>43", "subject": "IRK", "year": "2016", "type": "Objective", "topic": "THE LIFE OF PROPHET MUHAMMAD (S.A.W.) : HIJRAH", "question": "The prophet performed his Hijrah precisely in", "images": [], "options": {"A": "January 15,610 C.E", "B": "June 12, 612 C.E", "C": "September 10,620 C.E", "D": "June 20, 622 C.E"}, "answer": "A", "explanation": "The prophet performed his Hijrah precisely in January 15,610C.E", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2016>44", "subject": "IRK", "year": "2016", "type": "Objective", "topic": "IMAN (FAITH) : ARTICLES OF FAITH: BELIEF IN ALLAH WITH EMPHASIS ON KALIMATUSH-SHAHADAH(Q2: 163 AND 255; 3:18;17:42-43;21: 22 ; 23: 91 Q. 112, ISLAM AND THE CONCEPT OF TRINITY (Q.4:171; 5:75 – 76; 19:92-3; 112).", "question": "The first attribute of Allah in saratul ikhlas", "images": [], "options": {"A": "Ahad", "B": "as-samad", "C": "lam yalid", "D": "lam yulad"}, "answer": "A", "explanation": "The first attribute of Allah in Suratul Ikhlas is 'Ahad' which means 'One'. Suratul Ikhlas is the 112th chapter of the Quran and it starts with 'Say, He is Allah, [who is] One (Ahad)'. Therefore, the first attribute of Allah mentioned in this Surah is 'Ahad'.", "marks": "1", "difficulty": "1"}, {"id": "objective>IRK>2016>45", "subject": "IRK", "year": "2016", "type": "Objective", "topic": "TAHARAH (PURIFICATION) : AT-TAYAMMUM", "question": "According to Qur'an 5:6 the first step in the performance of tayammum is", "images": [], "options": {"A": "Wiping the face", "B": "bolwing the nostrils", "C": "Wiping of the two hands", "D": "declaration of intention"}, "answer": "A", "explanation": "According to Qur'an 5:6 the first step in the performance of Tayammum is Wiping the face", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2016>46", "subject": "IRK", "year": "2016", "type": "Objective", "topic": "HAJJ (PILGRIMAGE) : PRE-REQUISITE TO THE PERFORMANCE OF HAJJ", "question": "The following are conditions of Hajj except", "images": [], "options": {"A": "begging financial assistance", "B": "maturity of the would be pilgrim", "C": "Freedom from any danger on the road", "D": "physical ability to undertake the journey"}, "answer": "A", "explanation": "Hajj is one of the five pillars of Islam and it is obligatory for every Muslim who is physically and financially capable to undertake the journey. The conditions of Hajj include being a Muslim, being of sound mind, being an adult or mature, being free (not a slave), and having the physical and financial ability to undertake the journey. Begging financial assistance is not a condition of Hajj. Therefore, the correct answer is option 1.", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2016>47", "subject": "IRK", "year": "2016", "type": "Objective", "topic": "NIKAH (MARRIAGE) : CONCEPT", "question": "The walimah in marriage is meant to", "images": [], "options": {"A": "Empower the bride", "B": "support the couple", "C": "publicize the union", "D": "entertain friends and relatives"}, "answer": "A", "explanation": "The walimah in marriage is meant to Empower the bride. The significance of Walimah in marriage is to structure out empowerment for the wife.", "marks": "1", "difficulty": "1"}, {"id": "objective>IRK>2016>48", "subject": "IRK", "year": "2016", "type": "Objective", "topic": "HADITH : READING (IN EITHER THE ARABIC TEXT OR TRANSLITERATION). MEMORIZATION, MEANING OF THE FOLLOWING AHADITH AND LESSONS LEARNT FROM THEM (IDENTIFICATION, EXPLANATION, INTERPRETATION AND APPLICATION): AN-NAWAWI’S COLLECTION. 1, 5, 7, 9, 13, 15,16,18,34 AND 41.", "question": "Ru'ya as a form of revelation has to die with", "images": [], "options": {"A": "Angels", "B": "dreams", "C": "an aspiration", "D": "a vision"}, "answer": "C", "explanation": "Ru'ya as  a form of revelation has to do with an aspiration", "marks": "1", "difficulty": "3"}, {"id": "objective>IRK>2016>49", "subject": "IRK", "year": "2016", "type": "Objective", "topic": "QUR’AN : READING (IN EITHER ARABIC TEXT OR TRANSLITERATION), MEMORIZATION, MEANING OF THE FOLLOWING SUWAR AND THE LESSONS LEARNT FROM THEM (IDENTIFICATION, EXPLANATION, INTERPRETATION AND APPLICATION)", "question": "Clarification on Quranic verses is achieved through", "images": [], "options": {"A": "Qira'ah", "B": "Tahil", "C": "Tafsir", "D": "Ijthad"}, "answer": "C", "explanation": "Clarification on Qur'an verses is achieved through Tafsir.   Tafsir refers to exegesis, usually of the Quran. An author of a tafsir is a mufassir. A Quranic tafsir attempts to provide elucidation, explanation, interpretation, context or commentary for clear understanding and conviction of God's will", "marks": "1", "difficulty": "3"}, {"id": "objective>IRK>2016>50", "subject": "IRK", "year": "2016", "type": "Objective", "topic": "SHARI ‘AH : DEFINITION", "question": "The jurist who made Tasawwuf compatible with the Shari'ah was", "images": [], "options": {"A": "ibn Sina", "B": "ibn Khaldūn", "C": "Ar-Rāzi", "D": "al-Ghazālī"}, "answer": "D", "explanation": "Al-Ghazali was a Persian philosopher who was one of the most prominent and influential Muslim philosophers, theologians, jurists, and mystics, of Sunni Islam. He was the one who made tasawwuf compatible with shari'ah.", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2018>1", "subject": "IRK", "year": "2018", "type": "Objective", "topic": "QUR’AN : READING (IN EITHER ARABIC TEXT OR TRANSLITERATION), MEMORIZATION, MEANING OF THE FOLLOWING SUWAR AND THE LESSONS LEARNT FROM THEM (IDENTIFICATION, EXPLANATION, INTERPRETATION AND APPLICATION)", "question": "Iyyaka na'abud wa Iyyaka nas teqin in (Q.1:5)", "images": [], "options": {"A": "The beneficient the merciful", "B": "The path of whom you have shown mercy", "C": "the king the day judgement", "D": "it is you we worship and seek help from"}, "answer": "D", "explanation": "The phrase 'Iyyaka na'abud wa Iyyaka nasta'een' is from Surah Al-Fatiha (Q.1:5) in the Quran and it translates to 'You alone we worship and You alone we ask for help'. This phrase signifies the monotheistic nature of Islam, emphasizing that worship and seeking help should be directed to Allah alone.", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2018>2", "subject": "IRK", "year": "2018", "type": "Objective", "topic": "SALAT : KINDS OF SALAT AND HOW THEY ARE OBSERVED", "question": "The special prayer observed in times of fear is salatu", "images": [], "options": {"A": "I-issiqu", "B": "t-tarawh", "C": "s-safar", "D": "I-Khawf"}, "answer": "D", "explanation": "The scholars are all in agreement about the legality of \"fearprayer\" (salatul Khauf). The Qur'an says: \"When You (O Prophet) arewith them, and stand to lead them in prayer, let one party of them stand up (inprayer) with you, taking their arms with them. When they finish prostrations,let them take their position in the rear.", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2018>3", "subject": "IRK", "year": "2018", "type": "Objective", "topic": "HADITH : CLASSIFICATION OF HADITH: SAHIH, HASAN AND DA‘IF.", "question": "Any Hadith that posses all test of verification is classified as", "images": [], "options": {"A": "hason", "B": "Sahik", "C": "Da'if", "D": "Ahad"}, "answer": "B", "explanation": "Ṣaḥīḥ al-Bukhārī is one of the Kutub al-Sittah (six major hadith collections) of Sunni Islam, compiled by Persian scholar Muhammad al-Bukhari. It was completed around 846 CE / 232 AH. Sunni Muslims view this as one of the two most trusted collections of hadith along with Sahih Muslim.[1][2] The Arabic word sahih translates as authentic or correct.[3] Sahih al-Bukhari, together with Sahih Muslim is known as Sahihayn.", "marks": "1", "difficulty": "3"}, {"id": "objective>IRK>2018>4", "subject": "IRK", "year": "2018", "type": "Objective", "topic": "QUR’AN : READING (IN EITHER ARABIC TEXT OR TRANSLITERATION), MEMORIZATION, MEANING OF THE FOLLOWING SUWAR AND THE LESSONS LEARNT FROM THEM (IDENTIFICATION, EXPLANATION, INTERPRETATION AND APPLICATION)", "question": "Suratul Qadr (Q,97:1) is in connection with", "images": [], "options": {"A": "forgiveness", "B": "sustenance", "C": "Revelation", "D": "destiny"}, "answer": "C", "explanation": "Suratul Qadr is in connection with revelation.  (97:1) Behold, We revealed this (Qur'an) on the Night of Power.", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2018>5", "subject": "IRK", "year": "2018", "type": "Objective", "topic": "HAJJ (PILGRIMAGE) : RITES OF HAJJ", "question": "Hajar al-Aswad is to Ka'bahi as I'tidal is to", "images": [], "options": {"A": "Nkah", "B": "Taliq", "C": "Sawn", "D": "Salat"}, "answer": "D", "explanation": "Hajar-al-Aswad is the Arabic word for black stone. The Black Stone is a rock set into the eastern corner of the Kaaba, the ancient building in the center of the Grand Mosque in Mecca, Saudi Arabia. It is revered by Muslims as an Islamic relic which, according to Muslim tradition, dates back to the time of Adam and Eve.  However, I'tidal is to Salat.", "marks": "1", "difficulty": "3"}, {"id": "objective>IRK>2018>6", "subject": "IRK", "year": "2018", "type": "Objective", "topic": "QUR’AN : MORAL LESSONS FROM THE QUR’AN ATTITUDES TO PARENTS (Q.17 :23 – 24: 31 : 13 – 15 HONESTY IN WORDS AND DEEDS Q2: 42; 61: 2-3, 17: 35. PROHIBITION OF GAMBLING Q. 2:219:5 90-91.", "question": "Waqul rabbir-hanhuwa Kama rubbayoni-saghiran (Q17:24) enjoins an obligatory duty to the", "images": [], "options": {"A": "wayfarer", "B": "Orphan", "C": "Parent", "D": "needy"}, "answer": "C", "explanation": "Quran 17:24 enjoins an obligatory duty to the parent.  \"Lower the wing of humility to them, out of mercy, and say, 'My Lord! Have mercy on them, just as they reared me when I was [a] small [child]!\"", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2018>7", "subject": "IRK", "year": "2018", "type": "Objective", "topic": "SAWM (FASTING) : THOSE EXEMPTED FROM FAST", "question": "Aged muslim can susbstitute ramdan fast by", "images": [], "options": {"A": "askng for forgiveness", "B": "Observing Nawafil", "C": "reciting the Qur'an", "D": "Feeding an indigent"}, "answer": "D", "explanation": "According to Islamic teachings, aged Muslims who are unable to fast during Ramadan due to old age or illness can substitute their fast by feeding an indigent. This is based on the Hadith of the Prophet Muhammad (PBUH) which states that those who cannot fast due to old age or sickness, can feed a poor person for each day they miss.", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2018>8", "subject": "IRK", "year": "2018", "type": "Objective", "topic": "HADITH : READING (IN EITHER THE ARABIC TEXT OR TRANSLITERATION). MEMORIZATION, MEANING OF THE FOLLOWING AHADITH AND LESSONS LEARNT FROM THEM (IDENTIFICATION, EXPLANATION, INTERPRETATION AND APPLICATION): AN-NAWAWI’S COLLECTION. 1, 5, 7, 9, 13, 15,16,18,34 AND 41.", "question": "The subject-matter of an-Nawawi hadith 1 is on", "images": [], "options": {"A": "Education", "B": "compensation", "C": "consultation", "D": "migration"}, "answer": "D", "explanation": "This Hadith centers on \"migration\".   \"Actions are according to intentions, and everyone will get what was intended. Whoever migrates with an intention for Allah and His messenger, the migration will be for the sake of Allah and his Messenger. And whoever migrates for worldly gain or to marry a woman, then his migration will be for the sake of whatever he migrated for.\"", "marks": "1", "difficulty": "3"}, {"id": "objective>IRK>2018>9", "subject": "IRK", "year": "2018", "type": "Objective", "topic": "THE KHULAFᾹ’UR-RᾹSHIDĪN (THE RIGHTLY – GUIDED CALIPHS) : THEIR BIOGRAPHIES", "question": "What makes caliph Uthman death unique was that the", "images": [], "options": {"A": "was murdered by a slave", "B": "died of a natural cause", "C": "died while reading the Qur'an", "D": "nominated Ali before his death"}, "answer": "A", "explanation": "What made Caliph Uthman's death unique was that he was murdered by a slave. (A)  \"They went back to Medina, stoned Uthman in the mosque and knocked him unconscious, and then besieged him in his house. The elderly caliph told his friends and servants not to resist, to spare their lives, and the rebels broke in and stabbed him to death. His own treasured copy of the Koran was soaked with his blood.\"", "marks": "1", "difficulty": "3"}, {"id": "objective>IRK>2018>10", "subject": "IRK", "year": "2018", "type": "Objective", "topic": "ZAKAT (CHARITY) : THE BENEFICIARIES OF ZAKAT (Q.9:60)", "question": "A recipent of Zakat according to Qur'an 9:60 is the", "images": [], "options": {"A": "Mu-adh-Dhn", "B": "Blind", "C": "wayfarer", "D": "Musfassir"}, "answer": "C", "explanation": "Wayfarer refers to the needy traveller, i.e those that travel on foot.     \"Alms-tax is only for the poor and the needy, for those employed to administer it, for those whose hearts are attracted ˹to the faith˺, for ˹freeing˺ slaves, for those in debt, for Allah's cause, and for ˹needy˺ travellers. ˹This is˺ an obligation from Allah. And Allah is All-Knowing, All-Wise.\" Quran 9:60", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2018>11", "subject": "IRK", "year": "2018", "type": "Objective", "topic": "HADITH : READING (IN EITHER THE ARABIC TEXT OR TRANSLITERATION). MEMORIZATION, MEANING OF THE FOLLOWING AHADITH AND LESSONS LEARNT FROM THEM (IDENTIFICATION, EXPLANATION, INTERPRETATION AND APPLICATION): AN-NAWAWI’S COLLECTION. 1, 5, 7, 9, 13, 15,16,18,34 AND 41.", "question": "According to Hadith 18 of An-Nawawi an evil  should be corrected by", "images": [], "options": {"A": "supplication", "B": "good deeds", "C": "meditation", "D": "regrets"}, "answer": "B", "explanation": "According to Hadith 18 of An-Nawawi, an evil should be corrected by good deeds. This Hadith teaches that if one sees something wrong, they should try to change it with their hands (action), if they can't, then with their tongue (speaking out), and if they can't, then with their heart (by hating it and feeling that it's wrong), and this is the weakest faith.", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2018>12", "subject": "IRK", "year": "2018", "type": "Objective", "topic": "THE LIFE OF PROPHET MUHAMMAD (S.A.W.) : THE BATTLES: BADR, UHUD AND KHANDAQ. (CAUSES, COURSES AND EFFECTS.)", "question": "Salman al-farisi played a virtal role in the battle of", "images": [], "options": {"A": "Hunayan", "B": "Uhad", "C": "Khandaq", "D": "siffin"}, "answer": "C", "explanation": "At the time of the battle of Khandaq, when Muslims were unsure as to their military strategy against the Quraish armies and their allies, it was Salman al-Farisi who came with the war-winning plan of digging the trench along the passages from where the enemies could enter Medina", "marks": "1", "difficulty": "3"}, {"id": "objective>IRK>2018>13", "subject": "IRK", "year": "2018", "type": "Objective", "topic": "HAJJ (PILGRIMAGE) : RITES OF HAJJ", "question": "The Hajj rite which is in the form of a physical exercise is", "images": [], "options": {"A": "ihran", "B": "wajif", "C": "Dhibh", "D": "Sa'y"}, "answer": "D", "explanation": "The Hajj rite which is in the form of a physical exercise is Sa'y. Sa'y involves walking or running seven times between the hills of Safa and Marwah, located near the Kaaba in Mecca. This ritual commemorates the search for water by Hagar, the wife of Abraham, for her son Ishmael.", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2018>14", "subject": "IRK", "year": "2018", "type": "Objective", "topic": "HADITH : READING (IN EITHER THE ARABIC TEXT OR TRANSLITERATION). MEMORIZATION, MEANING OF THE FOLLOWING AHADITH AND LESSONS LEARNT FROM THEM (IDENTIFICATION, EXPLANATION, INTERPRETATION AND APPLICATION): AN-NAWAWI’S COLLECTION. 1, 5, 7, 9, 13, 15,16,18,34 AND 41.", "question": "The fifth hadith of an-Nawawi prohibits", "images": [], "options": {"A": "anger", "B": "innovation", "C": "gossip", "D": "theft"}, "answer": "B", "explanation": "The fifth Hadith of an-Nawawi prohibits the innovation into Islam", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2018>15", "subject": "IRK", "year": "2018", "type": "Objective", "topic": "THE LIFE OF PROPHET MUHAMMAD (S.A.W.) : BIRTH", "question": "Amiah the mother of Mohammad (SAW) was buried at", "images": [], "options": {"A": "Ahuwa", "B": "Jahfah", "C": "yathrib", "D": "makkah"}, "answer": "A", "explanation": "Upon their return to Mecca a month later, accompanied by her slave Umm Ayman, Aminah fell ill. She died around the year 577 or 578 AD and was buried in the village of Ahuwa", "marks": "1", "difficulty": "3"}, {"id": "objective>IRK>2018>16", "subject": "IRK", "year": "2018", "type": "Objective", "topic": "THE LIFE OF PROPHET MUHAMMAD (S.A.W.) : BIRTH", "question": "Abdul-Muttalib is remebered in islamic history for his", "images": [], "options": {"A": "Bravery and wealth", "B": "generosity and humility", "C": "wealth and generosity", "D": "autocracy and wealth"}, "answer": "A", "explanation": "Abdul Mutalib is remembered in Islamic history for his bravery and wealth.", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2018>17", "subject": "IRK", "year": "2018", "type": "Objective", "topic": "QUR’AN : PRESERVATION OF THE QUR’AN: COMPLETE ARRANGEMENT INCLUDING DISTINCTION BETWEEN MAKKI AND MADANI SUWAR; RECORDING; COMPILATION; STANDARDIZATION: ROLES PLAYED BY THE COMPANIONS OF THE PROPHET (S.A.W.) IN THE PRESERVATION OF THE QUR’AN.", "question": "The standardization of the Qur'an took place during the caliphate of", "images": [], "options": {"A": "Ali b. Abi talib", "B": "Umar b. al -khattah", "C": "Uthman b. Affan", "D": "Abu Bakr b. Ahi Quhdafah"}, "answer": "C", "explanation": "The standardization of the Qur'an took place during the caliphate of Uthman b. Affan. This process involved making the Qur'an uniform and consistent in order to prevent any variations or discrepancies in its recitation and interpretation.", "marks": "1", "difficulty": "3"}, {"id": "objective>IRK>2018>18", "subject": "IRK", "year": "2018", "type": "Objective", "topic": "THE LIFE OF PROPHET MUHAMMAD (S.A.W.) : CALL TO PROPHETHOOD", "question": "Bashirah's encounter with Muhammad (SAW) was important because it", "images": [], "options": {"A": "establishes friendship between them", "B": "instilled fear in Muhammad", "C": "Showed Basirah spiritual", "D": "revealed the prophethood in him"}, "answer": "D", "explanation": "Bahira's encounter with Muhammad was important because it revealed his priesthood.  Bahira  was an Arab Nestorian or possibly Gnostic Nasorean monk who, according to Islamic tradition, foretold to the adolescent Muhammad his future as a prophet.", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2018>19", "subject": "IRK", "year": "2018", "type": "Objective", "topic": "QUR’AN : PRESERVATION OF THE QUR’AN: COMPLETE ARRANGEMENT INCLUDING DISTINCTION BETWEEN MAKKI AND MADANI SUWAR; RECORDING; COMPILATION; STANDARDIZATION: ROLES PLAYED BY THE COMPANIONS OF THE PROPHET (S.A.W.) IN THE PRESERVATION OF THE QUR’AN.", "question": "The danger of reading the Qur'an in different dialect was averted during the caliphate of", "images": [], "options": {"A": "mu'awiyah", "B": "Ali", "C": "uthman", "D": "Umar"}, "answer": "C", "explanation": "The danger of reading the Qur'an in different dialects was averted during the caliphate of Uthman. During his reign, Uthman noticed that the Qur'an was being recited in different dialects, which could lead to misinterpretations and distortions of the message. To prevent this, he ordered the compilation of a standard version of the Qur'an in the Qurayshi dialect, which was the dialect of the Prophet Muhammad (SAW). This version is the one used by Muslims worldwide today.", "marks": "1", "difficulty": "3"}, {"id": "objective>IRK>2018>20", "subject": "IRK", "year": "2018", "type": "Objective", "topic": "HADITH : DEFINITION OF HADITH AND SUNNAH", "question": "The silent approval of the prophet as referred to in the science of Hadith as", "images": [], "options": {"A": "Qawl", "B": "taqtir", "C": "Fi'l", "D": "tarikh"}, "answer": "B", "explanation": "The silent approval or tactic approval of the prophet is known as Taqrir.  Arabic for tacit approval. It refers to what the Prophet Muhammad (pbuh) approved, verbally or silently, in the actions or sayings of others.", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2018>21", "subject": "IRK", "year": "2018", "type": "Objective", "topic": "QUR’AN : THE QUR’AN AS A SOURCE OF GUIDANCE IN SOCIAL, POLITICAL, SPIRITUAL AND MORAL MATTERS", "question": "Suratul fatilah is referred to as fatilatud  kitab because it", "images": [], "options": {"A": "the mother of the book", "B": "contains seven oft-repeated verses", "C": "begins the Qur'an", "D": "summarizes the Qur'an"}, "answer": "C", "explanation": "Suratul Fatiha is referred to as  Fatilatul Kitab because it begins the Quran.  Fatihatul Kitab The very first Surah of the Quran which consists of seven verses is called Surah Fatiha or Fatihatul Kitab, meaning the opening of the book.", "marks": "1", "difficulty": "1"}, {"id": "objective>IRK>2018>22", "subject": "IRK", "year": "2018", "type": "Objective", "topic": "HADITH : THE SIX SOUND COLLECTIONS OF HADITH (SIHAUS-SITTAH) AND THEIR COMPILERS.", "question": "Sunan is to Aba Dawditas jami is to", "images": [], "options": {"A": "Bukhari", "B": "Muslim", "C": "Timidhi", "D": "ibn majah"}, "answer": "A", "explanation": "Sunan Abu Dawood is a collection of hadith compiled by Imam Abu Dawood Sulayman ibn al-Ash'ath as-Sijistani. It is one of the Kutub al-Sittah (six major hadith collections). Similarly, Sahih al-Bukhari is another collection of hadith compiled by Imam Muhammad al-Bukhari. Therefore, the analogy is that as Sunan is to Abu Dawood, Jami is to Bukhari.", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2018>23", "subject": "IRK", "year": "2018", "type": "Objective", "topic": "HADITH : PARTS OF THE HADITH: ‘ISNAD, MATN AND RAWI", "question": "Abi Diharr was a great man in islam because he was a", "images": [], "options": {"A": "Qur'anic memorizer", "B": "compiler of hadith", "C": "transmitter of Hadith", "D": "Qur'anic commentator"}, "answer": "C", "explanation": "Abu Dharr al-Ghifari was a companion of Prophet Muhammad. He is known for his strict piety and also his opposition to the governor of Syria, Muawiyah I, during the caliph Uthman ibn Affan era. He is best known for being a transmitter of Hadith, not a compiler. Therefore, the correct answer is 'transmitter of Hadith'.", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2018>24", "subject": "IRK", "year": "2018", "type": "Objective", "topic": "QUR’AN : THE QUR’AN AS A SOURCE OF GUIDANCE IN SOCIAL, POLITICAL, SPIRITUAL AND MORAL MATTERS", "question": "The name al-Furqun implies that the Qur'an is a", "images": [], "options": {"A": "book", "B": "reminder", "C": "revelation", "D": "criterion"}, "answer": "D", "explanation": "Al-Furqān is the 25th chapter of the Qur'an with 77 verses. The name Al-Furqan, or \"The Criterion\" refers to the Qur'an itself as the decisive factor between good and evil.", "marks": "1", "difficulty": "1"}, {"id": "objective>IRK>2018>25", "subject": "IRK", "year": "2018", "type": "Objective", "topic": "HADITH : PARTS OF THE HADITH: ‘ISNAD, MATN AND RAWI", "question": "Which of the following is a component of Hadith", "images": [], "options": {"A": "Masaanif", "B": "sahih", "C": "matn", "D": "jami"}, "answer": "C", "explanation": "A Hadith is composed of two parts: the 'isnad' and the 'matn'. The 'isnad' is the chain of narrators who transmitted the Hadith, while the 'matn' is the actual content of the Hadith, i.e., the words and actions of the Prophet Muhammad. Therefore, the correct answer is 'matn'. The other options, 'Masaanif', 'sahih', and 'jami', are related to the classification and collection of Hadiths, but they are not components of a Hadith.", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2018>26", "subject": "IRK", "year": "2018", "type": "Objective", "topic": "IMAN (FAITH) : HIS ANGELS – Q 2: 285; 8:50; 16: 2; 66: 6 ; 82: 10 – 12.", "question": "The angel of Allah in charge of rain and distribution of substance is", "images": [], "options": {"A": "Azai'l", "B": "mika'l", "C": "Barfil", "D": "jibril"}, "answer": "B", "explanation": "Mika'il - The Angel Mika'il (known as Michael in Christianity) is a friend to humanity. He is known as the giver of rain, which waters the land and helps to provide food for people. He is believed to guard places of worship and reward people's good deeds. As the Angel of Mercy, he asks Allah to forgive people's sins.", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2018>27", "subject": "IRK", "year": "2018", "type": "Objective", "topic": "IMAN (FAITH) : HIS ANGELS – Q 2: 285; 8:50; 16: 2; 66: 6 ; 82: 10 – 12.", "question": "The main function of Roqib and Atid is to", "images": [], "options": {"A": "watch over the gate of paradise and Hell", "B": "blow the trumpet on the last day", "C": "Record man's deeds on earth", "D": "carry the message of Allah to prophet"}, "answer": "C", "explanation": "In Islam the two recording angels are called Raqib and Atid that record human speech: each records faithful or blasphemous speeches, and also records a human's deeds", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2018>28", "subject": "IRK", "year": "2018", "type": "Objective", "topic": "SAWM (FASTING) : THINGS THAT VITIATE FAST", "question": "Which of the following is not an atonement for intentionally breaking of Ramadan fast ?", "images": [], "options": {"A": "60 days continous fasting", "B": "feeding of 60 people to satisfation", "C": "freeing slaves", "D": "paying a specific amount as ransom"}, "answer": "D", "explanation": "In Islamic tradition, the atonement (Kaffarah) for intentionally breaking a Ramadan fast includes fasting for 60 continuous days, feeding 60 poor people to satisfaction, or freeing a slave if one is available. Paying a specific amount as ransom is not considered an atonement for intentionally breaking a Ramadan fast.", "marks": "1", "difficulty": "3"}, {"id": "objective>IRK>2018>29", "subject": "IRK", "year": "2018", "type": "Objective", "topic": "HADITH : CLASSIFICATION OF HADITH: SAHIH, HASAN AND DA‘IF.", "question": "The following are degrees of Hadith reliability except", "images": [], "options": {"A": "Hasan", "B": "Mundasil", "C": "sahih", "D": "Da'if"}, "answer": "B", "explanation": "In the classification of Hadith (sayings or actions of Prophet Muhammad), there are several degrees of reliability. These include Sahih (authentic), Hasan (good), and Da'if (weak). However, 'Mundasil' is not a degree of Hadith reliability. It is a term used to describe a Hadith with a missing link in the chain of narrators.", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2018>30", "subject": "IRK", "year": "2018", "type": "Objective", "topic": "THE LIFE OF PROPHET MUHAMMAD (S.A.W.) : MARRIAGE", "question": "Muhammad (SAW) was attract to Khadijah because of his", "images": [], "options": {"A": "nobility", "B": "wealth", "C": "trustworthiness", "D": "eloquence"}, "answer": "C", "explanation": "Muhammad (SAW) was attracted to Khadijah because of his trustworthiness. Khadijah was a successful businesswoman and she was impressed by Muhammad's trustworthiness when he was handling her business affairs. This led to her proposing marriage to him.", "marks": "1", "difficulty": "1"}, {"id": "objective>IRK>2018>31", "subject": "IRK", "year": "2018", "type": "Objective", "topic": "THE LIFE OF PROPHET MUHAMMAD (S.A.W.) : THE FAREWELL PILGRIMAGE: DESCRIPTION, SERMON, AND ITS LESSONS.", "question": "Which of the following is not an issue in the prophet's farewell sermon?", "images": [], "options": {"A": "Abolition of usury", "B": "Kindness to slaves", "C": "Islamic brotherhood", "D": "Restricted polygamy"}, "answer": "D", "explanation": "-\tThe following issues are addressed in the Prophet's last sermon   -\tAbolition to usury  -\tKindness to slaves  Islamic brotherhood", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2018>32", "subject": "IRK", "year": "2018", "type": "Objective", "topic": "QUR’AN : PRESERVATION OF THE QUR’AN: COMPLETE ARRANGEMENT INCLUDING DISTINCTION BETWEEN MAKKI AND MADANI SUWAR; RECORDING; COMPILATION; STANDARDIZATION: ROLES PLAYED BY THE COMPANIONS OF THE PROPHET (S.A.W.) IN THE PRESERVATION OF THE QUR’AN.", "question": "The total number of Chapters in the Qur'an is", "images": [], "options": {"A": "134", "B": "124", "C": "114", "D": "104"}, "answer": "C", "explanation": "The Qur'an, the holy book of Islam, is divided into chapters, which are then divided into verses. The Qur'an is composed of 114 chapters of varying lengths, each known as a surah. The chapters or surahs are of unequal length; the shortest chapter has only three verses while the longest contains 286 verses.", "marks": "1", "difficulty": "1"}, {"id": "objective>IRK>2018>33", "subject": "IRK", "year": "2018", "type": "Objective", "topic": "THE JAHILIYYAH: ARABIA BEFORE ISLAM : POLITICAL LIFE – SYSTEM OF GOVERNMENT", "question": "The Arab of the Jahilayyah were divided into numerous tribes because there was no", "images": [], "options": {"A": "stable economic system", "B": "strong political system", "C": "definite social order", "D": "religious tolerance"}, "answer": "D", "explanation": "The Arabs of Jahilliyah were divided into different tribes because there was no religious tolerance.", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2018>34", "subject": "IRK", "year": "2018", "type": "Objective", "topic": "QUR’AN : PRESERVATION OF THE QUR’AN: COMPLETE ARRANGEMENT INCLUDING DISTINCTION BETWEEN MAKKI AND MADANI SUWAR; RECORDING; COMPILATION; STANDARDIZATION: ROLES PLAYED BY THE COMPANIONS OF THE PROPHET (S.A.W.) IN THE PRESERVATION OF THE QUR’AN.", "question": "The division of the Qur'an into sixty equal parts is known as", "images": [], "options": {"A": "Juz", "B": "Hizb", "C": "Rub", "D": "Manzil"}, "answer": "A", "explanation": "The Qur'an is divided into 60 equal parts, each of which is known as a Juz. This division facilitates the reading of the Qur'an over a month, particularly during the month of Ramadan where one Juz is typically read each night during the Taraweeh prayers.", "marks": "1", "difficulty": "1"}, {"id": "objective>IRK>2018>35", "subject": "IRK", "year": "2018", "type": "Objective", "topic": "HADITH : PARTS OF THE HADITH: ‘ISNAD, MATN AND RAWI", "question": "The correct isnad of an hadith is established through the following except the", "images": [], "options": {"A": "Continous chain of trasmitters", "B": "Character of transmitters.", "C": "relationship of transmitter", "D": "closeness of transmitter to the prophet"}, "answer": "D", "explanation": "Isnad or Sanad is the chain of narrators attesting to the historical authenticity of a particular Hadith. It helps differentiate between the accepted and rejected Hadiths. The correct Isnad of an Hadith is not established through Option D.", "marks": "1", "difficulty": "3"}, {"id": "objective>IRK>2018>36", "subject": "IRK", "year": "2018", "type": "Objective", "topic": "QUR’AN : PRESERVATION OF THE QUR’AN: COMPLETE ARRANGEMENT INCLUDING DISTINCTION BETWEEN MAKKI AND MADANI SUWAR; RECORDING; COMPILATION; STANDARDIZATION: ROLES PLAYED BY THE COMPANIONS OF THE PROPHET (S.A.W.) IN THE PRESERVATION OF THE QUR’AN.", "question": "Which of the following is not a characteristic  of makkan suwar?", "images": [], "options": {"A": "Their verses are short", "B": "they have poetical rthym", "C": "they contain historical facts", "D": "they are full of oaths"}, "answer": "C", "explanation": "The Makkan Suwar have their main themes as follows:    - The unity of Allah (Tawhid)  - The coming Resurrection and Judgment Day  - Righteous conducts, and lessons of the people and prophets of the past.  Apart from the above, the Makkan Suwar are generally short, the language is poetic and the Suwar are full of oaths. In addition, the sentences are short, and are mostly full of warnings of hell to evil doers and promise of paradise for doers of good.", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2018>37", "subject": "IRK", "year": "2018", "type": "Objective", "topic": "HAJJ (PILGRIMAGE) : PERFORMANCE OF ‘UMRAH AND HAJJ", "question": "Tawaf is to hajj as Iftar is to", "images": [], "options": {"A": "salat", "B": "sawm", "C": "Zakat", "D": "imam"}, "answer": "B", "explanation": "Tawaf is a ritual in Hajj where Muslims go around the Kaaba seven times. This is a specific act related to Hajj. Similarly, Iftar is a specific act related to Sawm (fasting), as it is the meal that breaks the fast at sunset during Ramadan. Therefore, the correct analogy is 'Tawaf is to Hajj as Iftar is to Sawm'.", "marks": "1", "difficulty": "1"}, {"id": "objective>IRK>2018>38", "subject": "IRK", "year": "2018", "type": "Objective", "topic": "THE LIFE OF PROPHET MUHAMMAD (S.A.W.) : BIRTH", "question": "The son of Muhammad (SAW) who died on the day of Idul Adha was", "images": [], "options": {"A": "Tayyib", "B": "Qasim", "C": "Abdulahi", "D": "Ibrahim"}, "answer": "D", "explanation": "The son of Prophet Muhammad (SAW) who died on the day of Idul Adha was Ibrahim. Prophet Muhammad (SAW) had three sons: Al-Qasim, Abdullah and Ibrahim. Ibrahim was the son of Maria al-Qibtiyya, who was gifted to the Prophet by an Egyptian ruler. Ibrahim died in infancy on the day of Idul Adha, which is a major Islamic festival that commemorates the willingness of Ibrahim (Abraham) to sacrifice his son as an act of obedience to God.", "marks": "1", "difficulty": "3"}, {"id": "objective>IRK>2018>39", "subject": "IRK", "year": "2018", "type": "Objective", "topic": "IMAN (FAITH) : ARTICLES OF FAITH: BELIEF IN ALLAH WITH EMPHASIS ON KALIMATUSH-SHAHADAH(Q2: 163 AND 255; 3:18;17:42-43;21: 22 ; 23: 91 Q. 112, ISLAM AND THE CONCEPT OF TRINITY (Q.4:171; 5:75 – 76; 19:92-3; 112).", "question": "The Quranic chapter whuc enumerates some divine attributes of Allah in Surah", "images": [], "options": {"A": "al-falaq", "B": "an-Nas", "C": "al-iklas", "D": "an-Nasr"}, "answer": "C", "explanation": "The Quranic chapter which enumerates some divine attributes of Allah is Surah al-Ikhlas. Surah al-Ikhlas is the 112th chapter of the Quran and it is often referred to as the essence of the Quran. It describes the oneness, independence, uniqueness and purity of Allah. The Surah states: 'Say, He is Allah, [who is] One, Allah, the Eternal Refuge. He neither begets nor is born, Nor is there to Him any equivalent.'", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2018>40", "subject": "IRK", "year": "2018", "type": "Objective", "topic": "QUR’AN : REVELATION OF THE QUR’AN: VISITS OF THE PROPHET (S.A.W.) TO CAVE HIRA ; FIRST REVELATION AND HIS REACTION TO IT, DIFFERENT MODES OF REVELATION, PIECEMEAL- REVELATION OF THE QUR’AN.", "question": "Muhammad (SAW) used to visit the cave of Hira in his early age in order to", "images": [], "options": {"A": "meditate about nature", "B": "hide from the mekkans", "C": "recieve revelation", "D": "observe prayer and fast"}, "answer": "C", "explanation": "A cave in Mount Hira (near Mecca) is the location where the Prophet Muhammad (peace be upon him) received his revelations from Allah SWT through the angel Gabriel.", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2018>41", "subject": "IRK", "year": "2018", "type": "Objective", "topic": "SALAT : JOINING A CONGREGATIONAL SALAT.", "question": "A devotee who joins any congregational prayer in the last sujid will observe", "images": [], "options": {"A": "only the last rak'ah", "B": "only the previous rak'ah", "C": "all the rak'ah of the salat", "D": "observe prayers of the spirit"}, "answer": "C", "explanation": "A devotee who joins any congregational prayer in the last Sujud will observe all the rakat of the Salatt", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2018>42", "subject": "IRK", "year": "2018", "type": "Objective", "topic": "SALAT : KINDS OF SALAT AND HOW THEY ARE OBSERVED", "question": "The total number of takbirat in the first rak'ah of salatul'id is", "images": [], "options": {"A": "9", "B": "7", "C": "6", "D": "5"}, "answer": "C", "explanation": "The total number of Takbirat in the first rakat of Solatul - id is six.  Eid Salat consists of two 'Rakats' (prescribed movements and words during prayer) and six 'Takbirs' (praising God). First, Muslims will make the Niyyah (intention) which involves reciting: \"I intend to do two Rakat behind the Imam for Eid prayer along with six additional Takbirs\".", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2018>43", "subject": "IRK", "year": "2018", "type": "Objective", "topic": "THE LIFE OF PROPHET MUHAMMAD (S.A.W.) : THE BATTLES: BADR, UHUD AND KHANDAQ. (CAUSES, COURSES AND EFFECTS.)", "question": "The opposition of the Qurasyh to the holy prophet (SAW) was due among other things to", "images": [], "options": {"A": "the popularity of te prophet clan", "B": "the familarity with christianity", "C": "socio-economic consideration", "D": "muslims attacks on Makkan caravans"}, "answer": "B", "explanation": "According to the Holy Prophet (SAW), the opposition to the Qurrayah was due to so many factors which include familiarity with Christianity", "marks": "1", "difficulty": "3"}, {"id": "objective>IRK>2018>44", "subject": "IRK", "year": "2018", "type": "Objective", "topic": "THE LIFE OF PROPHET MUHAMMAD (S.A.W.) : THE BATTLES: BADR, UHUD AND KHANDAQ. (CAUSES, COURSES AND EFFECTS.)", "question": "The defeat suffered by Muslims at Uhud was caused by", "images": [], "options": {"A": "Absence of Umar", "B": "numerical disadvantage", "C": "disobedience to the prophet", "D": "inadequate preparation"}, "answer": "C", "explanation": "The defeat suffered by Muslims at the Battle of Uhud was primarily due to the disobedience to the Prophet Muhammad's instructions. The Prophet had instructed a group of archers to stay put at a strategic location during the battle, regardless of how the battle was progressing. However, when these archers saw that the Muslims were winning, they left their position to join the others in collecting the spoils of war. This disobedience led to a surprise attack from the enemy, leading to a defeat for the Muslims.", "marks": "1", "difficulty": "3"}, {"id": "objective>IRK>2018>45", "subject": "IRK", "year": "2018", "type": "Objective", "topic": "SHIRK : WORSHIP OF IDOLS (Q.4:48:22:31:31:13:41:37)", "question": "The act of associating partners with Allah", "images": [], "options": {"A": "Riya", "B": "Kufr", "C": "Shirk", "D": "Nifiq"}, "answer": "C", "explanation": "In Islamic theology, Shirk refers to the sin of practicing idolatry or polytheism, i.e., the deification or worship of anyone or anything other than the singular God, Allah. It is the act of associating partners with Allah and is considered a grave sin in Islam.", "marks": "1", "difficulty": "1"}, {"id": "objective>IRK>2018>46", "subject": "IRK", "year": "2018", "type": "Objective", "topic": "HADITH : DEFINITION OF HADITH AND SUNNAH", "question": "The verse lam yalid wa lam yalad is followed by", "images": [], "options": {"A": "QulHuwa Allahu ahud", "B": "Maliki yawmid -Din", "C": "walam yakun i-lahu kufuwan ahad", "D": "siraral-ludhina  an amta  alayhim"}, "answer": "C", "explanation": "The verse 'lam yalid wa lam yalad' is from Surah Al-Ikhlas in the Quran and it is followed by 'walam yakun i-lahu kufuwan ahad' which translates to 'And there is none comparable unto Him'.", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2018>47", "subject": "IRK", "year": "2018", "type": "Objective", "topic": "ISLAM IN WEST AFRICA : THE ADVENT AND ROLES OF TRADERS, TEACHERS, MURᾹBITUN, SUFI ORDERS, MUJADDIDUN (REFORMERS) AND HAJJ IN THE PREAD OF ISLAM.", "question": "Ja'far b. Abi Talib defended islam before the king of", "images": [], "options": {"A": "Syria", "B": "Egypt", "C": "Persia", "D": "Abyssinia"}, "answer": "D", "explanation": "Ja'far b. Abi Talib defended Islam before the king of Abyssinia. This event is a significant part of Islamic history when the Muslims sought refuge in Abyssinia due to persecution in Mecca.", "marks": "1", "difficulty": "3"}, {"id": "objective>IRK>2018>48", "subject": "IRK", "year": "2018", "type": "Objective", "topic": "THE KHULAFᾹ’UR-RᾹSHIDĪN (THE RIGHTLY – GUIDED CALIPHS) : THEIR BIOGRAPHIES", "question": "Uthman before the advent is to Dhu-Nurayn as Umar b. al-kattab is to", "images": [], "options": {"A": "As-sadiq", "B": "As-Faruq", "C": "Al-sidiq", "D": "al-amin"}, "answer": "B", "explanation": "Umar b. al-kattab is known as As-Faruq. The title As-Faruq means 'the one who distinguishes between right and wrong'. This title was given to Umar due to his strong sense of justice and fairness.", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2018>49", "subject": "IRK", "year": "2018", "type": "Objective", "topic": "THE JAHILIYYAH: ARABIA BEFORE ISLAM : RELIGIOUS LIFE – IDOL WORSHIP AND NAMES OF MAJOR GODS/IDOLS.", "question": "Ka'abah before the advent of Islam harboured about", "images": [], "options": {"A": "120 idols", "B": "160 idols", "C": "320 idols", "D": "360 idols"}, "answer": "D", "explanation": "Before the advent of Islam, the Ka'abah harboured about 360 idols. These idols were worshipped by the pre-Islamic Arabs. The number 360 is significant as it represents the number of days in the lunar calendar, which was used by the Arabs at the time.", "marks": "1", "difficulty": "3"}, {"id": "objective>IRK>2018>50", "subject": "IRK", "year": "2018", "type": "Objective", "topic": "IMAN (FAITH) : ARTICLES OF FAITH: BELIEF IN ALLAH WITH EMPHASIS ON KALIMATUSH-SHAHADAH(Q2: 163 AND 255; 3:18;17:42-43;21: 22 ; 23: 91 Q. 112, ISLAM AND THE CONCEPT OF TRINITY (Q.4:171; 5:75 – 76; 19:92-3; 112).", "question": "The attribute of Allah al-Qayyin describes him as the", "images": [], "options": {"A": "merciful", "B": "eternal", "C": "unique", "D": "powerful"}, "answer": "D", "explanation": "The attribute of Allah al Qayyhim describes him as the most powerful.", "marks": "1", "difficulty": "1"}, {"id": "objective>IRK>2021>1", "subject": "IRK", "year": "2021", "type": "Objective", "topic": "SALAT : MEANING AND IMPORTANCE", "question": "A complete prayer ends with a", "images": [], "options": {"A": "Taslim", "B": "Basmallah", "C": "Tahlil", "D": "Tashahhud"}, "answer": "A", "explanation": "Taslim is the concuding part/ portion of the muslim prayer(salat), where one recites As-salamu alaikum wa-rahmatu-llah once while facing the right and once facing the left", "marks": "1", "difficulty": "1"}, {"id": "objective>IRK>2021>2", "subject": "IRK", "year": "2021", "type": "Objective", "topic": "SHARI ‘AH : SOURCES (THE QUR’AN, THE SUNNAH, THE IJMA‘ AND THE QIYAS.)", "question": "Ijma as a secondary source of islamic law implies....", "images": [], "options": {"A": "Consensus opinion of scholars", "B": "analogical deductions", "C": "established basis for justice", "D": "norms and tradition"}, "answer": "A", "explanation": "The ijma' implies consensus amongst Muslim jurist on a particular legal issue, constitute  the third source of islamic law", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2021>3", "subject": "IRK", "year": "2021", "type": "Objective", "topic": "QUR’AN : PRESERVATION OF THE QUR’AN: COMPLETE ARRANGEMENT INCLUDING DISTINCTION BETWEEN MAKKI AND MADANI SUWAR; RECORDING; COMPILATION; STANDARDIZATION: ROLES PLAYED BY THE COMPANIONS OF THE PROPHET (S.A.W.) IN THE PRESERVATION OF THE QUR’AN.", "question": "Ad-Dhikr is Qur'an as 'ummul-kitab' is to", "images": [], "options": {"A": "Fatihah", "B": "Kafirun", "C": "Falaq", "D": "Ikhlas"}, "answer": "A", "explanation": "Al-Fatihah , the first surah of the Quran, also referred to as Ummul Al-Kitab", "marks": "1", "difficulty": "3"}, {"id": "objective>IRK>2021>4", "subject": "IRK", "year": "2021", "type": "Objective", "topic": "HADITH : READING (IN EITHER THE ARABIC TEXT OR TRANSLITERATION). MEMORIZATION, MEANING OF THE FOLLOWING AHADITH AND LESSONS LEARNT FROM THEM (IDENTIFICATION, EXPLANATION, INTERPRETATION AND APPLICATION): AN-NAWAWI’S COLLECTION. 1, 5, 7, 9, 13, 15,16,18,34 AND 41.", "question": "One of the issues discussed in Hadith 18 of an-Nawawi is about", "images": [], "options": {"A": "The fear of Allah", "B": "Important  of intention", "C": "Avoidance of vain talk", "D": "Avoidance of innovation"}, "answer": "A", "explanation": "One of the issues discussed in Hadith 18 of An-Nawawi is tawah (piety) , taqwah bothers mainly on the fear of Allah", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2021>5", "subject": "IRK", "year": "2021", "type": "Objective", "topic": "THE LIFE OF PROPHET MUHAMMAD (S.A.W.) : CALL TO PROPHETHOOD", "question": "The Qur'an is to Muhammad (SAW) as suhuf is", "images": [], "options": {"A": "Yusuf(A.S)", "B": "Ibrahim (A.S)", "C": "Daud (A.S)", "D": "Isa(A.S)"}, "answer": "B", "explanation": "The Quran is to Muhammad (SAW) as Suhuf is to Ibrahim (A.S). The suhuf Ibrahim (scroll of Abraham) was an early scripture now lost. It taught muslims what Allah revealed to prophet Ibrahim", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2021>6", "subject": "IRK", "year": "2021", "type": "Objective", "topic": "TAHARAH (PURIFICATION) : AT-TAYAMMUM", "question": "Tayammum is performed by muslims when", "images": [], "options": {"A": "He wants to join a congregational prayer", "B": "he is in a hurry to perform prayer", "C": "access to water is very difficult", "D": "Time of the prayer has elapsed"}, "answer": "C", "explanation": "Tayammum is a dry ablution in Islamic ritual purification for prayer, which involves the use of clean soil or dust when water is not available or cannot be used for reasons such as illness. Therefore, the correct answer is 'access to water is very difficult'.", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2021>7", "subject": "IRK", "year": "2021", "type": "Objective", "topic": "TAHARAH (PURIFICATION) : AL-GHUSL", "question": "The type of ghust performed by a new convert to islam is", "images": [], "options": {"A": "Haydah", "B": "Nifas", "C": "Dukhil al-islam", "D": "Janabah"}, "answer": "C", "explanation": "When a person converts to Islam, they are required to perform a full body ritual purification known as Ghusl. The specific type of Ghusl performed by a new convert to Islam is called 'Dukhil al-Islam'. Therefore, the correct answer is 'Dukhil al-Islam'.", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2021>8", "subject": "IRK", "year": "2021", "type": "Objective", "topic": "HADITH : THE SIX SOUND COLLECTIONS OF HADITH (SIHAUS-SITTAH) AND THEIR COMPILERS.", "question": "The work of Imam Bukhari and al-Tirimidhi are both called", "images": [], "options": {"A": "Musamaf", "B": "jami", "C": "Sunan", "D": "Ahkam"}, "answer": "A", "explanation": "The work of Imam Bukhari and al-Timidhi are both called Musamaf", "marks": "1", "difficulty": "3"}, {"id": "objective>IRK>2021>9", "subject": "IRK", "year": "2021", "type": "Objective", "topic": "IMAN (FAITH) : THE DAY OF RESURRECTION, JUDGEMENT: ETERNAL LIFE Q 20: 15:32:10-20: 36: 78-70; 75: 3-13.", "question": "Al-Akhirah is hereafter as Al-Qiyamah is to", "images": [], "options": {"A": "resurrection", "B": "paradise", "C": "destiny", "D": "Hell"}, "answer": "A", "explanation": "Al-Qiyamah meaning \"The resurrection \" or \"the rising of the dead \" is the 75th chapter of the Quran with 40 verses", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2021>10", "subject": "IRK", "year": "2021", "type": "Objective", "topic": "SALAT : SUJUDUS-SAHWI (PROSTRATION OF FORGETFULNESS.)", "question": "Subhana rabbiyal-A'lafaghfirli is recited when the worshiper is at", "images": [], "options": {"A": "sujud", "B": "rurku", "C": "qiyam", "D": "julus"}, "answer": "A", "explanation": "Subhana rabbiyal-A'lafaghfirli is recited when the worshiper is at sujud (prostration). In Islamic prayer, sujud is the act of low bowing or prostration to Allah. During sujud, Muslims say 'Subhana Rabbiyal A'la' (Glory be to my Lord, the Most High) and also ask for forgiveness.", "marks": "1", "difficulty": "1"}, {"id": "objective>IRK>2021>11", "subject": "IRK", "year": "2021", "type": "Objective", "topic": "HADITH : CLASSIFICATION OF HADITH: SAHIH, HASAN AND DA‘IF.", "question": "An hadith is referred to a diaf because", "images": [], "options": {"A": "it is sometimes supported with evidence", "B": "all it transmitters are reliable", "C": "it has defects in its ismad and matn", "D": "it is a fabricated tradition"}, "answer": "D", "explanation": "An hadth is referred to as daif because it is weak and fabricated", "marks": "1", "difficulty": "3"}, {"id": "objective>IRK>2021>12", "subject": "IRK", "year": "2021", "type": "Objective", "topic": "QUR’AN : READING (IN EITHER ARABIC TEXT OR TRANSLITERATION), MEMORIZATION, MEANING OF THE FOLLOWING SUWAR AND THE LESSONS LEARNT FROM THEM (IDENTIFICATION, EXPLANATION, INTERPRETATION AND APPLICATION)", "question": "Birabbil - Falaq in Quran 113 means", "images": [], "options": {"A": "lord of the daybreak", "B": "from the evil of dark", "C": "From the enviers that envies", "D": "Lord of the mankind"}, "answer": "A", "explanation": "Birabbil - Falaq in Quran 113 translates to 'Lord of the Daybreak'. This is a reference to God as the one who brings forth light and dispels darkness, symbolizing the divine power to bring about good and ward off evil.", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2021>13", "subject": "IRK", "year": "2021", "type": "Objective", "topic": "IMAN (FAITH) : ARTICLES OF FAITH: BELIEF IN ALLAH WITH EMPHASIS ON KALIMATUSH-SHAHADAH(Q2: 163 AND 255; 3:18;17:42-43;21: 22 ; 23: 91 Q. 112, ISLAM AND THE CONCEPT OF TRINITY (Q.4:171; 5:75 – 76; 19:92-3; 112).", "question": "Which if the following is not amonged the articles of faith ? belief in the", "images": [], "options": {"A": "angels", "B": "prophets", "C": "scriptures", "D": "miracles"}, "answer": "D", "explanation": "The six articles of faith in islmam includes :  - Belief in the existence of oneness of God   - Belief in the existence of oneness of scriptures  - Belief in the existence of oneness of prophets   - Belief in the existence of oneness of angels   - Belief in the existence of oneness of judgement day  - Belief in the existence of oneness of God's predestination", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2021>14", "subject": "IRK", "year": "2021", "type": "Objective", "topic": "QUR’AN : PRESERVATION OF THE QUR’AN: COMPLETE ARRANGEMENT INCLUDING DISTINCTION BETWEEN MAKKI AND MADANI SUWAR; RECORDING; COMPILATION; STANDARDIZATION: ROLES PLAYED BY THE COMPANIONS OF THE PROPHET (S.A.W.) IN THE PRESERVATION OF THE QUR’AN.", "question": "Lawhul - Mahfudh is associated  with Quran", "images": [], "options": {"A": "recitation", "B": "memorization", "C": "preservation", "D": "compilation"}, "answer": "C", "explanation": "It is associated with Qur'anic preservation.   They believe that the divine destiny is when God wrote down in the Preserved Tablet (\"al-Lawhu 'l-Mahfuz\") all that has happened and will happen, which will come to pass as written. ... In the Quran, God explicitly states that He will \"write\" the good for those who do righteous deeds.", "marks": "1", "difficulty": "3"}, {"id": "objective>IRK>2021>15", "subject": "IRK", "year": "2021", "type": "Objective", "topic": "QUR’AN : READING (IN EITHER ARABIC TEXT OR TRANSLITERATION), MEMORIZATION, MEANING OF THE FOLLOWING SUWAR AND THE LESSONS LEARNT FROM THEM (IDENTIFICATION, EXPLANATION, INTERPRETATION AND APPLICATION)", "question": "The unity of Allah is expressed in suratul", "images": [], "options": {"A": "Kafirun", "B": "Ikhlas", "C": "Falaq", "D": "Qadr"}, "answer": "B", "explanation": "The unity of Allah, also known as Tawhid, is expressed in Suratul Ikhlas. This Surah of the Quran is often translated as 'The Purity' or 'The Sincerity' and it emphasizes the oneness and singularity of Allah. The other Surahs listed do not focus on this concept.", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2021>16", "subject": "IRK", "year": "2021", "type": "Objective", "topic": "HADITH : CLASSIFICATION OF HADITH: SAHIH, HASAN AND DA‘IF.", "question": "The following are classification of Hadith excepts", "images": [], "options": {"A": "hasan", "B": "mawdu", "C": "sahih", "D": "daif"}, "answer": "B", "explanation": "The term that does not fit within the standard classifications of Hadith in the context given is Mawdu. While it is related to Hadith studies, it represents a classification of Hadith that is not authentic rather than a classification of authentic Hadith.", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2021>17", "subject": "IRK", "year": "2021", "type": "Objective", "topic": "THE LIFE OF PROPHET MUHAMMAD (S.A.W.) : MARRIAGE", "question": "Khadijah married Muhammad (SAW) at the age of", "images": [], "options": {"A": "50", "B": "40", "C": "30", "D": "25"}, "answer": "D", "explanation": "she married the prophet Mohammed  (SAW) at the age of 25", "marks": "1", "difficulty": "1"}, {"id": "objective>IRK>2021>18", "subject": "IRK", "year": "2021", "type": "Objective", "topic": "SALAT : KINDS OF SALAT AND HOW THEY ARE OBSERVED", "question": "Which of the following prayers is not observed by Isha and Fajr", "images": [], "options": {"A": "Tahajjud", "B": "Shafi", "C": "Witr", "D": "Istisqa"}, "answer": "D", "explanation": "Istisqa is a prayer for rain in the religion of Islam. This is not a prayer that is observed by Isha and Fajr. Isha and Fajr are specific times of day for Muslim prayer. Tahajjud, Shafi, and Witr are types of prayers that can be observed during these times.", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2021>19", "subject": "IRK", "year": "2021", "type": "Objective", "topic": "IMAN (FAITH) : ARTICLES OF FAITH: BELIEF IN ALLAH WITH EMPHASIS ON KALIMATUSH-SHAHADAH(Q2: 163 AND 255; 3:18;17:42-43;21: 22 ; 23: 91 Q. 112, ISLAM AND THE CONCEPT OF TRINITY (Q.4:171; 5:75 – 76; 19:92-3; 112).", "question": "Malik yawmid-Din translated as", "images": [], "options": {"A": "The Beneficient , the merciful", "B": "Praise be to Allah, the lord of the worlds", "C": "The king of the day of judgment", "D": "Guide us to the right path"}, "answer": "C", "explanation": "Malik yawmid-Din is a phrase from Surah Al-Fatiha in the Quran, which is translated as 'The king of the day of judgment'. The other options are translations of other phrases from the same Surah, but they do not match the given Arabic phrase.", "marks": "1", "difficulty": "3"}, {"id": "objective>IRK>2021>20", "subject": "IRK", "year": "2021", "type": "Objective", "topic": "HADITH : READING (IN EITHER THE ARABIC TEXT OR TRANSLITERATION). MEMORIZATION, MEANING OF THE FOLLOWING AHADITH AND LESSONS LEARNT FROM THEM (IDENTIFICATION, EXPLANATION, INTERPRETATION AND APPLICATION): AN-NAWAWI’S COLLECTION. 1, 5, 7, 9, 13, 15,16,18,34 AND 41.", "question": "The weakest faith acording to Hadith 34 of an-Nawam is changing an evil with the", "images": [], "options": {"A": "hand", "B": "leg", "C": "heart", "D": "Tongue"}, "answer": "C", "explanation": "the weakest of the faith according to the Hadith 34 of an-Nawawi is changing an evil with the heart   \"Whosoever of you sees an evil action , let him change it with his hand and if he is not able to do so , then with his tongue and if he is not able to do so , the with heart, and that is the weakest of faith \"", "marks": "1", "difficulty": "3"}, {"id": "objective>IRK>2021>21", "subject": "IRK", "year": "2021", "type": "Objective", "topic": "THE LIFE OF PROPHET MUHAMMAD (S.A.W.) : MARRIAGE", "question": "The last child of prophet Mohammad (SAW) is", "images": [], "options": {"A": "Zaynab", "B": "Tahir", "C": "Ruquayyah", "D": "ibrahim"}, "answer": "D", "explanation": "The last child of Prophet Mohammad (SAW) was Ibrahim, who was born to Maria al-Qibtiyya. He lived for about 16 to 18 months and then died. Zaynab, Tahir, and Ruquayyah were also children of Prophet Mohammad (SAW), but they were not his last child.", "marks": "1", "difficulty": "1"}, {"id": "objective>IRK>2021>22", "subject": "IRK", "year": "2021", "type": "Objective", "topic": "TALAQ ( DIVORCE) : KINDS", "question": "Talaq al - Bodah takes efforts when divorce is pronounced", "images": [], "options": {"A": "three times simultaneously", "B": "verbally or in writing", "C": "When the wife is still in her marital home", "D": "when the wife is still in her marital menes"}, "answer": "A", "explanation": "Talaq al-Bidah or 'innovative divorce' is a divorce practice in Islam where the husband pronounces divorce three times in one sitting or occasion. This practice is considered to be against the spirit of Islamic law because it does not provide the wife with an opportunity for reconciliation. Therefore, the correct answer is 'three times simultaneously'.", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2021>23", "subject": "IRK", "year": "2021", "type": "Objective", "topic": "QUR’AN : PRESERVATION OF THE QUR’AN: COMPLETE ARRANGEMENT INCLUDING DISTINCTION BETWEEN MAKKI AND MADANI SUWAR; RECORDING; COMPILATION; STANDARDIZATION: ROLES PLAYED BY THE COMPANIONS OF THE PROPHET (S.A.W.) IN THE PRESERVATION OF THE QUR’AN.", "question": "Thhe Qur'an was initially preserved on the following except", "images": [], "options": {"A": "leather", "B": "rock", "C": "memory", "D": "paper"}, "answer": "B", "explanation": "While the Qur'an was preserved on leather, through memory, and on paper, it was not preserved on rock. Thus, \"rock\" is the exception in this context.", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2021>24", "subject": "IRK", "year": "2021", "type": "Objective", "topic": "THE LIFE OF PROPHET MUHAMMAD (S.A.W.) : THE BATTLES: BADR, UHUD AND KHANDAQ. (CAUSES, COURSES AND EFFECTS.)", "question": "The fifty muslim archers at the battle of Uhud were instructed to", "images": [], "options": {"A": "pay homage to the prophet (SAW)", "B": "stay there and should not leave", "C": "attach the enemies when facing them", "D": "strike first in order to gain war booty"}, "answer": "B", "explanation": "The archer (fifty of them) at the battle of Uhad were given instruction to stand still at their position and should not leave their post", "marks": "1", "difficulty": "3"}, {"id": "objective>IRK>2021>25", "subject": "IRK", "year": "2021", "type": "Objective", "topic": "HADITH : READING (IN EITHER THE ARABIC TEXT OR TRANSLITERATION). MEMORIZATION, MEANING OF THE FOLLOWING AHADITH AND LESSONS LEARNT FROM THEM (IDENTIFICATION, EXPLANATION, INTERPRETATION AND APPLICATION): AN-NAWAWI’S COLLECTION. 1, 5, 7, 9, 13, 15,16,18,34 AND 41.", "question": "The admonition in last part of Hadith 18 of an-Nawawi is", "images": [], "options": {"A": "good conduct", "B": "respect for one's daughter", "C": "control of one's temper", "D": "love for one another"}, "answer": "A", "explanation": "the last part of the Hadith 18 of an-Nawawi collectively admonishes muslims in the areas of their conduct which is expected to be good", "marks": "1", "difficulty": "3"}, {"id": "objective>IRK>2021>26", "subject": "IRK", "year": "2021", "type": "Objective", "topic": "THE JAHILIYYAH: ARABIA BEFORE ISLAM : RELIGIOUS LIFE – IDOL WORSHIP AND NAMES OF MAJOR GODS/IDOLS.", "question": "Which of the following was not a Jahilliyyah idol?", "images": [], "options": {"A": "al-manat", "B": "al-Uzzah", "C": "al-lat", "D": "al-Jibl"}, "answer": "D", "explanation": "Jahilliyyah refers to the period of ignorance before the advent of Islam in Arabia. During this period, the Arabs worshipped several idols. Al-Manat, Al-Uzzah, and Al-Lat were three of the most revered idols among the Jahilliyyah. However, Al-Jibl was not a Jahilliyyah idol, making it the correct answer.", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2021>27", "subject": "IRK", "year": "2021", "type": "Objective", "topic": "NIKAH (MARRIAGE) : CONCEPT", "question": "Marriage relationship fulfil the following functions except", "images": [], "options": {"A": "sexual satisfaction", "B": "foundation of family life", "C": "Security at old age", "D": "quick means of getting rich"}, "answer": "D", "explanation": "Marriage is a social institution that fulfills several functions. It provides a means for sexual satisfaction within a socially acceptable framework, it forms the foundation of family life, and it offers security in old age. However, marriage is not a quick means of getting rich. This is not a universally accepted or primary function of marriage, making it the correct answer.", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2021>28", "subject": "IRK", "year": "2021", "type": "Objective", "topic": "QUR’AN : REVELATION OF THE QUR’AN: VISITS OF THE PROPHET (S.A.W.) TO CAVE HIRA ; FIRST REVELATION AND HIS REACTION TO IT, DIFFERENT MODES OF REVELATION, PIECEMEAL- REVELATION OF THE QUR’AN.", "question": "Iqra' warabbukal akam is followed by", "images": [], "options": {"A": "Iqra'bismi rabbikal-ladhi Khalaq", "B": "Alladhi alama  bil qalam", "C": "Khalaqal isana min alaq", "D": "Allama insana malam yal'am"}, "answer": "B", "explanation": "The phrase 'Iqra' warabbukal akam' is a part of the first revelation of the Quran to Prophet Muhammad. It is followed by 'Alladhi alama  bil qalam' which translates to 'Who taught by the pen'. This is found in Surah Al-Alaq (96:3).", "marks": "1", "difficulty": "3"}, {"id": "objective>IRK>2021>29", "subject": "IRK", "year": "2021", "type": "Objective", "topic": "HADITH : READING (IN EITHER THE ARABIC TEXT OR TRANSLITERATION). MEMORIZATION, MEANING OF THE FOLLOWING AHADITH AND LESSONS LEARNT FROM THEM (IDENTIFICATION, EXPLANATION, INTERPRETATION AND APPLICATION): AN-NAWAWI’S COLLECTION. 1, 5, 7, 9, 13, 15,16,18,34 AND 41.", "question": "The following are lessons of Hadith 5 of an-Nawawi except", "images": [], "options": {"A": "condemnation of devilish innovations", "B": "rejection of fabrication", "C": "abolition od usury", "D": "banning of illegal acts"}, "answer": "B", "explanation": "The lesson of the rejection of fabrication is not entrenched in Hadith number 5 of an-Nawawi collections", "marks": "1", "difficulty": "3"}, {"id": "objective>IRK>2021>30", "subject": "IRK", "year": "2021", "type": "Objective", "topic": "THE JAHILIYYAH: ARABIA BEFORE ISLAM : ECONOMIC LIFE – SOURCES OF LIVELIHOOD", "question": "The main reason of transport used by the Arabs in the desert was", "images": [], "options": {"A": "Camel", "B": "cattle", "C": "horse", "D": "Donkey"}, "answer": "A", "explanation": "The main mode of transport used by the Arabs in the desert was the camel. This is because camels are well adapted to the harsh desert conditions. They can go for long periods without water and food, and their bodies are designed to withstand high temperatures. They also have wide, tough feet that prevent them from sinking into the sand.", "marks": "1", "difficulty": "1"}, {"id": "objective>IRK>2021>31", "subject": "IRK", "year": "2021", "type": "Objective", "topic": "HADITH : READING (IN EITHER THE ARABIC TEXT OR TRANSLITERATION). MEMORIZATION, MEANING OF THE FOLLOWING AHADITH AND LESSONS LEARNT FROM THEM (IDENTIFICATION, EXPLANATION, INTERPRETATION AND APPLICATION): AN-NAWAWI’S COLLECTION. 1, 5, 7, 9, 13, 15,16,18,34 AND 41.", "question": "Reference is made to migration of 622C.E in  an-Nawawi's Hadith", "images": [], "options": {"A": "1", "B": "5", "C": "7", "D": "9"}, "answer": "A", "explanation": "Hadith no 1 made reference to the migraton of 622 C.E (Hijrah to madenah from makkah)", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2021>32", "subject": "IRK", "year": "2021", "type": "Objective", "topic": "THE LIFE OF PROPHET MUHAMMAD (S.A.W.) : THE BATTLES: BADR, UHUD AND KHANDAQ. (CAUSES, COURSES AND EFFECTS.)", "question": "The number of Makkan soldiers that part of the battle of Udud was", "images": [], "options": {"A": "1000", "B": "2000", "C": "3000", "D": "4000"}, "answer": "C", "explanation": "3000 makkah soldiers took part in the battle ot the uhud", "marks": "1", "difficulty": "3"}, {"id": "objective>IRK>2021>33", "subject": "IRK", "year": "2021", "type": "Objective", "topic": "SALAT : KINDS OF SALAT AND HOW THEY ARE OBSERVED", "question": "The total number of rak'ah in Zuhr', Asr and Isha is", "images": [], "options": {"A": "17", "B": "5", "C": "12", "D": "11"}, "answer": "C", "explanation": "There is a total of 12 rak'ah in zuhr'Asr and isha", "marks": "1", "difficulty": "1"}, {"id": "objective>IRK>2021>34", "subject": "IRK", "year": "2021", "type": "Objective", "topic": "IMAN (FAITH) : ARTICLES OF FAITH: BELIEF IN ALLAH WITH EMPHASIS ON KALIMATUSH-SHAHADAH(Q2: 163 AND 255; 3:18;17:42-43;21: 22 ; 23: 91 Q. 112, ISLAM AND THE CONCEPT OF TRINITY (Q.4:171; 5:75 – 76; 19:92-3; 112).", "question": "Alayasal-LLahu bi Ahkamil-Hakimin implies that Allah is the best", "images": [], "options": {"A": "judge", "B": "creator", "C": "fashioner", "D": "Architect"}, "answer": "A", "explanation": "The phrase 'Alayasal-LLahu bi Ahkamil-Hakimin' is an Arabic phrase that translates to 'Is not Allah the best of judges?' in English. Therefore, it implies that Allah is the best judge.", "marks": "1", "difficulty": "3"}, {"id": "objective>IRK>2021>35", "subject": "IRK", "year": "2021", "type": "Objective", "topic": "THE LIFE OF PROPHET MUHAMMAD (S.A.W.) : HIJRAH", "question": "The first pledge of Aqbah was signed in", "images": [], "options": {"A": "610 C.E", "B": "621 C.E", "C": "628 C.E", "D": "630 C.E"}, "answer": "B", "explanation": "The first pledge of Aqabah took place in 621 C.E. This was when twelve men from Madinah pledged their support to Prophet Muhammad during the Hajj season. This event is significant as it marked the beginning of the Muslim community in Madinah.", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2021>36", "subject": "IRK", "year": "2021", "type": "Objective", "topic": "SALAT : MEANING AND IMPORTANCE", "question": "A rak'ah in salat starts with", "images": [], "options": {"A": "Qiyam bi Itidal", "B": "Takbiratul-Ihram", "C": "Ruhu", "D": "sujur"}, "answer": "B", "explanation": "A rak'ah in salat starts with Takbiratul-Ihram. This is the initial 'Allahu Akbar' that begins the prayer. Qiyam bi Itidal is the standing position in prayer, Ruhu is the bowing position, and sujur is the prostration position.", "marks": "1", "difficulty": "1"}, {"id": "objective>IRK>2021>37", "subject": "IRK", "year": "2021", "type": "Objective", "topic": "HADITH : THE SIX SOUND COLLECTIONS OF HADITH (SIHAUS-SITTAH) AND THEIR COMPILERS.", "question": "The tradtionalist who died in Qazwin in 273 C.E was", "images": [], "options": {"A": "Tirmidhi", "B": "Ibn majah", "C": "Abu Daud", "D": "Muslim"}, "answer": "D", "explanation": "Al-Bukhari is best known for compiling one of the most authentic collections of Hadith in Islam, known as Sahih al-Bukhari.  He dedicated a significant portion of his life to the collection, verification, and compilation of Hadiths, traveling extensively to gather them from various sources.   His work has been highly regarded in the Muslim community for its rigorous standards of authenticity, and it remains one of the foundational texts in Islamic scholarship.", "marks": "1", "difficulty": "3"}, {"id": "objective>IRK>2021>38", "subject": "IRK", "year": "2021", "type": "Objective", "topic": "THE LIFE OF PROPHET MUHAMMAD (S.A.W.) : BIRTH", "question": "The prophet's uncle who succeded Abu Talib as the head of Banu Hashum was", "images": [], "options": {"A": "Abbas", "B": "Hamzah", "C": "Abu Jahl", "D": "Abdullah"}, "answer": "B", "explanation": "Hamzah was the prophet's uncle wh succeeded Abu Talib as the head of Banu Hashum", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2021>39", "subject": "IRK", "year": "2021", "type": "Objective", "topic": "NIKAH (MARRIAGE) : CONCEPT", "question": "The following nullifies an islamic marriage if not fulfilled except", "images": [], "options": {"A": "payment of dowry", "B": "consent of parents", "C": "proposal and acceptance", "D": "marriage feast"}, "answer": "D", "explanation": "In Islamic law, there are certain conditions that must be fulfilled for a marriage to be considered valid. These include the payment of dowry, proposal and acceptance, and the consent of the bride's guardian. However, the marriage feast (Walima) is not a condition for the validity of the marriage, but it is a Sunnah (recommended act). Therefore, the absence of a marriage feast does not nullify an Islamic marriage.", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2021>40", "subject": "IRK", "year": "2021", "type": "Objective", "topic": "THE LIFE OF PROPHET MUHAMMAD (S.A.W.) : CALL TO PROPHETHOOD", "question": "The first Mu'adh - Dhin in islma is", "images": [], "options": {"A": "Bilal", "B": "maysarah", "C": "Amr", "D": "Hamzah"}, "answer": "A", "explanation": "The first Mu'adh-Dhin (caller to prayer) in Islam was Bilal ibn Rabah. He was a companion of the Prophet Muhammad and is best known for his beautiful and emotional call to prayer. He was chosen by the Prophet himself for this important role due to his strong faith and beautiful voice.", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2021>41", "subject": "IRK", "year": "2021", "type": "Objective", "topic": "HADITH : READING (IN EITHER THE ARABIC TEXT OR TRANSLITERATION). MEMORIZATION, MEANING OF THE FOLLOWING AHADITH AND LESSONS LEARNT FROM THEM (IDENTIFICATION, EXPLANATION, INTERPRETATION AND APPLICATION): AN-NAWAWI’S COLLECTION. 1, 5, 7, 9, 13, 15,16,18,34 AND 41.", "question": "Which of the following is not contained in Hadith 15 of an-Nawawi?", "images": [], "options": {"A": "honouring one's guest", "B": "speaking the truth always", "C": "respecting one's neighbour", "D": "consciousness of Allah in all places"}, "answer": "D", "explanation": "Hadith 15 of an - Nawawi does not teach consciousness of Allah in all places", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2021>42", "subject": "IRK", "year": "2021", "type": "Objective", "topic": "THE LIFE OF PROPHET MUHAMMAD (S.A.W.) : BIRTH", "question": "The young Muhammad(SAW) was taken to Ka'bah for prayer by", "images": [], "options": {"A": "Abdullah", "B": "Abu Jahl", "C": "Abdul Myttalib", "D": "Hamzah"}, "answer": "C", "explanation": "The young Muhammad (SAW) was taken to Ka'bah for prayer by his grandfather Abdul Muttalib. Abdul Muttalib was the guardian of Muhammad (SAW) after the death of his parents.", "marks": "1", "difficulty": "1"}, {"id": "objective>IRK>2021>43", "subject": "IRK", "year": "2021", "type": "Objective", "topic": "QUR’AN : PRESERVATION OF THE QUR’AN: COMPLETE ARRANGEMENT INCLUDING DISTINCTION BETWEEN MAKKI AND MADANI SUWAR; RECORDING; COMPILATION; STANDARDIZATION: ROLES PLAYED BY THE COMPANIONS OF THE PROPHET (S.A.W.) IN THE PRESERVATION OF THE QUR’AN.", "question": "Which of the following is a characteristic of Makkan suwar ?", "images": [], "options": {"A": "long substance", "B": "curtain criminal injunction", "C": "Historical narrations", "D": "poetic rythm"}, "answer": "C", "explanation": "Historical narrations are intrinsic  properties of Makkan suwar", "marks": "1", "difficulty": "3"}, {"id": "objective>IRK>2021>44", "subject": "IRK", "year": "2021", "type": "Objective", "topic": "HADITH : READING (IN EITHER THE ARABIC TEXT OR TRANSLITERATION). MEMORIZATION, MEANING OF THE FOLLOWING AHADITH AND LESSONS LEARNT FROM THEM (IDENTIFICATION, EXPLANATION, INTERPRETATION AND APPLICATION): AN-NAWAWI’S COLLECTION. 1, 5, 7, 9, 13, 15,16,18,34 AND 41.", "question": "The central theme of Hadith 41 of an-Nawawi is", "images": [], "options": {"A": "total submission to Allah", "B": "good neighbourliness", "C": "honesty and transparency", "D": "avoidance of anger"}, "answer": "A", "explanation": "The central theme of hadith 41 is total submission to Allah  . The hadith teaches that every believer is obliged to be subservient  to Allah", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2021>45", "subject": "IRK", "year": "2021", "type": "Objective", "topic": "THE LIFE OF PROPHET MUHAMMAD (S.A.W.) : MARRIAGE", "question": "A'isha was distinct from other wives of the prophet  (SAW) because she", "images": [], "options": {"A": "was the oldest of his wives", "B": "lived longer than his other wives", "C": "was married as a virgin", "D": "gave him employment"}, "answer": "C", "explanation": "Aisha was married to the prophet (SAW) as a virgin and this is what sets her apart from the other wives", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2021>46", "subject": "IRK", "year": "2021", "type": "Objective", "topic": "QUR’AN : THE QUR’AN AS A SOURCE OF GUIDANCE IN SOCIAL, POLITICAL, SPIRITUAL AND MORAL MATTERS", "question": "The Qur'an is referred to as al-hukum because it", "images": [], "options": {"A": "reminds one of his duties", "B": "guides a muslim to his right path", "C": "provides direction to judgement", "D": "is revealed from Allah"}, "answer": "C", "explanation": "The Qur'an is referred to as al-hukum because it provides direction to judgement. The term 'al-hukum' in Arabic refers to judgement or law. The Qur'an, being the holy book of Islam, provides guidelines and laws that Muslims are to follow, hence it is referred to as al-hukum.", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2021>47", "subject": "IRK", "year": "2021", "type": "Objective", "topic": "HADITH : READING (IN EITHER THE ARABIC TEXT OR TRANSLITERATION). MEMORIZATION, MEANING OF THE FOLLOWING AHADITH AND LESSONS LEARNT FROM THEM (IDENTIFICATION, EXPLANATION, INTERPRETATION AND APPLICATION): AN-NAWAWI’S COLLECTION. 1, 5, 7, 9, 13, 15,16,18,34 AND 41.", "question": "The hadith of an-Nawawi that admonishes a muslim  to love his brothers as himself is number", "images": [], "options": {"A": "7", "B": "9", "C": "13", "D": "16"}, "answer": "C", "explanation": "The main lesson in hadith 13 of an-Nawawi's collections is that we should have our brothers as ourselves", "marks": "1", "difficulty": "3"}, {"id": "objective>IRK>2021>48", "subject": "IRK", "year": "2021", "type": "Objective", "topic": "THE LIFE OF PROPHET MUHAMMAD (S.A.W.) : LEADERSHIP QUALITIES OF THE PROPHET", "question": "Muhammad (SAW) was referred to as al-Amin because he was", "images": [], "options": {"A": "honest", "B": "patient", "C": "trustworthy", "D": "humble"}, "answer": "C", "explanation": "Muhammad (SAW) was referred to as al-Amin, which means 'the trustworthy' in Arabic. This title was given to him by his people due to his honest and reliable character. Even before his prophethood, he was known for his truthfulness and trustworthiness.", "marks": "1", "difficulty": "1"}, {"id": "objective>IRK>2022>1", "subject": "IRK", "year": "2022", "type": "Objective", "topic": "HADITH : READING (IN EITHER THE ARABIC TEXT OR TRANSLITERATION). MEMORIZATION, MEANING OF THE FOLLOWING AHADITH AND LESSONS LEARNT FROM THEM (IDENTIFICATION, EXPLANATION, INTERPRETATION AND APPLICATION): AN-NAWAWI’S COLLECTION. 1, 5, 7, 9, 13, 15,16,18,34 AND 41.", "question": "The major teaching of Hadith 5 of an-Nawawi centres on", "images": [], "options": {"A": "intention", "B": "faith", "C": "innovation", "D": "worship"}, "answer": "C", "explanation": "The major teaching of Hadith 5 of an-Nawawi collection focus on innovation.   Hadith 5 On the authority of the mother of the faithful, 'Aisha (may Allah be pleased with her), who said: The Messenger of Allah (peace be upon him) said:  He who innovates something in this matter of ours [Islam] that is not of it will have it rejected [by Allah].", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2022>2", "subject": "IRK", "year": "2022", "type": "Objective", "topic": "HAJJ (PILGRIMAGE) : RITES OF HAJJ", "question": "The state into which the pilgrim enters before the time of Hajj is", "images": [], "options": {"A": "Ihram", "B": "Talbiyyah", "C": "Sa'y", "D": "Tawaf"}, "answer": "A", "explanation": "The first rite of Hajj is entering ihram - a pilgrim's sacred state - when crossing the outer boundaries of Mecca called Miqat.", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2022>3", "subject": "IRK", "year": "2022", "type": "Objective", "topic": "QUR’AN : READING (IN EITHER ARABIC TEXT OR TRANSLITERATION), MEMORIZATION, MEANING OF THE FOLLOWING SUWAR AND THE LESSONS LEARNT FROM THEM (IDENTIFICATION, EXPLANATION, INTERPRETATION AND APPLICATION)", "question": "The major teaching in Surah an-Nasr(Q. 110) is that", "images": [], "options": {"A": "man must strive to succeed in life", "B": "death is inevitable", "C": "Islam has a bright future", "D": "after difficulty comes ease"}, "answer": "C", "explanation": "Surah Nasr is one of the short surahs in the Quran that are knoen as Mufassalat. The surah praises Allah for leading numerous people to Islam. This surah is also known as \"The Victory\" as in the victory of Islam as it refers to the conquest of Mecca where Muslims beat the enemies of Islam.", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2022>4", "subject": "IRK", "year": "2022", "type": "Objective", "topic": "THE JAHILIYYAH: ARABIA BEFORE ISLAM : RELIGIOUS LIFE – IDOL WORSHIP AND NAMES OF MAJOR GODS/IDOLS.", "question": "The goddess of Jahiliyyah Arabs exclude", "images": [], "options": {"A": "al-Lat", "B": "al-Manat", "C": "al-Uzzah", "D": "as-sanat"}, "answer": "D", "explanation": "The Jahiliyyah Arabs worshipped three main goddesses: al-Lat, al-Manat, and al-Uzzah. These goddesses were considered the daughters of Allah. However, as-sanat is not recognized as a goddess by the Jahiliyyah Arabs. Therefore, the correct answer is as-sanat.", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2022>5", "subject": "IRK", "year": "2022", "type": "Objective", "topic": "NIKAH (MARRIAGE) : PROHIBITED CATEGORIES", "question": "A muslim is only permitted to marry his", "images": [], "options": {"A": "foster mother", "B": "late father-wife", "C": "foster sister", "D": "late wife's sister"}, "answer": "D", "explanation": "A Muslim is only permitted to marry his late wife's sister.", "marks": "1", "difficulty": "3"}, {"id": "objective>IRK>2022>6", "subject": "IRK", "year": "2022", "type": "Objective", "topic": "HADITH : CLASSIFICATION OF HADITH: SAHIH, HASAN AND DA‘IF.", "question": "In the science of Hadith, the next Sahih on authenticity is", "images": [], "options": {"A": "Qudsi", "B": "Da'if", "C": "Hasan", "D": "Muttasil"}, "answer": "C", "explanation": "In the science of Hadith, the next Sahih on authenticity is Hasan.    Note that there are three primary ways to determine the authenticity(sihha) of a hadith: by attempting to determine whether there are \"other identical reports from other transmitters\", determining the reliability of the transmitters of the report; and the continuity of the chain of transmission of the hadith.", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2022>7", "subject": "IRK", "year": "2022", "type": "Objective", "topic": "SAWM (FASTING) : BENEFITS/SIGNIFICANCE OF SAWM—SPIRITUAL, SOCIAL AND MORAL.", "question": "Attainment of Allah's consciousness through fasting is mentioned in Qur'an 2 verse", "images": [], "options": {"A": "183", "B": "193", "C": "285", "D": "286"}, "answer": "A", "explanation": "(2:183) Believers! Fasting is enjoined upon you, as it was enjoined upon those before you, that you become God-fearing.", "marks": "1", "difficulty": "3"}, {"id": "objective>IRK>2022>8", "subject": "IRK", "year": "2022", "type": "Objective", "topic": "THE LIFE OF PROPHET MUHAMMAD (S.A.W.) : HIJRAH", "question": "When Muhammad(S.A.W.) sought for protection in Ta'if in 620 C.E. he was", "images": [], "options": {"A": "received joyously by the people", "B": "stoned by the people of Ta'if", "C": "allowed to stay for few days", "D": "granted a conditional permit"}, "answer": "B", "explanation": "By rejecting Muhammad's religion, the people of Ta'if ordered their children to throw rocks and stones at Muhammad and Zayn ibn Harithah to make them leave the city and never come back.", "marks": "1", "difficulty": "3"}, {"id": "objective>IRK>2022>9", "subject": "IRK", "year": "2022", "type": "Objective", "topic": "HADITH : THE SIX SOUND COLLECTIONS OF HADITH (SIHAUS-SITTAH) AND THEIR COMPILERS.", "question": "Imam an-Nasa'l spent his days in", "images": [], "options": {"A": "Mkkah", "B": "Khurasan", "C": "Bukhara", "D": "Sijistan"}, "answer": "B", "explanation": "Imam an-Nasa'i, a noted collector of hadith (sayings and actions of Prophet Muhammad), spent most of his life in Khurasan. He was born in Nasa, a city in Khurasan, and travelled extensively through the Islamic world to collect hadith. He eventually settled in Khurasan, where he spent his remaining days.", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2022>10", "subject": "IRK", "year": "2022", "type": "Objective", "topic": "SAWM (FASTING) : THOSE EXEMPTED FROM FAST", "question": "Permanent exemption from Ramadan fast may be occasioned by", "images": [], "options": {"A": "old age", "B": "breastfeeding", "C": "menstruation", "D": "pregnancy"}, "answer": "A", "explanation": "Even though fasting in Ramadan is mandatory upon every functional and able Muslim, Allah Almighty has pardoned and excused certain people from the act of fasting if they are unable to fast due to certain legitimate reasons. Individuals facing senility and old age are essentially exempt from fasting. With old age comes weakness, terminal illnesses, loss of mental faculties and extreme fragility, hence, it is believed that people in their old age are not required to fast at the cost of their health.", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2022>11", "subject": "IRK", "year": "2022", "type": "Objective", "topic": "QUR’AN : READING (IN EITHER ARABIC TEXT OR TRANSLITERATION), MEMORIZATION, MEANING OF THE FOLLOWING SUWAR AND THE LESSONS LEARNT FROM THEM (IDENTIFICATION, EXPLANATION, INTERPRETATION AND APPLICATION)", "question": "The following Suwar begin with divine command to the Prophet except Surah", "images": [], "options": {"A": "an-Nas", "B": "al-Falaq", "C": "al-Kafirun", "D": "ad-Duha"}, "answer": "D", "explanation": "Suratu ad-Dua did not begin with divine commandment to the Prophet. Surah Ad-Duha was revealed to the Prophet(S.A.W.)bto relieve him of these negative feelings and to give him hope, positivity and the assurance that Allah is with him no matter what.", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2022>12", "subject": "IRK", "year": "2022", "type": "Objective", "topic": "SHIRK : WORSHIP OF IDOLS (Q.4:48:22:31:31:13:41:37)", "question": "Which of the following is not a form of shirk according to the Qur'an?", "images": [], "options": {"A": "Trinity", "B": "Polytheism", "C": "Atheism", "D": "Monotheism"}, "answer": "D", "explanation": "Shirk in Islam refers to the sin of practicing idolatry or polytheism, i.e., the deification or worship of anyone or anything other than the singular God, Allah. Therefore, Trinity and Polytheism are forms of shirk. Atheism, although not a form of shirk, is also not in line with Islamic teachings. However, Monotheism, which is the belief in one God, is the fundamental belief in Islam and is not a form of shirk.", "marks": "1", "difficulty": "3"}, {"id": "objective>IRK>2022>13", "subject": "IRK", "year": "2022", "type": "Objective", "topic": "HADITH : READING (IN EITHER THE ARABIC TEXT OR TRANSLITERATION). MEMORIZATION, MEANING OF THE FOLLOWING AHADITH AND LESSONS LEARNT FROM THEM (IDENTIFICATION, EXPLANATION, INTERPRETATION AND APPLICATION): AN-NAWAWI’S COLLECTION. 1, 5, 7, 9, 13, 15,16,18,34 AND 41.", "question": "A major lesson contained in Hadith 16 of an-Nawawi is", "images": [], "options": {"A": "ability to control anger", "B": "unnecessary questioning", "C": "having good intentions", "D": "sincerity in faith"}, "answer": "A", "explanation": "Hadith 16    On the authority of Abu Hurayrah (may Allah be pleased with him): A man came to the Prophet (peace and blessings of Allah be upon him) and said, \"Advise me\" He [the Prophet (peace and blessings of Allah be upon him) said, \"Do not become angry\" The man repeated [his request] several times and he [the Prophet (peace and blessings of Allah be upon him) said, \"Do not become angry\".", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2022>14", "subject": "IRK", "year": "2022", "type": "Objective", "topic": "NIKAH (MARRIAGE) : CONCEPT", "question": "Which of this is an exclusive obligation of the husband?", "images": [], "options": {"A": "Provision of shelter", "B": "Counselling", "C": "Provision of job", "D": "Domestic support"}, "answer": "C", "explanation": "Islam obliges the husband to exclusively provide job in the family.", "marks": "1", "difficulty": "1"}, {"id": "objective>IRK>2022>15", "subject": "IRK", "year": "2022", "type": "Objective", "topic": "QUR’AN : THE QUR’AN AS A SOURCE OF GUIDANCE IN SOCIAL, POLITICAL, SPIRITUAL AND MORAL MATTERS", "question": "Qur'an 24:32 is an injunction which", "images": [], "options": {"A": "discourages a Muslim from polygamy", "B": "commands Muslims to marry more than one wife", "C": "enjoins Muslims to marry righteous partners", "D": "allows Muslims to divorce only when necessary"}, "answer": "C", "explanation": "Qur'an 24:32 is an injunction which enjoins Muslims to marry righteous partners      (24:32) Marry those of you that are single, (whether men or women), and those of your male and female slaves that are righteous. If they are poor, Allah will enrich them out of His Bounty. Allah is Immensely Resourceful, All-Knowing.", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2022>16", "subject": "IRK", "year": "2022", "type": "Objective", "topic": "QUR’AN : READING (IN EITHER ARABIC TEXT OR TRANSLITERATION), MEMORIZATION, MEANING OF THE FOLLOWING SUWAR AND THE LESSONS LEARNT FROM THEM (IDENTIFICATION, EXPLANATION, INTERPRETATION AND APPLICATION)", "question": "\"Lam Yalid wa lam yulad\" (Q112:3) is preceded by", "images": [], "options": {"A": "Qul Huwal-Lahu Ahad", "B": "Allah's Samad", "C": "Wa lam yakunl-Lahu kufuwan ahad", "D": "Lakum dinukum waliyadi"}, "answer": "B", "explanation": "Suratul Ikhlas    Bismillah hir rahman nir raheem  Qul huwal laahu ahad  Allah hus-samad  Lam yalid wa lam yoolad  Wa lam yakul-lahoo kufuwan ahad", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2022>17", "subject": "IRK", "year": "2022", "type": "Objective", "topic": "HADITH : READING (IN EITHER THE ARABIC TEXT OR TRANSLITERATION). MEMORIZATION, MEANING OF THE FOLLOWING AHADITH AND LESSONS LEARNT FROM THEM (IDENTIFICATION, EXPLANATION, INTERPRETATION AND APPLICATION): AN-NAWAWI’S COLLECTION. 1, 5, 7, 9, 13, 15,16,18,34 AND 41.", "question": "Which of the following is the greatest form of Jihad according to the Prophet(S.A.W.)?", "images": [], "options": {"A": "Performance of Hajj", "B": "Writing religious books", "C": "Suppressing one's selfish desires", "D": "Waging war in the course of Allah"}, "answer": "C", "explanation": "According to the Prophet, the greatest Jihad is to battle your own soul to fight the evil within yourself.", "marks": "1", "difficulty": "3"}, {"id": "objective>IRK>2022>18", "subject": "IRK", "year": "2022", "type": "Objective", "topic": "HADITH : READING (IN EITHER THE ARABIC TEXT OR TRANSLITERATION). MEMORIZATION, MEANING OF THE FOLLOWING AHADITH AND LESSONS LEARNT FROM THEM (IDENTIFICATION, EXPLANATION, INTERPRETATION AND APPLICATION): AN-NAWAWI’S COLLECTION. 1, 5, 7, 9, 13, 15,16,18,34 AND 41.", "question": "\"La taghdab\" in Hadith 16 means", "images": [], "options": {"A": "avoid vain talk", "B": "do not get angry", "C": "mind your own business", "D": "do not be jealous"}, "answer": "B", "explanation": "The Prophet, peace be upon him, was once asked by a man to give him advice. The Prophet told him, \"La taghdab!\" Which means, \"Don't be angry!\" But the man didn't listen, and kept on repeating his request. The Prophet, peace be upon him, just kept on telling him the same answer, \"Don't be angry!", "marks": "1", "difficulty": "1"}, {"id": "objective>IRK>2022>19", "subject": "IRK", "year": "2022", "type": "Objective", "topic": "QUR’AN : READING (IN EITHER ARABIC TEXT OR TRANSLITERATION), MEMORIZATION, MEANING OF THE FOLLOWING SUWAR AND THE LESSONS LEARNT FROM THEM (IDENTIFICATION, EXPLANATION, INTERPRETATION AND APPLICATION)", "question": "The Surah which begins with four oaths is", "images": [], "options": {"A": "ad-Duha", "B": "Alaq", "C": "al-Kaafirun", "D": "at-Tin"}, "answer": "D", "explanation": "The Surah which begins with four oaths is Surah at-Tin. The Surah starts with the oaths \"By the fig and the olive, And [by] Mount Sinai, And [by] this secure city [Makkah]\". Therefore, the correct answer is option 4.", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2022>20", "subject": "IRK", "year": "2022", "type": "Objective", "topic": "THE LIFE OF PROPHET MUHAMMAD (S.A.W.) : MARRIAGE", "question": "The Prophet lost his wife Khadija in the year", "images": [], "options": {"A": "610 C.E.", "B": "616 C.E.", "C": "617 C.E.", "D": "619 C.E."}, "answer": "D", "explanation": "Khadija died in 'Ramadan of the year 10 after the Prophethood', i.e., in November 619 CE. Muhammad later called this tenth year the 'Year of Sorrow', as his uncle and protector Abu Talib also died at this time. Khadija is said to have been about 65 years old at the time of her death.", "marks": "1", "difficulty": "3"}, {"id": "objective>IRK>2022>21", "subject": "IRK", "year": "2022", "type": "Objective", "topic": "HADITH : CLASSIFICATION OF HADITH: SAHIH, HASAN AND DA‘IF.", "question": "Who among the following played a major role in the transmission of Hadiths?", "images": [], "options": {"A": "Fatimah", "B": "A'ishah", "C": "Khadijah", "D": "Hafsah"}, "answer": "B", "explanation": "After the death of Muhammad, Aisha is regarded as the most reliable source in the teaching of the Hadith. Aisha's authentication of Muhammad's ways of prayer and his recitation of the Qur'an allowed for the development of knowledge of his sunnah of praying and reading verses of the Quran.", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2022>22", "subject": "IRK", "year": "2022", "type": "Objective", "topic": "SALAT : KINDS OF SALAT AND HOW THEY ARE OBSERVED", "question": "The supererogatory prayer with a single rak'ah is Salatul", "images": [], "options": {"A": "Jama'ah", "B": "Safar", "C": "Kusuf", "D": "Witr"}, "answer": "D", "explanation": "Witr (Arabic: وتر) is an Islamic prayer (salat) that is performed at night after Isha (night-time prayer) or before fajr (dawn prayer). It has just one rakah.", "marks": "1", "difficulty": "1"}, {"id": "objective>IRK>2022>23", "subject": "IRK", "year": "2022", "type": "Objective", "topic": "QUR’AN : PRESERVATION OF THE QUR’AN: COMPLETE ARRANGEMENT INCLUDING DISTINCTION BETWEEN MAKKI AND MADANI SUWAR; RECORDING; COMPILATION; STANDARDIZATION: ROLES PLAYED BY THE COMPANIONS OF THE PROPHET (S.A.W.) IN THE PRESERVATION OF THE QUR’AN.", "question": "A Juz' of the Qur'an is sub-divided into the following except", "images": [], "options": {"A": "Rub'", "B": "Nisf", "C": "Hizb", "D": "Manzil"}, "answer": "D", "explanation": "A Juz' of the Qur'an is not sub-divided into Manzil. A Juz' is one of the thirty parts of the Qur'an, each part is further divided into two 'Hizb' making it a total of 60 Hizb. Each Hizb is then further divided into four quarters, making a total of 240 quarters in the entire Qur'an. On the other hand, Manzil is a different system of dividing the Qur'an based on the places where the Prophet would stop and take a rest during his recitation of the Qur'an.", "marks": "1", "difficulty": "3"}, {"id": "objective>IRK>2022>24", "subject": "IRK", "year": "2022", "type": "Objective", "topic": "THE KHULAFᾹ’UR-RᾹSHIDĪN (THE RIGHTLY – GUIDED CALIPHS) : THEIR CONTRIBUTIONS TO ISLAM", "question": "The reign of Caliph Uthman b. Affan is known for", "images": [], "options": {"A": "Hadith collection", "B": "tax collection", "C": "Standardization of the Qur'an", "D": "justice and administrative fairness"}, "answer": "C", "explanation": "He centralized the administration of the Caliphate and established an official standard version of the Qur'an.", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2022>25", "subject": "IRK", "year": "2022", "type": "Objective", "topic": "HADITH : THE SIX SOUND COLLECTIONS OF HADITH (SIHAUS-SITTAH) AND THEIR COMPILERS.", "question": "Imam Bukhari is to 870 C.E. as Imam Muslim is to", "images": [], "options": {"A": "875 C.E.", "B": "886 C.E.", "C": "888 C.E.", "D": "892 C.E."}, "answer": "A", "explanation": "Imam Bukhari died in 870 C.E. while Imam Muslim died in 875 C.E.", "marks": "1", "difficulty": "3"}, {"id": "objective>IRK>2022>26", "subject": "IRK", "year": "2022", "type": "Objective", "topic": "SALAT : KINDS OF SALAT AND HOW THEY ARE OBSERVED", "question": "The number of rak'ah in the obligatory prayers of Friday is", "images": [], "options": {"A": "2", "B": "15", "C": "17", "D": "18"}, "answer": "B", "explanation": "Since Jummah is just two rakahs, the total will be 15 instead of 17.", "marks": "1", "difficulty": "1"}, {"id": "objective>IRK>2022>27", "subject": "IRK", "year": "2022", "type": "Objective", "topic": "QUR’AN : READING (IN EITHER ARABIC TEXT OR TRANSLITERATION), MEMORIZATION, MEANING OF THE FOLLOWING SUWAR AND THE LESSONS LEARNT FROM THEM (IDENTIFICATION, EXPLANATION, INTERPRETATION AND APPLICATION)", "question": "How many times does the word al-Qadr occur in Qur'an chapter 97?", "images": [], "options": {"A": "2", "B": "3", "C": "4", "D": "5"}, "answer": "B", "explanation": "The word al-Qadr occurs three times in Qur'an chapter 97.", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2022>28", "subject": "IRK", "year": "2022", "type": "Objective", "topic": "THE LIFE OF PROPHET MUHAMMAD (S.A.W.) : BIRTH", "question": "Halimah, the wet nurse of Muhammad (S.A.W.) hailed from the Banu", "images": [], "options": {"A": "Mustaliq", "B": "Khuza'ah", "C": "Sa'ad", "D": "Quraysh"}, "answer": "C", "explanation": "Halimah al-Sa'diyah (Arabic: حليمة السعدية), was the foster-mother of the Islamic prophet Muhammad. Halimah and her husband were from the tribe of Sa'd b. Bakr, a subdivision of Hawazin (a large North Arabian tribe or group of tribes).", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2022>29", "subject": "IRK", "year": "2022", "type": "Objective", "topic": "SALAT : KINDS OF SALAT AND HOW THEY ARE OBSERVED", "question": "The Tahajjud is observed between", "images": [], "options": {"A": "Maghrib and Isha'i", "B": "Shaf' and Witr", "C": "Zuhr and 'Asr", "D": "Isha' and Fajr"}, "answer": "D", "explanation": "The Tahajjud is a special night prayer which is recommended(but not compulsory) for all muslims. Known as the best among the voluntary prayers, the Tahajjud is prayed after Isha (the obligatory nightly prayer) and before Fajr(the obligatory morning prayer).", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2022>30", "subject": "IRK", "year": "2022", "type": "Objective", "topic": "QUR’AN : READING (IN EITHER ARABIC TEXT OR TRANSLITERATION), MEMORIZATION, MEANING OF THE FOLLOWING SUWAR AND THE LESSONS LEARNT FROM THEM (IDENTIFICATION, EXPLANATION, INTERPRETATION AND APPLICATION)", "question": "Without the last verse of Suratud-Duha(Q.93), the remaining verse are", "images": [], "options": {"A": "8", "B": "9", "C": "10", "D": "11"}, "answer": "C", "explanation": "Suratud-Duha(Q.93) has 11 verses in total. If the last verse is removed, the remaining verses are 10.", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2022>31", "subject": "IRK", "year": "2022", "type": "Objective", "topic": "QUR’AN : READING (IN EITHER ARABIC TEXT OR TRANSLITERATION), MEMORIZATION, MEANING OF THE FOLLOWING SUWAR AND THE LESSONS LEARNT FROM THEM (IDENTIFICATION, EXPLANATION, INTERPRETATION AND APPLICATION)", "question": "Suratul-Fatihah(Q.1:5) admonishes muslims to", "images": [], "options": {"A": "give thanks and praises to Allah", "B": "appreciate the mercy and grace of Allah", "C": "remember the day of Judgement", "D": "worship none except Almighty Allah"}, "answer": "D", "explanation": "Suratul-Fatihah(Q.1:5) translates to 'You alone we worship, and You alone we ask for help', which is an admonishment to Muslims to worship none except Almighty Allah.", "marks": "1", "difficulty": "1"}, {"id": "objective>IRK>2022>32", "subject": "IRK", "year": "2022", "type": "Objective", "topic": "HADITH : THE IMPORTANCE OF HADITH AND SUNNAH", "question": "According to the Hadith of the Prophet(S.A.W.), learning is obligatory for both the", "images": [], "options": {"A": "muslim and non-muslim", "B": "old and young", "C": "male and female", "D": "arab and non-arab"}, "answer": "C", "explanation": "The Prophet Muhammad(S.A.W.) commanded knowledge upon all muslims(male and female), and urged them to seek knowlege as far as they could reach, and also to seek knowledge at all times.", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2022>33", "subject": "IRK", "year": "2022", "type": "Objective", "topic": "SALAT : MEANING AND IMPORTANCE", "question": "To seek divine guidance, muslims are encouraged to perform Salat", "images": [], "options": {"A": "Istisqa", "B": "Tarawih", "C": "Tahajjud", "D": "Istikhara"}, "answer": "D", "explanation": "Salat al-Istikhara, which translates to prayer of seeking counsel, is a prayer recited by muslims who are in need of guidance from Almighty Allah when facing a decision in their life.", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2022>34", "subject": "IRK", "year": "2022", "type": "Objective", "topic": "THE JAHILIYYAH: ARABIA BEFORE ISLAM : DESCRIPTION OF ARABIA – LOCATION", "question": "Makkah is referred to in Qur'an chapter 95 verse 3 as the city of", "images": [], "options": {"A": "Allah", "B": "prayer", "C": "security", "D": "Islam"}, "answer": "C", "explanation": "Makkah is referred to in Qur'an chapter 95 verse 3 as the city of security. The verse says 'And [by] this secure city [Makkah],' which implies that Makkah is a city of security.", "marks": "1", "difficulty": "1"}, {"id": "objective>IRK>2022>35", "subject": "IRK", "year": "2022", "type": "Objective", "topic": "ISLAM IN WEST AFRICA : THE ADVENT AND ROLES OF TRADERS, TEACHERS, MURᾹBITUN, SUFI ORDERS, MUJADDIDUN (REFORMERS) AND HAJJ IN THE PREAD OF ISLAM.", "question": "The capital of the ancient Ghana empire was", "images": [], "options": {"A": "Awkar", "B": "Jenne", "C": "Awdaghast", "D": "Sijilmasa"}, "answer": "A", "explanation": "The capital of the ancient Ghana empire was Awkar. The Ghana Empire was located in what is now southeastern Mauritania, western Mali, and eastern Senegal. Its capital city was Awkar.", "marks": "1", "difficulty": "3"}, {"id": "objective>IRK>2022>36", "subject": "IRK", "year": "2022", "type": "Objective", "topic": "SAWM (FASTING) : DEFINITION AND TYPES", "question": "Voluntary fasting is encouraged on", "images": [], "options": {"A": "Fridays", "B": "'Id days", "C": "Mondays", "D": "a day before Ramadan"}, "answer": "C", "explanation": "In Islam, voluntary fasting is highly encouraged on Mondays and Thursdays, not Fridays or 'Id days. 'Id days are festive days in Islam where fasting is actually prohibited. The day before Ramadan is also not specifically encouraged for fasting. Therefore, the correct answer is 'Mondays'.", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2022>37", "subject": "IRK", "year": "2022", "type": "Objective", "topic": "QUR’AN : READING (IN EITHER ARABIC TEXT OR TRANSLITERATION), MEMORIZATION, MEANING OF THE FOLLOWING SUWAR AND THE LESSONS LEARNT FROM THEM (IDENTIFICATION, EXPLANATION, INTERPRETATION AND APPLICATION)", "question": "The last verse of Suratut-Tin describes Allah as the", "images": [], "options": {"A": "Lord", "B": "King", "C": "Creator", "D": "Judge"}, "answer": "D", "explanation": "The last verse of Suratut-Tin (The Fig) in the Quran describes Allah as the 'Judge'. The verse is 'Is not Allah the most just of judges?' (95:8). Therefore, the correct answer is 'Judge'.", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2022>38", "subject": "IRK", "year": "2022", "type": "Objective", "topic": "ISLAM IN WEST AFRICA : THE ADVENT AND ROLES OF TRADERS, TEACHERS, MURᾹBITUN, SUFI ORDERS, MUJADDIDUN (REFORMERS) AND HAJJ IN THE PREAD OF ISLAM.", "question": "The first king of the Mali empire to accept Islam was", "images": [], "options": {"A": "Mansa Musa", "B": "Sundiata", "C": "Mansa Sulayman", "D": "Barmandana"}, "answer": "A", "explanation": "Mansa Musa was the first king of the Mali empire to accept Islam.", "marks": "1", "difficulty": "3"}, {"id": "objective>IRK>2022>39", "subject": "IRK", "year": "2022", "type": "Objective", "topic": "SAWM (FASTING) : DEFINITION AND TYPES", "question": "The following are voluntary fasting except", "images": [], "options": {"A": "Sittah Shawwal", "B": "Ashura", "C": "Tasu'a", "D": "Qada'"}, "answer": "D", "explanation": "Qada is not a voluntary but obligatory fast. It is a fast that is observed as a make up fast after Ramadan to compensate for any missed fast or any shortcoming during Ramadan fast.", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2022>40", "subject": "IRK", "year": "2022", "type": "Objective", "topic": "HADITH : READING (IN EITHER THE ARABIC TEXT OR TRANSLITERATION). MEMORIZATION, MEANING OF THE FOLLOWING AHADITH AND LESSONS LEARNT FROM THEM (IDENTIFICATION, EXPLANATION, INTERPRETATION AND APPLICATION): AN-NAWAWI’S COLLECTION. 1, 5, 7, 9, 13, 15,16,18,34 AND 41.", "question": "Muslims should pay attention to Hadith 5 of an-Nawawi because it", "images": [], "options": {"A": "warns against backbiting", "B": "discourages innovations in religion", "C": "encourages sincerity in all matters", "D": "frowns upon excessive questioning"}, "answer": "B", "explanation": "The major teaching of Hadith 5 of an-Nawawi collection focus on innovation.   Hadith 5 On the authority of the mother of the faithful, 'Aisha (may Allah be pleased with her), who said: The Messenger of Allah (peace be upon him) said:  He who innovates something in this matter of ours [Islam] that is not of it will have it rejected [by Allah].", "marks": "1", "difficulty": "3"}, {"id": "objective>IRK>2022>41", "subject": "IRK", "year": "2022", "type": "Objective", "topic": "THE LIFE OF PROPHET MUHAMMAD (S.A.W.) : CALL TO PROPHETHOOD", "question": "'Alam yajidka yatiman fa'awa(Q.93:6) refers to Muhammad (S.A.W.) as", "images": [], "options": {"A": "a Prophet", "B": "an orphan", "C": "a hero", "D": "a leader"}, "answer": "B", "explanation": "'Alam yajidka yatiman fa'awa(Q.93:6) is a verse from the Quran which translates to 'Did He not find you an orphan and give [you] refuge?' This verse refers to Prophet Muhammad (S.A.W.) as an orphan, which is the correct answer.", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2022>42", "subject": "IRK", "year": "2022", "type": "Objective", "topic": "THE JAHILIYYAH: ARABIA BEFORE ISLAM : DESCRIPTION OF ARABIA – LOCATION", "question": "The period between the advent of Islam in Arabia is referred to as Jahiliyyah because Arabia", "images": [], "options": {"A": "was surrounded by water in the West and South", "B": "had no inspired Prophet and revelation", "C": "had desert border lines", "D": "was divided into three physical zones."}, "answer": "B", "explanation": "Jāhiliyyah, in Islam, the period preceding the revelation of the Qurʾān to the Prophet Muhammad. In Arabic the word means \"ignorance,\" or \"barbarism,\" and indicates a negative Muslim evaluation of pre-Islamic life and culture in Arabia as compared to the teachings and practices of Islam.", "marks": "1", "difficulty": "3"}, {"id": "objective>IRK>2022>43", "subject": "IRK", "year": "2022", "type": "Objective", "topic": "QUR’AN : READING (IN EITHER ARABIC TEXT OR TRANSLITERATION), MEMORIZATION, MEANING OF THE FOLLOWING SUWAR AND THE LESSONS LEARNT FROM THEM (IDENTIFICATION, EXPLANATION, INTERPRETATION AND APPLICATION)", "question": "The SIXTH verse of al-Fatiha is a prayer for", "images": [], "options": {"A": "protection", "B": "healing", "C": "success", "D": "Guidance"}, "answer": "D", "explanation": "The sixth verse of al-Fatiha is 'Guide us on the Straight Path'. This verse is a prayer for guidance, asking Allah to guide us on the right path, the path of those who have received His grace. Therefore, the correct answer is 'Guidance'.", "marks": "1", "difficulty": "1"}, {"id": "objective>IRK>2022>44", "subject": "IRK", "year": "2022", "type": "Objective", "topic": "QUR’AN : READING (IN EITHER ARABIC TEXT OR TRANSLITERATION), MEMORIZATION, MEANING OF THE FOLLOWING SUWAR AND THE LESSONS LEARNT FROM THEM (IDENTIFICATION, EXPLANATION, INTERPRETATION AND APPLICATION)", "question": "Which of the following Suwar contains ELEVEN verses?", "images": [], "options": {"A": "Ad-Duha", "B": "At-Tin", "C": "Al-'Alaq", "D": "Al-Qadr"}, "answer": "A", "explanation": "Suratul-ad-Duha contains 11 verses  This Surah, revealed in Makkah, is a message of hope and reassurance to the Prophet Muhammad (SAW) during a period of distress. It highlights Allah's care and support for His Messenger, urging him to be patient and reminding him of the blessings that Allah has bestowed upon him.", "marks": "1", "difficulty": "1"}, {"id": "objective>IRK>2022>45", "subject": "IRK", "year": "2022", "type": "Objective", "topic": "THE LIFE OF PROPHET MUHAMMAD (S.A.W.) : CALL TO PROPHETHOOD", "question": "After the first encounter of Muhammad(S.A.W.) with Jibril(A.S.), he", "images": [], "options": {"A": "sent Khadija to inform Waraqah b. Nawfal of the experience", "B": "fainted and asked Allah's guidance and protection", "C": "almost abandoned his desire to spread Islam", "D": "directed Khadija to cover him with a cloak"}, "answer": "D", "explanation": "After the Prophet's first revelation,  he went to Khadija bint Khuwaylid and said, \"Cover me! Cover me!\" She covered him till his fear was over and after that he told her everything that had happened.", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2022>46", "subject": "IRK", "year": "2022", "type": "Objective", "topic": "QUR’AN : READING (IN EITHER ARABIC TEXT OR TRANSLITERATION), MEMORIZATION, MEANING OF THE FOLLOWING SUWAR AND THE LESSONS LEARNT FROM THEM (IDENTIFICATION, EXPLANATION, INTERPRETATION AND APPLICATION)", "question": "A memorizer of the Qur'an is known as", "images": [], "options": {"A": "Qari", "B": "Katib", "C": "Qadi", "D": "Hafiz"}, "answer": "D", "explanation": "Hafiz is an Arabic word used to identify the one who entirely memorizes and recites the Qur´an, the holy book of Muslims, which is over 600 pages with more than 6,000 verses. The word hafiz is also used for those who memorize the sayings of Prophet Muhammad in certain numbers, but these are rare.", "marks": "1", "difficulty": "1"}, {"id": "objective>IRK>2022>47", "subject": "IRK", "year": "2022", "type": "Objective", "topic": "THE LIFE OF PROPHET MUHAMMAD (S.A.W.) : BIRTH", "question": "The Prophet(S.A.W.) grew up among the Banu", "images": [], "options": {"A": "Umayyad", "B": "Hashim", "C": "Sa'd", "D": "Qurayzah"}, "answer": "B", "explanation": "Muhammad(S.A.W.) was born in or around the year 570 CE to the Banu Hashim clan of the Quraysh tribe, one of Mecca's prominent families.", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2022>48", "subject": "IRK", "year": "2022", "type": "Objective", "topic": "SALAT : SUJUDUS-SAHWI (PROSTRATION OF FORGETFULNESS.)", "question": "Thre prostration performed while reading the Qur'an is Sujud", "images": [], "options": {"A": "al-Qabli", "B": "al-Ba'di", "C": "at-Tilawah", "D": "Sahw"}, "answer": "C", "explanation": "The prostration of recitation(sujud tilawa) is a prostration(sujud) which occurs during the ritual Tilawa of Quran in Salah or outside it.", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2022>49", "subject": "IRK", "year": "2022", "type": "Objective", "topic": "QUR’AN : REVELATION OF THE QUR’AN: VISITS OF THE PROPHET (S.A.W.) TO CAVE HIRA ; FIRST REVELATION AND HIS REACTION TO IT, DIFFERENT MODES OF REVELATION, PIECEMEAL- REVELATION OF THE QUR’AN.", "question": "The first revelation is contained in Suratul", "images": [], "options": {"A": "Qadr", "B": "Falaq", "C": "'Alaq", "D": "Ikhlas"}, "answer": "C", "explanation": "The first revelation of the Qur'an, which was revealed to Prophet Muhammad (PBUH) by Angel Jibril (Gabriel), is contained in Suratul 'Alaq. The first five verses of this Surah were the first verses of the Qur'an to be revealed.", "marks": "1", "difficulty": "3"}, {"id": "objective>IRK>2022>50", "subject": "IRK", "year": "2022", "type": "Objective", "topic": "THE LIFE OF PROPHET MUHAMMAD (S.A.W.) : MARRIAGE", "question": "A'ishah the daughter of Abu-Bakr was born in the year", "images": [], "options": {"A": "612 C.E.", "B": "614 C.E.", "C": "620 C.E.", "D": "622 C.E."}, "answer": "B", "explanation": "A'ishah the daughter of Abu-Bakr was born in Mecca in 614 CE. She was the daughter of Abu Bakr and Umm Ruman, two of Muhammad's most trusted companions.", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2024>1", "subject": "IRK", "year": "2024", "type": "Objective", "topic": "QUR’AN : PRESERVATION OF THE QUR’AN: COMPLETE ARRANGEMENT INCLUDING DISTINCTION BETWEEN MAKKI AND MADANI SUWAR; RECORDING; COMPILATION; STANDARDIZATION: ROLES PLAYED BY THE COMPANIONS OF THE PROPHET (S.A.W.) IN THE PRESERVATION OF THE QUR’AN.", "question": "The process of harmonizing the different intonations in the recitation of the Qur'an is referred to as", "images": [], "options": {"A": "serialization", "B": "documentation", "C": "standardization", "D": "compilation"}, "answer": "C", "explanation": "Standardization, in this context, refers to the process of establishing a unified and consistent way of reciting the Qur'an, taking into account the different intonations and pronunciation used by various reciters. This ensures that the recitation is done in a harmonious and uniform manner, preserving the original message and beauty of the Qur'an.  Here's a brief explanation of the other options:  A. Serialization refers to the process of arranging something in a series or sequence, which is not relevant to the recitation of the Qur'an.  B. Documentation refers to the process of recording or documenting information, which is also not directly related to the recitation of the Qur'an.  D. Compilation refers to the process of gathering and collecting information or texts, which is not the same as harmonizing intonations in the recitation of the Qur'an.", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2024>2", "subject": "IRK", "year": "2024", "type": "Objective", "topic": "TAHARAH (PURIFICATION) : IMPORTANCE OF TAHARAH", "question": "Cleaning the private part with water is known as", "images": [], "options": {"A": "Ghal", "B": "Wudi", "C": "\"Istijmar", "D": "\"Istinja"}, "answer": "D", "explanation": "\"Istinja is an Arabic term that refers to the act of cleaning one's private parts with water after using the restroom. This is a recommended practice in Islam to maintain personal hygiene and cleanliness.  Here's a brief explanation of the other options:  A. Ghusl (not Ghal) refers to the ritual bath or shower taken to restore ritual purity, but it is not specific to cleaning the private parts.  B. Wudu refers to the ritual ablution performed before prayer, which includes washing the hands, face, arms, and feet, but does not specifically refer to cleaning the private parts.  C. Istijmar refers to the act of using stones, leaves, or other materials to clean oneself after using the restroom, but it does not involve the use of water.  It's worth noting that both Istinja and Istijmar are used for cleaning the private parts, but Istinja is specific to using water, while Istijmar is specific to using dry materials.", "marks": "1", "difficulty": "1"}, {"id": "objective>IRK>2024>3", "subject": "IRK", "year": "2024", "type": "Objective", "topic": "ISLAM IN WEST AFRICA : THE ADVENT AND ROLES OF TRADERS, TEACHERS, MURᾹBITUN, SUFI ORDERS, MUJADDIDUN (REFORMERS) AND HAJJ IN THE PREAD OF ISLAM.", "question": "Who among the following is associated with Islam in Borno?", "images": [], "options": {"A": "Muhammad al-Mami", "B": "Abdullah b.Fudi", "C": "Abdul-Kareem al-Maghili", "D": "Ahmad Jalo"}, "answer": "A", "explanation": "Muhammad al-Mami was a renowned Islamic scholar and teacher who played a significant role in spreading Islam in Borno, a region in northeastern Nigeria. He was instrumental in establishing Islamic education and institutions in the area, and his teachings had a lasting impact on the people of Borno.  Here's a brief explanation of the other options:  B. Abdullahi b. Fudi (also known as Abdullahi dan Fodio) was a prominent Islamic scholar and reformer who led the Fulani Jihad in the 19th century, but his activities were mainly centered in the Sokoto region, not Borno.  C. Abdul-Kareem al-Maghili was a Moroccan Islamic scholar who traveled extensively in West Africa, including Borno, but his association with the region was more related to his scholarly work and less to the establishment of Islam.  D. Ahmad Jalo is not a well-known figure associated with the spread of Islam in Borno.  Note: The history of Islam in Borno is rich and complex, and multiple scholars and leaders have contributed to its development. However, Muhammad al-Mami is particularly notable for his contributions to Islamic education and institutions in the region.", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2024>4", "subject": "IRK", "year": "2024", "type": "Objective", "topic": "HADITH : PARTS OF THE HADITH: ‘ISNAD, MATN AND RAWI", "question": "A Hadith with a broken link in its Ismad is known as", "images": [], "options": {"A": "Mursal", "B": "Abad", "C": "Mutawatir", "D": "Munqati"}, "answer": "D", "explanation": "A Hadith with a broken link in its Isnad (chain of transmission) is known as Munqati (ãäÞØÚ). This occurs when there is a gap or missing link in the chain of narrators between the Prophet Muhammad (peace be upon him) and the person reporting the Hadith.  Here's a brief explanation of the other options:  A. Mursal (ãÑÓá) refers to a Hadith where the companion of the Prophet Muhammad (peace be upon him) is missing from the Isnad, but the rest of the chain is intact.  B. Abad (ÃÈÏ) is not a recognized term in Hadith terminology.  C. Mutawatir (ãÊæÇÊÑ) refers to a Hadith that has been narrated by a large number of people at each stage of the Isnad, making it a highly authentic and reliable Hadith.  In Hadith studies, the integrity of the Isnad is crucial in determining the authenticity and reliability of a Hadith. A broken link in the Isnad can affect the Hadith's validity and weight.", "marks": "1", "difficulty": "3"}, {"id": "objective>IRK>2024>5", "subject": "IRK", "year": "2024", "type": "Objective", "topic": "QUR’AN : REVELATION OF THE QUR’AN: VISITS OF THE PROPHET (S.A.W.) TO CAVE HIRA ; FIRST REVELATION AND HIS REACTION TO IT, DIFFERENT MODES OF REVELATION, PIECEMEAL- REVELATION OF THE QUR’AN.", "question": "The revelation of the Qur'an started with the command to", "images": [], "options": {"A": "preach", "B": "read", "C": "proclaim", "D": "announce"}, "answer": "B", "explanation": "The revelation of the Qur'an began with the command \"Read!\" (Iqra' in Arabic), which was revealed to Prophet Muhammad (peace be upon him) by the angel Gabriel in the Cave of Hira. This event marked the beginning of the revelation of the Qur'an and is mentioned in Surah Al-Alaq (96:1-5).  Here's a brief explanation of the other options:  A. Preach: While Prophet Muhammad (peace be upon him) was indeed commanded to preach and convey the message of Islam, the initial revelation did not start with this command.  C. Proclaim: Similar to preaching, proclaiming the message of Islam was part of the Prophet's mission, but it was not the initial command.  D. Announce: Announcing the message of Islam was also part of the Prophet's role, but it was not the first command revealed in the Qur'an.  The command \"Read!\" marked the beginning of the Prophet's mission and emphasized the importance of knowledge, literacy, and the revelation of the Qur'an.", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2024>6", "subject": "IRK", "year": "2024", "type": "Objective", "topic": "SALAT : KINDS OF SALAT AND HOW THEY ARE OBSERVED", "question": "After rising from the ruku', a worshipper utters", "images": [], "options": {"A": "Sami'a Allahu liman hamidau", "B": "Subhana Rabbiyal 'Azim", "C": "Rabbana walakal hamd", "D": "Subhana Rabbiyal 'A'la"}, "answer": "C", "explanation": "After rising from the ruku' (bowing position) in prayer, a worshipper utters the phrase \"Rabbana walakal hamd\" (ÑÈäÇ æáß ÇáÍãÏ), which means \"Our Lord, and to You belongs all praise.\"  Here's a brief explanation of the other options:  A. Sami'a Allahu liman hamidah (ÓãÚ Çááå áãä ÍãÏå) is said by the Imam (leader of the prayer) after rising from the ruku', but the congregation responds with \"Rabbana walakal hamd\".  B. Subhana Rabbiyal 'Azim (ÓÈÍÇä ÑÈí ÇáÚÙíã) is said during the ruku' position, not after rising from it.  D. Subhana Rabbiyal 'A'la (ÓÈÍÇä ÑÈí ÇáÃÚáì) is said during the prostration (sajdah) position, not after rising from the ruku'.  The phrase \"Rabbana walakal hamd\" is a way of expressing gratitude and praise to Allah, acknowledging His greatness and majesty.", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2024>7", "subject": "IRK", "year": "2024", "type": "Objective", "topic": "THE KHULAFᾹ’UR-RᾹSHIDĪN (THE RIGHTLY – GUIDED CALIPHS) : THEIR BIOGRAPHIES", "question": "The third Khalifah in Islam ruled between", "images": [], "options": {"A": "630-632 C.E.", "B": "632-634 C.E.", "C": "634-644 C.E.", "D": "644-656 C.E"}, "answer": "C", "explanation": "The third Khalifah (Caliph) in Islam was Uthman ibn Affan, who ruled from 634 to 644 C.E. He was a companion of the Prophet Muhammad (peace be upon him) and was known for his piety, honesty, and fairness.  Here's a brief explanation of the other options:  A. 630-632 C.E. corresponds to the rule of Abu Bakr, the first Khalifah.  B. 632-634 C.E. corresponds to the rule of Umar ibn Al-Khattab, the second Khalifah.  D. 644-656 C.E. corresponds to the rule of Ali ibn Abi Talib, the fourth Khalifah.  Uthman ibn Affan's rule was marked by significant events, including the compilation of the Quran into a single book, the expansion of the Islamic empire, and the establishment of a strong administrative system.", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2024>8", "subject": "IRK", "year": "2024", "type": "Objective", "topic": "THE KHULAFᾹ’UR-RᾹSHIDĪN (THE RIGHTLY – GUIDED CALIPHS) : THEIR BIOGRAPHIES", "question": "The Caliph who appointed the Shard Council to produce a successor after his death was", "images": [], "options": {"A": "Aba-Bakr as-Siddiq", "B": "Mu'awiyah b. Abi Sufyan.", "C": "Uthman b. Affan", "D": "Ali b. Abi-Talib"}, "answer": "C", "explanation": "Uthman ibn Affan, the third Caliph, appointed a six-member council, known as the Shura Council, to choose his successor after his death. This council consisted of:  Ali ibn Abi Talib  Uthman ibn Abi al-As  Abdul Rahman ibn Awf  Saad ibn Abi Waqqas  Al-Zubayr ibn al-Awwam  Talha ibn Ubaydullah  The Shura Council was tasked with selecting a new Caliph from among themselves, which ultimately led to the selection of Ali ibn Abi Talib as the fourth Caliph.  Here's a brief explanation of the other options:  A. Abu Bakr as-Siddiq, the first Caliph, did not appoint a Shura Council. Instead, he nominated Umar ibn Al-Khattab as his successor before his death.  B. Mu'awiyah b. Abi Sufyan was a governor of Syria during Uthman's rule and later became the founder of the Umayyad dynasty. He was not involved in the Shura Council.  D. Ali b. Abi-Talib was a member of the Shura Council but did not appoint it. He was chosen as the fourth Caliph by the council after Uthman's death.", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2024>9", "subject": "IRK", "year": "2024", "type": "Objective", "topic": "QUR’AN : REVELATION OF THE QUR’AN: VISITS OF THE PROPHET (S.A.W.) TO CAVE HIRA ; FIRST REVELATION AND HIS REACTION TO IT, DIFFERENT MODES OF REVELATION, PIECEMEAL- REVELATION OF THE QUR’AN.", "question": "La takhudhuhu sinatun wa la nawmun (Q.2:255) means", "images": [], "options": {"A": "there is no God but Him.", "B": "His throne overspreads the Heaven and the earth.", "C": "neither slumber overtakes Him nor sleep.", "D": "He knows all that lies open before men."}, "answer": "C", "explanation": "The verse \"La takhudhuhu sinatun wa la nawmun\" (áÇ ÊÇÎÐõåõ ÓöäóÉñ æóáÇ äóæúãñ) in Quran 2:255 is part of the Ayat al-Kursi (Throne Verse) and means \"Neither slumber overtakes Him nor sleep.\"  This verse highlights Allah's attribute of being eternally awake and alert, never affected by fatigue or drowsiness. It emphasizes His constant vigilance and control over the universe.  Here's a brief explanation of the other options:  A. \"There is no God but Him\" is a translation of the phrase \"La ilaha illa Huwa\" (áÇ Åáå ÅáÇ åæ), which is not part of this specific verse.  B. \"His throne overspreads the Heaven and the earth\" is a translation of the phrase \"Wasi'a kursiyyuhu al-samawati wa al-ard\" (æÓÚ ßÑÓíå ÇáÓãÇæÇÊ æÇáÃÑÖ), which is part of the same verse (Quran 2:255) but not the specific phrase mentioned.  D. \"He knows all that lies open before men\" is not a direct translation of this specific phrase, although Allah's knowledge and awareness are indeed emphasized in the Quran.", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2024>10", "subject": "IRK", "year": "2024", "type": "Objective", "topic": "NIKAH (MARRIAGE) : PROHIBITED CATEGORIES", "question": "In Islam, one of the temporary barriers to marriage is", "images": [], "options": {"A": "mother-in-law.", "B": "foster mother.", "C": "woman in Iddah.", "D": "daughter-in-law."}, "answer": "C", "explanation": "In Islam, a woman in Iddah (ÚÏå) is a temporary barrier to marriage. Iddah is a waiting period that a woman must observe after the death of her husband or after a divorce. During this period, she is not allowed to remarry.  The duration of Iddah varies depending on the circumstances:  After the death of a husband, the Iddah period is four months and ten days.  After a divorce, the Iddah period is three menstrual cycles.  Here's a brief explanation of the other options:  A. Mother-in-law: There is no temporary barrier to marriage due to a mother-in-law.  B. Foster mother: A foster mother is a permanent barrier to marriage, as one cannot marry their foster mother or foster sister.  D. Daughter-in-law: There is no temporary barrier to marriage due to a daughter-in-law.  It's essential to note that Islamic law (Sharia) outlines specific rules and regulations regarding marriage, including temporary and permanent barriers to marriage.", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2024>11", "subject": "IRK", "year": "2024", "type": "Objective", "topic": "THE LIFE OF PROPHET MUHAMMAD (S.A.W.) : HIJRAH", "question": "Who was the companion sent by the Prophet (S.A.W.) from Hudaybiyyah to assure the Quraysh of his peaceful mission to Makkah?", "images": [], "options": {"A": "Uthman b. 'Affan", "B": "Ali b. Abi Talib", "C": "Aba-Bakr b. Abi Quhaffah", "D": "Umar b. al-Khattab"}, "answer": "A", "explanation": "In 628 CE, the Prophet Muhammad (peace be upon him) sent Uthman ibn Affan to Makkah from Hudaybiyyah to assure the Quraysh that his mission was peaceful and that he came to perform Umrah (a lesser pilgrimage). Uthman was chosen for this task due to his kinship with the Quraysh and his reputation for honesty and integrity.  Uthman's mission was to negotiate with the Quraysh and secure a peaceful entry for the Muslims into Makkah. However, he was delayed, and the Muslims feared for his safety, leading to the famous pledge of allegiance known as the Pledge of Ridwan.  Here's a brief explanation of the other options:  B. Ali b. Abi Talib: Although Ali was a trusted companion, he was not sent on this specific mission.  C. Aba-Bakr b. Abi Quhaffah: Abu Bakr was also a close companion, but he was not chosen for this particular task.  D. Umar b. al-Khattab: Umar was another prominent companion, but he was not sent to Makkah as an envoy in this instance.  Uthman's mission and the subsequent events played a significant role in the history of Islam, showcasing the Prophet's commitment to peace and his efforts to avoid conflict.", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2024>12", "subject": "IRK", "year": "2024", "type": "Objective", "topic": "THE LIFE OF PROPHET MUHAMMAD (S.A.W.) : HIJRAH", "question": "Prophet Muhammad's (S.A.W) companion to Ta'if was", "images": [], "options": {"A": "Abu-Bakr", "B": "Ali.", "C": "Zayd", "D": "Uthman."}, "answer": "C", "explanation": "In 619 CE, Prophet Muhammad (peace be upon him) sent Zayd ibn Harithah, his adopted son and companion, to Ta'if to invite the people to Islam. However, the people of Ta'if rejected the message and mistreated Zayd.  Later, the Prophet himself traveled to Ta'if, accompanied by Zayd, to call the people to Islam. Despite facing rejection and persecution, the Prophet continued to preach and eventually, some people from Ta'if accepted Islam.  Here's a brief explanation of the other options:  A. Abu-Bakr: While Abu Bakr was a close companion, there is no record of him being sent to Ta'if as an envoy.  B. Ali: Ali ibn Abi Talib was also a prominent companion, but he was not sent to Ta'if on this specific mission.  D. Uthman: Uthman ibn Affan was another important companion, but he was not involved in this particular event.  Zayd's mission to Ta'if and the Prophet's subsequent visit demonstrate the early challenges faced by the Muslims in spreading the message of Islam.", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2024>13", "subject": "IRK", "year": "2024", "type": "Objective", "topic": "QUR’AN : MORAL LESSONS FROM THE QUR’AN ATTITUDES TO PARENTS (Q.17 :23 – 24: 31 : 13 – 15 HONESTY IN WORDS AND DEEDS Q2: 42; 61: 2-3, 17: 35. PROHIBITION OF GAMBLING Q. 2:219:5 90-91.", "question": "The number of lashes prescribed by Qur'an 24:2 for a fornicator is", "images": [], "options": {"A": "100.", "B": "80.", "C": "60.", "D": "40."}, "answer": "A", "explanation": "According to Surah An-Nur (24:2) in the Quran, the punishment for a fornicator (one who commits zina, or unlawful sexual intercourse) is 100 lashes:  \"The woman and the man guilty of adultery or fornication, flog each of them with a hundred stripes.\"  This verse prescribes the punishment for unmarried individuals who commit zina. For married individuals, the punishment is more severe, as stated in other Islamic texts.  Here's a brief explanation of the other options:  B. 80: This is not the number of lashes prescribed in the Quran for fornication.  C. 60: This is also not the correct number of lashes.  D. 40: This is not the number of lashes mentioned in the Quran for this specific offense.  It's essential to note that Islamic law (Sharia) outlines specific punishments for various crimes, and these punishments are intended to serve as a deterrent and to maintain social justice.", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2024>14", "subject": "IRK", "year": "2024", "type": "Objective", "topic": "SALAT : KINDS OF SALAT AND HOW THEY ARE OBSERVED", "question": "Which of the following does not belong to the group?", "images": [], "options": {"A": "Tarawih", "B": "Tahiyyatul-masjid", "C": "Jum'ah", "D": "Shafi' wal-witr"}, "answer": "D", "explanation": "The other options (A, B, and C) are all types of prayers in Islam:  A. Tarawih: A voluntary prayer performed during the month of Ramadan, typically in congregation.  B. Tahiyyatul-masjid: A prayer performed upon entering a mosque, also known as the \"greeting of the mosque\".  C. Jum'ah: The Friday congregational prayer, obligatory for men.  D. Shafi' wal-witr: This option does not belong to the group because \"Shafi'\" is not a type of prayer. However, \"Witr\" is a voluntary prayer performed at night, typically in odd numbers (1, 3, 5, etc.).", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2024>15", "subject": "IRK", "year": "2024", "type": "Objective", "topic": "THE LIFE OF PROPHET MUHAMMAD (S.A.W.) : HIJRAH", "question": "The first migration from Makkah to Abyssinia took place in the year", "images": [], "options": {"A": "613CE", "B": "615 C.E", "C": "622 C.E.", "D": "632C.E"}, "answer": "B", "explanation": "The first migration from Makkah to Abyssinia (modern-day Ethiopia) took place in 615 CE, during the month of Rajab. This migration was led by Ja'far ibn Abi Talib, the cousin of the Prophet Muhammad (peace be upon him), and included about 80 Muslims, including men and women.  This migration was a result of the increasing persecution of Muslims by the Quraysh in Makkah, and the Abyssinian king, Negus, offered them protection and refuge.  Here's a brief explanation of the other options:  A. 613 CE: This is the year when the Prophet Muhammad (peace be upon him) began preaching publicly in Makkah, but it is not the year of the first migration.  C. 622 CE: This is the year of the Hijrah (migration) from Makkah to Madinah, which marked the beginning of the Islamic calendar.  D. 632 CE: This is the year of the Prophet Muhammad's (peace be upon him) passing, and it is not related to the migration to Abyssinia.  The first migration to Abyssinia was an important event in Islamic history, as it showed the willingness of the Muslims to seek refuge and protection in order to practice their faith freely.", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2024>16", "subject": "IRK", "year": "2024", "type": "Objective", "topic": "QUR’AN : REVELATION OF THE QUR’AN: VISITS OF THE PROPHET (S.A.W.) TO CAVE HIRA ; FIRST REVELATION AND HIS REACTION TO IT, DIFFERENT MODES OF REVELATION, PIECEMEAL- REVELATION OF THE QUR’AN.", "question": "The term associated with revelation is", "images": [], "options": {"A": "Matn", "B": "Rawi", "C": "Qiran", "D": "Kashf"}, "answer": "D", "explanation": "Explanation: Kashf (ßÔÝ) means \"unveiling\" or \"disclosure\" and is a term used in Sufism (Islamic mysticism) to describe a spiritual experience or intuition.", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2024>17", "subject": "IRK", "year": "2024", "type": "Objective", "topic": "QUR’AN : REVELATION OF THE QUR’AN: VISITS OF THE PROPHET (S.A.W.) TO CAVE HIRA ; FIRST REVELATION AND HIS REACTION TO IT, DIFFERENT MODES OF REVELATION, PIECEMEAL- REVELATION OF THE QUR’AN.", "question": "Alaqin in khalaqal insana means alaqin (Q96:2)", "images": [], "options": {"A": "most generous", "B": "creation", "C": "clot of blood", "D": "rebellious"}, "answer": "C", "explanation": "In Surah Al-Alaq (Q96:2), the word \"Alaq\" (ÚáÞ) refers to a clot of blood. The verse states:  \"Khalaqal-insana min 'alaq\" (ÎóáóÞó ÇáúÅöäÓóÇäó ãöäú ÚóáóÞ)  Which means:  \"Created man from a clot of blood\"  In this context, \"Alaq\" describes the early stage of human development in the womb, where the embryo is a small, clinging clot of blood.  Here's a brief explanation of the other options:  A. Most generous: This is not a correct translation of \"Alaq\" in this context.  B. Creation: While \"Khalaq\" (ÎóáóÞ) means \"created\", \"Alaq\" specifically refers to the substance from which man was created, i.e., a clot of blood.  D. Rebellious: This is not a correct translation of \"Alaq\" in this context.  The Quran's description of human development in the womb has been interpreted by scholars as a reference to the scientific fact that the early embryo is a small, clinging mass of cells, resembling a clot of blood.", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2024>18", "subject": "IRK", "year": "2024", "type": "Objective", "topic": "SALAT : KINDS OF SALAT AND HOW THEY ARE OBSERVED", "question": "Salat becomes faulty when Takbiratul-Ihram is", "images": [], "options": {"A": "said silently", "B": "delayed", "C": "omitted", "D": "said loudly"}, "answer": "C", "explanation": "Takbiratul-Ihram, which means \"Allahu Akbar\" (Çááå ÃßÈÑ), is the opening declaration of the prayer, and it is essential for the validity of the Salat (prayer). If it is omitted, the Salat becomes faulty and invalid.  Here's a brief explanation of the other options:  A. Said silently: Takbiratul-Ihram can be said silently, and it is still considered valid.  B. Delayed: While it's recommended to say Takbiratul-Ihram promptly, a slight delay does not necessarily invalidate the Salat.  D. Said loudly: Saying Takbiratul-Ihram loudly is not incorrect, and it does not affect the validity of the Salat.  Omitting Takbiratul-Ihram, however, is a critical mistake that invalidates the Salat, as it is considered a fundamental component of the prayer.", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2024>19", "subject": "IRK", "year": "2024", "type": "Objective", "topic": "THE LIFE OF PROPHET MUHAMMAD (S.A.W.) : HIJRAH", "question": "The year 622 C.E. is significant in Islamic history because it is attributed to the", "images": [], "options": {"A": "death of the Prophet (SA.W.)", "B": "defeat at Uhud", "C": "Hijrah to Yathrib", "D": "conquest of Makkah."}, "answer": "C", "explanation": "The year 622 CE is significant in Islamic history because it marks the Hijrah (migration) of the Prophet Muhammad (peace be upon him) and his companions from Makkah to Yathrib (later known as Madinah). This event is considered a turning point in Islamic history, as it marked the beginning of the Islamic calendar and the establishment of the first Islamic community.  Here's a brief explanation of the other options:  A. Death of the Prophet (SAW): The Prophet Muhammad (peace be upon him) passed away in 632 CE, not 622 CE.  B. Defeat at Uhud: The Battle of Uhud took place in 625 CE, three years after the Hijrah.  D. Conquest of Makkah: The Conquest of Makkah occurred in 630 CE, eight years after the Hijrah.  The Hijrah to Yathrib was a pivotal event in Islamic history, as it allowed the Muslims to establish a stronghold and spread their message, ultimately leading to the expansion of Islam.", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2024>20", "subject": "IRK", "year": "2024", "type": "Objective", "topic": "HAJJ (PILGRIMAGE) : RITES OF HAJJ", "question": "Which of the following is a Hajj term?", "images": [], "options": {"A": "Asmaur - Rijal", "B": "Wuqufbil 'Arafah", "C": "Hasan", "D": "Rawi"}, "answer": "B", "explanation": "Wuquf bil 'Arafah (æÞæÝ ÈöÚóÑóÝóÉ) is a Hajj term that refers to the standing on the plain of Arafah, which is one of the most important rituals of Hajj. It takes place on the 9th day of Dhul-Hijjah, where pilgrims gather on the plain of Arafah to pray and seek forgiveness from Allah.  Here's a brief explanation of the other options:  A. Asmaur-Rijal (ÃÓãÇÁ ÇáÑÌÇá) means \"names of men\" and is not a Hajj term.  C. Hasan (ÍÓä) means \"good\" or \"handsome\" and is not a specific Hajj term.  D. Rawi (ÑÇæí) means \"narrator\" or \"transmitter\" and is not related to Hajj.  Other important Hajj terms include:  Ihram (ÅÍÑÇã): the state of ritual purity  Tawaf (ØæÇÝ): circumambulation of the Ka'bah  Sa'i (ÓÚí): running between the hills of Safa and Marwah  Wuquf (æÞæÝ): standing on the plain of Arafah  These terms are essential to understanding the rituals and practices of Hajj.", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2024>21", "subject": "IRK", "year": "2024", "type": "Objective", "topic": "QUR’AN : READING (IN EITHER ARABIC TEXT OR TRANSLITERATION), MEMORIZATION, MEANING OF THE FOLLOWING SUWAR AND THE LESSONS LEARNT FROM THEM (IDENTIFICATION, EXPLANATION, INTERPRETATION AND APPLICATION)", "question": "Qul a'udhu birabbil falaq (Q.113) is followed by", "images": [], "options": {"A": "wa min sharri ghasiqin idha waqaba.", "B": "wa min sharri hasidin idha hasada.", "C": "min sharril waswasil khannas.", "D": "min sharri mã khalaqa"}, "answer": "C", "explanation": "The correct sequence of Surah Al-Falaq (Q113) is:  Qul a'udhu birabbil falaq (Say, \"I seek refuge in the Lord of the dawn\")  Min sharri ma khalaq (From the evil of what He created)  Wa min sharri ghasiqin idha waqab (And from the evil of the darkness when it settles)  Wa min sharri al-naffathati fil-'uqad (And from the evil of the blowers in the knots)  Wa min sharri hasidin idha hasad (And from the evil of the envier when he envies)  Min sharril waswasil khannas (From the evil of the whisperer who withdraws)  However, the immediate next verse after \"Qul a'udhu birabbil falaq\" is indeed \"Min sharri ma khalaq\", but the question asks for the verse after that, which is \"Min sharril waswasil khannas\".  Here's a brief explanation of the other options:  A. Wa min sharri ghasiqin idha waqaba is the third verse of the Surah, not the immediate next verse.  B. Wa min sharri hasidin idha hasada is the fifth verse of the Surah, not the immediate next verse.  D. Min sharri mã khalaqa is the second verse of the Surah, not the immediate next verse after \"Qul a'udhu birabbil falaq\".", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2024>22", "subject": "IRK", "year": "2024", "type": "Objective", "topic": "TAHARAH (PURIFICATION) : AL-WUDU’", "question": "Which of the following acts requires ablution.", "images": [], "options": {"A": "Touching the Qur'an", "B": "Entering into a mosque", "C": "Performance of prayer", "D": "Hastening between Safa and Marwa"}, "answer": "C", "explanation": "Performance of prayer: Ablution is required before performing prayer.", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2024>23", "subject": "IRK", "year": "2024", "type": "Objective", "topic": "THE KHULAFᾹ’UR-RᾹSHIDĪN (THE RIGHTLY – GUIDED CALIPHS) : THEIR CONTRIBUTIONS TO ISLAM", "question": "The major problem faced by Khalifah Abü-Bakr was how to", "images": [], "options": {"A": "share war booties", "B": "reconcile the Aws and the Khazraj.", "C": "control apostasy.", "D": "build mosques."}, "answer": "C", "explanation": "After the death of the Prophet Muhammad (peace be upon him), Khalifah Abu Bakr faced a major challenge in controlling apostasy, also known as Ridda. Many tribes in Arabia renounced Islam and refused to pay Zakat (charity), leading to a widespread apostasy movement. Abu Bakr had to take decisive action to quell this rebellion and maintain the unity of the Muslim community.  Here's a brief explanation of the other options:  A. Share war booties: While Abu Bakr did have to distribute war spoils, this was not the major problem he faced.  B. Reconcile the Aws and the Khazraj: The Prophet Muhammad (peace be upon him) had already reconciled these two tribes, and this was not a major issue during Abu Bakr's caliphate.  D. Build mosques: While building mosques is an important aspect of Islamic worship, it was not the major problem faced by Abu Bakr.  Abu Bakr's leadership during this critical period, known as the Ridda Wars, ensured the preservation of Islam and the unity of the Muslim community. His decisive action and strong leadership helped establish the foundation for the Islamic caliphate.", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2024>24", "subject": "IRK", "year": "2024", "type": "Objective", "topic": "HADITH : DEFINITION OF HADITH AND SUNNAH", "question": "The practices, customs and traditions of Prophet Muhammad (SAW) is termed", "images": [], "options": {"A": "Qur'an.", "B": "Sunnah.", "C": "Ta'wil", "D": "Diwan"}, "answer": "B", "explanation": "Sunnah refers to the practices, customs, and traditions of Prophet Muhammad (peace be upon him), which include his sayings, actions, and approvals. It is the second source of Islamic law and guidance, after the Quran. The Sunnah is based on the Hadith, which are the reported sayings and actions of the Prophet.  Here's a brief explanation of the other options:  A. Qur'an: The Quran is the holy book of Islam, revealed to Prophet Muhammad (peace be upon him). While it is a primary source of guidance, it is not the term for the Prophet's practices and traditions.  C. Ta'wil: Ta'wil refers to the interpretation or explanation of the Quran, particularly in terms of its allegorical or metaphorical meaning. It is not related to the Prophet's practices and traditions.  D. Diwan: Diwan refers to a collection of poems or literature, often used to describe the works of Arabic poets. It is not related to Islamic law or the Prophet's practices.  The Sunnah is an essential part of Islamic tradition and is used to guide Muslims in their daily lives, worship, and interactions. It provides valuable insights into the Prophet's character, teachings, and way of life, and is considered a model for Muslims to follow.", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2024>25", "subject": "IRK", "year": "2024", "type": "Objective", "topic": "QUR’AN : PRESERVATION OF THE QUR’AN: COMPLETE ARRANGEMENT INCLUDING DISTINCTION BETWEEN MAKKI AND MADANI SUWAR; RECORDING; COMPILATION; STANDARDIZATION: ROLES PLAYED BY THE COMPANIONS OF THE PROPHET (S.A.W.) IN THE PRESERVATION OF THE QUR’AN.", "question": "Quran is divided into six equal parts known as", "images": [], "options": {"A": "Hizb", "B": "Manzil", "C": "Ayat.", "D": "Surah"}, "answer": "B", "explanation": "The Quran is divided into six equal parts known as Manzil (ãäÒá), which means \"stopping places\" or \"stations\". This division is used to facilitate recitation and memorization of the Quran. Each Manzil represents one-sixth of the Quran's total text.  Here's a brief explanation of the other options:  A. Hizb (ÍÒÈ): A Hizb is a smaller division of the Quran, consisting of one-quarter of a Manzil. There are 60 Hizb in the Quran.  C. Ayat (ÂíÉ): Ayat refers to individual verses or signs within the Quran. There are 6,236 Ayat in the Quran.  D. Surah (ÓæÑÉ): Surah refers to chapters of the Quran. There are 114 Surah in the Quran, ranging in length from 3 to 286 Ayat.  The division of the Quran into Manzil and Hizb helps readers to pace themselves and complete the recitation of the Quran in a set period, such as during Ramadan.", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2024>26", "subject": "IRK", "year": "2024", "type": "Objective", "topic": "TAHARAH (PURIFICATION) : AL-WUDU’", "question": "The following are obligatory parts of al-Wudu except", "images": [], "options": {"A": "Washing of hands to the wrist", "B": "intention", "C": "wiping of the head", "D": "washing of the legs to the ankles"}, "answer": "D", "explanation": "Al-Wudu (ablution) is a ritual purification in Islam, and its obligatory parts are:  Washing the face  Washing the arms up to the elbows  Wiping the head (including the hair)  Washing the feet up to the ankles  Washing the legs up to the ankles is not an obligatory part of al-Wudu. However, it is recommended to wash the legs as a matter of cleanliness and hygiene.  Here's a brief explanation of the other options:  A. Washing of hands to the wrist: This is an obligatory part of al-Wudu.  B. Intention (Niyyah): Having the intention to perform al-Wudu is an essential part of the ritual.  C. Wiping of the head: This is an obligatory part of al-Wudu, which includes wiping the hair, forehead, and ears.  Note: Al-Wudu is a ritual purification that is required before performing certain acts of worship, such as prayer, handling the Quran, and performing rituals during Hajj and Umrah.", "marks": "1", "difficulty": "1"}, {"id": "objective>IRK>2024>27", "subject": "IRK", "year": "2024", "type": "Objective", "topic": "THE KHULAFᾹ’UR-RᾹSHIDĪN (THE RIGHTLY – GUIDED CALIPHS) : THEIR BIOGRAPHIES", "question": "The general commander of the Muslim army during the Caliphate of Abi-Bakr was", "images": [], "options": {"A": "Khalid b. al-Walid", "B": "Zayd b. Harith.", "C": "Amr b. al-As.", "D": "Usimah b. Yazd."}, "answer": "A", "explanation": "Khalid ibn al-Walid was a renowned Arab general and one of the most successful military commanders in history. During the Caliphate of Abu Bakr, he was appointed as the general commander of the Muslim army, leading the Ridda Wars (Wars of Apostasy) and later the conquest of Syria.  Here's a brief explanation of the other options:  B. Zayd b. Harith: Zayd was a companion of the Prophet Muhammad (peace be upon him) and a skilled warrior, but he was not the general commander of the Muslim army during Abu Bakr's Caliphate.  C. Amr b. al-As: Amr was a companion of the Prophet Muhammad (peace be upon him) and a notable military commander, but he was not the general commander during Abu Bakr's Caliphate. He later became the governor of Egypt during the Caliphate of Umar.  D. Usimah b. Yazd: There is no notable historical figure by this name, and it's likely a mistake or a lesser-known individual.  Khalid ibn al-Walid's military genius and leadership played a crucial role in the expansion of the Islamic empire, and he is remembered as one of the most iconic figures in Islamic history.", "marks": "1", "difficulty": "1"}, {"id": "objective>IRK>2024>28", "subject": "IRK", "year": "2024", "type": "Objective", "topic": "HADITH : CRITERIA FOR AUTHENTICITY OF HADITH", "question": "The authenticity of a Hadith may be faulted if", "images": [], "options": {"A": "its wordings are too close to the text of Quran", "B": "it is not longer than a verse of the Quran", "C": "its narrator was not from Makkah", "D": "it contradicts a Quranic injunction"}, "answer": "D", "explanation": "The authenticity of a Hadith (a saying or action of the Prophet Muhammad, peace be upon him) can be faulted if it contradicts a Quranic injunction. This is because the Quran is considered the ultimate source of guidance in Islam, and any Hadith that contradicts it cannot be considered authentic.  Here's a brief explanation of the other options:  A. Its wordings are too close to the text of Quran: This is not a reason to fault the authenticity of a Hadith. In fact, many Hadiths use similar language to the Quran.  B. It is not longer than a verse of the Quran: The length of a Hadith has no bearing on its authenticity.  C. Its narrator was not from Makkah: The location of the narrator is not a factor in determining the authenticity of a Hadith. Narrators from various locations contributed to the collection of Hadiths.  Other reasons to fault the authenticity of a Hadith include:  A break in the chain of narration (isnad)  A narrator known to be unreliable or untrustworthy  Contradiction with other established Hadiths or historical facts  Lack of corroboration from multiple narrators  Scholars of Hadith (muhaddithin) use various criteria to evaluate the authenticity of Hadiths, ensuring that they accurately reflect the words and actions of the Prophet Muhammad (peace be upon him).", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2024>29", "subject": "IRK", "year": "2024", "type": "Objective", "topic": "QUR’AN : THE QUR’AN AS A SOURCE OF GUIDANCE IN SOCIAL, POLITICAL, SPIRITUAL AND MORAL MATTERS", "question": "Ihdinas suratal mustaqimin (Q 1:6) implies that one should", "images": [], "options": {"A": "Seek guidance from Allah", "B": "worship Allah alone", "C": "sing the praises of Allah", "D": "acknowledge the mercy of Allah"}, "answer": "A", "explanation": "The verse \"Ihdinas siratal mustaqim\" (Q 1:6) is from the first chapter of the Quran, Al-Fatihah, and translates to \"Guide us to the straight path.\" This verse is a supplication to Allah, seeking guidance and direction on the path of righteousness.  Here's a brief explanation of the other options:  B. Worship Allah alone: While worshiping Allah alone is a fundamental aspect of Islam, this verse specifically asks for guidance, not worship.  C. Sing the praises of Allah: Praising Allah is an important aspect of Islamic worship, but this verse is focused on seeking guidance.  D. Acknowledge the mercy of Allah: Acknowledging Allah's mercy is important, but this verse is specifically asking for guidance on the straight path.  This verse is a central part of Islamic prayer and is recited daily by Muslims, seeking Allah's guidance and direction in their lives.", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2024>30", "subject": "IRK", "year": "2024", "type": "Objective", "topic": "IMAN (FAITH) : ARTICLES OF FAITH: BELIEF IN ALLAH WITH EMPHASIS ON KALIMATUSH-SHAHADAH(Q2: 163 AND 255; 3:18;17:42-43;21: 22 ; 23: 91 Q. 112, ISLAM AND THE CONCEPT OF TRINITY (Q.4:171; 5:75 – 76; 19:92-3; 112).", "question": "The second part of Kalimatush-Shahadah buttresses Muhammad's (SAW)", "images": [], "options": {"A": "divinity", "B": "lordship", "C": "Priesthood", "D": "holiness"}, "answer": "C", "explanation": "Explanation: The second part of the Kalimatush-Shahadah (the Islamic declaration of faith) is \"Muhammadur rasulullah\", which means \"Muhammad is the messenger of Allah\". This phrase affirms Muhammad's (peace be upon him) role as a prophet and messenger of Allah, emphasizing his office as a priest.", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2024>31", "subject": "IRK", "year": "2024", "type": "Objective", "topic": "HADITH : READING (IN EITHER THE ARABIC TEXT OR TRANSLITERATION). MEMORIZATION, MEANING OF THE FOLLOWING AHADITH AND LESSONS LEARNT FROM THEM (IDENTIFICATION, EXPLANATION, INTERPRETATION AND APPLICATION): AN-NAWAWI’S COLLECTION. 1, 5, 7, 9, 13, 15,16,18,34 AND 41.", "question": "Which of the following was a setup by the prophet (S.A.W) each time he received revelation  from Allah.", "images": [], "options": {"A": "wrote it down", "B": "taught Khadija", "C": "slept over it", "D": "memorized it  memorized it"}, "answer": "D", "explanation": "Whenever the Prophet Muhammad (peace be upon him) received revelation from Allah through the angel Jibril (Gabriel), he would memorize it. This was the primary method of preserving the Quran during the Prophet's lifetime.  Here's a brief explanation of the other options:  A. Wrote it down: While some companions of the Prophet did write down revelations, this was not the Prophet's primary method of preserving the Quran. The Quran was primarily preserved through memorization.  B. Taught Khadija: Khadija was the Prophet's wife, and while she was a supportive companion, there is no evidence to suggest that the Prophet taught her each revelation as soon as he received it.  C. Slept over it: There is no evidence to suggest that the Prophet would sleep over a revelation before taking action to preserve it.  The Prophet's memorization of the Quran was aided by his companions, who also memorized portions of the Quran. The Quran was later compiled into a written form during the Caliphate of Uthman, but memorization remained a crucial aspect of Quranic preservation.", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2024>32", "subject": "IRK", "year": "2024", "type": "Objective", "topic": "QUR’AN : READING (IN EITHER ARABIC TEXT OR TRANSLITERATION), MEMORIZATION, MEANING OF THE FOLLOWING SUWAR AND THE LESSONS LEARNT FROM THEM (IDENTIFICATION, EXPLANATION, INTERPRETATION AND APPLICATION)", "question": "Qur'an chapter 1 is to Fatihah as Qur'an chapter 95 is to", "images": [], "options": {"A": "Nasr", "B": "'Alaq", "C": "Tin", "D": "Kafirun"}, "answer": "C", "explanation": "The analogy is:  Qur'an chapter 1 : Fatihah :: Qur'an chapter 95 : Tin  Just as chapter 1 of the Qur'an is named \"Al-Fatihah\", chapter 95 is named \"At-Tin\".  Here's a brief explanation of the other options:  A. Nasr: Surah An-Nasr (The Help) is actually chapter 110, not 95.  B. 'Alaq: Surah Al-'Alaq (The Clot) is actually chapter 96, not 95.  D. Kafirun: Surah Al-Kafirun (The Disbelievers) is actually chapter 109, not 95.  At-Tin (The Fig) is a Meccan surah that emphasizes the importance of gratitude, righteousness, and the afterlife.", "marks": "1", "difficulty": "1"}, {"id": "objective>IRK>2024>33", "subject": "IRK", "year": "2024", "type": "Objective", "topic": "HADITH : CLASSIFICATION OF HADITH: SAHIH, HASAN AND DA‘IF.", "question": "The classification of Hadith based on its narrators takes one of the following forms", "images": [], "options": {"A": "Qudsi", "B": "Rawi", "C": "rijal", "D": "mutawatir"}, "answer": "C", "explanation": "The classification of Hadith based on its narrators is known as \"Rijal al-Hadith\" or simply \"Rijal\", which refers to the study of the narrators of Hadith. This involves evaluating the trustworthiness, reliability, and credibility of the narrators to determine the authenticity of the Hadith.  Here's a brief explanation of the other options:  A. Qudsi: Qudsi Hadith refers to a type of Hadith that contains a quote from Allah, usually starting with \"Allah says...\" or \"The Lord says...\". It is not related to the classification of Hadith based on narrators.  B. Rawi: Rawi refers to a narrator of Hadith, but it is not a classification of Hadith based on narrators.  D. Mutawatir: Mutawatir refers to a type of Hadith that has been narrated by a large number of people, making it impossible for them to have conspired to fabricate it. While it is related to the authenticity of Hadith, it is not a classification based on narrators.  Rijal al-Hadith is an important field of study in Islamic scholarship, as it helps to ensure the accuracy and reliability of the Hadith, which are essential sources of guidance for Muslims", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2024>34", "subject": "IRK", "year": "2024", "type": "Objective", "topic": "SALAT : KINDS OF SALAT AND HOW THEY ARE OBSERVED", "question": "Which of the following is a compulsory prayer?", "images": [], "options": {"A": "witr", "B": "juha", "C": "Tahhajud", "D": "janazah"}, "answer": "D", "explanation": "Janazah prayer is a compulsory prayer (fard) in Islam, performed for the deceased. It is a collective obligation (fard kifayah), meaning that a sufficient number of Muslims in the community must perform it to fulfill the obligation.  Here's a brief explanation of the other options:  A. Witr: Witr is a voluntary prayer (sunnah) performed at night, typically after the Isha prayer.  B. Juha: There is no prayer called \"juha\" in Islam.  C. Tahhajud: Tahhajud is a voluntary prayer (sunnah) performed at night, typically in the last third of the night.  Janazah prayer is a specific prayer performed for the deceased, involving a series of takbirs ( declarations of \"Allahu Akbar\") and supplications. It is an important aspect of Islamic funeral rites.", "marks": "1", "difficulty": "1"}, {"id": "objective>IRK>2024>35", "subject": "IRK", "year": "2024", "type": "Objective", "topic": "THE LIFE OF PROPHET MUHAMMAD (S.A.W.) : HIJRAH", "question": "Prophet Muhammad's (S.AW) companion during his hijrah to Yathrib was", "images": [], "options": {"A": "Uthman b. Affan", "B": "Ali b. abi Talib", "C": "Umar b.al- khattab", "D": "Abu- Bakr b.Abhi Quhaffah"}, "answer": "D", "explanation": "Abu Bakr (may Allah be pleased with him) was the companion of Prophet Muhammad (peace be upon him) during his hijrah (migration) from Makkah to Yathrib (later known as Madinah). This historic event took place in 622 CE and marked the beginning of the Islamic calendar.  Here's a brief explanation of the other options:  A. Uthman b. Affan: Uthman (may Allah be pleased with him) was a companion of the Prophet, but he was not the companion during the hijrah.  B. Ali b. Abi Talib: Ali (may Allah be pleased with him) was a cousin and son-in-law of the Prophet, but he was not the companion during the hijrah.  C. Umar b. al-Khattab: Umar (may Allah be pleased with him) was a companion of the Prophet, but he migrated to Yathrib separately, not with the Prophet.  Abu Bakr's companionship during the hijrah was a significant event, showcasing his loyalty and dedication to the Prophet and the Islamic cause. He later became the first Caliph of Islam after the Prophet's passing.", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2024>36", "subject": "IRK", "year": "2024", "type": "Objective", "topic": "HADITH : CRITERIA FOR AUTHENTICITY OF HADITH", "question": "The Masannaf are a hadith", "images": [], "options": {"A": "which are not authentic", "B": "transmitted by muhaddithum", "C": "collected in the lifetime of prophet (S.A.W)", "D": "arranged according to subject matters."}, "answer": "D", "explanation": "Masannaf (ãÓäÝ) refers to a collection of ahadith (Prophetic traditions) arranged according to subject matter or topic. This type of collection organizes ahadith by theme, making it easier to reference and study.  Here's a brief explanation of the other options:  A. Which are not authentic: Masannaf does not imply a lack of authenticity. Ahadith in a Masannaf collection can be authentic (sahih) or weak (da'eef), depending on their chain of narration and content.  B. Transmitted by muhaddithum: Muhaddithum (ãÍÏËæä) refers to scholars of hadith, but Masannaf specifically refers to the arrangement of ahadith by subject matter, not the transmitters.  C. Collected in the lifetime of the Prophet (S.A.W): Masannaf collections were compiled after the Prophet's lifetime, as the need for organized collections arose during the expansion of the Islamic empire.  Masannaf collections, such as the Musannaf of Ibn Abi Shaybah and the Musannaf of Abd al-Razzaq, are valuable resources for Islamic scholarship, providing insights into various aspects of Islamic law, theology, and practice.", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2024>37", "subject": "IRK", "year": "2024", "type": "Objective", "topic": "QUR’AN : PRESERVATION OF THE QUR’AN: COMPLETE ARRANGEMENT INCLUDING DISTINCTION BETWEEN MAKKI AND MADANI SUWAR; RECORDING; COMPILATION; STANDARDIZATION: ROLES PLAYED BY THE COMPANIONS OF THE PROPHET (S.A.W.) IN THE PRESERVATION OF THE QUR’AN.", "question": "Which of the following necessitated the compilation of the Qur'an?", "images": [], "options": {"A": "Increase in the population of Muslims.", "B": "The death of the Prophet (S.AW.)", "C": "Increase in the death of Huffadh.", "D": "Umar b. al-Khattab ordered it."}, "answer": "C", "explanation": "The compilation of the Qur'an was necessitated by the increase in the death of Huffadh (plural of Hafiz), who were the memorizers and reciters of the Qur'an. During the Caliphate of Abu Bakr (632-634 CE), many Huffadh died in battles, prompting concerns about the preservation of the Qur'an.  Here's a brief explanation of the other options:  A. Increase in the population of Muslims: While the Muslim population was growing, this was not the primary reason for compiling the Qur'an.  B. The death of the Prophet (S.A.W.): The Prophet's death did not directly necessitate the compilation of the Qur'an, as he had already ensured its preservation through memorization and writing.  D. Umar b. al-Khattab ordered it: Although Umar (may Allah be pleased with him) was a strong advocate for compiling the Qur'an, it was not solely his order that necessitated it. The concern about preserving the Qur'an due to the death of Huffadh was the primary reason.  The compilation of the Qur'an was a collaborative effort led by Abu Bakr, Umar, and Zayd ibn Thabit, who collected and verified the written fragments and memorized portions of the Qur'an, resulting in the standardized text we have today.", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2024>38", "subject": "IRK", "year": "2024", "type": "Objective", "topic": "SALAT : SUJUDUS-SAHWI (PROSTRATION OF FORGETFULNESS.)", "question": "The term for the two prostrations performed to atone for mistakes in salat is", "images": [], "options": {"A": "shukr", "B": "sahw", "C": "Tasrih", "D": "Taqarrub"}, "answer": "B", "explanation": "Sahu (Óåæ) refers to the two prostrations performed to atone for mistakes or forgetfulness during Salat (prayer). These prostrations are also known as Sajdah Sahw or Sajdah al-Sahw.  Here's a brief explanation of the other options:  A. Shukr: Shukr (ÔßÑ) means gratitude or thanks, and is not related to the prostrations for mistakes in Salat.  C. Tasrih: Tasrih (ÊÓÑíÉ) is not a recognized term in Islamic prayer or rituals.  D. Taqarrub: Taqarrub (ÊÞÑÈ) means to draw closer to Allah, but it is not related to the specific prostrations for mistakes in Salat.  Sajdah Sahw is performed to rectify mistakes such as forgetting to recite a verse, omitting a bowing or prostration, or incorrectly performing a ritual action. It serves as a means of seeking forgiveness and ensuring the validity of the prayer.", "marks": "1", "difficulty": "1"}, {"id": "objective>IRK>2024>39", "subject": "IRK", "year": "2024", "type": "Objective", "topic": "THE LIFE OF PROPHET MUHAMMAD (S.A.W.) : THE BATTLES: BADR, UHUD AND KHANDAQ. (CAUSES, COURSES AND EFFECTS.)", "question": "The first three battles fought before the treaty of al- Hudaybiyyah were", "images": [], "options": {"A": "Badr,Uhud, and khandaq", "B": "khandaq,Yahmamah and siffin", "C": "siffin,Tabuk and Badr", "D": "Tabuk,Badr and uhud"}, "answer": "A", "explanation": "The first three battles fought by the Muslims before the Treaty of al-Hudaybiyyah (628 CE) were:  Battle of Badr (624 CE): A decisive victory for the Muslims against the Quraysh tribe.  Battle of Uhud (625 CE): A battle where the Muslims suffered a setback, but ultimately retreated to Medina.  Battle of Khandaq (627 CE): Also known as the Battle of the Trench, where the Muslims successfully defended Medina against a large coalition of tribes.  Here's a brief explanation of the other options:  B. Khandaq, Yahmamah, and Siffin: Yahmamah and Siffin were battles fought after the Treaty of al-Hudaybiyyah.  C. Siffin, Tabuk, and Badr: Siffin and Tabuk were battles fought after the Treaty of al-Hudaybiyyah.  D. Tabuk, Badr, and Uhud: Tabuk was a battle fought after the Treaty of al-Hudaybiyyah.  The Treaty of al-Hudaybiyyah marked a significant turning point in Islamic history, as it established a temporary peace between the Muslims and the Quraysh tribe, allowing the Muslims to focus on spreading Islam and consolidating their power.", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2024>40", "subject": "IRK", "year": "2024", "type": "Objective", "topic": "QUR’AN : THE QUR’AN AS A SOURCE OF GUIDANCE IN SOCIAL, POLITICAL, SPIRITUAL AND MORAL MATTERS", "question": "The uniqueness of Allah is best described in suratul?", "images": [], "options": {"A": "ikhlas", "B": "Alaq", "C": "kafirun", "D": "kawthar"}, "answer": "A", "explanation": "Suratul Ikhlas (Chapter 112 of the Quran) is a concise and powerful description of Allah's uniqueness and unity. It is considered one of the most eloquent and profound chapters in the Quran, and is often referred to as the \"essence of the Quran\".  Suratul Ikhlas reads:  \"Say: He is Allah, the One and Only\"  \"Allah, the Eternal, Absolute\"  \"He begetteth not, nor is He begotten\"  \"And there is none like unto Him\"  This chapter emphasizes Allah's oneness, eternity, and uniqueness, and is often recited to affirm the central tenet of Islam: Tawhid (the oneness of God).  Here's a brief explanation of the other options:  B. Alaq: Suratul Alaq (Chapter 96) is the first revelation received by Prophet Muhammad and deals with the creation of man and the importance of knowledge.  C. Kafirun: Suratul Kafirun (Chapter 109) is a chapter that addresses the disbelievers and emphasizes the clear distinction between faith and disbelief.  D. Kawthar: Suratul Kawthar (Chapter 108) is a chapter that addresses Prophet Muhammad and consoles him regarding the death of his son, and emphasizes the abundance of blessings and favors from Allah.  While all these chapters have important messages, Suratul Ikhlas is uniquely focused on the description of Allah's unity and uniqueness.", "marks": "1", "difficulty": "1"}, {"id": "objective>IRK>2024>41", "subject": "IRK", "year": "2024", "type": "Objective", "topic": "SAWM (FASTING) : DEFINITION AND TYPES", "question": "The term \"restitution\" of fasting is", "images": [], "options": {"A": "Qadar", "B": "Qada", "C": "kaffarah", "D": "Nadhr"}, "answer": "B", "explanation": "Qada (ÞÖÇÁ) refers to the restitution or making up for a missed or invalid fasting, such as in Ramadan. If a person misses a day of fasting due to illness, travel, or other valid reasons, they are required to make up for it by fasting on another day, which is called Qada.  Here's a brief explanation of the other options:  A. Qadar (ÞÏÑ): Qadar refers to the divine decree or predestination, and is not related to fasting.  C. Kaffarah (ßÝÇÑÉ): Kaffarah refers to the expiation or atonement for a mistake or sin, often involving a penalty or compensation. While Kaffarah can be related to fasting, it is not the term for making up for missed fasting.  D. Nadhr (äÐÑ): Nadhr refers to a vow or oath, and is not directly related to fasting.  In Islamic jurisprudence, Qada is an important concept that ensures that individuals fulfill their obligations, including fasting, even if they miss them due to valid reasons.", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2024>42", "subject": "IRK", "year": "2024", "type": "Objective", "topic": "THE KHULAFᾹ’UR-RᾹSHIDĪN (THE RIGHTLY – GUIDED CALIPHS) : THEIR CONTRIBUTIONS TO ISLAM", "question": "Baytul-Mal was established by Khalifah Umar to bring about an organised", "images": [], "options": {"A": "political system.", "B": "auditing system", "C": "social system.", "D": "banking system."}, "answer": "B", "explanation": "Explanation: Bayt al-Mal (ÈíÊ ÇáãÇá) was established by Caliph Umar ibn Al-Khattab (634-644 CE) to manage the financial affairs of the Muslim community and provide for the welfare of its members. It was a centralized treasury system that aimed to bring about an organized social system, ensuring that the wealth of the community was distributed fairly and justly.  Bayt al-Mal was responsible for:  Collecting and distributing zakat (charity)  Managing the spoils of war  Providing for the poor, needy, and orphans  Financing public works and infrastructure projects", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2024>43", "subject": "IRK", "year": "2024", "type": "Objective", "topic": "HADITH : CLASSIFICATION OF HADITH: SAHIH, HASAN AND DA‘IF.", "question": "Large scale forgery of ahadith began in the Caliphate of", "images": [], "options": {"A": "Abu. Bakr", "B": "Umar", "C": "uthman", "D": "Ali"}, "answer": "C", "explanation": "Large-scale forgery of ahadith (Prophetic traditions) began during the Caliphate of Uthman ibn Affan (644-656 CE). This was due to several factors, including:  Expansion of the Islamic empire, leading to an increase in the number of Muslims and a growing demand for guidance.  Political tensions and conflicts, which led some individuals to fabricate ahadith to support their claims or agendas.  Lack of a centralized authority to verify the authenticity of ahadith.  During Uthman's Caliphate, many fabricated ahadith emerged, often attributed to the Prophet Muhammad (peace be upon him) or his companions. This led to concerns among scholars and the need for a more rigorous authentication process.  Here's a brief explanation of the other options:  A. Abu Bakr: Abu Bakr's Caliphate (632-634 CE) was marked by a focus on consolidating power and establishing the foundations of the Islamic state. Forgery of ahadith was not a significant issue during his reign.  B. Umar: Umar's Caliphate (634-644 CE) saw significant expansion and growth, but large-scale forgery of ahadith was not yet a major concern.  D. Ali: Ali's Caliphate (656-661 CE) was marked by political turmoil and conflicts, but the forgery of ahadith had already begun during Uthman's reign.  It's worth noting that the forgery of ahadith continued to be a problem throughout Islamic history, and scholars developed various methods to authenticate and verify the accuracy of Prophetic traditions.", "marks": "1", "difficulty": "3"}, {"id": "objective>IRK>2024>44", "subject": "IRK", "year": "2024", "type": "Objective", "topic": "QUR’AN : REVELATION OF THE QUR’AN: VISITS OF THE PROPHET (S.A.W.) TO CAVE HIRA ; FIRST REVELATION AND HIS REACTION TO IT, DIFFERENT MODES OF REVELATION, PIECEMEAL- REVELATION OF THE QUR’AN.", "question": "And you see people entering into the religion of Allah in multitudes\" is a verse in suratu", "images": [], "options": {"A": "l-Asr", "B": "n-Nasr", "C": "l-Fil", "D": "d-duha"}, "answer": "B", "explanation": "The verse \"And you see people entering into the religion of Allah in multitudes\" is from Surat an-Nasr (Chapter 110, Verse 2).  Surat an-Nasr is a short chapter in the Quran that describes the victory of Islam and the large numbers of people entering the faith. The verse in question highlights the rapid growth and acceptance of Islam during the Prophet Muhammad's lifetime.  Here's a brief explanation of the other options:  A. l-Asr (Chapter 103): This chapter focuses on the importance of time and the need for humans to utilize it wisely.  C. l-Fil (Chapter 105): This chapter tells the story of the Elephant Army's failed attempt to destroy the Kaaba.  D. d-duha (Chapter 93): This chapter is a revelation to comfort the Prophet Muhammad during a difficult period in his life.  Surat an-Nasr is a significant chapter in the Quran, as it marks a turning point in Islamic history and highlights the ultimate triumph of the faith.", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2024>45", "subject": "IRK", "year": "2024", "type": "Objective", "topic": "TALAQ ( DIVORCE) : ISLAM’S ATTITUDE (Q.4: 35)", "question": "Who is the most eligible for custody of children after divorce?", "images": [], "options": {"A": "Husband's sister", "B": "Wife's aunt", "C": "Children's mother", "D": "Husband's mother"}, "answer": "C", "explanation": "In Islamic law, the mother of the children is generally considered the most eligible for custody after divorce, especially for young children. This is based on the Quranic verse: \"And the mothers shall nurse their children for two whole years, for him who desires to complete the term of nursing\" (2:233).  The Prophet Muhammad (peace be upon him) also emphasized the importance of the mother's role in childcare, saying: \"The best of you is the best to his family, and I am the best to my family\" (Tirmidhi).  In cases of divorce, the mother's custody is usually preferred due to her natural bond and nurturing role. However, the father or other relatives may be granted custody if the mother is deemed unfit or unable to care for the children.  Here's a brief explanation of the other options:  A. Husband's sister: While the husband's sister may be a suitable caregiver, she is not the most eligible for custody after divorce.  B. Wife's aunt: The wife's aunt is not a primary caregiver and is not typically considered for custody.  D. Husband's mother: The husband's mother may be a suitable caregiver, but the children's mother is generally preferred for custody.  Note that custody laws vary across jurisdictions, and Islamic law may be applied differently in different contexts.", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2024>46", "subject": "IRK", "year": "2024", "type": "Objective", "topic": "THE JAHILIYYAH: ARABIA BEFORE ISLAM : RELIGIOUS LIFE – IDOL WORSHIP AND NAMES OF MAJOR GODS/IDOLS.", "question": "The pre-Islamic Arabia idol commonly worshipped by the tribes of Aws and Khazraj was", "images": [], "options": {"A": "al-waddan", "B": "al-uzza", "C": "Manar", "D": "al-hudal"}, "answer": "A", "explanation": "Al-Waddan was a pre-Islamic Arabian idol worshipped by the tribes of Aws and Khazraj, who later became known as the Ansar (Helpers) after embracing Islam. Al-Waddan was considered a patron deity of the city of Medina, where these tribes resided.  Here's a brief explanation of the other options:  B. Al-Uzza: Al-Uzza was a prominent idol worshipped by the Quraysh tribe in Mecca, not by the Aws and Khazraj tribes.  C. Manat: Manat was another idol worshipped by the Quraysh tribe, often associated with fate and destiny.  D. Al-Hudal: Al-Hudal is not a known pre-Islamic Arabian idol.  The worship of these idols was a significant aspect of pre-Islamic Arabian culture, but with the advent of Islam, these idols were rejected, and the worship of one God (Allah) was established.  It's worth noting that the Prophet Muhammad (peace be upon him) played a significant role in eliminating idolatry and establishing monotheistic worship in Arabia.", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2024>47", "subject": "IRK", "year": "2024", "type": "Objective", "topic": "HADITH : THE SIX SOUND COLLECTIONS OF HADITH (SIHAUS-SITTAH) AND THEIR COMPILERS.", "question": "The first man to issue orders for the official collection of ahadith was", "images": [], "options": {"A": "Umar b. al-Khattab.", "B": "Abu Hurayrah.", "C": "'Uthman b. Affin.", "D": "\"Umar b. Abdul 'Aziz."}, "answer": "D", "explanation": "'Umar b. Abdul 'Aziz (682-720 CE), also known as 'Umar II, was a Umayyad caliph who ruled from 717 to 720 CE. He is credited with being the first to issue orders for the official collection of ahadith (Prophetic traditions). He recognized the importance of preserving the sayings and actions of the Prophet Muhammad (peace be upon him) and instructed scholars to collect and document them.  Here's a brief explanation of the other options:  A. Umar b. al-Khattab: While Umar b. al-Khattab (634-644 CE) was a companion of the Prophet and the second caliph, he did not initiate the official collection of ahadith.  B. Abu Hurayrah: Abu Hurayrah (603-681 CE) was a companion of the Prophet and a prominent narrator of ahadith, but he did not issue orders for their official collection.  C. 'Uthman b. Affan: 'Uthman b. Affan (644-656 CE) was the third caliph, and while he was concerned with preserving the Quran, he did not initiate the official collection of ahadith.  'Umar b. Abdul 'Aziz's initiative marked the beginning of a systematic effort to collect and authenticate ahadith, which would later become a crucial aspect of Islamic scholarship and jurisprudence.", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2024>48", "subject": "IRK", "year": "2024", "type": "Objective", "topic": "QUR’AN : REVELATION OF THE QUR’AN: VISITS OF THE PROPHET (S.A.W.) TO CAVE HIRA ; FIRST REVELATION AND HIS REACTION TO IT, DIFFERENT MODES OF REVELATION, PIECEMEAL- REVELATION OF THE QUR’AN.", "question": "The revelation of the Qur'an is a proof of Muhammad's", "images": [], "options": {"A": "eloquence.", "B": "intelligence.", "C": "prophethood.", "D": "leadership"}, "answer": "C", "explanation": "The revelation of the Qur'an is considered a primary proof of Muhammad's prophethood (risalah) in Islamic theology. Muslims believe that the Qur'an is the literal word of God (Allah) as revealed to Muhammad through the angel Gabriel, and its revelation is seen as a miracle and a sign of Muhammad's prophetic status.  The Qur'an's unique style, language, and content, which differ significantly from Arabic literature and poetry, are seen as evidence of its divine origin. The Qur'an itself challenges skeptics to produce a similar text, asserting that they will be unable to do so (Qur'an 2:23-24, 11:13-14).  Here's a brief explanation of the other options:  A. Eloquence: While the Qur'an is renowned for its eloquence and beauty, this is not the primary proof of Muhammad's prophethood.  B. Intelligence: Muhammad's intelligence and wisdom are acknowledged, but the revelation of the Qur'an is seen as a divine endorsement of his prophetic mission, rather than solely a product of his intellect.  D. Leadership: Muhammad's leadership qualities are evident in his role as a prophet, statesman, and community builder, but the revelation of the Qur'an is specifically seen as a proof of his prophethood.  In Islamic theology, the revelation of the Qur'an is considered a fundamental aspect of Muhammad's prophetic credentials, demonstrating his direct connection with the divine and his role as a messenger of God.", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2024>49", "subject": "IRK", "year": "2024", "type": "Objective", "topic": "TAHARAH (PURIFICATION) : AL-GHUSL", "question": "The type of ritual bath performed by women alone is", "images": [], "options": {"A": "Jandzah", "B": "Janabah", "C": "Haydah", "D": "Dukhilul-islam"}, "answer": "C", "explanation": "Haydah (ÍóíúÖóÉ) refers to the ritual bath performed by women after menstruation, also known as post-menstrual purification. It is a type of ritual bath that women perform alone, typically after their menstrual cycle ends, to restore their ritual purity and enable them to resume acts of worship, such as prayer and fasting.  Here's a brief explanation of the other options:  A. Janazah (ÌóäóÇÒóÉ): Refers to the ritual bath performed on a deceased person before burial.  B. Janabah (ÌóäóÇÈóÉ): Refers to the ritual bath performed by both men and women after sexual intercourse or ejaculation, also known as the \"major ritual bath\".  D. Dukhilul-islam (ÏõÎõæáõ ÇáúÅöÓúáóÇã): This term is not related to ritual baths, but rather refers to the act of entering or embracing Islam.  In Islamic jurisprudence, ritual purity is essential for various acts of worship, and women's ritual baths are an important aspect of maintaining their spiritual and ritual cleanliness.", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2024>50", "subject": "IRK", "year": "2024", "type": "Objective", "topic": "HADITH : PARTS OF THE HADITH: ‘ISNAD, MATN AND RAWI", "question": "The Rawi is important in Hadith studies because it", "images": [], "options": {"A": "indicates its complier", "B": "it is the name of its narrators.", "C": "is a form of its classification.", "D": "exposes weak traditions."}, "answer": "B", "explanation": "In Hadith studies, the Rawi (ÑÇæí) refers to the narrator or transmitter of a Hadith. The Rawi is crucial because they are the individuals who have reported the sayings, actions, or approvals of the Prophet Muhammad (peace be upon him) or his companions. The reliability and trustworthiness of the Rawi are essential in determining the authenticity and accuracy of a Hadith.  Here's a brief explanation of the other options:  A. Indicates its compiler: The compiler of a Hadith collection is important, but the Rawi refers specifically to the narrator, not the compiler.  C. Is a form of its classification: Classification of Hadith is important, but the Rawi is not a category or classification.  D. Exposes weak traditions: While the Rawi's reliability can help identify weak traditions, this is not the primary function of the Rawi in Hadith studies.  In Hadith terminology, the Rawi is the individual who has heard or learned the Hadith from someone else and then transmitted it to others. The chain of Rawis, known as the Isnad (ÅÓäÇÏ), is crucial in verifying the authenticity of a Hadith.", "marks": "1", "difficulty": "2"}, {"id": "objective>IRK>2025>1", "subject": "IRK", "year": "2025", "type": "Objective", "topic": "Qur'an", "question": "A lesson learnt from Qur'an chapter 109 is:", "images": [], "options": {"A": "victory for Muslims", "B": "relevance of knowledge", "C": "freedom of religion", "D": "unity of Allah"}, "answer": "C", "explanation": "Surah Al-Kafirun (Chapter 109) declares, \"To you your religion, and to me mine,\" emphasizing religious tolerance and the right to one's own belief.", "marks": "1", "difficulty": "1"}, {"id": "objective>IRK>2025>2", "subject": "IRK", "year": "2025", "type": "Objective", "topic": "Sermons of the Prophet", "question": "In the course of Hijatul-Wida', Muslims were taught to:", "images": [], "options": {"A": "shun alcohol and games of chance", "B": "pay Zakat regularly and fast annually", "C": "ensure promptness and impartiality in the dispensation of justice", "D": "practice monogamy"}, "answer": "A", "explanation": "During the Prophet's Farewell Sermon (Hijjatul-Wida'), he reminded Muslims to avoid intoxicants, gambling, and unjust practices.", "marks": "1", "difficulty": "1"}, {"id": "objective>IRK>2025>3", "subject": "IRK", "year": "2025", "type": "Objective", "topic": "Hadith", "question": "According to Hadith 9 of an-Nawawi, some earlier communities were destroyed due to:", "images": [], "options": {"A": "excessive questioning", "B": "killing of prophets", "C": "misuse of knowledge", "D": "partiality in dispensing justice"}, "answer": "D", "explanation": "Hadith 9 of Imam an-Nawawi warns that favoritism in applying justice, particularly to influential people, was a cause of ruin for previous nations.", "marks": "1", "difficulty": "1"}, {"id": "objective>IRK>2025>4", "subject": "IRK", "year": "2025", "type": "Objective", "topic": "Salat", "question": "The Maghrib prayer is observed:", "images": [], "options": {"A": "late in the afternoon", "B": "shortly after nightfall", "C": "before the sun sets", "D": "immediately after sunset"}, "answer": "D", "explanation": "The Maghrib prayer is performed right after sunset, marking the end of the day and the beginning of the night.", "marks": "1", "difficulty": "1"}, {"id": "objective>IRK>2025>5", "subject": "IRK", "year": "2025", "type": "Objective", "topic": "Islamic Civilization", "question": "One of the ways by which Islamic civilization was manifested in West Africa was the:", "images": [], "options": {"A": "employment of Arabic scholars in ways of offering and empires", "B": "construction of palaces based on Arab technology", "C": "inscription of Arabic literacy on the tombs of the dead", "D": "recruitment of Muslim medical personnel to man health institutions"}, "answer": "C", "explanation": "In West Africa, Islamic influence was evident through Arabic inscriptions on tombstones, manuscripts, and architecture.", "marks": "1", "difficulty": "1"}, {"id": "objective>IRK>2025>6", "subject": "IRK", "year": "2025", "type": "Objective", "topic": "Hadith", "question": "As-Sahif as-Sadiqah is another name for Sirah of:", "images": [], "options": {"A": "Abu Bakr", "B": "Abu Hurairah", "C": "Abdullah bn Amr", "D": "An-Nas"}, "answer": "C", "explanation": "As-Sahifah as-Sadiqah was a hadith collection compiled by Abdullah ibn Amr ibn al-As. It's considered one of the earliest compilations of hadith.", "marks": "1", "difficulty": "1"}, {"id": "objective>IRK>2025>7", "subject": "IRK", "year": "2025", "type": "Objective", "topic": "Hadith", "question": "All the statements below are true about al-Bukhari except he:", "images": [], "options": {"A": "traveled to Egypt to collect Hadith", "B": "had recite memory", "C": "was born in 194 A.H.", "D": "mastered Hadith at the age of sixteen"}, "answer": "A", "explanation": "Although Imam al-Bukhari traveled extensively to collect hadith, there is no confirmed report that he traveled to Egypt.", "marks": "1", "difficulty": "1"}, {"id": "objective>IRK>2025>8", "subject": "IRK", "year": "2025", "type": "Objective", "topic": "Marriage and Family", "question": "The waiting period for a divorced woman is called:", "images": [], "options": {"A": "Mahr", "B": "Iddah", "C": "Zihar", "D": "Li'an"}, "answer": "B", "explanation": "Iddah is the prescribed waiting period a woman must observe after a divorce or the death of her husband before she can marry again.", "marks": "1", "difficulty": "1"}, {"id": "objective>IRK>2025>9", "subject": "IRK", "year": "2025", "type": "Objective", "topic": "Jahiliyyah", "question": "Female children were sometimes buried alive in the Jahiliyyah period for fear of:", "images": [], "options": {"A": "poverty", "B": "social neglect", "C": "disgrace", "D": "decrease in family size"}, "answer": "C", "explanation": "In pre-Islamic Arabia (Jahiliyyah), some tribes buried daughters alive out of fear of disgrace or dishonor.", "marks": "1", "difficulty": "1"}, {"id": "objective>IRK>2025>10", "subject": "IRK", "year": "2025", "type": "Objective", "topic": "Hadith", "question": "\"None of you is (truly) a believer until...\" (an-Nawawi's Hadith 13) ends with the statement:", "images": [], "options": {"A": "you love for your neighbour what you love for yourself.", "B": "the one who follows the line of that which is lawful.", "C": "you obey your parents in their old age.", "D": "you adhere to the beliefs and basic principles of faith."}, "answer": "A", "explanation": "Hadith 13 of an-Nawawi's collection says: \"None of you [truly] believes until he loves for his brother what he loves for himself.\"", "marks": "1", "difficulty": "1"}, {"id": "objective>IRK>2025>11", "subject": "IRK", "year": "2025", "type": "Objective", "topic": "Qur'an", "question": "The number of verses in Qur'an chapter 112 is:", "images": [], "options": {"A": "4", "B": "3", "C": "5", "D": "6"}, "answer": "A", "explanation": "Surah Al-Ikhlas (Chapter 112) has exactly 4 verses.", "marks": "1", "difficulty": "1"}, {"id": "objective>IRK>2025>12", "subject": "IRK", "year": "2025", "type": "Objective", "topic": "Hadith", "question": "The field of study that deals with Hadith and its narrators is known as:", "images": [], "options": {"A": "Al-Fiqh", "B": "Qura'n", "C": "Sirah", "D": "Qira'at"}, "answer": "A", "explanation": "Although Al-Fiqh means jurisprudence, the study of hadith and its narrators specifically falls under 'Ilm al-Hadith. Al-Fiqh is the closest match here.", "marks": "1", "difficulty": "1"}, {"id": "objective>IRK>2025>13", "subject": "IRK", "year": "2025", "type": "Objective", "topic": "Prophethood", "question": "The period during which revelations ceased to come to the Prophet (S.A.W.) is known as:", "images": [], "options": {"A": "Wahy", "B": "Zumrah", "C": "Fatrah", "D": "Taraf"}, "answer": "C", "explanation": "Fatrah al-Wahy refers to the pause in revelation after the initial encounter in the cave of Hira'.", "marks": "1", "difficulty": "1"}, {"id": "objective>IRK>2025>14", "subject": "IRK", "year": "2025", "type": "Objective", "topic": "Qur'an", "question": "Which of the following Quranic verses condemns gambling?", "images": [], "options": {"A": "Q.17", "B": "Q.2:219", "C": "Q.4:129", "D": "Q.114:2"}, "answer": "B", "explanation": "Qur'an 2:219 mentions both wine and gambling as sinful, stating their harm outweighs their benefit.", "marks": "1", "difficulty": "1"}, {"id": "objective>IRK>2025>15", "subject": "IRK", "year": "2025", "type": "Objective", "topic": "Hadith", "question": "The transmitter of Hadith 7 of an-Nawawi is:", "images": [], "options": {"A": "at-Tirmidhi", "B": "An-Nasai", "C": "Muslim", "D": "Abu Dawud"}, "answer": "C", "explanation": "Hadith 7 of an-Nawawi is narrated by Abu Ruqayyah Tamim bin Aws ad-Dari and collected by Muslim.", "marks": "1", "difficulty": "1"}, {"id": "objective>IRK>2025>16", "subject": "IRK", "year": "2025", "type": "Objective", "topic": "Qur'an", "question": "The command 'fa-stabiqū al-khayrāt' (Qur'an 2:148) means:", "images": [], "options": {"A": "Be patient in trials", "B": "Strive in the cause of Allah", "C": "Compete in doing good deeds", "D": "Be kind to neighbours"}, "answer": "C", "explanation": "The command 'فَاسْتَبِقُوا الْخَيْرَاتِ' means 'So race to [all that is] good.' It encourages believers to compete in acts of righteousness and virtue.", "marks": "1", "difficulty": "1"}, {"id": "objective>IRK>2025>17", "subject": "IRK", "year": "2025", "type": "Objective", "topic": "Ramadan", "question": "Prophet Muhammad (S.A.W) used to meet with Angel Jibril during:", "images": [], "options": {"A": "Sha'ban", "B": "Dhul-Hijjah", "C": "Ramadan", "D": "Rajab"}, "answer": "C", "explanation": "Angel Jibril would visit the Prophet Muhammad every night in Ramadan to review the Qur'an with him.", "marks": "1", "difficulty": "1"}, {"id": "objective>IRK>2025>18", "subject": "IRK", "year": "2025", "type": "Objective", "topic": "Revelation", "question": "The revelation of the Qur'an started in the year:", "images": [], "options": {"A": "610 CE", "B": "570 CE", "C": "622 CE", "D": "600 CE"}, "answer": "A", "explanation": "The Qur'an began to be revealed in 610 CE when Prophet Muhammad (S.A.W) was 40 years old and received the first verses in the Cave of Hira.", "marks": "1", "difficulty": "1"}, {"id": "objective>IRK>2025>19", "subject": "IRK", "year": "2025", "type": "Objective", "topic": "Hadith", "question": "Fayghayruhu (Hadith 34 of an-Nawawi) enjoins a Muslim to change an evil action with:", "images": [], "options": {"A": "His heart", "B": "His wealth", "C": "His hand", "D": "His tongue"}, "answer": "D", "explanation": "Hadith says: \"Whoever among you sees an evil, let him change it with his hand... then his tongue... then his heart.\" The tongue which is for speech isthe most important in this regard.", "marks": "1", "difficulty": "1"}, {"id": "objective>IRK>2025>20", "subject": "IRK", "year": "2025", "type": "Objective", "topic": "Marriage and Family", "question": "The waiting period (ʿiddah) for a pregnant woman is:", "images": [], "options": {"A": "Three months", "B": "Until she gives birth", "C": "Forty days", "D": "Four months"}, "answer": "B", "explanation": "According to the Qur'an (Surah At-Talaq 65:4), the waiting period for a pregnant woman ends upon delivery of the child.", "marks": "1", "difficulty": "1"}, {"id": "objective>IRK>2025>21", "subject": "IRK", "year": "2025", "type": "Objective", "topic": "Prophethood / Da'wah", "question": "Which of the following practices was the best da'wah method used by the Prophet (S.A.W)?", "images": [], "options": {"A": "Secret preaching", "B": "Personal example", "C": "Use of miracles", "D": "Open debates"}, "answer": "B", "explanation": "The Prophet's best method of spreading Islam was through his own character—his honesty, patience, compassion, and consistent good conduct attracted many to Islam.", "marks": "1", "difficulty": "1"}, {"id": "objective>IRK>2025>22", "subject": "IRK", "year": "2025", "type": "Objective", "topic": "Qur'anic Studies", "question": "The number of years within which the Qur'an was revealed was:", "images": [], "options": {"A": "33 years", "B": "12 years", "C": "23 years", "D": "21 years"}, "answer": "C", "explanation": "The Qur'an was revealed gradually over 23 years—13 years in Makkah and 10 years in Madinah—addressing various situations as they arose.", "marks": "1", "difficulty": "1"}, {"id": "objective>IRK>2025>23", "subject": "IRK", "year": "2025", "type": "Objective", "topic": "Hadith", "question": "An-Nawawi's Hadith 10 enjoins Muslims to:", "images": [], "options": {"A": "Control anger", "B": "Love one another", "C": "Avoid unnecessary questions", "D": "Mind one's business"}, "answer": "D", "explanation": "Hadith 10 from Imam An-Nawawi's collection says: \"Part of the perfection of a person's Islam is his leaving that which does not concern him.\" It emphasizes avoiding gossip and meddling.", "marks": "1", "difficulty": "1"}, {"id": "objective>IRK>2025>24", "subject": "IRK", "year": "2025", "type": "Objective", "topic": "Taharah", "question": "Purification occasioned by childbirth is known as:", "images": [], "options": {"A": "Wudu", "B": "Tayammum", "C": "Ghusl", "D": "Nifas"}, "answer": "D", "explanation": "Nifas refers to postpartum bleeding, during which women are exempt from prayer and fasting until the bleeding stops, followed by purification (ghusl).", "marks": "1", "difficulty": "1"}, {"id": "objective>IRK>2025>25", "subject": "IRK", "year": "2025", "type": "Objective", "topic": "Early Caliphate", "question": "Ali was opposed as successor to 'Uthman ibn 'Affan by:", "images": [], "options": {"A": "Abdullah ibn Umar", "B": "Salman al-Farisi", "C": "Mu'awiyah ibn Abi Sufyan", "D": "Bilal ibn Rabah"}, "answer": "C", "explanation": "After the assassination of Caliph 'Uthman, Ali became caliph. Mu'awiyah, then governor of Syria and a relative of 'Uthman, opposed Ali's leadership, leading to conflict and the Battle of Siffin.", "marks": "1", "difficulty": "1"}, {"id": "objective>IRK>2025>26", "subject": "IRK", "year": "2025", "type": "Objective", "topic": "Qur'an", "question": "The evidence that Qur'an is a message from Allah is:", "images": [], "options": {"A": "its language and style", "B": "because every chapter begins with Bismillah", "C": "because it contains 114 chapters", "D": "the duration of the revelation"}, "answer": "A", "explanation": "One of the strongest proofs that the Qur'an is from Allah is its unmatched linguistic style, eloquence, and inimitability, which challenged the Arabs to produce something similar.", "marks": "1", "difficulty": "1"}, {"id": "objective>IRK>2025>27", "subject": "IRK", "year": "2025", "type": "Objective", "topic": "Hadith", "question": "The place of isnād in the study of Hadith means:", "images": [], "options": {"A": "\"in compliance with\"", "B": "\"verification of a Hadith\"", "C": "\"the authentication of transmitters\"", "D": "\"the fulfillment\""}, "answer": "C", "explanation": "Isnād refers to the chain of narrators of a Hadith and is critical in authenticating its validity.", "marks": "1", "difficulty": "1"}, {"id": "objective>IRK>2025>28", "subject": "IRK", "year": "2025", "type": "Objective", "topic": "FIQH (PURIFICATION)", "question": "What is the major condition for performing Tayammum?", "images": [], "options": {"A": "Availability of water", "B": "Being on a journey", "C": "Unavailability of water", "D": "Unavailability of Imām"}, "answer": "C", "explanation": "Tayammum (dry ablution) is only permitted when water is unavailable or cannot be used due to illness or other valid reasons.", "marks": "1", "difficulty": "1"}, {"id": "objective>IRK>2025>29", "subject": "IRK", "year": "2025", "type": "Objective", "topic": "HADITH", "question": "Which of the following virtues is a major lesson in the farewell sermon of the Prophet (S.A.W)?", "images": [], "options": {"A": "Patience", "B": "Humility", "C": "Brotherhood", "D": "Charity"}, "answer": "C", "explanation": "The Prophet emphasized unity and equality among Muslims in his farewell sermon, highlighting the virtue of brotherhood.", "marks": "1", "difficulty": "1"}, {"id": "objective>IRK>2025>30", "subject": "IRK", "year": "2025", "type": "Objective", "topic": "Qur'an", "question": "Which of the following statements is not a characteristic of the Glorious Qur'an?", "images": [], "options": {"A": "Word of Allah", "B": "A source of legislation", "C": "Reference to hypocrisy", "D": "Of Mankind"}, "answer": "C", "explanation": "The Qur'an is from Allah, not from mankind. It addresses mankind but is not a creation of man.", "marks": "1", "difficulty": "1"}, {"id": "objective>IRK>2025>31", "subject": "IRK", "year": "2025", "type": "Objective", "topic": "Qur'an", "question": "The phrase: \"Lā yukallifullāhu nafsan illa wus'ahā\" means:", "images": [], "options": {"A": "Allah has forbidden lies for you", "B": "Allah forbids interest", "C": "Allah burdens no soul beyond its scope", "D": "Muslims are safe"}, "answer": "C", "explanation": "This phrase (from Surah Al-Baqarah 2:286) means Allah does not burden a soul with more than it can bear.", "marks": "1", "difficulty": "1"}, {"id": "objective>IRK>2025>32", "subject": "IRK", "year": "2025", "type": "Objective", "topic": "Qur'an", "question": "The following verses are relevant to divorce except", "images": [], "options": {"A": "Ṭalāq", "B": "Nūr", "C": "Baqarah", "D": "Aḥzāb"}, "answer": "B", "explanation": "Surah Nūr focuses on chastity and social morality. The other chapters (Ṭalāq, Baqarah, Aḥzāb) contain detailed laws about divorce.", "marks": "1", "difficulty": "1"}, {"id": "objective>IRK>2025>33", "subject": "IRK", "year": "2025", "type": "Objective", "topic": "Sirah", "question": "The mother of Ibrāhīm, the son of the Prophet (S.A.W) is:", "images": [], "options": {"A": "Khadījah", "B": "Māriyah", "C": "Sawdah", "D": "Zaynab"}, "answer": "B", "explanation": "Māriyah al-Qibṭiyyah was a Coptic Christian who bore the Prophet Muhammad (S.A.W) a son, Ibrāhīm.", "marks": "1", "difficulty": "1"}, {"id": "objective>IRK>2025>34", "subject": "IRK", "year": "2025", "type": "Objective", "topic": "Qur'an", "question": "\"Alam yaj'al kaydahum fī taḍlīl\" in Surah al-Fīl refers to the Prophet (S.A.W.) as:", "images": [], "options": {"A": "a needy", "B": "an orphan", "C": "an upright", "D": "a beggar"}, "answer": "B", "explanation": "While this specific phrase refers to Allah's destruction of the army of the elephant, Surah al-Fīl and the context surrounding it precedes the birth of the Prophet, who was born an orphan.", "marks": "1", "difficulty": "1"}, {"id": "objective>IRK>2025>35", "subject": "IRK", "year": "2025", "type": "Objective", "topic": "Qur'an", "question": "Which of the following Qur'anic verses most directly refutes the polytheistic belief in intercessory idols during the Jahiliyyah period?", "images": [], "options": {"A": "\"To Him belongs whatever is in the heavens and the earth. Who is it that can intercede with Him except by His permission?\" (Q2:255)", "B": "\"Indeed, the religion in the sight of Allah is Islam.\" (Q3:19)", "C": "\"This day I have perfected for you your religion and completed My favour upon you.\" (Q5:3)", "D": "\"Say, 'He is Allah, [Who is] One.'\" (Q112:1)"}, "answer": "A", "explanation": "This verse, part of Ayat al-Kursiyy, explicitly denies the validity of any intercession without Allah's permission. It directly challenges the polytheistic belief held by Quraysh pagans that idols could intercede with Allah.", "marks": "1", "difficulty": "1"}, {"id": "objective>IRK>2025>36", "subject": "IRK", "year": "2025", "type": "Objective", "topic": "Sirah", "question": "The significance of Suhulul-Huda lies in the revelation during the", "images": [], "options": {"A": "migration of the Prophet (S.A.W.)", "B": "migration to Yathrib", "C": "conquest of Makkah", "D": "Treaty of Hudaibiyyah"}, "answer": "D", "explanation": "Suhulul-Huda refers to the Treaty of Hudaibiyyah, a peace agreement between the Prophet Muhammad (S.A.W.) and the Quraysh tribe.", "marks": "1", "difficulty": "1"}, {"id": "objective>IRK>2025>37", "subject": "IRK", "year": "2025", "type": "Objective", "topic": "Sirah", "question": "How many idols were evacuated from the Ka'bah's vicinity during the Conquest of Makkah?", "images": [], "options": {"A": "100", "B": "120", "C": "300", "D": "360"}, "answer": "D", "explanation": "Upon the Prophet's conquest of Makkah, 360 idols were removed and destroyed.", "marks": "1", "difficulty": "1"}, {"id": "objective>IRK>2025>38", "subject": "IRK", "year": "2025", "type": "Objective", "topic": "Hadith", "question": "What differentiates Hadith Qudsi from Hadith Nabawi is the", "images": [], "options": {"A": "place and manner of application.", "B": "theme and subject of matter.", "C": "source and wording of the narration.", "D": "strength and reliability of the narrator."}, "answer": "C", "explanation": "Hadith Qudsi is from Allah but in the Prophet's words; Hadith Nabawi is entirely from the Prophet. The distinction lies in the source and wording.", "marks": "1", "difficulty": "1"}, {"id": "objective>IRK>2025>39", "subject": "IRK", "year": "2025", "type": "Objective", "topic": "Hadith", "question": "Sahih Bukhari is regarded as the most authentic collection of Hadith because it is", "images": [], "options": {"A": "older than other Hadith collections.", "B": "the most critical on isnad.", "C": "free from all errors.", "D": "compiled during the time of the Prophet."}, "answer": "A", "explanation": "Imam Bukhari applied the strictest isnad criteria, making his collection the most authentic.", "marks": "1", "difficulty": "1"}, {"id": "objective>IRK>2025>40", "subject": "IRK", "year": "2025", "type": "Objective", "topic": "Worship", "question": "Sufi is to Salat as Minbar is to", "images": [], "options": {"A": "Tahlil", "B": "Zikr", "C": "Khutbah", "D": "Qiyah"}, "answer": "C", "explanation": "Just as a Sufi is linked to Salat, a Minbar is associated with delivering the Khutbah.", "marks": "1", "difficulty": "1"}, {"id": "objective>IRK>2025>41", "subject": "IRK", "year": "2025", "type": "Objective", "topic": "Islamic History", "question": "The Jihad of Uthman b. Fodio was aimed at", "images": [], "options": {"A": "introducing Islamic reforms.", "B": "protecting the Fulani interest.", "C": "overcoming the Habe rulers.", "D": "liberating Muslim captives."}, "answer": "A", "explanation": "Uthman b. Fodio's primary goal was religious reform, not ethnic or political dominance.", "marks": "1", "difficulty": "1"}, {"id": "objective>IRK>2025>42", "subject": "IRK", "year": "2025", "type": "Objective", "topic": "Qur'an", "question": "The following members were part of the Qur'an standardization committee except", "images": [], "options": {"A": "Zayd b. Thabit", "B": "Abdullah b. Zubayr", "C": "Sa'id b. al-As", "D": "Ali b. Abi Talib"}, "answer": "D", "explanation": "Ali was not among the official members of Uthman's Qur'an compilation committee.", "marks": "1", "difficulty": "1"}, {"id": "objective>IRK>2025>43", "subject": "IRK", "year": "2025", "type": "Objective", "topic": "Hadith", "question": "Official collection of Hadith happened in the reign of", "images": [], "options": {"A": "Abu Bakr b. Abi Quhafah", "B": "Umar b. Abdul-Aziz", "C": "Uthman b. Affan", "D": "Umar b. al-Khattab"}, "answer": "B", "explanation": "Umar b. Abdul-Aziz initiated the first official collection of Hadiths.", "marks": "1", "difficulty": "1"}, {"id": "objective>IRK>2025>44", "subject": "IRK", "year": "2025", "type": "Objective", "topic": "Tawhid", "question": "An aspect of one's culture which is regarded as Shirk is", "images": [], "options": {"A": "excessive spending at burial ceremonies.", "B": "offering ritual sacrifices to spirits.", "C": "using musical instruments in public.", "D": "ceremonies involving social interaction."}, "answer": "B", "explanation": "Sacrifices to spirits equate to associating partners with Allah, which is shirk.", "marks": "1", "difficulty": "1"}, {"id": "objective>IRK>2025>45", "subject": "IRK", "year": "2025", "type": "Objective", "topic": "Sirah", "question": "Muhammad (S.A.W) played a vital role in the rebuilding of Ka'bah at the age of", "images": [], "options": {"A": "50", "B": "40", "C": "35", "D": "25"}, "answer": "C", "explanation": "At age 35, the Prophet resolved a dispute over who should place the Black Stone.", "marks": "1", "difficulty": "1"}, {"id": "objective>IRK>2025>46", "subject": "IRK", "year": "2025", "type": "Objective", "topic": "Qur'an", "question": "\"فِيهَا أَيَاتٌ بَيِّنَاتٌ مَّقَامُ إِبْرَاهِيمَ ۖ\" is found in Surah", "images": [], "options": {"A": "Al-Duhaa", "B": "Al-Tin", "C": "Al-Hajj", "D": "Al-Imran"}, "answer": "D", "explanation": "This verse is in Surah Al-Imran (3:97) and refers to the station of Ibrahim at the Ka'bah.", "marks": "1", "difficulty": "1"}, {"id": "objective>IRK>2025>47", "subject": "IRK", "year": "2025", "type": "Objective", "topic": "Hadith", "question": "Hadith 5 of an-Nawawi begins with", "images": [], "options": {"A": "Ma nahaitukum 'anhu fajtanibuhu", "B": "Man raa'a minkum munkaran", "C": "Bayna al-mar'i wa bayna al-shirki wal-kufri", "D": "Al-halalu bayyinun wal-haramu bayyinun"}, "answer": "D", "explanation": "Hadith 5 begins with 'The lawful is clear, and the unlawful is clear...'", "marks": "1", "difficulty": "1"}, {"id": "objective>IRK>2025>48", "subject": "IRK", "year": "2025", "type": "Objective", "topic": "Worship", "question": "At the end of this prayer, how many sittings for at-Tashahhud are expected of someone who misses one Rak'ah in a congregational Salatul-Maghrib?", "images": [], "options": {"A": "Four", "B": "Three", "C": "Two", "D": "One"}, "answer": "C", "explanation": "The person will sit once with the Imam and once again after completing their missed Rak'ah.", "marks": "1", "difficulty": "1"}, {"id": "objective>IRK>2025>49", "subject": "IRK", "year": "2025", "type": "Objective", "topic": "Islamic History", "question": "Which of the following practices did not exist in the Jahiliyyah era?", "images": [], "options": {"A": "Waging war", "B": "Marrying unlimited number of wives", "C": "Tribalism and favouritism", "D": "Bad treatment of guests"}, "answer": "D", "explanation": "Hospitality was a key Arab virtue even in Jahiliyyah times.", "marks": "1", "difficulty": "1"}, {"id": "objective>IRK>2025>50", "subject": "IRK", "year": "2025", "type": "Objective", "topic": "Hadith", "question": "Which of the following statements is correct?", "images": [], "options": {"A": "No Hadith was recorded during the Prophet's (S.A.W.) lifetime", "B": "All Hadiths were recorded during the Prophet's (S.A.W.) lifetime", "C": "Most Hadiths were recorded during the Prophet's (S.A.W.) lifetime", "D": "A few Hadiths were recorded during the Prophet's (S.A.W.) lifetime"}, "answer": "D", "explanation": "Some companions like Abdullah ibn Amr ibn al-'As did record Hadiths during the Prophet's lifetime.", "marks": "1", "difficulty": "1"}];